import api from "@/lib/axios";

// Order types
export interface OrderItem {
  productId: {
    _id: string;
    title: string;
    price?: number;
    image?: string;
    images?: string[];
  };
  title: string;
  unitPrice: number;
  quantity: number;
  selectedVariants?: { name: string; value: string }[];
  variantSku?: string;
  note?: string;
}

export interface Order {
  _id: string;
  orderGroup?: string | null;
  customer: { _id: string; username: string; email: string };
  seller: { _id: string; username: string; email: string };
  shipper?: { _id: string; username: string; email: string } | null;
  items: OrderItem[];
  subtotalAmount?: number;
  discountAmount?: number;
  voucher?: {
    code?: string;
    discountAmount?: number;
  } | null;
  totalAmount: number;
  status: string;
  paymentStatus?: string;
  shippingAddress?: {
    fullName: string;
    phone: string;
    country?: string;
    city?: string;
    district?: string;
    ward?: string;
    street?: string;
    detail?: string;
  };
  shippingPrice?: number;
  paymentMethod?: string;
  note?: string;
  statusHistory?: Array<{ status: string; timestamp: string; note: string }>;
  createdAt: string;
}

export interface GetOrdersParams {
  role?: "buyer" | "seller";
  includeHidden?: boolean;
}

export interface GetOrdersResponse {
  data: Order[];
}

// Get list of orders
export const getOrders = async (
  params: GetOrdersParams = {},
): Promise<GetOrdersResponse> => {
  const response = await api.get("/api/orders", { params });
  return response.data;
};

export interface GetOrderDetailsResponse {
  data: Order[];
  isGroup?: boolean;
  groupId?: string;
  shippingPrice?: number;
  groupTotal?: number;
}

export interface GetOrderDetailsParams {
  role?: "buyer" | "seller";
}

// Get order details by ID
export const getOrderDetails = async (
  orderId: string,
  params: GetOrderDetailsParams = {},
): Promise<GetOrderDetailsResponse> => {
  const response = await api.get(`/api/orders/${orderId}`, { params });
  return response.data;
};

// Save a seller
export const saveSeller = async (
  sellerId: string,
): Promise<{ message: string; data: { sellerId: string } }> => {
  const response = await api.post(`/api/users/saved-sellers/${sellerId}`);
  return response.data;
};

// Unsave a seller
export const unsaveSeller = async (
  sellerId: string,
): Promise<{ message: string; data: { sellerId: string } }> => {
  const response = await api.delete(`/api/users/saved-sellers/${sellerId}`);
  return response.data;
};

// Get saved sellers
export const getSavedSellers = async (): Promise<{
  data: Array<{
    _id: string;
    username: string;
    email: string;
    avatarUrl?: string;
    reputationScore: number;
  }>;
}> => {
  const response = await api.get("/api/users/saved-sellers");
  return response.data;
};

// Hide an order
export const hideOrder = async (
  orderId: string,
): Promise<{ message: string; data: { orderId: string } }> => {
  const response = await api.post(`/api/users/hidden-orders/${orderId}`);
  return response.data;
};

// Unhide an order
export const unhideOrder = async (
  orderId: string,
): Promise<{ message: string; data: { orderId: string } }> => {
  const response = await api.delete(`/api/users/hidden-orders/${orderId}`);
  return response.data;
};

// Cancel an order (buyer only - status must be "created" or "packaging")
// reason must be one of the predefined codes; if "other", a custom text may
// be supplied in otherText.
export const cancelOrder = async (
  orderId: string,
  reason: string,
  otherText?: string,
): Promise<{ message: string; data: any }> => {
  const response = await api.patch(`/api/orders/${orderId}/status`, {
    status: "cancelled",
    reason,
    otherReason: otherText,
  });
  return response.data;
};

import api from "@/lib/axios";

export interface Product {
  _id: string;
  title: string;
  description: string;
  price: number;
  image?: string;
  images?: string[];
  sellerId: {
    _id: string;
    username: string;
    avatarUrl?: string;
  };
  categoryId?: {
    _id: string;
    name: string;
    slug: string;
  };
  averageRating: number;
  ratingCount: number;
  status: string;
  createdAt: string;
  variantCombinations?: {
    key: string;
    selections: { name: string; value: string }[];
    price?: number;
    quantity: number;
  }[];
}

export interface Seller {
  _id: string;
  username: string;
  avatarUrl?: string;
  reputationScore: number;
}

export interface SearchProductsResponse {
  page: number;
  limit: number;
  total: number;
  data: Product[];
}

export interface SearchSellersResponse {
  page: number;
  limit: number;
  total: number;
  data: Seller[];
}

export interface GlobalSearchResponse {
  data: {
    products: Product[];
    sellers: Seller[];
  };
}

/**
 * Search products by name, price, and rating
 */
export const searchProducts = async (
  q: string,
  options?: {
    page?: number;
    limit?: number;
    minPrice?: number;
    maxPrice?: number;
    minRating?: number;
    sort?: string;
  },
): Promise<SearchProductsResponse> => {
  const params = new URLSearchParams();
  if (q) params.append("search", q);
  if (options?.page) params.append("page", String(options.page));
  if (options?.limit) params.append("limit", String(options.limit));
  if (options?.minPrice !== undefined)
    params.append("minPrice", String(options.minPrice));
  if (options?.maxPrice !== undefined)
    params.append("maxPrice", String(options.maxPrice));
  if (options?.minRating !== undefined)
    params.append("minRating", String(options.minRating));
  if (options?.sort) params.append("sort", options.sort);

  const response = await api.get<SearchProductsResponse>(
    `/api/products?${params}`,
  );
  return response.data;
};

/**
 * Search sellers by name
 */
export const searchSellers = async (
  q: string,
  options?: {
    page?: number;
    limit?: number;
  },
): Promise<SearchSellersResponse> => {
  const params = new URLSearchParams();
  if (q) params.append("q", q);
  if (options?.page) params.append("page", String(options.page));
  if (options?.limit) params.append("limit", String(options.limit));

  const response = await api.get<SearchSellersResponse>(
    `/api/search/sellers?${params}`,
  );
  return response.data;
};

/**
 * Global search that returns both products and sellers
 */
export const globalSearch = async (
  q: string,
  options?: {
    productLimit?: number;
    sellerLimit?: number;
  },
): Promise<GlobalSearchResponse> => {
  // Fetch products and sellers in parallel
  const [productsRes, sellersRes] = await Promise.all([
    searchProducts(q, { limit: options?.productLimit }),
    searchSellers(q, { limit: options?.sellerLimit }),
  ]);

  return {
    data: {
      products: productsRes.data,
      sellers: sellersRes.data,
    },
  };
};

import api from "@/lib/axios";

export interface ProductVariant {
  name: string;
  options: {
    value: string;
    price?: number;
    quantity?: number;
    sku?: string;
  }[];
}

export interface ProductVariantCombination {
  key: string;
  selections: { name: string; value: string }[];
  quantity: number;
  price?: number;
  sku?: string;
}

export interface Product {
  _id: string;
  sellerId: string;
  title: string;
  description: string;
  price: number;
  basePrice?: number;
  salePrice?: number | null;
  saleStartDate?: string | null;
  saleEndDate?: string | null;
  isOnSale?: boolean;
  image?: string;
  images?: string[];
  categoryId?: any;
  quantity: number;
  condition: string;
  status: string;
  listingStatus: "active" | "paused" | "ended" | "deleted";
  lowStockThreshold: number;
  variants?: ProductVariant[];
  variantCombinations?: ProductVariantCombination[];
  promotionType?: "normal" | "outlet" | "daily_deal";
  originalPrice?: number | null;
  discountPercent?: number | null;
  dealStartDate?: string | null;
  dealEndDate?: string | null;
  averageRating: number;
  ratingCount: number;
  createdAt: string;
  updatedAt: string;
}

export interface InventorySummary {
  totalProducts: number;
  activeProducts: number;
  lowStockCount: number;
  lowStockProducts: Product[];
  outOfStock: number;
}

export interface CreateProductPayload {
  title: string;
  description?: string;
  price: number;
  saleEnabled?: boolean;
  salePrice?: number;
  saleStartDate?: string;
  saleEndDate?: string;
  quantity: number;
  condition?: string;
  categoryId: string;
  image?: string;
  images?: string[];
  variants?: ProductVariant[];
  variantCombinations?: ProductVariantCombination[];
}

export interface UpdateProductPayload extends Partial<Product> {
  saleEnabled?: boolean;
  salePrice?: number;
  saleStartDate?: string;
  saleEndDate?: string;
}

/**
 * Create new product
 */
export async function createProduct(data: CreateProductPayload) {
  const response = await api.post("/api/products", data);
  return response.data;
}

/**
 * Get seller's product listings
 */
export async function getMyListings(params?: {
  status?: string;
  search?: string;
  page?: number;
  limit?: number;
}) {
  const response = await api.get("/api/products/seller/my-listings", { params });
  return response.data;
}

/**
 * Update product
 */
export async function updateProduct(productId: string, data: UpdateProductPayload) {
  const response = await api.put(`/api/products/${productId}`, data);
  return response.data;
}

/**
 * Update listing status
 */
export async function updateListingStatus(
  productId: string,
  listingStatus: "active" | "paused" | "ended"
) {
  const response = await api.patch(`/api/products/${productId}/status`, {
    listingStatus,
  });
  return response.data;
}

/**
 * Delete product (soft delete)
 */
export async function deleteProduct(productId: string) {
  const response = await api.delete(`/api/products/${productId}`);
  return response.data;
}

/**
 * Get inventory summary
 */
export async function getInventorySummary(): Promise<{ data: InventorySummary }> {
  const response = await api.get("/api/products/seller/inventory");
  return response.data;
}

/**
 * Get low stock products
 */
export async function getLowStockProducts() {
  const response = await api.get("/api/products/seller/low-stock");
  return response.data;
}

