import {
  Dialog,
  DialogTrigger,
  DialogHeader,
  DialogContent,
  DialogFooter,
  DialogTitle,
} from "../ui/dialog";
import { Button } from "../ui/button";
import { Input } from "../ui/input";
import { useCart } from "@/contexts/cart-context";
import { useEffect, useState } from "react";
import type { ProductDetail } from "@/pages/product-detail";
import { toast } from "sonner";

type Props = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  product: ProductDetail | undefined;
};

const AddToCartDialog = ({ open, onOpenChange, product }: Props) => {
  const [quantity, setQuantity] = useState(1);
  const [selectedVariants, setSelectedVariants] = useState<
    Record<string, string>
  >({});
  const { addToCart } = useCart();

  const selectedVariantPairs = Object.entries(selectedVariants)
    .filter(([, value]) => value)
    .map(([name, value]) => ({ name, value }));

  const getSelectedCombinationStock = () => {
    if (!product?.variantCombinations?.length) return product?.quantity || 0;
    if (!product?.variants?.length) return product?.quantity || 0;
    if (selectedVariantPairs.length !== product.variants.length) {
      return product?.quantity || 0;
    }

    const key = [...selectedVariantPairs]
      .sort((a, b) => a.name.localeCompare(b.name))
      .map((p) => `${p.name}:${p.value}`)
      .join("|");
    const combo = product.variantCombinations.find((c) => c.key === key);
    return combo?.quantity || 0;
  };

  const getOptionAvailable = (variantName: string, optionValue: string) => {
    if (!product?.variantCombinations?.length) return true;
    const expected = selectedVariantPairs.filter((p) => p.name !== variantName);
    expected.push({ name: variantName, value: optionValue });

    return product.variantCombinations.some((combo) => {
      if ((combo.quantity || 0) <= 0) return false;
      return expected.every((item) =>
        combo.selections.some(
          (s) => s.name === item.name && s.value === item.value,
        ),
      );
    });
  };

  const selectedStock = getSelectedCombinationStock();
  const isExactVariantSelected =
    (product?.variants?.length || 0) > 0 &&
    selectedVariantPairs.length === (product?.variants?.length || 0);
  const maxSelectableQty = isExactVariantSelected
    ? selectedStock
    : product?.quantity || 0;

  useEffect(() => {
    const maxQty = Math.max(1, maxSelectableQty || 1);
    setQuantity((prev) => Math.max(1, Math.min(prev, maxQty)));
  }, [maxSelectableQty]);

  const handleAdd = async () => {
    if (product) {
      await addToCart(product._id, quantity, selectedVariantPairs);
    }
    if (
      (product?.variants?.length || 0) > 0 &&
      selectedVariantPairs.length !== product?.variants!.length
    ) {
      toast.error("Please select all product variants");
      return;
    }
    onOpenChange(false);
    setQuantity(1);
  };

  if (!product) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Add to Cart</DialogTitle>
        </DialogHeader>

        <div className="flex gap-4">
          <img
            src={product.image}
            alt={product.title}
            className="w-24 h-24 object-cover rounded-md"
          />

          <div className="flex flex-col gap-2 flex-1">
            <div className="flex items-center gap-2">
              <h3 className="font-semibold">{product.title}</h3>-
              <p className="text-muted-foreground">
                ${product.price?.toFixed(2)}
              </p>
            </div>
            <h3 className="text-muted-foreground">{product.description}</h3>

            {product?.variants && product.variants.length > 0 && (
              <div className="flex flex-col gap-3">
                {product.variants.map((variant) => (
                  <div key={variant.name} className="flex flex-col gap-2">
                    <h3 className="text-sm font-semibold">
                      {variant.name.charAt(0).toUpperCase() +
                        variant.name.slice(1)}
                      :
                      {selectedVariants[variant.name] && (
                        <span className="ml-2 font-normal text-muted-foreground">
                          {selectedVariants[variant.name]}
                        </span>
                      )}
                    </h3>
                    <div className="flex flex-wrap gap-2">
                      {variant.options.map((opt) => {
                        const optionAvailable = getOptionAvailable(
                          variant.name,
                          opt.value,
                        );
                        return (
                          <button
                            key={opt.value}
                            type="button"
                            onClick={() =>
                              setSelectedVariants((prev) => ({
                                ...prev,
                                [variant.name]:
                                  prev[variant.name] === opt.value
                                    ? ""
                                    : opt.value,
                              }))
                            }
                            className={`px-3 py-1.5 rounded-md border text-sm transition-all ${
                              selectedVariants[variant.name] === opt.value
                                ? "border-primary bg-primary text-primary-foreground"
                                : "border-border hover:border-primary"
                            } ${optionAvailable ? "cursor-pointer" : "opacity-40 cursor-not-allowed line-through"}`}
                            disabled={!optionAvailable}
                          >
                            {opt.value}
                          </button>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            )}

            <div className="flex items-center gap-2 mt-2">
              <span>Quantity:</span>
              <Input
                type="number"
                required
                min={1}
                max={Math.max(1, maxSelectableQty)}
                value={quantity}
                onChange={(e) =>
                  setQuantity(
                    Math.max(
                      1,
                      Math.min(
                        Math.max(1, maxSelectableQty),
                        parseInt(e.target.value) || 1,
                      ),
                    ),
                  )
                }
                className="w-20"
              />
            </div>

            <p className="text-sm text-muted-foreground">
              Stock: {maxSelectableQty} available
            </p>
          </div>
        </div>

        <DialogFooter>
          <Button
            className="cursor-pointer"
            variant="outline"
            onClick={() => onOpenChange(false)}
          >
            Cancel
          </Button>
          <Button className="cursor-pointer" onClick={handleAdd}>
            Add to Cart
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

export default AddToCartDialog;

import { Button } from "@/components/ui/button";
import { type CartItem as CartItemType } from "@/services/cart.service";
import { useCart } from "@/contexts/cart-context";
import { Minus, Plus, Trash2 } from "lucide-react";
import { Link } from "react-router-dom";

interface CartItemProps {
  item: CartItemType;
}

export const CartDropdownItem = ({ item }: CartItemProps) => {
  const { updateQuantity, removeFromCart } = useCart();
  const availableStock = Number(item.availableStock ?? item.product.stock ?? 0);
  const isPurchasable = item.availabilityStatus
    ? item.availabilityStatus === "ok"
    : !item.isOutOfStock && item.quantity <= availableStock;
  const hasProductDetail = Boolean(item.product._id);
  const availabilityMessage =
    item.availabilityMessage ||
    (isPurchasable ? "" : "Product is currently unavailable");

  const handleIncrease = () => {
    if (!isPurchasable) return;
    updateQuantity(item._id, "increase");
  };

  const handleDecrease = () => {
    if (!isPurchasable) {
      removeFromCart(item._id);
      return;
    }

    if (item.quantity > 1) {
      updateQuantity(item._id, "decrease");
    } else {
      removeFromCart(item._id);
    }
  };

  const handleRemove = () => {
    removeFromCart(item._id);
  };

  return (
    <div className="flex gap-4 py-3 group">
      <div className="h-20 w-20 overflow-hidden rounded-md border shrink-0">
        {item.product?.image ? (
          <img
            src={item.product.image}
            alt={item.product?.title}
            className="h-full w-full object-cover"
          />
        ) : (
          <div className="h-full w-full bg-gray-100" />
        )}
      </div>
      <div className="flex flex-1 flex-col justify-between">
        <div className="flex justify-between gap-2">
          <div className="flex flex-col gap-1 mb-1">
            {hasProductDetail ? (
              <Link
                to={`/products/${item.product._id}`}
                className="text-sm font-medium leading-tight line-clamp-2 hover:underline"
              >
                {item.product.title}
              </Link>
            ) : (
              <p className="text-sm font-medium leading-tight line-clamp-2">
                {item.product.title}
              </p>
            )}
            <p className="text-sm text-muted-foreground line-clamp-1">
              {item.product.description}
            </p>
          </div>
          <p className="text-sm font-bold whitespace-nowrap">
            ${(item.priceSnapShot * item.quantity).toFixed(2)}
          </p>
        </div>
        <div className="flex items-center justify-between text-xs text-muted-foreground">
          <div className="flex items-center gap-2 border rounded-md p-0.5">
            <Button
              variant="ghost"
              size="icon"
              className="h-5 w-5 rounded-sm cursor-pointer"
              onClick={handleDecrease}
            >
              <Minus className="size-3" />
            </Button>
            <span className="w-4 text-center text-xs font-medium text-foreground">
              {item.quantity}
            </span>
            <Button
              variant="ghost"
              size="icon"
              className="h-5 w-5 rounded-sm cursor-pointer"
              onClick={handleIncrease}
              disabled={!isPurchasable || item.quantity >= availableStock}
            >
              <Plus className="size-3" />
            </Button>
          </div>
          {availabilityMessage && (
            <span className="text-[11px] font-medium text-red-600">
              {availabilityMessage}
            </span>
          )}
          <button
            onClick={handleRemove}
            className="text-red-500 cursor-pointer hover:text-red-600 hover:bg-red-50 p-1 rounded transition-colors opacity-0 group-hover:opacity-100"
            title="Remove item"
          >
            <Trash2 className="size-4" />
          </button>
        </div>
      </div>
    </div>
  );
};

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { ScrollArea } from "@/components/ui/scroll-area";
import { LogIn, ShoppingCart } from "lucide-react";
import type { PropsWithChildren } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { useCart } from "@/contexts/cart-context";
import { CartDropdownItem } from "./cart-dropdown-item";
import { useAuth } from "@/hooks/use-auth";

export const CartDropdown = ({ children }: PropsWithChildren) => {
  const { cart, refreshCart } = useCart();
  const { user } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();

  // Calculate from cart or default to 0
  const itemCount = cart?.items.length || 0;
  const subtotal = cart?.totalPrice || 0;

  const isCart = location.pathname === "/cart";

  if (isCart) {
    return (
      <div className="relative">
        {children}
        {itemCount > 0 && (
          <span className="absolute -top-1.5 -right-1.5 flex h-4 w-4 items-center justify-center rounded-full bg-red-600 text-[10px] font-bold text-white">
            {itemCount > 99 ? "99+" : itemCount}
          </span>
        )}
      </div>
    );
  }
  return (
    <DropdownMenu
      onOpenChange={(open) => {
        if (open && user) {
          void refreshCart();
        }
      }}
    >
      <DropdownMenuTrigger asChild>
        <div className="relative">
          {children}
          {itemCount > 0 && (
            <span className="absolute -top-1.5 -right-1.5 flex h-4 w-4 items-center justify-center rounded-full bg-red-600 text-[10px] font-bold text-white">
              {itemCount > 99 ? "99+" : itemCount}
            </span>
          )}
        </div>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-[350px]">
        <DropdownMenuLabel className="flex items-center justify-between">
          <span className="font-bold text-lg">Shopping Cart</span>
          {user && (
            <span className="text-muted-foreground text-sm font-normal">
              ({itemCount} items)
            </span>
          )}
        </DropdownMenuLabel>
        <DropdownMenuSeparator />

        <div className="flex flex-col h-full">
          <ScrollArea
            className={`${user ? "h-[300px] p-2" : "h-[200px] p-2 flex-1"}`}
          >
            {user ? (
              cart && cart.items.length > 0 ? (
                <div className="flex flex-col gap-0 divide-y">
                  {cart.items.map((item) => (
                    <CartDropdownItem key={item._id} item={item} />
                  ))}
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center h-full text-muted-foreground gap-2 py-8">
                  <ShoppingCart className="size-12 opacity-20" />
                  <p>Your cart is empty</p>
                </div>
              )
            ) : (
              <div className="flex flex-col items-center justify-center h-full text-muted-foreground gap-2 py-8">
                <LogIn className="size-12 opacity-20" />
                <p>You have to login to view your cart</p>
              </div>
            )}
          </ScrollArea>

          {!user && (
            <div className="p-3 border-t flex gap-2">
              <Button
                onClick={() => navigate("/auth/sign-in")}
                className="w-1/2 cursor-pointer"
              >
                Login
              </Button>
              <Button
                onClick={() => navigate("/auth/sign-up")}
