export default CartDropdown;

import { type CartItem as CartItemType } from "@/services/cart.service";
import { useCart } from "@/contexts/cart-context";
import { Minus, Plus, Trash2 } from "lucide-react";
import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";

interface CartItemProps {
  item: CartItemType;
  isSelected?: boolean;
  onToggle?: () => void;
}

const formatVND = (amount: number) => amount.toLocaleString("vi-VN") + " VND";

export const CartItem = ({ item, isSelected, onToggle }: CartItemProps) => {
  const { updateQuantity, removeFromCart, toggleSaveForLater } = useCart();
  const [quantity, setQuantity] = useState(item.quantity);
  const navigate = useNavigate();

  useEffect(() => {
    setQuantity(item.quantity);
  }, [item.quantity]);

  const description = item.product.description || "";

  const price = item.priceSnapShot;
  const originalPrice =
    item.originalPriceSnapShot && item.originalPriceSnapShot > price
      ? item.originalPriceSnapShot
      : null;
  const isOnSale = Boolean(item.isOnSale && originalPrice);
  const priceVND = price * 25400; // Approx rate
  const availableStock = Number(
    item.availableStock ?? item.product.quantity ?? item.product.stock ?? 0,
  );
  const isOutOfStock = Boolean(
    item.isOutOfStock || item.availabilityStatus === "out_of_stock",
  );
  const isInsufficient = item.availabilityStatus === "insufficient_stock";
  const isPurchasable = item.savedForLater ? false : item.availabilityStatus
    ? item.availabilityStatus === "ok"
    : !isOutOfStock && !isInsufficient && quantity <= availableStock;
  const availabilityMessage =
    item.availabilityMessage ||
    (isPurchasable ? "" : "Product is currently unavailable");
  const hasProductDetail = Boolean(item.product._id);

  const imageUrl = item.product.image || "";

  const handleDecrease = () => {
    if (!isPurchasable) {
      removeFromCart(item._id);
      return;
    }

    if (quantity > 1) {
      const newQty = quantity - 1;
      setQuantity(newQty);
      updateQuantity(item._id, "decrease");
    } else {
      removeFromCart(item._id);
    }
  };

  const handleIncrease = () => {
    if (isPurchasable && quantity < availableStock) {
      const newQty = quantity + 1;
      setQuantity(newQty);
      updateQuantity(item._id, "increase");
    }
  };

  const handleRemove = () => {
    removeFromCart(item._id);
  };

  const handleBuyNow = () => {
    if (!isPurchasable) return;
    navigate("/checkout", {
      state: {
        source: "cart",
        cartItemIds: [item._id],
      },
    });
  };

  return (
    <div
      onClick={() => {
        if (!isPurchasable) return;
        onToggle?.();
      }}
      className={`bg-white rounded-xl border-2 transition-all duration-200 shadow-sm overflow-hidden font-sans w-full mb-4 cursor-pointer hover:shadow-md ${
        isSelected ? "border-blue-300 ring-1 ring-blue-300" : "border-gray-200"
      } ${isPurchasable ? "" : "opacity-80"}`}
    >
      {/* Item body */}
      <div className="p-4 flex gap-4 items-start">
        {/* Product image */}
        <div className="flex-shrink-0 w-28 h-28 rounded-lg bg-gray-100 border border-gray-200 overflow-hidden flex items-center justify-center relative">
          {isOnSale && (
            <div className="absolute left-0 top-0 bg-red-600 px-2 py-0.5 text-[10px] font-bold text-white shadow-sm z-10 rounded-br-md">
              SALE
            </div>
          )}
          {imageUrl ? (
            <img
              src={imageUrl}
              alt={item.product.title}
              className="w-full h-full object-cover"
            />
          ) : (
            <svg
              viewBox="0 0 100 100"
              className="w-20 h-20 text-gray-300"
              fill="currentColor"
            >
              <rect
                x="20"
                y="35"
                width="60"
                height="45"
                rx="5"
                fill="#1a1a1a"
              />
              <path
                d="M35 35 Q35 20 50 20 Q65 20 65 35"
                stroke="#1a1a1a"
                strokeWidth="4"
                fill="none"
                strokeLinecap="round"
              />
              <rect
                x="15"
                y="30"
                width="70"
                height="12"
                rx="3"
                fill="#2a2a2a"
              />
            </svg>
          )}
        </div>

        {/* Product details */}
        <div className="flex-1 min-w-0">
          {hasProductDetail ? (
            <Link
              to={`/products/${item.product._id}`}
              onClick={(e) => e.stopPropagation()}
              className="text-lg font-semibold text-blue-700 hover:text-blue-900 hover:underline leading-snug line-clamp-2 block transition-colors"
            >
              {item.product.title}
            </Link>
          ) : (
            <p className="text-lg font-semibold text-gray-700 leading-snug line-clamp-2">
              {item.product.title}
            </p>
          )}
          <p className="text-sm text-gray-500 mt-0.5 mb-2">{description}</p>

          {/* Pricing */}
          <div className="space-y-0.5">
            <div>
              {originalPrice && (
                <span className="mr-2 text-sm text-gray-400 line-through">
                  US ${originalPrice.toFixed(2)}
                </span>
              )}
              <span className={`text-xl font-bold ${isOnSale ? "text-red-600" : "text-gray-900"}`}>
                US ${price.toFixed(2)}
              </span>
              <span className="text-sm text-gray-400 ml-1">
                ({formatVND(priceVND)})
              </span>
            </div>
          </div>

          {/* Quantity + Actions */}
          <div className="flex items-center justify-between mt-3 flex-wrap gap-2">
            {/* Quantity controls */}
            <div className="flex items-center gap-5">
              <div
                className="flex items-center gap-0 border border-gray-300 rounded-lg overflow-hidden h-8 shadow-sm bg-white"
                onClick={(e) => e.stopPropagation()}
              >
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleDecrease();
                  }}
                  className="w-8 h-8 flex cursor-pointer items-center justify-center text-gray-500 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed transition-colors border-r border-gray-300"
                >
                  {quantity === 1 ? (
                    <Trash2 className="size-3.5" />
                  ) : (
                    <Minus className="size-3.5" />
                  )}
                </button>
                <span className="w-8 text-center text-base font-semibold text-gray-800 select-none">
                  {quantity}
                </span>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    handleIncrease();
                  }}
                  disabled={!isPurchasable || quantity >= availableStock}
                  className="w-8 h-8 flex cursor-pointer items-center justify-center text-gray-500 hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed transition-colors border-l border-gray-300"
                >
                  <Plus className="size-3.5" />
                </button>
              </div>
              <span className="text-muted-foreground">
                Stock: {availableStock}
              </span>
            </div>
            {availabilityMessage && (
              <div className="w-full text-sm font-medium text-red-600">
                {availabilityMessage}
              </div>
            )}
            {item.selectedVariants && item.selectedVariants.length > 0 && (
              <div className="text-sm text-muted-foreground">
                Variant:{" "}
                {item.selectedVariants
                  .map((v) => `${v.name}: ${v.value}`)
                  .join(", ")}
              </div>
            )}
          </div>
          {/* Action links */}
          <div className="flex items-center justify-end gap-1 text-sm flex-wrap mt-2">
            <button
              onClick={(e) => {
                e.stopPropagation();
                handleBuyNow();
              }}
              disabled={!isPurchasable}
              className="text-blue-600 cursor-pointer hover:text-blue-800 hover:underline font-medium transition-colors px-1 disabled:opacity-40 disabled:cursor-not-allowed"
            >
              Buy it now
            </button>
            <span className="text-gray-300">|</span>
            <button
              onClick={(e) => {
                e.stopPropagation();
                toggleSaveForLater(item._id);
              }}
              className="text-blue-600 cursor-pointer hover:text-blue-800 hover:underline font-medium transition-colors px-1"
            >
              {item.savedForLater ? "Move to cart" : "Save for later"}
            </button>
            <span className="text-gray-300">|</span>
            <button
              onClick={(e) => {
                e.stopPropagation();
                handleRemove();
              }}
              className="text-blue-600 cursor-pointer hover:text-blue-800 hover:underline font-medium transition-colors px-1"
            >
              Remove
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CartItem;

import { Link } from "react-router-dom";
import {
  Tag,
  Shirt,
  Smartphone,
  Laptop,
  Home,
  Dumbbell,
  BookOpen,
  Gamepad2,
  Gem,
  Camera,
  LayoutGrid,
  ArrowRight,
} from "lucide-react";
import type { LucideIcon } from "lucide-react";

interface Category {
  _id: string;
  name: string;
  slug: string;
  imageUrl?: string;
}

interface CategoryGridProps {
  categories: Category[];
  loading?: boolean;
}

const ICON_MAP: [string, LucideIcon][] = [
  ["phone", Smartphone],
  ["mobile", Smartphone],
  ["electronic", Smartphone],
  ["computer", Laptop],
  ["laptop", Laptop],
  ["fashion", Shirt],
  ["cloth", Shirt],
  ["wear", Shirt],
  ["home", Home],
  ["furniture", Home],
  ["decor", Home],
  ["sport", Dumbbell],
  ["fitness", Dumbbell],
  ["book", BookOpen],
  ["education", BookOpen],
  ["game", Gamepad2],
  ["jewel", Gem],
  ["watch", Gem],
  ["camera", Camera],
  ["photo", Camera],
];

function getIcon(name: string): LucideIcon {
  const lower = name.toLowerCase();
  for (const [key, Icon] of ICON_MAP) {
    if (lower.includes(key)) return Icon;
  }
  return Tag;
}

export function CategoryGrid({ categories, loading = false }: CategoryGridProps) {
  const displayed = categories.slice(0, 8);

  return (
    <div className="w-full h-full flex flex-col gap-3 p-5 bg-gradient-to-br from-slate-50 to-indigo-50/40 rounded-2xl">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <div className="p-1.5 bg-primary/10 rounded-lg">
            <LayoutGrid className="w-4 h-4 text-primary" />
          </div>
          <span className="text-sm font-semibold text-foreground">Shop by Category</span>
        </div>
        <Link
          to="/products"
          className="flex items-center gap-1 text-xs text-primary hover:text-primary/70 font-medium transition-colors"
        >
          View all <ArrowRight className="w-3 h-3" />
        </Link>
      </div>

      {/* Grid */}
      {loading ? (
        <div className="grid grid-cols-4 gap-2 flex-1">
          {Array.from({ length: 8 }).map((_, i) => (
            <div key={i} className="aspect-square rounded-xl bg-muted animate-pulse" />
          ))}
        </div>
      ) : displayed.length === 0 ? (
        <div className="flex-1 flex items-center justify-center">
          <p className="text-muted-foreground text-sm">No categories available</p>
        </div>
      ) : (
        <div className="grid grid-cols-4 gap-2 flex-1 content-start">
          {displayed.map((cat) => {
            const FallbackIcon = getIcon(cat.name);
            return (
              <Link
                key={cat._id}
                to={`/products?categories=${cat.slug}`}
                className="group flex flex-col items-center gap-1.5 p-2 rounded-xl bg-white border border-border/50 hover:border-primary/40 hover:shadow-md hover:-translate-y-0.5 transition-all duration-200 cursor-pointer"
              >
                {/* Image / Icon */}
                <div className="w-full aspect-square rounded-lg overflow-hidden bg-muted flex items-center justify-center">
                  {cat.imageUrl ? (
                    <img
                      src={cat.imageUrl}
                      alt={cat.name}
