                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    markAsRead(notif._id);
                                                }}
                                                className="p-1 rounded hover:bg-muted cursor-pointer"
                                                title="Mark as read"
                                            >
                                                <Check className="h-3 w-3 text-muted-foreground" />
                                            </button>
