                                        <div className={cn(
                                            "w-2 h-2 rounded-full shrink-0 mt-1.5",
                                            isBroadcast ? "bg-primary" : "bg-primary"
                                        )} />
                                    )}
                                </div>
                            );
                        })
                    )}
                </div>
            </DropdownMenuContent>
        </DropdownMenu>
    );
}

