import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { AlertCircle, CheckCircle } from 'lucide-react';
import { toast } from 'sonner';
import api from '@/lib/axios';

interface SellerReplyDialogProps {
    review: any;
    open: boolean;
    onOpenChange: (open: boolean) => void;
    onSuccess: () => void;
}

export default function SellerReplyDialog({ review, open, onOpenChange, onSuccess }: SellerReplyDialogProps) {
    const [response, setResponse] = useState(review?.sellerResponse || '');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async () => {
        if (!response.trim()) {
            toast.error('Please enter a response');
            return;
        }

        if (response.length > 500) {
            toast.error('Response must be 500 characters or less');
            return;
        }

        try {
            setLoading(true);
            const res = await api.post(`/api/reviews/${review._id}/seller-response`, {
                response: response.trim()
            });

            if (res.data.warning) {
                toast.warning(res.data.warning);
            } else {
                toast.success(res.data.message);
            }

            onSuccess();
            onOpenChange(false);
        } catch (err: any) {
            toast.error(err.response?.data?.message || 'Failed to post response');
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async () => {
        if (!confirm('Are you sure you want to delete your response?')) {
            return;
        }

        try {
            setLoading(true);
            await api.delete(`/api/reviews/${review._id}/seller-response`);
            toast.success('Response deleted successfully');
            onSuccess();
            onOpenChange(false);
        } catch (err: any) {
            toast.error(err.response?.data?.message || 'Failed to delete response');
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-2xl">
                <DialogHeader>
                    <DialogTitle>
                        {review?.sellerResponse ? 'Edit Your Response' : 'Reply to Feedback'}
                    </DialogTitle>
                </DialogHeader>

                <div className="space-y-4">
                    {/* Original Feedback */}
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <p className="text-sm font-semibold mb-2">Buyer's Feedback:</p>
                        <div className="flex items-center gap-2 mb-2">
                            <span className="text-2xl">{'⭐'.repeat(review?.rating || 0)}</span>
                            <span className="text-sm text-muted-foreground">
                                ({review?.rating}/5)
                            </span>
                        </div>
                        <p className="text-sm">{review?.comment || 'No comment'}</p>
                        <p className="text-xs text-muted-foreground mt-2">
                            By: {review?.reviewer?.username} • {new Date(review?.createdAt).toLocaleDateString()}
                        </p>
                    </div>

                    {/* Response Form */}
                    <div>
                        <label className="text-sm font-medium mb-2 block">
                            Your Response
                        </label>
                        <Textarea
                            placeholder="Write a professional response to explain the situation..."
                            value={response}
                            onChange={(e) => setResponse(e.target.value)}
                            rows={6}
                            maxLength={500}
                            className="resize-none"
                        />
                        <p className="text-sm text-muted-foreground mt-1 text-right">
                            {response.length}/500 characters
                        </p>
                    </div>

                    {/* Guidelines */}
                    <Alert>
                        <AlertCircle className="h-4 w-4" />
                        <AlertDescription>
                            <strong>Guidelines for Professional Responses:</strong>
                            <ul className="list-disc list-inside mt-2 space-y-1 text-sm">
                                <li>Be professional and courteous</li>
                                <li>Explain the situation factually</li>
                                <li>Avoid personal attacks or offensive language</li>
                                <li>Don't share contact information (phone, email)</li>
                                <li>Focus on resolving the issue</li>
                            </ul>
                        </AlertDescription>
                    </Alert>

                    {/* Example */}
                    <Alert className="bg-green-50 border-green-200">
                        <CheckCircle className="h-4 w-4 text-green-600" />
                        <AlertDescription>
                            <strong className="text-green-900">Good Example:</strong>
                            <p className="text-sm text-green-800 mt-1">
                                "We sincerely apologize for the delay. The item was shipped on time but was held up in customs. We've issued a full refund and improved our shipping process. Thank you for your patience."
                            </p>
                        </AlertDescription>
                    </Alert>

                    {/* Actions */}
                    <div className="flex justify-between gap-2">
                        <div>
                            {review?.sellerResponse && (
                                <Button
                                    variant="destructive"
                                    onClick={handleDelete}
                                    disabled={loading}
                                >
                                    Delete Response
                                </Button>
                            )}
                        </div>
                        <div className="flex gap-2">
                            <Button
                                variant="outline"
                                onClick={() => onOpenChange(false)}
                                disabled={loading}
                            >
                                Cancel
                            </Button>
                            <Button
                                onClick={handleSubmit}
                                disabled={loading || !response.trim()}
                            >
                                {loading ? 'Posting...' : review?.sellerResponse ? 'Update Response' : 'Post Response'}
                            </Button>
                        </div>
                    </div>
                </div>
            </DialogContent>
        </Dialog>
    );
}

import { useState, useEffect } from 'react';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { updateProduct, type Product } from '@/api/seller-products';
import { toast } from 'sonner';
import ProductVariantsManager from '@/components/seller/product-variants-manager';

interface EditProductDialogProps {
    product: Product;
    open: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

const numericInputClass =
    "h-12 text-base font-semibold tracking-wide transition-[box-shadow,border-color,background-color] duration-200 focus-visible:shadow-sm focus-visible:ring-2 focus-visible:ring-blue-200";

export default function EditProductDialog({
    product,
    open,
    onClose,
    onSuccess,
}: EditProductDialogProps) {
    const toInputDateTime = (value?: string | null) => {
        if (!value) return "";
        const date = new Date(value);
        if (Number.isNaN(date.getTime())) return "";
        const offset = date.getTimezoneOffset();
        const local = new Date(date.getTime() - offset * 60000);
        return local.toISOString().slice(0, 16);
    };

    const [formData, setFormData] = useState({
        title: product.title,
        description: product.description,
        price: product.basePrice ?? product.originalPrice ?? product.price,
        saleEnabled: Boolean(product.promotionType === "daily_deal" || product.salePrice),
        salePrice: product.salePrice ?? product.price,
        saleStartDate: toInputDateTime(product.saleStartDate ?? product.dealStartDate),
        saleEndDate: toInputDateTime(product.saleEndDate ?? product.dealEndDate),
        quantity: product.quantity,
        condition: product.condition,
        lowStockThreshold: product.lowStockThreshold || 5,
        variants: product.variants || [],
        variantCombinations: product.variantCombinations || [],
    });
    const [loading, setLoading] = useState(false);


    useEffect(() => {
        setFormData({
            title: product.title,
            description: product.description,
            price: product.basePrice ?? product.originalPrice ?? product.price,
            saleEnabled: Boolean(product.promotionType === "daily_deal" || product.salePrice),
            salePrice: product.salePrice ?? product.price,
            saleStartDate: toInputDateTime(product.saleStartDate ?? product.dealStartDate),
            saleEndDate: toInputDateTime(product.saleEndDate ?? product.dealEndDate),
            quantity: product.quantity,
            condition: product.condition,
            lowStockThreshold: product.lowStockThreshold || 5,
            variants: product.variants || [],
            variantCombinations: product.variantCombinations || [],
        });
    }, [product]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (formData.saleEnabled) {
            if (!formData.salePrice || !formData.saleStartDate || !formData.saleEndDate) {
                toast.error("Please fill sale price and sale time range");
                return;
            }
            if (Number(formData.salePrice) >= Number(formData.price)) {
                toast.error("Sale price must be lower than base price");
                return;
            }
        }
        setLoading(true);

        try {
            await updateProduct(product._id, formData);
            toast.success('Product updated successfully');
            onSuccess();
        } catch (err: any) {
            toast.error(err.response?.data?.message || 'Failed to update product');
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onClose}>
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>Edit Product</DialogTitle>
                </DialogHeader>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <Label htmlFor="title">Title *</Label>
                        <Input
                            id="title"
                            value={formData.title}
                            onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                            required
                        />
                    </div>

                    {/* Product Image */}
                    <div>
                        <Label>Product Image</Label>
                        <div className="mt-2">
                            {product.image && (
                                <div className="relative inline-block">
                                    <img
                                        src={product.image}
                                        alt={product.title}
                                        className="w-32 h-32 object-cover rounded-lg border"
                                    />
                                    <p className="text-xs text-gray-500 mt-1">
                                        Current image (upload feature coming soon)
                                    </p>
                                </div>
                            )}
                            {!product.image && (
                                <div className="w-32 h-32 bg-gray-100 rounded-lg border flex items-center justify-center">
                                    <p className="text-xs text-gray-400">No image</p>
                                </div>
                            )}
                        </div>
                    </div>

                    <div>
                        <Label htmlFor="description">Description</Label>
                        <Textarea
                            id="description"
                            value={formData.description}
                            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                            rows={4}
                        />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <Label htmlFor="price">Price ($) *</Label>
                            <Input
                                id="price"
                                type="number"
                                step="0.01"
                                min="0"
                                className={numericInputClass}
                                value={formData.price}
                                onChange={(e) => setFormData({ ...formData, price: parseFloat(e.target.value) })}
                                required
                            />
                        </div>

                        <div>
                            <Label htmlFor="quantity">Quantity *</Label>
                            <Input
                                id="quantity"
                                type="number"
                                min="0"
                                className={numericInputClass}
                                value={formData.quantity}
                                onChange={(e) => setFormData({ ...formData, quantity: parseInt(e.target.value) })}
                                required
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <Label htmlFor="condition">Condition</Label>
                            <Input
                                id="condition"
                                value={formData.condition}
                                onChange={(e) => setFormData({ ...formData, condition: e.target.value })}
                                placeholder="e.g., New, Used, Refurbished"
                            />
                        </div>

                        <div>
                            <Label htmlFor="lowStockThreshold">Low Stock Alert Threshold</Label>
                            <Input
                                id="lowStockThreshold"
                                type="number"
                                min="0"
                                className={numericInputClass}
                                value={formData.lowStockThreshold}
                                onChange={(e) =>
                                    setFormData({ ...formData, lowStockThreshold: parseInt(e.target.value) })
                                }
                            />
                        </div>
                    </div>

                    <div>
                        <Label>Product Variants</Label>
                        <ProductVariantsManager
                            variants={formData.variants}
                            onChange={(variants: import('@/api/seller-products').ProductVariant[]) => setFormData({ ...formData, variants })}
                            variantCombinations={formData.variantCombinations}
                            basePrice={Number(formData.price) || 0}
                            onCombinationsChange={(variantCombinations) =>
                                setFormData({ ...formData, variantCombinations })
                            }
                        />
                    </div>

                    <div className="space-y-3 rounded-lg border border-dashed border-red-300 p-3 bg-red-50/40">
                        <Label className="flex items-center justify-between">
                            <span>Sale Time</span>
                            <input
                                type="checkbox"
                                checked={formData.saleEnabled}
                                onChange={(e) =>
                                    setFormData({ ...formData, saleEnabled: e.target.checked })
                                }
                            />
                        </Label>
                        {formData.saleEnabled && (
                            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                                <div>
                                    <Label htmlFor="salePrice">Sale Price *</Label>
                                    <Input
                                        id="salePrice"
                                        type="number"
                                        step="0.01"
                                        min="0"
                                        className={numericInputClass}
                                        value={formData.salePrice}
                                        onChange={(e) =>
                                            setFormData({ ...formData, salePrice: parseFloat(e.target.value) || 0 })
                                        }
                                    />
                                </div>
                                <div>
                                    <Label htmlFor="saleStartDate">Start *</Label>
                                    <Input
                                        id="saleStartDate"
                                        type="datetime-local"
                                        value={formData.saleStartDate}
                                        onChange={(e) =>
                                            setFormData({ ...formData, saleStartDate: e.target.value })
                                        }
                                    />
                                </div>
                                <div>
                                    <Label htmlFor="saleEndDate">End *</Label>
                                    <Input
                                        id="saleEndDate"
                                        type="datetime-local"
                                        value={formData.saleEndDate}
                                        onChange={(e) =>
                                            setFormData({ ...formData, saleEndDate: e.target.value })
                                        }
                                    />
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="flex justify-end gap-2 pt-4">
                        <Button type="button" variant="outline" onClick={onClose}>
                            Cancel
                        </Button>
                        <Button type="submit" disabled={loading}>
                            {loading ? 'Saving...' : 'Save Changes'}
                        </Button>
                    </div>
                </form>
            </DialogContent>
        </Dialog>
    );
}

﻿import { useEffect, useMemo, useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card } from '@/components/ui/card';
import { PlusIcon, TrashIcon, XIcon } from 'lucide-react';
import type {
    ProductVariant,
    ProductVariantCombination,
} from '@/api/seller-products';

interface ProductVariantsManagerProps {
    variants: ProductVariant[];
    variantCombinations: ProductVariantCombination[];
    basePrice?: number;
    showSkuFields?: boolean;
    onChange: (variants: ProductVariant[]) => void;
    onCombinationsChange: (variantCombinations: ProductVariantCombination[]) => void;
}

const numericInputClass =
    "h-12 text-base font-semibold transition-[box-shadow,border-color,background-color] duration-200 focus-visible:shadow-sm focus-visible:ring-2 focus-visible:ring-blue-200";

export default function ProductVariantsManager({
    variants,
    variantCombinations,
    basePrice = 0,
    showSkuFields = true,
    onChange,
    onCombinationsChange,
}: ProductVariantsManagerProps) {
    const [newVariantName, setNewVariantName] = useState('');

    const buildVariantKey = (selections: { name: string; value: string }[]) =>
        [...selections]
            .sort((a, b) => a.name.localeCompare(b.name))
            .map((s) => `${s.name}:${s.value}`)
            .join('|');

    const generatedCombinations = useMemo(() => {
        if (!variants.length) return [];
        if (variants.some((v) => !v.options || v.options.length === 0)) return [];

        const normalizedVariants = variants.map((variant) => {
            const seen = new Set<string>();
            const uniqueOptions = (variant.options || []).filter((option) => {
                const value = String(option.value || '').trim();
                if (!value) return false;
                const dedupeKey = value.toLowerCase();
                if (seen.has(dedupeKey)) return false;
                seen.add(dedupeKey);
                return true;
            });
            return {
                ...variant,
                options: uniqueOptions,
            };
        });

        const cartesian = (
            index: number,
            acc: { name: string; value: string }[],
        ): ProductVariantCombination[] => {
            if (index >= normalizedVariants.length) {
                const selections = [...acc].sort((a, b) => a.name.localeCompare(b.name));
                return [
                    {
                        key: buildVariantKey(selections),
                        selections,
                        quantity: 0,
                        price: Number(basePrice || 0),
                        sku: '',
                    },
                ];
            }

            const current = normalizedVariants[index];
            const results: ProductVariantCombination[] = [];
            for (const option of current.options || []) {
                const value = String(option.value || '').trim();
                if (!value) continue;
                results.push(
                    ...cartesian(index + 1, [...acc, { name: current.name, value }]),
                );
            }
            return results;
        };

        return cartesian(0, []);
    }, [variants, basePrice]);

    useEffect(() => {
        if (!generatedCombinations.length) {
            if (variantCombinations.length) onCombinationsChange([]);
            return;
        }

        const prevMap = new Map(
            variantCombinations.map((c) => [c.key, c]),
        );
        const merged = generatedCombinations.map((combo) => {
            const prev = prevMap.get(combo.key);
            return {
                ...combo,
                quantity: Number(prev?.quantity || 0),
                price:
                    prev?.price === undefined || prev?.price === null
                        ? Number(basePrice || 0)
                        : Number(prev.price),
                sku: String(prev?.sku || ''),
            };
        });
        const mergedSorted = [...merged].sort((a, b) => a.key.localeCompare(b.key));
        const currentSorted = [...variantCombinations].sort((a, b) =>
            a.key.localeCompare(b.key),
        );
        const mergedJson = JSON.stringify(mergedSorted);
        const currentJson = JSON.stringify(
            currentSorted,
        );
        if (mergedJson !== currentJson) {
            onCombinationsChange(mergedSorted);
        }
    }, [generatedCombinations, variantCombinations, basePrice, onCombinationsChange]);

    const addVariant = () => {
        if (!newVariantName.trim()) return;
        onChange([...variants, { name: newVariantName, options: [] }]);
        setNewVariantName('');
    };

    const removeVariant = (index: number) => {
        onChange(variants.filter((_, i) => i !== index));
    };

    const updateVariantName = (index: number, name: string) => {
        const updated = [...variants];
        updated[index].name = name;
        onChange(updated);
    };

    const addOption = (variantIndex: number) => {
        const updated = [...variants];
        updated[variantIndex].options.push({
            value: '',
        });
        onChange(updated);
    };

    const removeOption = (variantIndex: number, optionIndex: number) => {
        const updated = [...variants];
        updated[variantIndex].options = updated[variantIndex].options.filter(
            (_, i) => i !== optionIndex
        );
        onChange(updated);
    };

    const updateOption = (
        variantIndex: number,
        optionIndex: number,
        field: string,
        value: any
    ) => {
        const updated = [...variants];
        (updated[variantIndex].options[optionIndex] as any)[field] = value;
        onChange(updated);
    };

    const updateCombination = (
        key: string,
        field: 'quantity' | 'price' | 'sku',
        value: number | string,
    ) => {
        onCombinationsChange(
            variantCombinations.map((combo) =>
                combo.key === key ? { ...combo, [field]: value } : combo,
            ),
        );
    };

    return (
        <div className="space-y-5">
            {/* Add Variant */}
            <div className="flex flex-col sm:flex-row gap-3">
                <Input
                    placeholder="Variant name (e.g., Size, Color)"
                    value={newVariantName}
                    className="h-11 flex-1"
                    onChange={(e) => setNewVariantName(e.target.value)}
                    onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                            e.preventDefault();
                            addVariant();
                        }
                    }}
                />
                <Button type="button" onClick={addVariant} size="sm" className="h-11 px-4">
                    <PlusIcon className="w-4 h-4 mr-1" />
                    Add Variant
                </Button>
            </div>

            {/* Variant List */}
            {variants.map((variant, variantIndex) => (
                <Card key={variantIndex} className="p-5">
                    <div className="flex items-center justify-between mb-4 gap-3">
                        <Input
                            value={variant.name}
                            onChange={(e) => updateVariantName(variantIndex, e.target.value)}
                            className="max-w-xs h-11 font-medium"
                            placeholder="Variant name"
                        />
                        <Button
                            type="button"
                            variant="ghost"
                            size="sm"
                            onClick={() => removeVariant(variantIndex)}
                        >
                            <TrashIcon className="w-4 h-4 text-red-600" />
                        </Button>
                    </div>

                    {/* Options */}
                    <div className="space-y-3">
                        {showSkuFields ? (
                            <div className="space-y-2">
                                {variant.options.map((option, optionIndex) => (
                                    <div key={optionIndex} className="flex gap-2 items-end">
                                        <div className="flex-1 grid gap-2 grid-cols-2">
                                            <div>
                                                <Label className="text-xs">Value</Label>
                                                <Input
                                                    value={option.value}
                                                    className="h-11"
                                                    onChange={(e) =>
                                                        updateOption(variantIndex, optionIndex, "value", e.target.value)
                                                    }
                                                    placeholder="e.g., M, Red"
                                                    size={1}
                                                />
                                            </div>
                                            <div>
                                                <Label className="text-xs">SKU</Label>
                                                <Input
                                                    value={option.sku || ""}
                                                    className="h-11"
                                                    onChange={(e) =>
                                                        updateOption(variantIndex, optionIndex, "sku", e.target.value)
                                                    }
                                                    placeholder="Optional"
                                                    size={1}
                                                />
                                            </div>
                                        </div>
                                        <Button
                                            type="button"
                                            variant="ghost"
                                            size="sm"
                                            onClick={() => removeOption(variantIndex, optionIndex)}
                                        >
                                            <XIcon className="w-4 h-4 text-gray-500" />
                                        </Button>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="space-y-2">
                                <Label className="text-xs text-muted-foreground">Values</Label>
                                <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-3 gap-3">
                                    {variant.options.map((option, optionIndex) => (
                                        <div key={optionIndex} className="relative">
                                            <Input
                                                value={option.value}
                                                className="h-11 pr-9"
                                                onChange={(e) =>
                                                    updateOption(variantIndex, optionIndex, "value", e.target.value)
                                                }
                                                placeholder="e.g., M, Red"
                                                size={1}
                                            />
                                            <Button
                                                type="button"
                                                variant="ghost"
                                                size="sm"
                                                className="absolute right-1 top-1/2 -translate-y-1/2 h-7 w-7 p-0"
                                                onClick={() => removeOption(variantIndex, optionIndex)}
                                            >
                                                <XIcon className="w-4 h-4 text-gray-500" />
                                            </Button>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        <Button
                            type="button"
                            variant="outline"
                            size="sm"
                            className="h-10 px-3"
                            onClick={() => addOption(variantIndex)}
                        >
                            <PlusIcon className="w-3 h-3 mr-1" />
                            Add Option
                        </Button>
                    </div>
                </Card>
            ))}

            {variants.length === 0 && (
                <p className="text-sm text-gray-500 italic">
                    No variants added yet.
                </p>
            )}

            {variantCombinations.length > 0 && (
                <Card className="p-5">
                    <h4 className="font-medium mb-3">Combination Stock</h4>
                    <div className="space-y-3">
                        {variantCombinations.map((combo) => (
                            <div
                                key={combo.key}
                                className={
                                    showSkuFields
                                        ? "grid gap-3 items-end md:grid-cols-[minmax(0,1fr)_7rem_11rem_minmax(0,1fr)]"
                                        : "grid gap-3 items-end md:grid-cols-[minmax(0,1fr)_6rem_12rem]"
                                }
                            >
                                <div>
                                    <Label className="text-xs">Combination</Label>
                                    <Input
                                        value={combo.selections.map((s) => s.value).join(" / ")}
                                        readOnly
                                        className="h-12 bg-muted/30 border-dashed font-medium"
                                    />
                                </div>
                                <div>
                                    <Label className="text-xs">Quantity</Label>
                                    <Input
                                        type="number"
                                        min="0"
                                        value={combo.quantity}
                                        className={`${numericInputClass} text-center`}
                                        onChange={(e) =>
                                            updateCombination(
                                                combo.key,
                                                'quantity',
                                                parseInt(e.target.value) || 0,
                                            )
                                        }
                                    />
                                </div>
                                <div>
                                    <Label className="text-xs">Price</Label>
                                    <Input
                                        type="number"
                                        min="0"
                                        step="0.01"
                                        value={combo.price ?? basePrice}
                                        className={numericInputClass}
                                        onChange={(e) =>
                                            updateCombination(
                                                combo.key,
                                                'price',
                                                e.target.value ? parseFloat(e.target.value) : 0,
                                            )
                                        }
                                    />
                                </div>
                                {showSkuFields && (
                                    <div>
                                        <Label className="text-xs">SKU</Label>
                                        <Input
                                            value={combo.sku || ''}
                                            className="h-12"
                                            onChange={(e) =>
                                                updateCombination(combo.key, 'sku', e.target.value)
                                            }
                                            placeholder="Optional"
                                        />
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </Card>
            )}
        </div>
    );
}

import { useState } from 'react';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { requestDailyDeal } from '@/api/promotions';
import { toast } from 'sonner';
import type { Product } from '@/api/seller-products';

interface RequestDailyDealDialogProps {
    product: Product;
    open: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

export default function RequestDailyDealDialog({
    product,
    open,
    onClose,
    onSuccess,
}: RequestDailyDealDialogProps) {
    const [formData, setFormData] = useState({
        discountedPrice: 0,
        startDate: '',
        endDate: '',
        quantityLimit: 0,
    });
    const [loading, setLoading] = useState(false);

    const originalPrice = product.price;
    const discountPercent =
        formData.discountedPrice > 0 && formData.discountedPrice < originalPrice
            ? Math.round(
                ((originalPrice - formData.discountedPrice) / originalPrice) * 100
            )
            : 0;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        try {
            await requestDailyDeal({
                productId: product._id,
                discountedPrice: formData.discountedPrice,
                startDate: formData.startDate,
                endDate: formData.endDate,
                quantityLimit: formData.quantityLimit,
            });

            toast.success('Sale Time request submitted successfully!');
            onSuccess();
            onClose();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to submit request');
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onClose}>
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>Request Sale Time Status</DialogTitle>
                    <DialogDescription>
                        Create a time-limited deal with special pricing
                    </DialogDescription>
                </DialogHeader>

                <form onSubmit={handleSubmit} className="space-y-6">
                    {/* Product Info */}
                    <div className="flex gap-4 p-4 bg-gray-50 rounded-lg">
                        {product.image && (
                            <img
                                src={product.image}
                                alt={product.title}
                                className="w-20 h-20 object-cover rounded"
                            />
                        )}
                        <div className="flex-1">
                            <h3 className="font-semibold line-clamp-2">{product.title}</h3>
                            <p className="text-sm text-gray-600 mt-1">
                                Available Quantity: {product.quantity}
                            </p>
                            <p className="text-sm text-gray-600">
                                Current Price: ${originalPrice.toFixed(2)}
                            </p>
                        </div>
                    </div>

                    {/* Pricing */}
                    <div>
                        <Label htmlFor="discountedPrice">Deal Price (USD) *</Label>
                        <Input
                            id="discountedPrice"
                            type="number"
                            step="0.01"
                            min="0.01"
                            max={originalPrice - 0.01}
                            value={formData.discountedPrice || ''}
                            onChange={(e) =>
                                setFormData({
                                    ...formData,
                                    discountedPrice: parseFloat(e.target.value),
                                })
                            }
                            required
                            placeholder="Enter deal price"
                        />
                        {discountPercent > 0 && (
                            <p className="text-sm mt-1 text-gray-600">
                                Discount: <span className="font-semibold">{discountPercent}%</span>{' '}
                                (Recommended: 10-90%)
                            </p>
                        )}
                    </div>

                    {/* Date Range */}
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <Label htmlFor="startDate">Start Date & Time *</Label>
                            <Input
                                id="startDate"
                                type="datetime-local"
                                value={formData.startDate}
                                onChange={(e) =>
                                    setFormData({ ...formData, startDate: e.target.value })
                                }
                                required
                                min={new Date().toISOString().slice(0, 16)}
                            />
                        </div>
                        <div>
                            <Label htmlFor="endDate">End Date & Time *</Label>
                            <Input
                                id="endDate"
                                type="datetime-local"
                                value={formData.endDate}
                                onChange={(e) =>
                                    setFormData({ ...formData, endDate: e.target.value })
                                }
                                required
                                min={formData.startDate || new Date().toISOString().slice(0, 16)}
                            />
                        </div>
                    </div>

                    {/* Quantity Limit */}
                    <div>
                        <Label htmlFor="quantityLimit">Quantity Limit *</Label>
                        <Input
                            id="quantityLimit"
                            type="number"
                            min="1"
                            max={product.quantity}
                            value={formData.quantityLimit || ''}
                            onChange={(e) =>
                                setFormData({
                                    ...formData,
                                    quantityLimit: parseInt(e.target.value),
                                })
                            }
                            required
                            placeholder={`Max: ${product.quantity}`}
                        />
                        <p className="text-sm text-gray-600 mt-1">
                            Maximum units available for this deal
                        </p>
                    </div>

                    {/* Info Box */}
                    <div className="p-4 bg-blue-50 border border-blue-200 rounded-lg">
                        <h4 className="font-semibold text-sm text-blue-900 mb-2">
                            ℹ️ Sale Time Requirements
                        </h4>
                        <ul className="text-sm text-blue-800 space-y-1">
                            <li>• Deal end date must be in the future</li>
                            <li>• Start date must be before end date</li>
                            <li>• Discount between 10% and 90%</li>
                            <li>• Quantity limit must be at least 1</li>
                            <li>• All deals require admin approval</li>
                        </ul>
                    </div>

                    {/* Submit */}
                    <div className="flex justify-end gap-2 pt-4">
                        <Button type="button" variant="outline" onClick={onClose}>
                            Cancel
                        </Button>
                        <Button
                            type="submit"
                            disabled={
                                loading ||
                                !formData.discountedPrice ||
                                !formData.startDate ||
                                !formData.endDate ||
                                !formData.quantityLimit ||
                                formData.discountedPrice >= originalPrice ||
                                discountPercent < 10 ||
                                discountPercent > 90
                            }
                        >
                            {loading ? 'Submitting...' : 'Submit Request'}
                        </Button>
                    </div>
                </form>
            </DialogContent>
        </Dialog>
    );
}

import { useState } from 'react';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { requestOutlet } from '@/api/promotions';
import { toast } from 'sonner';
import { CheckCircle2, XCircle, AlertCircle } from 'lucide-react';
import type { Product } from '@/api/seller-products';

interface RequestOutletDialogProps {
    product: Product;
    open: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

export default function RequestOutletDialog({
    product,
    open,
    onClose,
    onSuccess,
}: RequestOutletDialogProps) {
    const [discountedPrice, setDiscountedPrice] = useState<number>(0);
    const [loading, setLoading] = useState(false);
    const [eligibility, setEligibility] = useState<any>(null);

    const originalPrice = product.price;
    const discountPercent =
        discountedPrice > 0 && discountedPrice < originalPrice
            ? Math.round(((originalPrice - discountedPrice) / originalPrice) * 100)
            : 0;

    // Calculate listing age
    const listingAge = Math.floor(
        (Date.now() - new Date(product.createdAt).getTime()) / (1000 * 60 * 60 * 24)
    );

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        try {
            const response = await requestOutlet({
                productId: product._id,
                discountedPrice,
            });

            setEligibility(response.eligibility);

            if (response.eligibility.allPassed) {
                toast.success('Brand Outlet request submitted successfully!');
                onSuccess();
                onClose();
            } else {
                toast.warning('Request submitted but product may not meet all criteria');
            }
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to submit request');
        } finally {
            setLoading(false);
        }
    };

    const EligibilityCheck = ({
        label,
        passed,
        value,
    }: {
        label: string;
        passed: boolean;
        value?: string;
    }) => (
        <div className="flex items-center justify-between py-2 border-b">
            <div className="flex items-center gap-2">
                {passed ? (
                    <CheckCircle2 className="w-5 h-5 text-green-600" />
                ) : (
                    <XCircle className="w-5 h-5 text-red-600" />
                )}
                <span className="text-sm">{label}</span>
            </div>
            {value && <span className="text-sm font-medium">{value}</span>}
        </div>
    );

    return (
        <Dialog open={open} onOpenChange={onClose}>
            <DialogContent className="max-w-2xl">
                <DialogHeader>
                    <DialogTitle>Request Brand Outlet Status</DialogTitle>
                    <DialogDescription>
                        Submit your product for Brand Outlet promotion
                    </DialogDescription>
                </DialogHeader>

                <form onSubmit={handleSubmit} className="space-y-6">
                    {/* Product Info */}
                    <div className="flex gap-4 p-4 bg-gray-50 rounded-lg">
                        {product.image && (
                            <img
                                src={product.image}
                                alt={product.title}
                                className="w-20 h-20 object-cover rounded"
                            />
                        )}
                        <div className="flex-1">
                            <h3 className="font-semibold line-clamp-2">{product.title}</h3>
                            <p className="text-sm text-gray-600 mt-1">
                                Condition: {product.condition || 'N/A'}
                            </p>
                            <p className="text-sm text-gray-600">
                                Current Price: ${originalPrice.toFixed(2)}
                            </p>
                        </div>
                    </div>

                    {/* Pricing Input */}
                    <div className="space-y-4">
                        <div>
                            <Label htmlFor="discountedPrice">
                                Discounted Price (USD) *
                            </Label>
                            <Input
                                id="discountedPrice"
                                type="number"
                                step="0.01"
                                min="0.01"
                                max={originalPrice - 0.01}
                                value={discountedPrice || ''}
                                onChange={(e) => setDiscountedPrice(parseFloat(e.target.value))}
                                required
                                placeholder="Enter discounted price"
                            />
                            {discountPercent > 0 && (
                                <p className="text-sm mt-1">
                                    Discount:{' '}
                                    <span
                                        className={
                                            discountPercent >= 30
                                                ? 'text-green-600 font-semibold'
                                                : 'text-red-600 font-semibold'
                                        }
                                    >
                                        {discountPercent}%
                                    </span>
                                    {discountPercent < 30 && ' (Minimum 30% required)'}
                                </p>
                            )}
                        </div>
                    </div>

                    {/* Eligibility Checks */}
                    <div className="space-y-2">
                        <h4 className="font-semibold text-sm flex items-center gap-2">
                            <AlertCircle className="w-4 h-4" />
                            Eligibility Requirements
                        </h4>
                        <div className="border rounded-lg p-4 space-y-2">
                            <EligibilityCheck
                                label="Product Condition is NEW"
                                passed={product.condition?.toLowerCase() === 'new'}
                            />
                            <EligibilityCheck
                                label="Listed for 60+ days"
                                passed={listingAge >= 60}
                                value={`${listingAge} days`}
                            />
                            <EligibilityCheck
                                label="Discount ≥ 30%"
                                passed={discountPercent >= 30}
                                value={`${discountPercent}%`}
                            />
                            <EligibilityCheck
                                label="Seller verified"
                                passed={true} // Assume verified if they can access this
                                value="✓"
                            />
                        </div>

                        {product.condition?.toLowerCase() !== 'new' && (
                            <div className="p-3 bg-red-50 border border-red-200 rounded-lg">
                                <p className="text-sm text-red-800">
                                    Your product condition must be "NEW" to qualify for Brand
                                    Outlet.
                                </p>
                            </div>
                        )}

                        {listingAge < 60 && (
                            <div className="p-3 bg-yellow-50 border border-yellow-200 rounded-lg">
                                <p className="text-sm text-yellow-800">
                                    Your product needs to be listed for at least 60 days. Wait{' '}
                                    {60 - listingAge} more days.
                                </p>
                            </div>
                        )}
                    </div>

                    {/* Submit */}
                    <div className="flex justify-end gap-2 pt-4">
                        <Button type="button" variant="outline" onClick={onClose}>
                            Cancel
                        </Button>
                        <Button
                            type="submit"
                            disabled={
                                loading ||
                                !discountedPrice ||
                                discountedPrice >= originalPrice ||
                                discountPercent < 30
                            }
                        >
                            {loading ? 'Submitting...' : 'Submit Request'}
                        </Button>
                    </div>
                </form>
            </DialogContent>
        </Dialog>
    );
}

import React, { useEffect, useMemo, useState } from "react";
import { useParams, useNavigate, useLocation } from "react-router-dom";
