import { Button } from "@/components/ui/button";
import { ScrollArea } from "@/components/ui/scroll-area";
import {
  Star,
  CheckCircle,
  Zap,
  ShieldAlert,
  Clock,
  Package,
  Eye,
  TrendingUp,
  AlertCircle,
  ShoppingBag,
  Grid,
  List,
  ArrowLeft,
  Store,
  MessageCircle,
  Share2,
  Flag,
  Loader2,
  Heart,
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
