// Types (giữ nguyên)
type SellerReviewApi = {
  _id: string;
  order: string;
  product: {
    _id: string;
    title: string;
  };
  reviewer: {
    _id: string;
    username: string;
  };
  seller: string;
  rating: number;
  comment: string;
  type?: "positive" | "neutral" | "negative";
  createdAt: string;
  verifiedPurchase?: boolean;
  rating1?: number;
  rating2?: number;
  rating3?: number;
  rating4?: number;
};

type SellerReviewsResponse = {
  data: SellerReviewApi[];
  page: number;
  limit: number;
  total: number;
  averageRate: number;
  averageRate1?: number;
  averageRate2?: number;
  averageRate3?: number;
  averageRate4?: number;
  positiveRate: number;
  positiveCount: number;
};

type SellerProduct = {
  _id: string;
  title: string;
  description: string;
  price: number;
  stock: number;
  quantity: number;
  averageRating: number;
  ratingCount: number;
  image?: string;
  images?: string[];
  condition: string;
  listingStatus: "active" | "inactive" | "sold" | "draft";
  status: "available" | "out_of_stock" | "discontinued";
  categoryId?: {
    _id: string;
    name: string;
  };
  watchCount: number;
  dealQuantitySold: number;
  createdAt: string;
  isAuction: boolean;
  promotionType: string;
  variants: any[];
};

type Category = {
  id: string;
  name: string;
  count: number;
};

type RatingFilter = "all" | "positive" | "neutral" | "negative";
type ProductViewMode = "grid" | "list";
type ProductSort = "newest" | "price_asc" | "price_desc" | "popular" | "rating";
type InfoTab = "feedback" | "products" | "about";

type TrustData = {
  finalScore: number;
  tier: "TRUSTED" | "STANDARD" | "RISK" | "HIGH_RISK";
  badge: string;
  avgRating: number;
  reviewCount: number;
  completionRate: string;
  responseRate: string;
  disputeRate: string;
  accountAgeMonths: number;
  underMonitoring: boolean;
};

// Helper functions
function getComputedType(
  review: SellerReviewApi,
): "positive" | "neutral" | "negative" {
  if (review.type) return review.type;
  if (review.rating >= 4) return "positive";
  if (review.rating === 3) return "neutral";
  return "negative";
}

const TIER_STYLES: Record<
  string,
  { bg: string; text: string; border: string; icon: string }
> = {
  TRUSTED: {
    bg: "bg-emerald-50",
    text: "text-emerald-700",
    border: "border-emerald-300",
    icon: "🛡",
  },
  STANDARD: {
    bg: "bg-blue-50",
    text: "text-blue-700",
    border: "border-blue-300",
    icon: "✓",
  },
  RISK: {
    bg: "bg-amber-50",
    text: "text-amber-700",
    border: "border-amber-300",
    icon: "⚠",
  },
  HIGH_RISK: {
    bg: "bg-red-50",
    text: "text-red-700",
    border: "border-red-300",
    icon: "✗",
  },
};

export default function SellerInformationPage() {
  const { sellerId } = useParams<{ sellerId: string }>();
  const location = useLocation();
  const navigate = useNavigate();
  const { payload } = useAuth();
  const queryParams = new URLSearchParams(location.search);
  const productId = queryParams.get("productId");
  const sellerName = queryParams.get("name") || undefined;
  const initialTab = (queryParams.get("tab") as InfoTab) || "feedback";

  const isOwnProfile = payload?.userId === sellerId;

  // State
  const [allData, setAllData] = useState<SellerReviewsResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<InfoTab>(initialTab);
  const [ratingFilter, setRatingFilter] = useState<RatingFilter>("all");

  // Products state
  const [products, setProducts] = useState<SellerProduct[]>([]);
  const [loadingProducts, setLoadingProducts] = useState(false);
  const [filteredProductsTotal, setFilteredProductsTotal] = useState(0);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [viewMode, setViewMode] = useState<ProductViewMode>("grid");
  const [sortBy, setSortBy] = useState<ProductSort>("newest");
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategory, setSelectedCategory] = useState<string>("all");

  // Tổng số sản phẩm thực tế (không bị ảnh hưởng bởi filter)
  const [totalProductsCount, setTotalProductsCount] = useState(0);

  // Categories state
  const [allCategories, setAllCategories] = useState<Category[]>([]);
  const [loadingCategories, setLoadingCategories] = useState(false);

  // Trust score
  const [trust, setTrust] = useState<TrustData | null>(null);
  const [loadingTrust, setLoadingTrust] = useState(true);

  // Follow state
  const [isFollowing, setIsFollowing] = useState(false);
  const [followLoading, setFollowLoading] = useState(false);

  // Seller description
  const [sellerDescription, setSellerDescription] = useState<string>("");

  const displayName =
    sellerName || (sellerId ? `Seller #${sellerId.slice(-5)}` : "Seller");

  // ===== LOAD REVIEWS DATA =====
  useEffect(() => {
    if (!sellerId) {
      setErrorMsg("No seller ID provided");
      setLoading(false);
      return;
    }

    const fetchData = async () => {
      try {
        setLoading(true);
        setErrorMsg(null);

        const res = await api.get<SellerReviewsResponse>(
          `/api/reviews/seller/${sellerId}`,
          { params: { page: 1, limit: 50 } },
        );

        setAllData(res.data);
      } catch (err: any) {
        console.error("Error fetching reviews:", err);
        setErrorMsg(
          err.response?.data?.message || "Unable to load seller feedback.",
        );
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [sellerId]);

  // ===== LOAD TRUST SCORE =====
  useEffect(() => {
    if (!sellerId) return;

    const fetchTrustScore = async () => {
      try {
        const res = await api.get(`/api/trust-score/seller/${sellerId}`);
        setTrust(res.data.data);
      } catch (err) {
        console.error("Error fetching trust score:", err);
      } finally {
        setLoadingTrust(false);
      }
    };

    fetchTrustScore();
  }, [sellerId]);

  // ===== LOAD FOLLOW STATE =====
  useEffect(() => {
    if (!sellerId || !payload?.userId || isOwnProfile) return;
    api.get("/api/users/saved-sellers").then((res) => {
      const saved = res.data?.data ?? [];
      setIsFollowing(saved.some((s: any) => s._id === sellerId));
    }).catch(() => {});
  }, [sellerId, payload?.userId, isOwnProfile]);

  // ===== LOAD SELLER DESCRIPTION =====
  useEffect(() => {
    if (!sellerId) return;
    api.get(`/api/seller/${sellerId}/profile`).then((res) => {
      if (res.data.success) setSellerDescription(res.data.data.description || "");
    }).catch(() => {});
  }, [sellerId]);

  // ===== LOAD TOTAL PRODUCTS COUNT =====
  useEffect(() => {
    if (!sellerId) return;

    const fetchTotalProducts = async () => {
      try {
        // Thử gọi API stats trước
        const res = await api.get(`/api/seller/${sellerId}/products/stats`);
        if (res.data.success) {
          setTotalProductsCount(res.data.data.totalProducts);
        } else {
          // Fallback: gọi API products với limit=1 để lấy total
          const fallbackRes = await api.get(`/api/seller/${sellerId}/products`, {
            params: { limit: 1 }
          });
          if (fallbackRes.data.success) {
            setTotalProductsCount(fallbackRes.data.total);
          }
        }
      } catch (err) {
        console.error("Error fetching total products:", err);
        // Set mặc định là 0 nếu lỗi
        setTotalProductsCount(0);
      }
    };

    fetchTotalProducts();
  }, [sellerId]);

  // ===== LOAD ALL CATEGORIES =====
  useEffect(() => {
    if (!sellerId || activeTab !== "products") return;

    const fetchAllCategories = async () => {
      try {
        setLoadingCategories(true);
        
        // Gọi API riêng để lấy tất cả categories của seller
        const res = await api.get(`/api/seller/${sellerId}/categories`);
        
        if (res.data.success) {
          setAllCategories(res.data.data);
        }
      } catch (err) {
        console.error("Error fetching categories:", err);
        
        // Fallback: Nếu API không có, fetch 1 trang lớn để lấy categories
        try {
          const fallbackRes = await api.get(`/api/seller/${sellerId}/products`, {
            params: { limit: 100 }
          });
          
          if (fallbackRes.data.success) {
            const categoryMap = new Map<string, Category>();
            
            fallbackRes.data.data.forEach((product: any) => {
              if (product.categoryId && product.categoryId._id) {
                const catId = product.categoryId._id;
                const catName = product.categoryId.name;
                
                if (categoryMap.has(catId)) {
                  const existing = categoryMap.get(catId)!;
                  categoryMap.set(catId, {
                    ...existing,
                    count: existing.count + 1
                  });
                } else {
                  categoryMap.set(catId, {
                    id: catId,
                    name: catName,
                    count: 1
                  });
                }
              }
            });
            
            setAllCategories(Array.from(categoryMap.values()));
          }
        } catch (fallbackErr) {
          console.error("Error in fallback categories fetch:", fallbackErr);
        }
      } finally {
        setLoadingCategories(false);
      }
    };

    fetchAllCategories();
  }, [sellerId, activeTab]);

  // ===== LOAD PRODUCT COUNT (always, for sidebar stat) =====
  useEffect(() => {
    if (!sellerId) return;
    api.get(`/api/seller/${sellerId}/products`, { params: { limit: 1 } })
      .then((res) => { if (res.data.success) setFilteredProductsTotal(res.data.total); })
      .catch(() => {});
  }, [sellerId]);

  // ===== LOAD PRODUCTS =====
  useEffect(() => {
    if (!sellerId || activeTab !== "products") return;

    const fetchProducts = async () => {
      try {
        setLoadingProducts(true);

        const params: any = {
          page: currentPage,
          limit: 12,
          sort: sortBy,
        };

        if (searchTerm) {
          params.search = searchTerm;
        }

        if (selectedCategory && selectedCategory !== "all") {
          params.categoryId = selectedCategory;
        }

        const res = await api.get(`/api/seller/${sellerId}/products`, {
          params,
        });

        if (res.data.success) {
          setProducts(res.data.data);
          setFilteredProductsTotal(res.data.total);
          setTotalPages(res.data.totalPages);
        }
      } catch (err: any) {
        console.error("Error fetching products:", err);
      } finally {
        setLoadingProducts(false);
      }
    };

    fetchProducts();
  }, [sellerId, activeTab, currentPage, sortBy, searchTerm, selectedCategory]);

  // Reset pagination khi thay đổi filter
  useEffect(() => {
    setCurrentPage(1);
  }, [sortBy, searchTerm, selectedCategory]);

  // Computed values
  const allReviews = allData?.data ?? [];

  const thisItemReviews = useMemo(() => {
    if (!productId) return [];
    return allReviews.filter((r) => r.product._id === productId);
  }, [allReviews, productId]);

  const totalAllItems = allData?.total ?? 0;

  const filteredReviews: SellerReviewApi[] = useMemo(() => {
    if (ratingFilter === "all") return allReviews;

    return allReviews.filter((r) => {
      const t = getComputedType(r);
      if (ratingFilter === "positive") return t === "positive";
      if (ratingFilter === "neutral") return t === "neutral";
      if (ratingFilter === "negative") return t === "negative";
      return true;
    });
  }, [allReviews, ratingFilter]);

  const positivePercent = allData?.positiveRate ?? 0;

  const avg1 = allData?.averageRate1 ?? null;
  const avg2 = allData?.averageRate2 ?? null;
  const avg3 = allData?.averageRate3 ?? null;
  const avg4 = allData?.averageRate4 ?? allData?.averageRate ?? null;

  // Helper functions
  const formatDate = (iso: string) =>
    new Date(iso).toLocaleDateString(undefined, {
      year: "numeric",
      month: "short",
      day: "numeric",
      timeZone: "Asia/Ho_Chi_Minh",
    });

  const calcRelativeTime = (iso: string): string => {
    const created = new Date(iso).getTime();
    const now = Date.now();
    const diffDays = (now - created) / (1000 * 60 * 60 * 24);
    if (diffDays <= 180) return "Past 6 months";
    if (diffDays <= 365) return "Past year";
    return "More than a year ago";
  };

  const getStockStatus = (stock: number, quantity: number) => {
    const total = stock + quantity;
    if (total <= 0)
      return { label: "Out of stock", color: "bg-red-100 text-red-800" };
    if (total < 5)
      return { label: "Low stock", color: "bg-yellow-100 text-yellow-800" };
    return { label: "In stock", color: "bg-green-100 text-green-800" };
  };

  const handleViewProduct = (productId: string) => {
    navigate(`/products/${productId}`);
  };

  const handleGoBack = () => {
    navigate(-1);
  };

  const handleContactSeller = () => {
    if (!payload?.userId) {
      navigate("/auth/sign-in");
      return;
    }
    navigate(`/my-ebay/messages?sellerId=${sellerId}`);
  };

  const handleShare = () => {
    navigator.clipboard.writeText(window.location.href);
  };

  const handleToggleFollow = async () => {
    if (!payload?.userId) {
      navigate("/auth/sign-in");
      return;
    }
    setFollowLoading(true);
    try {
      if (isFollowing) {
        await unsaveSeller(sellerId!);
        setIsFollowing(false);
        toast.success("Unfollowed seller");
      } else {
        await saveSeller(sellerId!);
        setIsFollowing(true);
        toast.success("Following seller");
      }
    } catch {
      toast.error("Failed to update follow status");
    } finally {
      setFollowLoading(false);
    }
  };

  const clearAllFilters = () => {
    setSearchTerm("");
    setSelectedCategory("all");
    setSortBy("newest");
    setCurrentPage(1);
  };

  // Loading state
  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <Loader2 className="h-8 w-8 animate-spin text-primary mx-auto mb-3" />
          <p className="text-muted-foreground text-sm">Loading seller information...</p>
        </div>
      </div>
    );
  }

  // Error state
  if (errorMsg || !sellerId) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center max-w-md mx-auto p-6">
          <AlertCircle className="h-12 w-12 text-destructive mx-auto mb-4" />
          <h1 className="text-2xl font-bold mb-2">Error</h1>
          <p className="text-muted-foreground mb-4">{errorMsg || "Seller not found"}</p>
          <Button onClick={handleGoBack}>Go Back</Button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-muted/30">
      <div className="container mx-auto px-4 py-6">
        {/* Back button */}
        <Button variant="ghost" size="sm" onClick={handleGoBack} className="mb-4 -ml-2">
          <ArrowLeft className="h-4 w-4 mr-1" />
          Back
        </Button>

        <div className="grid grid-cols-1 lg:grid-cols-[280px_1fr] gap-5">
          {/* Left Sidebar */}
          <div className="space-y-4">
            {/* Seller profile card */}
            <div className="bg-white rounded-xl shadow-sm border p-5">
              {/* Avatar + Name */}
              <div className="flex flex-col items-center text-center mb-4">
                <div className="h-20 w-20 rounded-full bg-primary/10 flex items-center justify-center mb-3 shadow-sm">
                  <span className="text-2xl font-bold text-primary">
                    {displayName.charAt(0).toUpperCase()}
                  </span>
                </div>
                <h2 className="font-semibold text-base">{displayName}</h2>
                {totalAllItems > 0 && (
                  <p className="text-xs text-muted-foreground mt-1">
                    {positivePercent.toFixed(0)}% positive · {totalAllItems} reviews
                  </p>
                )}
                {sellerDescription && (
                  <p className="text-xs text-muted-foreground mt-2 leading-relaxed">
                    {sellerDescription}
                  </p>
                )}
              </div>

              {/* Action buttons */}
              <div className="flex gap-2">
                <Button size="sm" className="flex-1" onClick={handleContactSeller}>
                  <MessageCircle className="h-4 w-4 mr-1.5" />
                  Contact
                </Button>
                {!isOwnProfile && (
                  <Button
                    size="sm"
                    variant={isFollowing ? "default" : "outline"}
                    className="flex-1"
                    onClick={handleToggleFollow}
                    disabled={followLoading}
                  >
                    <Heart className={`h-4 w-4 mr-1.5 ${isFollowing ? "fill-current" : ""}`} />
                    {isFollowing ? "Following" : "Follow"}
                  </Button>
                )}
              </div>

              {/* Stats row */}
              <div className="grid grid-cols-2 gap-2 mt-4 pt-4 border-t">
                <div className="text-center">
                  <p className="text-lg font-bold">{filteredProductsTotal || totalProductsCount}</p>
                  <p className="text-xs text-muted-foreground">Products</p>
                </div>
                <div className="text-center">
                  <p className="text-lg font-bold">{totalAllItems}</p>
                  <p className="text-xs text-muted-foreground">Reviews</p>
                </div>
              </div>
            </div>

            {/* Tab navigation */}
            <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
              {(["products", "feedback", "about"] as InfoTab[]).map((tab) => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={`w-full text-left px-4 py-3 text-sm font-medium border-b last:border-b-0 flex items-center justify-between cursor-pointer transition-colors ${
                    activeTab === tab
                      ? "bg-primary/5 text-primary"
                      : "text-muted-foreground hover:bg-muted/40"
                  }`}
                >
                  <span>
                    {tab === "products" ? "Products" : tab === "feedback" ? "Feedback" : "About Seller"}
                  </span>
                  {activeTab === tab && <span className="w-1.5 h-1.5 rounded-full bg-primary" />}
                </button>
              ))}
            </div>

            {/* Trust Score */}
            {!loadingTrust && trust && (
              <div className="bg-white rounded-xl shadow-sm border p-5">
                <SellerTrustScore trust={trust} />
              </div>
            )}

            {/* Detailed Ratings */}
            {totalAllItems > 0 && (
              <div className="bg-white rounded-xl shadow-sm border p-5">
                <h3 className="font-semibold text-sm mb-3">Seller ratings</h3>
                <div className="space-y-3">
                  <DetailRatingRow label="Accurate description" value={avg1} />
                  <DetailRatingRow label="Reasonable shipping cost" value={avg2} />
                  <DetailRatingRow label="Shipping speed" value={avg3} />
                  <DetailRatingRow label="Communication" value={avg4} />
                </div>
                <p className="text-xs text-muted-foreground mt-3">Average for the last 12 months</p>
              </div>
            )}
          </div>

          {/* Right Content */}
          <div className="bg-white rounded-xl shadow-sm border p-5">
            <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as InfoTab)} className="w-full">

                {/* Feedback Tab */}
                <TabsContent value="feedback" className="p-5">
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-2">
                      <span className="text-sm text-muted-foreground">
                        Filter:
                      </span>
                      <Select
                        value={ratingFilter}
                        onValueChange={(v: RatingFilter) => setRatingFilter(v)}
                      >
                        <SelectTrigger className="w-[140px]">
                          <SelectValue placeholder="All ratings" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="all">All ratings</SelectItem>
                          <SelectItem value="positive">Positive</SelectItem>
                          <SelectItem value="neutral">Neutral</SelectItem>
                          <SelectItem value="negative">Negative</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>

                  <div>
                    {loading ? (
                      <div className="space-y-4">
                        {[1, 2, 3].map((i) => (
                          <div key={i} className="border-b pb-4">
                            <Skeleton className="h-4 w-32 mb-2" />
                            <Skeleton className="h-16 w-full" />
                          </div>
                        ))}
                      </div>
                    ) : filteredReviews.length === 0 ? (
                      <div className="text-center py-8">
                        <p className="text-muted-foreground">
                          No feedback yet for this seller.
                        </p>
                      </div>
                    ) : (
                      <div className="space-y-3">
                        {filteredReviews.map((review) => {
                          const type = getComputedType(review);
                          return (
                            <div
                              key={review._id}
                              className="flex items-start gap-3 p-3 rounded-lg bg-muted/30 hover:bg-muted/50 transition-colors"
                            >
                              <TypeBadge type={type} rating={review.rating} />
                              <div className="flex-1 min-w-0">
                                <div className="flex items-center gap-2 text-sm mb-1">
                                  <span className="font-medium">
                                    {review.reviewer.username}
                                  </span>
                                  <span className="text-xs text-muted-foreground/50">·</span>
                                  <span className="text-xs text-muted-foreground">
                                    {calcRelativeTime(review.createdAt)}
                                  </span>
                                </div>
                                <p className="text-sm text-foreground/80 mb-1.5">
                                  {review.comment}
                                </p>
                                <div className="flex items-center gap-2 text-xs text-muted-foreground">
                                  <span className="truncate max-w-[200px]">{review.product?.title}</span>
                                  {review.verifiedPurchase && (
                                    <>
                                      <span>·</span>
                                      <span className="text-emerald-600 font-medium">
                                        Verified purchase
                                      </span>
                                    </>
                                  )}
                                </div>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    )}
                  </div>
                </TabsContent>

                {/* Products Tab */}
                <TabsContent value="products" className="p-5">
                  {/* Search and filters */}
                  <div className="flex flex-col sm:flex-row gap-3 mb-5">
                    <div className="flex-1">
                      <Input
                        placeholder="Search in store..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full"
                      />
                    </div>

                    <div className="flex gap-2">
                      <Select
                        value={sortBy}
                        onValueChange={(value: ProductSort) => setSortBy(value)}
                      >
                        <SelectTrigger className="w-[180px] cursor-pointer">
                          <SelectValue placeholder="Sort by" />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="newest" className="cursor-pointer">
                            Newest first
                          </SelectItem>
                          <SelectItem
                            value="price_asc"
                            className="cursor-pointer"
                          >
                            Price: Low to High
                          </SelectItem>
                          <SelectItem
                            value="price_desc"
                            className="cursor-pointer"
                          >
                            Price: High to Low
                          </SelectItem>
                          <SelectItem
                            value="popular"
                            className="cursor-pointer"
                          >
                            Most popular
                          </SelectItem>
                          <SelectItem value="rating" className="cursor-pointer">
                            Top rated
                          </SelectItem>
                        </SelectContent>
                      </Select>

                      <div className="flex border rounded-md">
                        <Button
                          variant={viewMode === "grid" ? "default" : "ghost"}
                          size="icon"
                          className="rounded-l-md rounded-r-none cursor-pointer"
                          onClick={() => setViewMode("grid")}
                        >
                          <Grid className="h-4 w-4" />
                        </Button>
                        <Button
                          variant={viewMode === "list" ? "default" : "ghost"}
                          size="icon"
                          className="rounded-r-md rounded-l-none cursor-pointer"
                          onClick={() => setViewMode("list")}
                        >
                          <List className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  </div>

                  {/* Category filters */}
                  {allCategories.length > 0 && (
                    <div className="flex flex-wrap gap-2 mb-6">
                      <Badge
                        variant={selectedCategory === "all" ? "default" : "outline"}
                        className="cursor-pointer hover:bg-primary/90 transition-colors px-4 py-1"
                        onClick={() => {
                          setSelectedCategory("all");
                          setCurrentPage(1);
                        }}
                      >
                        All Products 
                      </Badge>
                      {allCategories.map((cat) => (
                        <Badge
                          key={cat.id}
                          variant={selectedCategory === cat.id ? "default" : "outline"}
                          className="cursor-pointer hover:bg-primary/90 transition-colors px-4 py-1"
                          onClick={() => {
                            setSelectedCategory(cat.id);
                            setCurrentPage(1);
                          }}
                        >
                          {cat.name} 
                        </Badge>
                      ))}
                    </div>
                  )}

                  {/* Loading categories indicator */}
                  {loadingCategories && (
                    <div className="flex items-center gap-2 mb-4">
                      <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                      <span className="text-sm text-muted-foreground">
                        Loading categories...
                      </span>
                    </div>
                  )}

                  {/* Results info and filters */}
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-4">
                      
                      {(searchTerm || selectedCategory !== "all") && (
                        <Button
                          variant="link"
                          size="sm"
                          onClick={clearAllFilters}
                          className="h-auto p-0 text-xs"
                        >
                          Clear all filters
                        </Button>
                      )}
                    </div>
                    {loadingProducts && (
                      <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                    )}
                  </div>

                  {/* Products grid/list */}
                  <div>
                    {loadingProducts ? (
                      <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                        {[1, 2, 3, 4, 5, 6].map((i) => (
                          <Card key={i} className="overflow-hidden">
                            <Skeleton className="aspect-square w-full" />
                            <CardContent className="p-3">
                              <Skeleton className="h-4 w-3/4 mb-2" />
                              <Skeleton className="h-4 w-1/2" />
                            </CardContent>
                          </Card>
                        ))}
                      </div>
                    ) : products.length === 0 ? (
                      <div className="flex items-center justify-center h-40">
                        <div className="text-center">
                          <Package className="h-8 w-8 text-muted-foreground mx-auto mb-2" />
                          <p className="text-muted-foreground">No products found</p>
                          {(searchTerm || selectedCategory !== "all") && (
                            <Button
                              variant="link"
                              className="mt-2"
                              onClick={clearAllFilters}
                            >
                              Clear filters
                            </Button>
                          )}
                        </div>
                      </div>
                    ) : viewMode === "grid" ? (
                      <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                        {products.map((product) => {
                          const stockStatus = getStockStatus(
                            product.stock,
                            product.quantity,
                          );

                          return (
                            <div
                              key={product._id}
                              className="border rounded-xl shadow-sm bg-white flex flex-col overflow-hidden cursor-pointer hover:shadow-md hover:border-primary/30 transition-all"
                              onClick={() => handleViewProduct(product._id)}
                            >
                              {/* Image */}
                              <div className="aspect-square relative overflow-hidden rounded-t-xl bg-muted">
                                {product.image || (product.images && product.images[0]) ? (
                                  <img
                                    src={product.image || product.images?.[0]}
                                    alt={product.title}
                                    className="w-full h-full object-cover"
                                  />
                                ) : (
                                  <div className="w-full h-full flex items-center justify-center">
                                    <Package className="h-12 w-12 text-muted-foreground" />
                                  </div>
                                )}
                                {product.promotionType === "daily_deal" && (
                                  <span className="absolute top-2 left-2 bg-red-500 text-white text-xs px-1.5 py-0.5 rounded-md font-medium">
                                    SALE
                                  </span>
                                )}
                                <span className={`absolute top-2 right-2 text-xs px-1.5 py-0.5 rounded-md font-medium ${stockStatus.color}`}>
                                  {stockStatus.label}
                                </span>
                              </div>

                              {/* Info */}
                              <div className="p-3 flex flex-col flex-1">
                                <h3 className="font-medium text-sm line-clamp-2 leading-snug flex-1 mb-2">
                                  {product.title}
                                </h3>

                                <div className="mt-auto space-y-2">
                                  <p className="font-bold text-base text-primary">
                                    {product.price.toLocaleString("vi-VN")}₫
                                  </p>

                                  <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
                                    <Star className="h-3 w-3 fill-yellow-400 text-yellow-400" />
                                    <span>{product.averageRating.toFixed(1)}</span>
                                    <span>·</span>
                                    <span>{product.ratingCount} reviews</span>
                                  </div>

                                  <Button className="w-full" size="sm" onClick={(e) => { e.stopPropagation(); handleViewProduct(product._id); }}>
                                    View details
                                  </Button>
                                </div>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    ) : (
                      // List view
                      <div className="space-y-3">
                        {products.map((product) => {
                          const stockStatus = getStockStatus(
                            product.stock,
                            product.quantity,
                          );

                          return (
                            <div
                              key={product._id}
                              className="border rounded-xl shadow-sm bg-white overflow-hidden hover:shadow-md hover:border-primary/30 transition-all cursor-pointer flex min-h-[100px]"
                              onClick={() => handleViewProduct(product._id)}
                            >
                              {/* Image — self-stretch matches card height */}
                              <div className="w-28 flex-shrink-0 self-stretch bg-muted overflow-hidden">
                                <div
                                  className="w-full h-full bg-center bg-cover"
                                  style={{
                                    backgroundImage:
                                      product.image || product.images?.[0]
                                        ? `url(${product.image || product.images?.[0]})`
                                        : "none",
                                  }}
                                >
                                  {!product.image && !product.images?.[0] && (
                                    <div className="w-full h-full flex items-center justify-center">
                                      <Package className="h-8 w-8 text-muted-foreground" />
                                    </div>
                                  )}
                                </div>
                              </div>

                              {/* Content */}
                              <div className="flex-1 p-3 flex flex-col justify-between min-w-0">
                                <div>
                                  <div className="flex justify-between items-start gap-2 mb-1">
                                    <h3 className="font-medium text-sm line-clamp-1 flex-1">
                                      {product.title}
                                    </h3>
                                    <span className={`text-xs px-1.5 py-0.5 rounded-md font-medium flex-shrink-0 ${stockStatus.color}`}>
                                      {stockStatus.label}
                                    </span>
                                  </div>
                                  <p className="text-xs text-muted-foreground line-clamp-2">
                                    {product.description}
                                  </p>
                                </div>

                                <div className="flex items-center justify-between mt-2 flex-wrap gap-y-1">
                                  <div className="flex items-center gap-3 text-xs">
                                    <span className="font-bold text-sm text-primary">
                                      {product.price.toLocaleString("vi-VN")}₫
                                    </span>
                                    <div className="flex items-center gap-1 text-muted-foreground">
                                      <Star className="h-3 w-3 fill-yellow-400 text-yellow-400" />
                                      <span>{product.averageRating.toFixed(1)}</span>
                                      <span className="opacity-50">·</span>
                                      <span>{product.ratingCount} reviews</span>
                                    </div>
                                  </div>
                                  <Button
                                    size="sm"
                                    onClick={(e) => { e.stopPropagation(); handleViewProduct(product._id); }}
                                  >
                                    View details
                                  </Button>
                                </div>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    )}

                    {/* Pagination */}
                    {totalPages > 1 && (
                      <>
                        <div className="flex items-center justify-center gap-2 mt-8 pt-4 border-t">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                            disabled={currentPage === 1}
                            className="cursor-pointer"
                          >
                            Previous
                          </Button>

                          <div className="flex items-center gap-1">
                            {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                              let pageNum;
                              if (totalPages <= 5) {
                                pageNum = i + 1;
                              } else if (currentPage <= 3) {
                                pageNum = i + 1;
                              } else if (currentPage >= totalPages - 2) {
                                pageNum = totalPages - 4 + i;
                              } else {
                                pageNum = currentPage - 2 + i;
                              }

                              return (
                                <Button
                                  key={pageNum}
                                  variant={currentPage === pageNum ? "default" : "outline"}
                                  size="sm"
                                  onClick={() => setCurrentPage(pageNum)}
                                  className="cursor-pointer min-w-[32px]"
                                >
                                  {pageNum}
                                </Button>
                              );
                            })}
                          </div>

                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                            disabled={currentPage === totalPages}
                            className="cursor-pointer"
                          >
                            Next
                          </Button>
                        </div>
                        <div className="text-center text-xs text-muted-foreground mt-2">
                          Page {currentPage} of {totalPages}
                        </div>
                      </>
                    )}
                  </div>
                </TabsContent>

                {/* About Tab */}
                <TabsContent value="about" className="p-5">
                  <div className="space-y-6">
                    <div>
                      <h3 className="font-semibold mb-2">
                        About {displayName}
                      </h3>
                      {sellerDescription ? (
                        <p className="text-sm text-muted-foreground whitespace-pre-line">
                          {sellerDescription}
                        </p>
                      ) : (
                        <p className="text-sm text-muted-foreground">
                          {sellerName
                            ? `${sellerName} is a seller on our marketplace.`
                            : `This seller has been a member for ${trust ? Math.floor(trust.accountAgeMonths) : "several"} months.`}
                        </p>
                      )}
                    </div>

                    <Separator />

                    <div>
                      <h3 className="font-semibold mb-3">Seller Statistics</h3>
                      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        <div className="bg-gray-50 rounded-lg p-4 text-center">
                          <p className="text-2xl font-bold text-primary">
                            {totalProductsCount}
                          </p>
                          <p className="text-xs text-muted-foreground">
                            Total Products
                          </p>
                        </div>
                        <div className="bg-gray-50 rounded-lg p-4 text-center">
                          <p className="text-2xl font-bold text-primary">
                            {totalAllItems}
                          </p>
                          <p className="text-xs text-muted-foreground">
                            Total Reviews
                          </p>
                        </div>
                        <div className="bg-gray-50 rounded-lg p-4 text-center">
                          <p className="text-2xl font-bold text-primary">
                            {positivePercent.toFixed(0)}%
                          </p>
                          <p className="text-xs text-muted-foreground">
                            Positive Feedback
                          </p>
                        </div>
                        <div className="bg-gray-50 rounded-lg p-4 text-center">
                          <p className="text-2xl font-bold text-primary">
                            {trust?.completionRate || "0"}%
                          </p>
                          <p className="text-xs text-muted-foreground">
                            Order Completion
                          </p>
                        </div>
                      </div>
                    </div>

                    {trust && (
                      <>
                        <Separator />
                        <div>
                          <h3 className="font-semibold mb-3">
                            Performance Metrics
                          </h3>
                          <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                              <div className="flex justify-between text-sm">
                                <span className="text-muted-foreground">
                                  Response Rate
                                </span>
                                <span className="font-medium">
                                  {trust.responseRate}%
                                </span>
                              </div>
                              <div className="flex justify-between text-sm">
                                <span className="text-muted-foreground">
                                  Dispute Rate
                                </span>
                                <span className="font-medium">
                                  {trust.disputeRate}%
                                </span>
                              </div>
                              <div className="flex justify-between text-sm">
                                <span className="text-muted-foreground">
                                  Account Age
                                </span>
                                <span className="font-medium">
                                  {Math.floor(trust.accountAgeMonths)} months
                                </span>
                              </div>
                            </div>
                            <div className="space-y-2">
                              <div className="flex justify-between text-sm">
                                <span className="text-muted-foreground">
                                  Trust Score
                                </span>
                                <span className="font-medium">
                                  {trust.finalScore.toFixed(1)}/5
                                </span>
                              </div>
                              <div className="flex justify-between text-sm">
                                <span className="text-muted-foreground">
                                  Status
                                </span>
                                <Badge className={TIER_STYLES[trust.tier]?.bg}>
                                  {trust.badge}
                                </Badge>
                              </div>
                              {trust.underMonitoring && (
                                <div className="flex items-center gap-1 text-amber-600 text-sm">
                                  <ShieldAlert className="h-4 w-4" />
                                  <span>Under monitoring</span>
                                </div>
                              )}
                            </div>
                          </div>
                        </div>
                      </>
                    )}

                    <Separator />

                    <div>
                      <h3 className="font-semibold mb-2">Shipping & Returns</h3>
                      <p className="text-sm text-muted-foreground mb-2">
                        Standard shipping within 3-5 business days. Returns
                        accepted within 30 days of delivery.
                      </p>
                      <p className="text-sm text-muted-foreground">
                        Contact seller for specific shipping rates and return
                        policies.
                      </p>
                    </div>

                    <div className="bg-blue-50 p-4 rounded-lg">
                      <h4 className="font-medium text-blue-700 mb-2">
                        Need help?
                      </h4>
                      <p className="text-sm text-blue-600 mb-3">
                        If you have questions about this seller or their
                        products, feel free to contact them directly.
                      </p>
                      <Button size="sm" onClick={handleContactSeller}>
                        <MessageCircle className="h-4 w-4 mr-2" />
                        Contact Seller
                      </Button>
                    </div>
                  </div>
                </TabsContent>
            </Tabs>
          </div>
        </div>
      </div>
    </div>
  );
}

// Helper Components
function DetailRatingRow({
  label,
  value,
}: {
  label: string;
  value: number | null | undefined;
}) {
  const hasValue = typeof value === "number" && !Number.isNaN(value);

  return (
    <div className="flex items-center justify-between gap-3 text-sm">
      <span className="text-muted-foreground">{label}</span>
      <div className="flex items-center gap-2">
        <div className="w-16 h-1.5 bg-gray-200 rounded-full overflow-hidden">
          {hasValue && (
            <div
              className="h-full bg-primary rounded-full"
              style={{ width: `${(value / 5) * 100}%` }}
            />
          )}
        </div>
        <span className="text-sm font-medium w-8">
          {hasValue ? value!.toFixed(1) : "-"}
        </span>
      </div>
    </div>
  );
}

function TypeBadge({
  type,
}: {
  type: "positive" | "neutral" | "negative";
  rating: number;
}) {
  const baseClass =
    "flex h-6 w-6 items-center justify-center rounded-full text-xs font-bold text-white";

  if (type === "positive") {
    return <div className={`${baseClass} bg-green-600`}>+</div>;
  }

  if (type === "negative") {
    return <div className={`${baseClass} bg-red-600`}>-</div>;
  }

  return <div className={`${baseClass} bg-gray-400`}>•</div>;
}

function SellerTrustScore({ trust }: { trust: TrustData }) {
  const style = TIER_STYLES[trust.tier] ?? TIER_STYLES.STANDARD;
  const scoreBarWidth = Math.min((trust.finalScore / 5) * 100, 100);
  const scoreColor =
    trust.finalScore >= 4.5
      ? "#10b981"
      : trust.finalScore >= 4.0
        ? "#3b82f6"
        : trust.finalScore >= 3.0
          ? "#f59e0b"
          : "#ef4444";

  return (
    <div>
      <div className="flex items-center justify-between mb-2">
        <span className="text-sm font-semibold">Trust Score</span>
        <span
          className={`inline-flex items-center gap-1 rounded-full border px-2 py-0.5 text-xs ${style.bg} ${style.text} ${style.border}`}
        >
          {style.icon} {trust.badge}
        </span>
      </div>

      <div className="flex items-center gap-3 mb-2">
        <div
          className="flex h-12 w-12 flex-shrink-0 flex-col items-center justify-center rounded-full border-2"
          style={{ borderColor: scoreColor }}
        >
          <span
            className="text-base font-bold leading-none"
            style={{ color: scoreColor }}
          >
            {trust.finalScore.toFixed(1)}
          </span>
          <span className="text-[9px] text-muted-foreground">/5</span>
        </div>
        <div className="flex-1">
          <div className="flex items-center gap-0.5 mb-1">
            {[1, 2, 3, 4, 5].map((s) => (
              <Star
                key={s}
                className={`h-3 w-3 ${s <= Math.round(trust.avgRating) ? "fill-yellow-400 text-yellow-400" : "text-gray-200"}`}
              />
            ))}
          </div>
          <div className="h-1.5 w-full rounded-full bg-gray-100 overflow-hidden">
            <div
              className="h-full rounded-full transition-all"
              style={{
                width: `${scoreBarWidth}%`,
                backgroundColor: scoreColor,
              }}
            />
          </div>
        </div>
      </div>

      {trust.underMonitoring && (
        <div className="mt-2 flex items-center gap-1.5 rounded-md bg-amber-50 border border-amber-200 px-2 py-1.5 text-xs text-amber-700">
          <ShieldAlert className="h-3 w-3" />
          This seller is under quality monitoring
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import api from "@/lib/axios";
import { Star, CheckCircle, Zap, ShieldAlert, Clock } from "lucide-react";

interface TrustScoreData {
    sellerId: string;
    finalScore: number;
    tier: "TRUSTED" | "STANDARD" | "RISK" | "HIGH_RISK";
    badge: string;
    avgRating: number;
    reviewCount: number;
    completionRate: string;
    totalDelivered: number;
    responseRate: string;
    disputeRate: string;
    accountAgeMonths: number;
    breakdown: {
        ratingScore: number;
        completionRateScore: number;
        responseRateScore: number;
        disputeScore: number;
        stabilityScore: number;
    };
    underMonitoring: boolean;
    lastCalculatedAt: string;
}

const TIER_CONFIG = {
    TRUSTED: {
        label: "Trusted Seller",
        color: "text-emerald-700",
        bg: "bg-emerald-50 border-emerald-200",
        icon: "🛡",
        dot: "bg-emerald-500",
    },
    STANDARD: {
        label: "Standard Seller",
        color: "text-blue-700",
        bg: "bg-blue-50 border-blue-200",
        icon: "✓",
        dot: "bg-blue-500",
    },
    RISK: {
        label: "Risk Seller",
        color: "text-amber-700",
        bg: "bg-amber-50 border-amber-200",
        icon: "⚠",
        dot: "bg-amber-500",
    },
    HIGH_RISK: {
        label: "High Risk",
        color: "text-red-700",
        bg: "bg-red-50 border-red-200",
        icon: "✗",
        dot: "bg-red-500",
    },
};

function ScoreBar({ value, max = 5, color = "bg-blue-500" }: { value: number; max?: number; color?: string }) {
    const pct = Math.min((value / max) * 100, 100);
    return (
        <div className="h-1.5 w-full rounded-full bg-gray-200 overflow-hidden">
            <div className={`h-full rounded-full transition-all ${color}`} style={{ width: `${pct}%` }} />
        </div>
    );
}

interface Props {
    sellerId: string;
}

export function SellerTrustCard({ sellerId }: Props) {
    const [data, setData] = useState<TrustScoreData | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (!sellerId) return;
        api
            .get(`/api/trust-score/seller/${sellerId}`)
            .then((res) => setData(res.data.data))
            .catch(() => { })
            .finally(() => setLoading(false));
    }, [sellerId]);

    if (loading) {
        return (
            <div className="animate-pulse rounded-xl border border-border p-4 h-40 bg-muted/30" />
        );
    }

    if (!data) return null;

    const tier = TIER_CONFIG[data.tier] ?? TIER_CONFIG.STANDARD;
    const scoreColor =
        data.finalScore >= 4.5 ? "bg-emerald-500" :
            data.finalScore >= 4.0 ? "bg-blue-500" :
                data.finalScore >= 3.0 ? "bg-amber-400" : "bg-red-500";

    return (
        <div className="rounded-xl border border-border bg-card p-5 flex flex-col gap-4">
            {/* Header */}
            <div className="flex items-center justify-between">
                <h3 className="font-semibold text-base text-foreground">Seller Trust Score</h3>
                {/* Badge */}
                <span
                    className={`inline-flex items-center gap-1.5 rounded-full border px-3 py-1 text-xs font-semibold ${tier.bg} ${tier.color}`}
                >
                    <span>{tier.icon}</span>
                    {data.underMonitoring ? "Under Monitoring" : tier.label}
                </span>
            </div>

            {/* Score + Stars */}
            <div className="flex items-center gap-4">
                {/* Big score circle */}
                <div className="flex-shrink-0 w-16 h-16 rounded-full border-4 border-border flex flex-col items-center justify-center">
                    <span className="text-xl font-bold leading-none">{data.finalScore.toFixed(1)}</span>
                    <span className="text-[10px] text-muted-foreground">/5</span>
                </div>

                <div className="flex-1 flex flex-col gap-1">
                    {/* Stars */}
                    <div className="flex items-center gap-1">
                        {[1, 2, 3, 4, 5].map((s) => (
                            <Star
                                key={s}
                                className={`h-4 w-4 ${s <= Math.round(data.avgRating) ? "fill-yellow-400 text-yellow-400" : "text-gray-300"}`}
                            />
                        ))}
                        <span className="ml-1 text-sm text-muted-foreground">
                            {data.avgRating.toFixed(1)} ({data.reviewCount} reviews)
                        </span>
                    </div>

                    {/* Score bar */}
                    <ScoreBar value={data.finalScore} color={scoreColor} />
                </div>
            </div>

            {/* 4 Stats */}
            <div className="grid grid-cols-2 gap-3">
                <StatRow
                    icon={<CheckCircle className="h-4 w-4 text-emerald-500" />}
                    label="Completion rate"
                    value={`${data.completionRate}%`}
                    subLabel={`${data.totalDelivered} delivered`}
                />
                <StatRow
                    icon={<Zap className="h-4 w-4 text-blue-500" />}
                    label="Response rate"
                    value={`${data.responseRate}%`}
                    subLabel="within 24h"
                />
                <StatRow
                    icon={<ShieldAlert className="h-4 w-4 text-amber-500" />}
                    label="Dispute rate"
                    value={`${data.disputeRate}%`}
                    subLabel="of all orders"
                    valueClass={parseFloat(data.disputeRate) > 5 ? "text-red-600" : ""}
                />
                <StatRow
                    icon={<Clock className="h-4 w-4 text-purple-500" />}
                    label="Account age"
                    value={`${Math.floor(data.accountAgeMonths)}m`}
                    subLabel="seller tenure"
                />
            </div>

            {/* Under monitoring notice */}
            {data.underMonitoring && (
                <div className="flex items-start gap-2 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-xs text-amber-700">
                    <span className="mt-0.5 flex-shrink-0">⚠️</span>
                    <span>This seller is currently under quality monitoring.</span>
                </div>
            )}
        </div>
    );
}

function StatRow({
    icon,
    label,
    value,
    subLabel,
    valueClass = "",
}: {
    icon: React.ReactNode;
    label: string;
    value: string;
    subLabel?: string;
    valueClass?: string;
}) {
    return (
        <div className="flex items-start gap-2">
            <div className="mt-0.5 flex-shrink-0">{icon}</div>
            <div>
                <p className="text-xs text-muted-foreground">{label}</p>
                <p className={`text-sm font-semibold leading-tight ${valueClass}`}>{value}</p>
                {subLabel && <p className="text-[11px] text-muted-foreground">{subLabel}</p>}
            </div>
        </div>
    );
}

import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Field,
  FieldDescription,
  FieldGroup,
  FieldLabel,
} from "@/components/ui/field";
import { Input } from "@/components/ui/input";
import { Password } from "./ui/password";
import { Link, useNavigate } from "react-router-dom";
import React from "react";
import { useAuth } from "@/hooks/use-auth";
import { toast } from "sonner";
import { z } from "zod";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";

const signInSchema = z.object({
  username: z.string().min(1, "Please enter your username or email"),
  password: z.string().min(1, "Please enter your password"),
});

type SignInValues = z.infer<typeof signInSchema>;

export function SignInForm({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const navigate = useNavigate();
  const { signIn } = useAuth();

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<SignInValues>({
    resolver: zodResolver(signInSchema),
    defaultValues: {
      username: "",
      password: "",
    },
  });

  const onSubmit = async (data: SignInValues) => {
    try {
      const loginUser = await signIn(data.username, data.password);
      toast.info("Sign in successfully", {
        position: "top-center",
        closeButton: true,
      });
      if (loginUser?.role === "shipper") window.location.href = "/shipper";
      else if (loginUser?.role === "admin") window.location.href = "/admin";
      else if (loginUser?.role === "seller") window.location.href = "/seller";
      else navigate("/");
    } catch (error: any) {
      if (error.response?.status === 401) {
        toast.error(
          error.response?.data?.message || "Invalid username or password",
          {
            position: "top-center",
            closeButton: true,
          },
        );
      } else if (error.response?.status === 403) {
        const appealUrl: string | undefined = error.response?.data?.appealUrl;
        if (appealUrl) {
          // Redirect trực tiếp tới trang ban appeal với token
          window.location.href = appealUrl;
          return;
        }
        const serverMessage =
          error.response?.data?.message || "Access denied";
        const reason = error.response?.data?.reason;
        toast.warning(reason ? `${serverMessage}: ${reason}` : serverMessage, {
          position: "top-center",
          closeButton: true,
        });
      } else {
        toast.error("Invalid username or password", {
          position: "top-center",
          closeButton: true,
        });
      }
    }
  };

  return (
    <div className={cn("flex flex-col gap-6", className)} {...props}>
      <Card>
        <CardHeader>
          <CardTitle>Login to your account</CardTitle>
          <CardDescription>
            Enter your email below to login to your account
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit(onSubmit)}>
            <FieldGroup>
              <Field>
                <FieldLabel htmlFor="identifier">Username or Email</FieldLabel>
                <Input
                  id="identifier"
                  type="text"
                  placeholder="Enter your username or email"
                  {...register("username")}
                />
                {errors.username && (
                  <p className="text-sm text-destructive">
                    {errors.username.message}
                  </p>
                )}
              </Field>
              <Field>
                <div className="flex items-center">
                  <FieldLabel htmlFor="password">Password</FieldLabel>
                  <Link
                    to="/auth/forgot-password"
                    className="ml-auto inline-block text-sm underline-offset-4 hover:underline"
                  >
                    Forgot your password?
                  </Link>
                </div>
                <Password id="password" {...register("password")} />
                {errors.password && (
                  <p className="text-sm text-destructive">
                    {errors.password.message}
                  </p>
                )}
              </Field>
              <Field>
                <Button type="submit" className="w-full cursor-pointer">
                  Login
                </Button>
                <Button
                  variant="outline"
                  type="button"
                  className="w-full cursor-pointer"
                  onClick={() => {
                    window.location.href = `${import.meta.env.VITE_API_URL}/api/auth/google`;
                  }}
                >
                  Login with Google
                </Button>
                <FieldDescription className="text-center">
                  Don&apos;t have an account?{" "}
                  <Link to="/auth/sign-up">Sign up</Link>
                </FieldDescription>
              </Field>
            </FieldGroup>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Field,
  FieldDescription,
  FieldGroup,
  FieldLabel,
} from "@/components/ui/field";
import { Input } from "@/components/ui/input";
import { Password } from "./ui/password";
import { Separator } from "./ui/separator";
import { Link, useNavigate } from "react-router-dom";
import React from "react";
import { useAuth } from "@/hooks/use-auth";
import { toast } from "sonner";
import LoadingAuth from "./loading-auth";
import { z } from "zod";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import api from "@/lib/axios";

const signUpSchema = z.object({
  username: z.string().min(3, "Username must be at least 3 characters"),
  email: z.string().email("Invalid email address"),
  password: z.string().min(6, "Password must be at least 6 characters"),
});

type SignUpValues = z.infer<typeof signUpSchema>;
type Step = "form" | "pending";

export function SignupForm({ ...props }: React.ComponentProps<typeof Card>) {
  const [step, setStep] = React.useState<Step>("form");
  const [resendLoading, setResendLoading] = React.useState(false);
  const navigate = useNavigate();
  const { signUp, loading } = useAuth();

  const normalForm = useForm<SignUpValues>({
    resolver: zodResolver(signUpSchema),
    defaultValues: { username: "", email: "", password: "" },
  });

  const [countdown, setCountdown] = React.useState(0);

  React.useEffect(() => {
    let timer: ReturnType<typeof setTimeout>;
    if (countdown > 0) {
      timer = setTimeout(() => setCountdown(countdown - 1), 1000);
    }
    return () => clearTimeout(timer);
  }, [countdown]);

  const handleResendEmail = async () => {
    try {
      setResendLoading(true);
      const email = normalForm.getValues("email");
      const username = normalForm.getValues("username");
      if (!email) return;

      await api.post("/api/auth/resend-email", { username, email });

      toast.success("Verification email sent successfully!");
      setCountdown(60);
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Failed to resend email");
    } finally {
      setResendLoading(false);
    }
  };

  const onSubmit = async (data: SignUpValues) => {
    try {
      await signUp(data.username, data.email, data.password);
      toast.info("Check your email for verification", {
        position: "top-center",
        closeButton: true,
      });
      setStep("pending");
    } catch (error: any) {
      toast.error(
        error.response?.data?.message || "Invalid username or password",
        { position: "top-center", closeButton: true },
      );
    }
  };

  if (loading) {
    return <LoadingAuth />;
  }

  if (step === "pending") {
    return (
      <Card {...props}>
        <CardHeader>
          <CardTitle>Verify your email</CardTitle>
          <CardDescription>
            We've sent a verification link to your email address.
          </CardDescription>
        </CardHeader>
        <Separator />
        <CardContent className="text-center space-y-3">
          <p>
            Please check your inbox and click the verification link to activate
            your account.
          </p>
          <p className="text-sm text-muted-foreground">
            If you don't see the email, check your Spam folder.
          </p>

          <div className="pt-2">
            <p className="text-sm text-muted-foreground mb-2">
              Didn't receive the email?
            </p>
            <Button
              className="p-3 cursor-pointer h-auto font-normal"
              onClick={handleResendEmail}
              disabled={resendLoading ? true : countdown > 0}
            >
              {resendLoading
                ? "Sending"
                : countdown > 0
                  ? `Resend email in ${countdown}s`
                  : "Click to resend"}
            </Button>
          </div>
        </CardContent>
        <Separator />
        <CardFooter className="flex justify-center">
          <Button
            className="cursor-pointer"
            variant="outline"
            onClick={() => navigate("/auth/sign-in")}
          >
            Back to Sign in
          </Button>
        </CardFooter>
      </Card>
    );
  }

  return (
    <Card {...props}>
      <CardHeader>
        <CardTitle>Create an account</CardTitle>
        <CardDescription>
          Enter your information below to create your account
        </CardDescription>
      </CardHeader>

      <Separator />
      <CardContent>
        <form onSubmit={normalForm.handleSubmit(onSubmit)}>
          <FieldGroup>
            <Field>
              <FieldLabel htmlFor="username">Username</FieldLabel>
              <Input
                id="username"
                type="text"
                placeholder="Enter your username"
                {...normalForm.register("username")}
              />
              {normalForm.formState.errors.username && (
                <p className="text-sm text-destructive">
                  {normalForm.formState.errors.username.message}
                </p>
              )}
            </Field>
            <Field>
              <FieldLabel htmlFor="email">Email</FieldLabel>
              <Input
                id="email"
                type="email"
                placeholder="Enter your email"
                {...normalForm.register("email")}
              />
              {normalForm.formState.errors.email && (
                <p className="text-sm text-destructive">
                  {normalForm.formState.errors.email.message}
                </p>
              )}
            </Field>
            <Field>
              <FieldLabel htmlFor="password">Password</FieldLabel>
              <Password id="password" {...normalForm.register("password")} />
              {normalForm.formState.errors.password && (
                <p className="text-sm text-destructive">
                  {normalForm.formState.errors.password.message}
                </p>
              )}
            </Field>
          </FieldGroup>
          <Separator className="my-4" />
          <FieldGroup>
            <Field>
              <Button className="cursor-pointer w-full" type="submit">
                Create Account
              </Button>
              <Button
                className="cursor-pointer w-full"
                variant="outline"
                type="button"
                onClick={() =>
                  (window.location.href =
                    "http://localhost:8080/api/auth/google")
                }
              >
                Sign up with Google
              </Button>
              <FieldDescription className="px-6 text-center">
                Already have an account?{" "}
                <Link to={"/auth/sign-in"}>Sign in</Link>
              </FieldDescription>
            </Field>
          </FieldGroup>
        </form>
      </CardContent>
    </Card>
  );
}

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-full text-sm font-medium transition-all disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 shrink-0 [&_svg]:shrink-0 outline-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-white hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline:
          "border bg-background shadow-xs hover:bg-accent hover:text-accent-foreground dark:bg-input/30 dark:border-input dark:hover:bg-input/50",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80 border",
        ghost:
          "hover:bg-accent hover:text-accent-foreground dark:hover:bg-accent/50",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2 has-[>svg]:px-3",
        sm: "h-8 rounded-full gap-1.5 px-3 has-[>svg]:px-2.5",
        lg: "h-10 rounded-full px-6 has-[>svg]:px-4",
        icon: "size-9",
        "icon-sm": "size-8",
        "icon-lg": "size-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

function Button({
  className,
  variant,
  size,
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean;
  }) {
  const Comp = asChild ? Slot : "button";

  return (
    <Comp
      data-slot="button"
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  );
}

