import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { useAuth } from "@/hooks/use-auth";
import {
  changeUserPassword,
  createAddress,
  deleteAddress,
  getAddresses,
  setDefaultAddress,
  updateAddress,
  updateUserEmail,
  updateUserProfile,
  uploadImageToCloudinary,
  type Address,
} from "@/api/user";
import { useForm } from "react-hook-form";
import {
  changePasswordSchema,
  emailSchema,
  type ChangePasswordFormValues,
  type EmailFormValues,
} from "@/schema/user.schema";
import { zodResolver } from "@hookform/resolvers/zod";
import { toast } from "sonner";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "./ui/alert-dialog";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "./ui/form";
import { MapIcon } from "lucide-react";
import AddressItems from "./address-items";
import AddressForm from "./address-form";
import { ConfirmDialog } from "./confirm-dialog";

export interface UserProfileProps {
  user: {
    username: string;
    email: string;
    avatarUrl?: string;
    provider?: string;
  };
  orders?: Array<{
    id: string;
    orderNumber: string;
    date: string;
    total: number;
    status: "pending" | "processing" | "shipped" | "delivered" | "cancelled";
    items: number;
  }>;
}

export function UserProfile({ user }: UserProfileProps) {
  const { fetchMe } = useAuth();
  const [addresses, setAddresses] = useState<Address[]>([]);
  const [selectedAddress, setSelectedAddress] = useState<Address | null>(null);
  const [editEmail, setEditEmail] = useState(false);
  const [changePassOpen, setChangePassOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [editProfileOpen, setEditProfileOpen] = useState(false);
  const [newUsername, setNewUsername] = useState(user.username);
  const [avatarPreview, setAvatarPreview] = useState<string | undefined>(
    user.avatarUrl,
  );
  const [avatarFile, setAvatarFile] = useState<File | null>(null);
  const [avatarKey, setAvatarKey] = useState(Date.now()); // For forcing re-render
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [confirmDialogOpen, setConfirmDialogOpen] = useState(false);
  const [confirmDialogAction, setConfirmDialogAction] = useState<
    "setDefault" | "delete" | null
  >(null);
  const [pendingAddressId, setPendingAddressId] = useState<string | null>(null);
  const [isSettingDefault, setIsSettingDefault] = useState(false);
  const [isDeletingAddress, setIsDeletingAddress] = useState(false);

  useEffect(() => {
    setNewUsername(user.username);
    // Add timestamp to force cache refresh
    const avatarUrl = user.avatarUrl
      ? `${user.avatarUrl}?t=${Date.now()}`
      : undefined;
    setAvatarPreview(avatarUrl);
    setAvatarKey(Date.now());
  }, [user]);

  const fetchAddresses = async () => {
    try {
      setLoading(true);
      const res = await getAddresses();
      // náº¿u API return { message, data }
      setAddresses(res.data);
    } catch (error) {
      console.error("Failed to fetch addresses", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAddresses();
  }, []);

  const form = useForm<EmailFormValues>({
    resolver: zodResolver(emailSchema),
    defaultValues: {
      email: user.email,
    },
  });

  useEffect(() => {
    form.setValue("email", user.email);
  }, [user.email, form]);

  const onEmailSubmit = async (values: EmailFormValues) => {
    if (values.email === user.email) {
      setEditEmail(false);
      return;
    }

    try {
      setLoading(true);
      await updateUserEmail(values.email);
      await fetchMe();
      setEditEmail(false);
      toast.success("Email has been updated successfully!");
    } catch (error) {
      console.error("Error updating email:", error);
      toast.error("Update failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const passwordForm = useForm<ChangePasswordFormValues>({
    resolver: zodResolver(changePasswordSchema),
    defaultValues: {
      currentPassword: "",
      newPassword: "",
      confirmPassword: "",
    },
  });

  const onChangePasswordSubmit = async (values: ChangePasswordFormValues) => {
    try {
      setLoading(true);
      await changeUserPassword(values.currentPassword, values.newPassword);
      await fetchMe();
      setChangePassOpen(false);
      passwordForm.reset();
      toast.success("Password has been changed successfully");
    } catch (error: any) {
      if (error.response && error.response.status === 400) {
        toast.error(error.response.data.message);
      } else if (error.response && error.response.status === 404) {
        toast.error("User not found");
      } else {
        toast.error("Failed to change password");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Kiá»ƒm tra kÃ­ch thÆ°á»›c file (5MB max)
      if (file.size > 5 * 1024 * 1024) {
        toast.error("File size exceeds 5MB limit");
        return;
      }

      setAvatarFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatarPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleUpdateProfile = async () => {
    if (!newUsername.trim()) {
      alert("Username cannot be empty");
      return;
    }

    try {
      setLoading(true);
      let uploadedAvatarUrl = avatarPreview;

      // Náº¿u cÃ³ áº£nh má»›i, upload lÃªn Cloudinary
      if (avatarFile) {
        uploadedAvatarUrl = await uploadImageToCloudinary(avatarFile);
      }

      // Update profile vá»›i username vÃ  avatar URL
      await updateUserProfile({
        username: newUsername,
        avatarUrl: uploadedAvatarUrl,
      });

      // Refresh user data tá»« backend
      await fetchMe();

      setEditProfileOpen(false);
      setAvatarFile(null);
      toast.success("Your profile has been updated successfully!");
    } catch (error) {
      console.error("Error updating profile:", error);
      toast.error("Failed to update profile. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleCancelEditProfile = () => {
    setEditProfileOpen(false);
    setNewUsername(user.username);
    setAvatarPreview(user.avatarUrl);
    setAvatarFile(null);
  };

  const handleEditAddress = (address: Address) => {
    setSelectedAddress(address);
    setIsModalOpen(true);
  };

  const handleConfirmDialog = async () => {
    if (confirmDialogAction === "setDefault") {
      if (!pendingAddressId) return;
      try {
        setIsSettingDefault(true);
        await setDefaultAddress(pendingAddressId);
        await fetchAddresses();
        toast.success("Set Default Address Successfully");
        setConfirmDialogOpen(false);
        setPendingAddressId(null);
        setConfirmDialogAction(null);
      } catch (error: any) {
        console.log(error);
        toast.error("Failed to set default address");
      } finally {
        setIsSettingDefault(false);
      }
    } else if (confirmDialogAction === "delete") {
      if (!pendingAddressId) return;
      try {
        setIsDeletingAddress(true);
        await deleteAddress(pendingAddressId);
        await fetchAddresses();
        toast.success("Delete Address Successfully");
        setConfirmDialogOpen(false);
        setPendingAddressId(null);
        setConfirmDialogAction(null);
      } catch (error: any) {
        console.log(error);
        toast.error("Failed to delete address");
      } finally {
        setIsDeletingAddress(false);
      }
    }
  };

  return (
    <div className="w-full">
      {/* Section 1: Avatar & User Info */}
      <Card className="mb-6">
        <CardContent className="p-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-6">
              <Avatar className="w-36 h-36" key={avatarKey}>
                <AvatarImage src={avatarPreview} alt={user.username} />
                <AvatarFallback className="bg-[#AAED56] text-[#324E0F] font-bold text-2xl">
                  {user.username
                    .split(" ")
                    .map((n) => n[0])
                    .join("")
                    .toUpperCase()}
                </AvatarFallback>
              </Avatar>
              <div>
                <h2 className="text-3xl font-bold text-gray-900">
                  {user.username}
                </h2>
                {/* <p className="text-gray-600 mt-1">ID: {user.id}</p> */}
              </div>
            </div>

            {/* Edit Profile Button */}
            <AlertDialog
              open={editProfileOpen}
              onOpenChange={setEditProfileOpen}
            >
              <AlertDialogTrigger asChild>
                <Button className="bg-[#AAED56] text-[#324E0F] hover:bg-[#9CD845] cursor-pointer">
                  Update Profile
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent className="max-w-md">
                <AlertDialogTitle>Update Profile</AlertDialogTitle>
                <AlertDialogDescription>
                  Update your username and avatar image.
                </AlertDialogDescription>

                <div className="space-y-6 py-4">
                  {/* Avatar Preview */}
                  <div className="flex justify-center">
                    <Avatar className="w-24 h-24">
                      <AvatarImage src={avatarPreview} alt={newUsername} />
                      <AvatarFallback className="bg-[#AAED56] text-[#324E0F] font-bold text-xl">
                        {newUsername
                          .split(" ")
                          .map((n) => n[0])
                          .join("")
                          .toUpperCase()}
                      </AvatarFallback>
                    </Avatar>
                  </div>

                  {/* Avatar Upload */}
                  <div className="space-y-2">
                    <Label htmlFor="avatar-upload">Upload Avatar</Label>
                    <Input
                      id="avatar-upload"
                      type="file"
                      accept="image/*"
                      onChange={handleAvatarChange}
                      className="cursor-pointer"
                    />
                    <p className="text-xs text-gray-500">
                      Only accept: JPG, PNG, GIF (max 5MB)
                    </p>
                  </div>

                  {/* Username */}
                  <div className="space-y-2">
                    <Label htmlFor="username">Username</Label>
                    <Input
                      id="username"
                      value={newUsername}
                      onChange={(e) => setNewUsername(e.target.value)}
                      placeholder="Enter username"
                    />
                  </div>
                </div>

                <div className="flex gap-2 justify-end">
                  <AlertDialogCancel
                    className="cursor-pointer"
                    onClick={handleCancelEditProfile}
                  >
                    Cancel
                  </AlertDialogCancel>
                  <AlertDialogAction
                    className="cursor-pointer bg-[#AAED56] text-[#324E0F] hover:bg-[#8feb1d]"
                    onClick={handleUpdateProfile}
                    disabled={loading}
                  >
                    {loading ? "Saving..." : "Save Changes"}
                  </AlertDialogAction>
                </div>
              </AlertDialogContent>
            </AlertDialog>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Section 2: Email & Password (Left) */}
        <div className="lg:col-span-1 space-y-6">
          {/* Email Card */}
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Email</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {!editEmail ? (
                <>
                  <div className="p-3 bg-gray-50 rounded-md text-gray-700">
                    {user.email}
                  </div>

                  {user.provider !== "google" && (
                    <Button
                      variant="outline"
                      className="w-full cursor-pointer"
                      onClick={() => setEditEmail(true)}
                    >
                      Change Email
                    </Button>
                  )}

                  {user.provider === "google" && (
                    <p className="text-sm text-gray-500">
                      You cannot change your email because you signed up with
                      Google. Please manage your email through your Google
                      account settings.
                    </p>
                  )}
                </>
              ) : (
                <Form {...form}>
                  <form
                    onSubmit={form.handleSubmit(onEmailSubmit)}
                    className="space-y-4"
                  >
                    <FormField
                      control={form.control}
                      name="email"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>New email</FormLabel>
                          <FormControl>
                            <Input placeholder="Enter new email" {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <div className="flex gap-2">
                      <Button
                        type="submit"
                        disabled={loading}
                        className="flex-1 cursor-pointer bg-[#AAED56] text-[#324E0F] hover:bg-[#8feb1d]"
                      >
                        {loading ? "Saving..." : "Save Email"}
                      </Button>

                      <Button
                        type="button"
                        variant="outline"
                        onClick={() => {
                          setEditEmail(false);
                          form.reset({ email: user.email });
                        }}
                        className="flex-1 cursor-pointer"
                      >
                        Cancel
                      </Button>
                    </div>
                  </form>
                </Form>
              )}
            </CardContent>
          </Card>

          {/* Password Card */}
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Password</CardTitle>
            </CardHeader>
            <CardContent>
              <AlertDialog
                open={changePassOpen}
                onOpenChange={setChangePassOpen}
              >
                <AlertDialogTrigger asChild>
                  <Button variant="outline" className="w-full cursor-pointer">
                    Change Password
                  </Button>
                </AlertDialogTrigger>
                <AlertDialogContent className="max-w-md">
                  <AlertDialogTitle>Change Password</AlertDialogTitle>
                  <AlertDialogDescription>
                    Enter your current password and a new password to change it.
                  </AlertDialogDescription>

                  <Form {...passwordForm}>
                    <form
                      onSubmit={passwordForm.handleSubmit(
                        onChangePasswordSubmit,
                      )}
                      className="space-y-4 py-4"
                    >
                      <FormField
                        control={passwordForm.control}
                        name="currentPassword"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Current Password</FormLabel>
                            <FormControl>
                              <Input
                                type="password"
                                placeholder="Enter current password"
                                {...field}
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <FormField
                        control={passwordForm.control}
                        name="newPassword"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>New Password</FormLabel>
                            <FormControl>
                              <Input
                                type="password"
                                placeholder="Enter new password"
                                {...field}
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <FormField
                        control={passwordForm.control}
                        name="confirmPassword"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Confirm Password</FormLabel>
                            <FormControl>
                              <Input
                                type="password"
                                placeholder="Confirm new password"
                                {...field}
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />

                      <div className="flex gap-2 justify-end">
                        <AlertDialogCancel
                          className="cursor-pointer"
                          onClick={() => passwordForm.reset()}
                        >
                          Cancel
                        </AlertDialogCancel>
                        <Button
                          type="submit"
                          className="cursor-pointer bg-[#AAED56] text-[#324E0F] hover:bg-[#8feb1d]"
                          disabled={loading}
                        >
                          {loading ? "Saving..." : "Save Password"}
                        </Button>
                      </div>
                    </form>
                  </Form>
                </AlertDialogContent>
              </AlertDialog>
            </CardContent>
          </Card>
        </div>

        {/* Section 3: User Address */}
        <div className="lg:col-span-2">
          <Card>
            <CardHeader>
              <div className="flex items-center justify-between">
                <CardTitle className="text-lg">Address</CardTitle>
                {Array.isArray(addresses) && addresses.length >= 1 && (
                  <Button
                    className="cursor-pointer bg-[#AAED56] text-[#324E0F] hover:bg-[#8feb1d]"
                    onClick={() => setIsModalOpen(true)}
                  >
                    Add Address
                  </Button>
                )}
              </div>
              <CardDescription>
                Your saved addresses will appear here.
              </CardDescription>
            </CardHeader>
            {!loading && addresses.length === 0 && (
              <CardContent className="flex flex-col items-center mt-4 justify-center gap-2">
                <MapIcon className="w-10 h-10 text-muted-foreground" />
                <p className="text-md text-muted-foreground">
                  You have no address yet
                </p>
                <Button
                  className="cursor-pointer bg-[#AAED56] text-[#324E0F] hover:bg-[#8feb1d]"
                  onClick={() => setIsModalOpen(true)}
                >
                  Create Address
                </Button>
              </CardContent>
            )}
            <CardContent className="space-y-4">
              {addresses.map((address) => (
                <AddressItems
                  key={address._id}
                  address={address}
                  onEdit={handleEditAddress}
                  onSetDefault={() => {
                    setPendingAddressId(address._id);
                    setConfirmDialogAction("setDefault");
                    setConfirmDialogOpen(true);
                  }}
                  onDelete={() => {
                    setPendingAddressId(address._id);
                    setConfirmDialogAction("delete");
                    setConfirmDialogOpen(true);
                  }}
                />
              ))}
            </CardContent>
          </Card>
        </div>
      </div>
      <AddressForm
        open={isModalOpen}
        onClose={() => {
          setIsModalOpen(false);
          setSelectedAddress(null);
        }}
        initialData={selectedAddress}
        onSubmit={async (payload) => {
          if (selectedAddress) {
            await updateAddress(selectedAddress._id, payload);
          } else {
            await createAddress(payload);
          }
          fetchAddresses();
          setIsModalOpen(false);
        }}
      />
      <ConfirmDialog
        open={confirmDialogOpen}
        onOpenChange={(open) => {
          setConfirmDialogOpen(open);
          if (!open) {
            setConfirmDialogAction(null);
            setPendingAddressId(null);
          }
        }}
        title={
          confirmDialogAction === "setDefault"
            ? "Set Default Address?"
            : "Delete Address?"
        }
        description={
          confirmDialogAction === "setDefault"
            ? "Are you sure you want to set this as your default address?"
            : "Are you sure you want to delete this address?"
        }
        confirmText={
          confirmDialogAction === "setDefault" ? "Set as Default" : "Delete"
        }
        cancelText="Cancel"
        loading={
          confirmDialogAction === "setDefault"
            ? isSettingDefault
            : isDeletingAddress
        }
        isDangerous={confirmDialogAction === "delete"}
        onConfirm={handleConfirmDialog}
      />
    </div>
  );
}

import { useState } from "react";
import { Link } from "react-router-dom";
import { getUserWatchlist, type WatchlistItem } from "@/api/watchlist";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Skeleton } from "@/components/ui/skeleton";
import { ArrowRight } from "lucide-react";
import { formatProductPrice } from "@/lib/utils";

export function WatchlistPreview() {
  const [items, setItems] = useState<WatchlistItem[]>([]);
  const [loading, setLoading] = useState(false);

  const handleOpenChange = (open: boolean) => {
    if (open) {
      setLoading(true);
      getUserWatchlist()
        .then((res) => {
          setItems(res.data.data || []);
        })
        .catch((err) => console.error(err))
        .finally(() => setLoading(false));
    }
  };

  return (
    <DropdownMenu onOpenChange={handleOpenChange}>
      <DropdownMenuTrigger className="font-medium text-sm hover:underline cursor-pointer outline-none">
        Watchlist
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end" className="w-80">
        <DropdownMenuLabel>
          <Link
            to="/my-ebay/activity/watchlist"
            className="text-black text-lg hover:underline w-full inline-flex items-center gap-1"
          >
            View all items you are watching
            <ArrowRight className="text-black w-5 h-5" />
          </Link>
        </DropdownMenuLabel>

        {loading ? (
          <div className="p-2 space-y-2">
            <Skeleton className="h-12 w-full" />
            <Skeleton className="h-12 w-full" />
          </div>
        ) : items.length === 0 ? (
          <div className="p-4 text-center text-sm text-muted-foreground">
            Your watchlist is empty
          </div>
        ) : (
          <div className="space-y-1">
            {items.slice(0, 2).map((item) => (
              <DropdownMenuItem
                key={item._id}
                asChild
                className="cursor-pointer"
              >
                <Link
                  to={`/products/${item.product._id}`}
                  className="flex gap-3 py-2"
                >
                  <div className="h-10 w-10 shrink-0 overflow-hidden rounded bg-muted">
                    <img
                      src={
                        item.product.images?.[0] ||
                        item.product.image ||
                        "/placeholder.png"
                      }
                      alt={item.product.title}
                      className="h-full w-full object-cover"
                    />
                  </div>
                  <div className="flex flex-col overflow-hidden">
                    <span className="truncate text-sm font-medium">
                      {item.product.title}
                    </span>
                    <span className="text-xs text-muted-foreground">
                      US {formatProductPrice(item.product as any)}
                    </span>
                  </div>
                </Link>
              </DropdownMenuItem>
            ))}
          </div>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useRef,
  useState,
} from "react";
import { cartService, type Cart } from "@/services/cart.service";
import { useAuth } from "@/hooks/use-auth";
import { toast } from "sonner";

interface CartContextProps {
  cart: Cart | null;
  loading: boolean;
  addToCart: (
    productId: string,
    quantity: number,
    selectedVariants?: { name: string; value: string }[],
  ) => Promise<void>;
  updateQuantity: (
    itemId: string,
    action: "increase" | "decrease",
    quantity?: number,
  ) => Promise<void>;
  removeFromCart: (itemId: string) => Promise<void>;
  toggleSaveForLater: (itemId: string) => Promise<void>;
  refreshCart: () => Promise<void>;
}

const CartContext = createContext<CartContextProps | undefined>(undefined);

export const CartProvider = ({ children }: { children: React.ReactNode }) => {
  const [cart, setCart] = useState<Cart | null>(null);
  const [loading, setLoading] = useState(false);
  const { user } = useAuth();
  const unavailableNotifiedRef = useRef<Set<string>>(new Set());
  const isFetchingRef = useRef(false);

  const fetchCart = useCallback(async (options?: { silent?: boolean }) => {
    if (!user) {
      setCart(null);
      return;
    }

    if (isFetchingRef.current) {
      return;
    }

    try {
      isFetchingRef.current = true;
      if (!options?.silent) {
        setLoading(true);
      }
      const cartData = await cartService.getMyCart();
      setCart(cartData);

      const latestUnavailable = new Set<string>();
      for (const item of cartData?.items || []) {
        const isUnavailable = item.availabilityStatus
          ? ["out_of_stock", "unavailable"].includes(item.availabilityStatus)
          : Boolean(item.isOutOfStock);
        if (isUnavailable) {
          latestUnavailable.add(item._id);
          if (!unavailableNotifiedRef.current.has(item._id)) {
            toast.error(
              item.availabilityMessage ||
                `Product ${item.product?.title || ""} is currently unavailable`,
            );
            unavailableNotifiedRef.current.add(item._id);
          }
        }
      }

      for (const existing of [...unavailableNotifiedRef.current]) {
        if (!latestUnavailable.has(existing)) {
          unavailableNotifiedRef.current.delete(existing);
        }
      }
    } catch (error) {
      console.error("Failed to fetch cart:", error);
    } finally {
      isFetchingRef.current = false;
      if (!options?.silent) {
        setLoading(false);
      }
    }
  }, [user]);

  useEffect(() => {
    fetchCart();
  }, [fetchCart]);

  useEffect(() => {
    if (!user || !(cart?.items?.length || 0)) return;

    const pollId = window.setInterval(() => {
      if (document.visibilityState !== "visible") return;
      fetchCart({ silent: true });
    }, 3000);

    const handleFocusRefresh = () => {
      fetchCart({ silent: true });
    };
    const handleVisibilityChange = () => {
      if (document.visibilityState !== "visible") return;
      fetchCart({ silent: true });
    };

    window.addEventListener("focus", handleFocusRefresh);
    document.addEventListener("visibilitychange", handleVisibilityChange);

    return () => {
      window.clearInterval(pollId);
      window.removeEventListener("focus", handleFocusRefresh);
      document.removeEventListener("visibilitychange", handleVisibilityChange);
    };
  }, [user, cart?.items?.length, fetchCart]);

  const addToCart = async (
    productId: string,
    quantity: number,
    selectedVariants?: { name: string; value: string }[],
  ) => {
    if (!user) {
      toast.error("Please login to add items to cart");
      return;
    }

    try {
      await cartService.addToCart(productId, quantity, selectedVariants);
      toast.success("Added to cart");
      await fetchCart();
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Failed to add to cart");
    }
  };

  const updateQuantity = async (
    itemId: string,
    action: "increase" | "decrease",
    quantity?: number,
  ) => {
    try {
      await cartService.updateCartItemQuantity(itemId, action, quantity);
      await fetchCart();
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Failed to update cart");
    }
  };

  const removeFromCart = async (itemId: string) => {
    try {
      await cartService.deleteCartItem(itemId);
      toast.success("Item removed from cart");
      await fetchCart();
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Failed to remove item");
    }
  };

  const toggleSaveForLater = async (itemId: string) => {
    try {
      const res = await cartService.toggleSaveForLater(itemId);
      toast.success(res.message);
      await fetchCart();
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Failed to toggle save for later item");
    }
  };

  return (
    <CartContext.Provider
      value={{
        cart,
        loading,
        addToCart,
        updateQuantity,
        removeFromCart,
        toggleSaveForLater,
        refreshCart: () => fetchCart(),
      }}
    >
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => {
  const context = useContext(CartContext);
  if (context === undefined) {
    throw new Error("useCart must be used within a CartProvider");
  }
  return context;
};

import { useState, useEffect, useCallback, useRef } from "react";
import api from "@/lib/axios";
import { toast } from "sonner";

export interface AppNotification {
  _id: string;
  type: string;
  title: string;
  body: string;
  link: string;
  isRead: boolean;
  createdAt: string;
  metadata?: Record<string, unknown>;
}

export function useNotifications(
  socket?: { on: Function; off: Function } | undefined,
) {
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const fetchedRef = useRef(false);

  const fetchNotifications = useCallback(async () => {
    setLoading(true);
    try {
      const res = await api.get("/api/notifications", {
        params: { limit: 30 },
      });
      setNotifications(res.data.data);
      setUnreadCount(res.data.unreadCount);
    } catch {
      // silent
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (!fetchedRef.current) {
      fetchedRef.current = true;
      fetchNotifications();
    }
  }, [fetchNotifications]);

  useEffect(() => {
    if (!socket) return;

    const TYPE_ICONS: Record<string, string> = {
      seller_application_approved: "\u2705",
      seller_application_rejected: "\u274C",
      new_message: "\uD83D\uDCAC",
      order_placed: "\uD83D\uDCE6",
      new_order: "\uD83D\uDCE6",
      order_status_changed: "\uD83D\uDE9A",
      order_shipping: "\uD83D\uDE9A",
      order_delivered: "\uD83D\uDCE6",
      order_completed: "\u2705",
      new_review: "\u2B50",
      user_banned: "\uD83D\uDD12",
      user_unbanned: "\uD83D\uDD13",
      product_warning: "\u26A0\uFE0F",
      admin_broadcast: "\uD83D\uDCE2",
      cart_item_out_of_stock: "\uD83D\uDEAB",
      cart_item_price_changed: "\uD83D\uDCB2",
      watchlist_product_updated: "\uD83D\uDC41\uFE0F",
      delivery_dispute_new: "\u26A0\uFE0F",
      delivery_dispute_responded: "\uD83D\uDCAC",
      delivery_dispute_admin: "\uD83D\uDEA8",
      delivery_dispute_admin_replied: "\uD83D\uDCDD",
      feedback_revision_request: "\u2B50",
      order_assigned: "\uD83D\uDCE6",
    };

    const handleNotification = (notif: AppNotification) => {
      const normalizedNotif =
        notif.type === "cart_item_out_of_stock"
          ? {
              ...notif,
              link: "/cart",
            }
          : notif.type === "cart_item_price_changed"
            ? {
                ...notif,
                link: "/cart",
              }
            : notif.type === "watchlist_product_updated"
              ? {
                  ...notif,
                  link: notif.link || `/products/${notif.metadata?.productId}`,
                }
            : notif;

      setNotifications((prev) => [normalizedNotif, ...prev]);
      setUnreadCount((prev) => prev + 1);

      const icon = TYPE_ICONS[normalizedNotif.type] || "\uD83D\uDD14";

      if (normalizedNotif.type === "admin_broadcast") {
        toast(normalizedNotif.title, {
          description: normalizedNotif.body,
          icon,
          duration: 8000,
          style: {
            borderLeft: "4px solid hsl(var(--primary))",
          },
        });
      } else {
        toast(normalizedNotif.title, {
          description: normalizedNotif.body,
          icon,
          duration: 5000,
        });
      }
    };

    socket.on("notification", handleNotification);
    return () => {
      socket.off("notification", handleNotification);
    };
  }, [socket]);

  const markAsRead = useCallback(async (id: string) => {
    try {
      await api.patch(`/api/notifications/${id}/read`);
      setNotifications((prev) =>
        prev.map((n) => (n._id === id ? { ...n, isRead: true } : n)),
      );
      setUnreadCount((prev) => Math.max(0, prev - 1));
    } catch {
      // silent
    }
  }, []);

  const markAllAsRead = useCallback(async () => {
    try {
      await api.patch("/api/notifications/read-all");
      setNotifications((prev) => prev.map((n) => ({ ...n, isRead: true })));
      setUnreadCount(0);
    } catch {
      // silent
    }
  }, []);

  const deleteNotification = useCallback(async (id: string) => {
    try {
      await api.delete(`/api/notifications/${id}`);
      setNotifications((prev) => {
        const notif = prev.find((n) => n._id === id);
        if (notif && !notif.isRead) setUnreadCount((c) => Math.max(0, c - 1));
        return prev.filter((n) => n._id !== id);
      });
    } catch {
      // silent
    }
  }, []);

  return {
    notifications,
    unreadCount,
    loading,
    fetchNotifications,
    markAsRead,
    markAllAsRead,
    deleteNotification,
  };
}

