    role: string = "buyer",
  ) => {
    try {
      setLoading(true);
      const response = await api.post("/api/auth/register", {
        username,
        email,
        password,
        role,
      });

      const { user, token } = response.data;
      setUser(user);
      setPayload(user);
      setAuthToken(token);
      localStorage.setItem("token", token);
      setAccessToken(token);
    } catch (error) {
      console.error("Failed to sign up:", error);
      throw error;
    } finally {
      setLoading(false);
    }
  };

  const signIn = async (username: string, password: string) => {
    try {
      setLoading(true);
      const res = await api.post("/api/auth/login", { username, password });
      const { token, user: loginUser } = res.data.data;
      setAuthToken(token);
      localStorage.setItem("token", token);
      setAccessToken(token);

      // Fetch full user profile immediately
      await fetchMe();

      return loginUser as { username: string; email: string; role: string };
    } catch (error) {
      console.error("Failed to sign in:", error);
      throw error;
    } finally {
      setLoading(false);
    }
  };

  const fetchMe = async () => {
    try {
      setLoading(true);
      const res = await api.get("/api/users/me");
      const { user } = res.data;
      setUser(user);
      setPayload({
        userId: user._id,
        username: user.username,
        role: user.role,
      });
    } catch (error: any) {
      console.error("Failed to fetch user:", error);
      // Only sign out if it's an auth/token error, not other errors
      if (error.response?.status === 401) {
        // Could be expired token, let's try to continue without force logout
        console.warn("Unauthorized - token may be invalid");
      }
      // Don't automatically sign out - let the user stay logged in with the token
      // signOut(); // REMOVED - this was causing the logout loop
    } finally {
      setLoading(false);
    }
  };

  const signOut = async () => {
    try {
      await api.post("/api/auth/logout");
      setAuthToken(null);
      setUser(undefined);
      setPayload(undefined);
      setAccessToken(null);
      localStorage.removeItem("token");
    } catch (error) {
      console.error(error);
      setAuthToken(null);
      setUser(undefined);
      setPayload(undefined);
      setAccessToken(null);
      localStorage.removeItem("token");
    }
  };

  const refresh = async () => {
    try {
      const res = await api.post(
        "/api/auth/refresh",
        {},
        {
          withCredentials: true,
        },
      );
      const { accessToken } = res.data;

      setAuthToken(accessToken);
      localStorage.setItem("token", accessToken);
      setAccessToken(accessToken);

      const payload = jwtDecode<Payload>(accessToken);
      setPayload(payload);
    } catch (error) {
      console.error("Refresh token failed:", error);
      // Silent sign out when refresh fails as it is an automatic flow.
      signOut();
    }
  };

  const value: AuthContextProps = {
    user,
    payload,
    loading,
    signUp,
    signIn,
    signOut,
    refresh,
    fetchMe,
    accessToken,
    setUser,
    setToken: (token: string) => {
      setAuthToken(token);
      localStorage.setItem("token", token);
      setAccessToken(token);
      const payload = jwtDecode<Payload>(token);
      setPayload(payload);
    },
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

import { useEffect, useState } from "react";
import {
  getAuditLogDetail,
  getAuditLogs,
  type AuditLogDetail,
  type AuditLogRow,
  type GetAuditLogsParams,
} from "@/api/admin";
