type Tab = "complaints" | "disputes" | "buyer-reports";

export default function AdminReportsPage() {
  const [tab, setTab] = useState<Tab>("complaints");

  const TABS: { key: Tab; label: string }[] = [
    { key: "complaints", label: "Complaints" },
    { key: "disputes", label: "Delivery Disputes" },
    { key: "buyer-reports", label: "Buyer Reports" },
  ];

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Reports Management</h1>

      <div className="flex border-b mb-6">
        {TABS.map((t) => (
          <button key={t.key} onClick={() => setTab(t.key)}
            className={`px-5 py-2.5 text-sm font-medium border-b-2 transition-colors ${
              tab === t.key ? "border-blue-600 text-blue-600" : "border-transparent text-gray-500 hover:text-gray-700"
            }`}>
            {t.label}
          </button>
        ))}
      </div>

      {tab === "complaints" && <ComplaintsTab />}
      {tab === "disputes" && <DeliveryDisputesTab />}
      {tab === "buyer-reports" && <BuyerReportsTab />}
    </div>
  );
}

import { useEffect, useState, useCallback } from "react";
import { toast } from "sonner";
import { ChevronDown, ChevronUp, Search } from "lucide-react";
import ShippingTimeline from "@/components/shipping-timeline";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import api from "@/lib/axios";

interface AdminOrder {
  _id: string;
  status: string;
  totalAmount: number;
  paymentStatus: string;
  paymentMethod: string;
  createdAt: string;
  buyer: { _id: string; username: string; email: string } | null;
  seller: { _id: string; username: string; email: string } | null;
  shipper: { _id: string; username: string; email: string } | null;
  items: { title: string; quantity: number; unitPrice: number }[];
  shippingAddress?: { fullName?: string; city?: string; district?: string };
  complaints: { reason: string; content: string; status: string; createdAt: string }[];
  deliveryDisputes: { status: string; buyerNote: string; shipperNote: string; adminNote: string; createdAt: string }[];
  statusHistory?: { status: string; timestamp: string; note: string }[];
}

const STATUS_COLORS: Record<string, string> = {
  created: "bg-gray-100 text-gray-700",
  packaging: "bg-yellow-100 text-yellow-700",
  ready_to_ship: "bg-blue-100 text-blue-700",
  queued: "bg-orange-100 text-orange-700",
  pending_acceptance: "bg-orange-100 text-orange-700",
  shipping: "bg-indigo-100 text-indigo-700",
  delivered: "bg-green-100 text-green-700",
  completed: "bg-green-100 text-green-700",
  cancelled: "bg-red-100 text-red-700",
  returned: "bg-purple-100 text-purple-700",
  failed: "bg-red-100 text-red-700",
};

const STATUS_LABELS: Record<string, string> = {
  created: "Created",
  packaging: "Packaging",
  ready_to_ship: "Ready to Ship",
  queued: "Waiting",
  pending_acceptance: "Waiting Shipper",
  shipping: "Shipping",
  delivered: "Delivered",
  completed: "Completed",
  cancelled: "Cancelled",
  returned: "Returned",
  failed: "Failed",
};

const ALL_STATUSES = [
  "created", "packaging", "ready_to_ship", "queued", "pending_acceptance",
  "shipping", "delivered", "completed", "cancelled", "returned", "failed",
];

export default function AdminOrders() {
  const [orders, setOrders] = useState<AdminOrder[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [pages, setPages] = useState(1);
  const [statusFilter, setStatusFilter] = useState("all");
  const [search, setSearch] = useState("");
  const [searchInput, setSearchInput] = useState("");
  const [loading, setLoading] = useState(true);
  const [expanded, setExpanded] = useState<Record<string, boolean>>({});

  const fetchOrders = useCallback(async () => {
    setLoading(true);
    try {
      const params: Record<string, any> = { page, limit: 20 };
      if (statusFilter !== "all") params.status = statusFilter;
      if (search.trim()) params.search = search.trim();
      const res = await api.get("/api/admin/orders", { params });
      setOrders(res.data.orders);
      setTotal(res.data.total);
      setPages(res.data.pages);
    } catch {
      toast.error("Failed to load orders");
    } finally {
      setLoading(false);
    }
  }, [page, statusFilter, search]);

  useEffect(() => {
    fetchOrders();
  }, [fetchOrders]);

  const handleSearch = () => {
    setSearch(searchInput);
    setPage(1);
  };

  const toggleExpand = (id: string) =>
    setExpanded((prev) => ({ ...prev, [id]: !prev[id] }));

  return (
    <div className="p-6">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Order Management</h1>
          <p className="text-sm text-gray-500 mt-1">{total} total orders</p>
        </div>
      </div>

      {/* Filters */}
      <div className="flex gap-3 mb-6 flex-wrap">
        <div className="flex gap-2 flex-1 min-w-[240px]">
          <Input
            placeholder="Search by Order ID..."
            value={searchInput}
            onChange={(e) => setSearchInput(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSearch()}
            className="flex-1"
          />
          <Button variant="outline" size="icon" onClick={handleSearch}>
            <Search className="h-4 w-4" />
          </Button>
        </div>
        <Select
          value={statusFilter}
          onValueChange={(v) => { setStatusFilter(v); setPage(1); }}
        >
          <SelectTrigger className="w-48">
            <SelectValue placeholder="Filter by status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Statuses</SelectItem>
            {ALL_STATUSES.map((s) => (
              <SelectItem key={s} value={s}>
                {STATUS_LABELS[s] ?? s.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase())}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      {/* Orders list */}
      {loading ? (
        <div className="text-center py-16 text-gray-400">Loading...</div>
      ) : orders.length === 0 ? (
        <div className="text-center py-16 text-gray-400">No orders found.</div>
      ) : (
        <div className="space-y-2">
          {orders.map((order) => {
            const statusColor = STATUS_COLORS[order.status] || "bg-gray-100 text-gray-700";
            const isExpanded = expanded[order._id];

            return (
              <div key={order._id} className="bg-white border rounded-xl overflow-hidden shadow-sm">
                {/* Header row */}
                <div
                  className="flex items-center justify-between px-5 py-3 cursor-pointer hover:bg-gray-50"
                  onClick={() => toggleExpand(order._id)}
                >
                  <div className="flex items-center gap-3">
                    <span className="font-mono text-xs text-gray-500">
                      #{order._id.slice(-8).toUpperCase()}
                    </span>
                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${statusColor}`}>
                      {STATUS_LABELS[order.status] ?? order.status?.replace(/_/g, " ").toUpperCase() ?? "—"}
                    </span>
                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${
                      order.paymentStatus === "paid"
                        ? "bg-emerald-100 text-emerald-700"
                        : "bg-amber-100 text-amber-700"
                    }`}>
                      {order.paymentStatus?.toUpperCase()}
                    </span>
                  </div>
                  <div className="flex items-center gap-5 text-sm text-gray-600">
                    <span className="font-semibold">${order.totalAmount?.toFixed(2)}</span>
                    <span className="text-xs text-gray-400">
                      {new Date(order.createdAt).toLocaleDateString()}
                    </span>
                    <span className="text-xs text-gray-500">
                      Buyer: <b>{order.buyer?.username || "—"}</b>
                    </span>
                    <span className="text-xs text-gray-500">
                      Shipper: <b>{order.shipper?.username || <span className="text-gray-400 italic font-normal">Not assigned</span>}</b>
                    </span>
                    {isExpanded
                      ? <ChevronUp className="h-4 w-4 text-gray-400" />
                      : <ChevronDown className="h-4 w-4 text-gray-400" />
                    }
                  </div>
                </div>

                {/* Expanded detail */}
                {isExpanded && (
                  <div className="border-t px-5 py-4 space-y-4 bg-gray-50">
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3 text-sm">
                      <div>
                        <p className="text-xs text-gray-400 mb-0.5">Buyer</p>
                        <p className="font-medium">{order.buyer?.username || "—"}</p>
                        <p className="text-xs text-gray-400">{order.buyer?.email}</p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-400 mb-0.5">Seller</p>
                        <p className="font-medium">{order.seller?.username || "—"}</p>
                        <p className="text-xs text-gray-400">{order.seller?.email}</p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-400 mb-0.5">Shipper</p>
                        {order.shipper ? (
                          <>
                            <p className="font-medium">{order.shipper.username}</p>
                            <p className="text-xs text-gray-400">{order.shipper.email}</p>
                          </>
                        ) : (
                          <p className="font-medium text-gray-400 italic">Not assigned</p>
                        )}
                      </div>
                      <div>
                        <p className="text-xs text-gray-400 mb-0.5">Shipping Address</p>
                        <p className="font-medium">
                          {order.shippingAddress?.fullName || "—"}
                        </p>
                        <p className="text-xs text-gray-400">
                          {[order.shippingAddress?.district, order.shippingAddress?.city]
                            .filter(Boolean)
                            .join(", ") || "—"}
                        </p>
                      </div>
                    </div>

                    {/* Items */}
                    <div>
                      <p className="text-xs text-gray-400 mb-2">Items</p>
                      <div className="space-y-1">
                        {order.items.map((item, i) => (
                          <div key={i} className="flex justify-between text-sm bg-white p-2 rounded border">
                            <span className="text-gray-700">{item.title || "—"}</span>
                            <span className="text-gray-500">
                              x{item.quantity} · ${((item.unitPrice || 0) * item.quantity).toFixed(2)}
                            </span>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="flex gap-6 text-sm text-gray-600">
                      <span>Payment: <b className="capitalize">{order.paymentMethod}</b></span>
                      <span>Total: <b>${order.totalAmount?.toFixed(2)}</b></span>
                      <span>Ordered: <b>{new Date(order.createdAt).toLocaleString()}</b></span>
                    </div>

                    {/* Complaints */}
                    {order.complaints?.length > 0 && (
                      <div>
                        <p className="text-xs text-gray-400 mb-2 font-semibold uppercase tracking-wide">Buyer Complaints ({order.complaints.length})</p>
                        <div className="space-y-1">
                          {order.complaints.map((c, i) => (
                            <div key={i} className="bg-red-50 border border-red-100 rounded-lg p-3 text-sm">
                              <div className="flex items-center justify-between mb-1">
                                <span className="font-medium text-red-700 capitalize">{c.reason}</span>
                                <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${
                                  c.status === "RESOLVED" ? "bg-green-100 text-green-700" :
                                  c.status === "CLOSED" ? "bg-gray-100 text-gray-600" :
                                  c.status === "SENT_TO_ADMIN" ? "bg-orange-100 text-orange-700" :
                                  "bg-yellow-100 text-yellow-700"
                                }`}>{c.status}</span>
                              </div>
                              <p className="text-gray-600 text-xs line-clamp-2">{c.content}</p>
                              <p className="text-xs text-gray-400 mt-1">{new Date(c.createdAt).toLocaleString()}</p>
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Delivery Disputes */}
                    {order.deliveryDisputes?.length > 0 && (
                      <div>
                        <p className="text-xs text-gray-400 mb-2 font-semibold uppercase tracking-wide">Delivery Disputes ({order.deliveryDisputes.length})</p>
                        <div className="space-y-1">
                          {order.deliveryDisputes.map((d, i) => (
                            <div key={i} className="bg-orange-50 border border-orange-100 rounded-lg p-3 text-sm">
                              <div className="flex items-center justify-between mb-1">
                                <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${
                                  d.status === "CONFIRMED" ? "bg-green-100 text-green-700" :
                                  d.status === "REPORTED_TO_ADMIN" ? "bg-red-100 text-red-700" :
                                  d.status === "SHIPPER_RESPONDED" ? "bg-blue-100 text-blue-700" :
                                  "bg-yellow-100 text-yellow-700"
                                }`}>{d.status.replace(/_/g, " ")}</span>
                                <p className="text-xs text-gray-400">{new Date(d.createdAt).toLocaleString()}</p>
                              </div>
                              {d.buyerNote && <p className="text-xs text-gray-600"><b>Buyer:</b> {d.buyerNote}</p>}
                              {d.shipperNote && <p className="text-xs text-gray-600"><b>Shipper:</b> {d.shipperNote}</p>}
                              {d.adminNote && <p className="text-xs text-gray-600"><b>Admin:</b> {d.adminNote}</p>}
                            </div>
                          ))}
                        </div>
                      </div>
                    )}

                    {/* Lịch sử vận chuyển */}
                    {order.statusHistory && order.statusHistory.length > 0 && (
                      <div>
                        <ShippingTimeline
                          statusHistory={order.statusHistory}
                          currentStatus={order.status}
                        />
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Pagination */}
      {pages > 1 && (
        <div className="flex justify-center gap-2 mt-6">
          <Button variant="outline" size="sm" disabled={page <= 1} onClick={() => setPage((p) => p - 1)}>
            Previous
          </Button>
          <span className="px-3 py-1 text-sm text-gray-600">{page} / {pages}</span>
          <Button variant="outline" size="sm" disabled={page >= pages} onClick={() => setPage((p) => p + 1)}>
            Next
          </Button>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from "react";
import api from "@/lib/axios";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { toast } from "sonner";
import { Eye } from "lucide-react";

type RefundRequest = {
  _id: string;
  order: { _id: string; totalAmount?: number } | null;
  buyer: { _id: string; username?: string; email?: string } | null;
  seller: { _id: string; username?: string; email?: string } | null;
  reason: string;
  description: string;
  faultType: "SELLER_FAULT" | "BUYER_FAULT" | "LOGISTICS_FAULT" | "PENDING_REVIEW";
  status:
    | "PENDING"
    | "APPROVED"
    | "REJECTED"
    | "AUTO_APPROVED"
    | "DISPUTED"
    | "ADMIN_APPROVED"
    | "ADMIN_REJECTED"
    | "CANCELLED"
    | "SELLER_RECEIVED_RETURN";
  requestedAt: string;
  sellerNote?: string;
  adminNote?: string;
};

const STATUSES = ["DISPUTED", "PENDING", "REJECTED", "APPROVED", "SELLER_RECEIVED_RETURN", "ALL"];

export default function AdminRefunds() {
  const [refunds, setRefunds] = useState<RefundRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [status, setStatus] = useState("DISPUTED");

  const [selectedRefund, setSelectedRefund] = useState<RefundRequest | null>(null);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [resolutionStatus, setResolutionStatus] = useState<
    "ADMIN_APPROVED" | "ADMIN_REJECTED"
  >("ADMIN_APPROVED");
  const [faultType, setFaultType] = useState<
    "SELLER_FAULT" | "BUYER_FAULT" | "LOGISTICS_FAULT"
  >("SELLER_FAULT");
  const [adminNote, setAdminNote] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const fetchRefunds = async () => {
    try {
      setLoading(true);
      const res = await api.get("/api/refund/admin", {
        params: { status, page: 1, limit: 50 },
      });
      setRefunds(res.data?.data || []);
    } catch (err: any) {
      toast.error(err.response?.data?.message || "Failed to load refund disputes");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRefunds();
  }, [status]);

  const openDialog = (refund: RefundRequest) => {
    setSelectedRefund(refund);
    setDialogOpen(true);
    setAdminNote(refund.adminNote || "");
    setResolutionStatus("ADMIN_APPROVED");
    setFaultType("SELLER_FAULT");
  };

  const handleReview = async () => {
    if (!selectedRefund) return;
    if (!adminNote.trim()) {
      toast.error("Please provide an admin note before submitting.");
      return;
    }

    try {
      setSubmitting(true);
      await api.post(`/api/refund/${selectedRefund._id}/admin-review`, {
        resolutionStatus,
        faultType,
        adminNote,
      });
      toast.success("Refund dispute reviewed successfully");
      setDialogOpen(false);
      setSelectedRefund(null);
      fetchRefunds();
    } catch (err: any) {
      toast.error(err.response?.data?.message || "Failed to review dispute");
    } finally {
      setSubmitting(false);
    }
  };

  const getStatusVariant = (value: string) => {
    if (["APPROVED", "AUTO_APPROVED", "ADMIN_APPROVED", "SELLER_RECEIVED_RETURN"].includes(value)) {
      return "default";
    }
    if (["REJECTED", "ADMIN_REJECTED"].includes(value)) {
      return "destructive";
    }
    return "secondary";
  };

  return (
    <div className="p-6">
      <div className="mb-6 flex items-center justify-between">
        <h1 className="text-2xl font-bold">Refund Disputes</h1>
        <div>
          <label className="mr-2 text-sm text-muted-foreground">Status</label>
          <select
            className="rounded-md border px-3 py-2 text-sm"
            value={status}
            onChange={(e) => setStatus(e.target.value)}
          >
            {STATUSES.map((s) => (
              <option key={s} value={s}>
                {s}
              </option>
            ))}
          </select>
        </div>
      </div>

      {loading ? (
        <div className="py-12 text-center text-muted-foreground">Loading...</div>
      ) : refunds.length === 0 ? (
        <Card className="py-12 text-center text-muted-foreground">No refund requests found.</Card>
      ) : (
        <div className="grid gap-4">
          {refunds.map((refund) => (
            <Card key={refund._id} className="p-4">
              <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
                <div className="space-y-2">
                  <div className="flex items-center gap-2">
                    <Badge variant={getStatusVariant(refund.status) as any}>{refund.status}</Badge>
                    <span className="text-sm font-medium">
                      Order: #{refund.order?._id?.slice(-8)?.toUpperCase() || "N/A"}
                    </span>
                    <span className="text-xs text-muted-foreground">
                      {new Date(refund.requestedAt).toLocaleString()}
                    </span>
                  </div>
                  <div className="text-sm">
                    Buyer: <b>{refund.buyer?.username || "N/A"}</b> | Seller: <b>{refund.seller?.username || "N/A"}</b>
                  </div>
                  <div className="text-sm text-muted-foreground">Reason: {refund.reason}</div>
                </div>
                <div>
                  <Button variant="outline" size="sm" onClick={() => openDialog(refund)}>
                    <Eye className="mr-2 h-4 w-4" />
                    View / Review
                  </Button>
                </div>
              </div>
            </Card>
          ))}
        </div>
      )}

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
