import { useState, useEffect } from 'react';
import {
    getAllProducts,
    reviewPendingProduct,
    type Product,
    type GetProductsParams,
} from '@/api/admin-products';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { CheckCircle2, Clock3, Eye, Flag, Flame, Layers, XCircle } from 'lucide-react';
import { toast } from 'sonner';
import api from '@/lib/axios';

const REPORT_REASONS = [
    'Product violates policy',
    'Inappropriate images',
    'Misleading or fraudulent information',
    'Restricted product',
    'Abnormal pricing',
    'Other',
];

type SaleState = 'none' | 'upcoming' | 'active' | 'expired';

interface SaleInfo {
    state: SaleState;
    basePrice: number;
    salePrice: number | null;
    startDate: Date | null;
    endDate: Date | null;
    discountPercent: number;
    countdown: string;
}

const toValidDate = (value?: string | Date | null) => {
    if (!value) return null;
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? null : date;
};

const formatCountdown = (target: Date) => {
    const diffMs = target.getTime() - Date.now();
    if (diffMs <= 0) return 'Ending soon';
    const totalMinutes = Math.floor(diffMs / (1000 * 60));
    const days = Math.floor(totalMinutes / (60 * 24));
    const hours = Math.floor((totalMinutes % (60 * 24)) / 60);
    const mins = totalMinutes % 60;
    if (days > 0) return `${days}d ${hours}h left`;
    if (hours > 0) return `${hours}h ${mins}m left`;
    return `${Math.max(1, mins)}m left`;
};

const resolveSaleInfo = (product: Product): SaleInfo => {
    const currentPrice = Number(product.price ?? 0);
    const baseCandidate = Number(product.basePrice ?? product.originalPrice ?? currentPrice);
    const basePrice =
        Number.isFinite(baseCandidate) && baseCandidate > 0
            ? baseCandidate
            : currentPrice;
    const saleCandidate = Number(product.salePrice ?? product.price ?? 0);
    const salePrice =
        Number.isFinite(saleCandidate) && saleCandidate > 0 && saleCandidate < basePrice
            ? saleCandidate
            : null;

    const startDate = toValidDate(product.saleStartDate ?? product.dealStartDate ?? null);
    const endDate = toValidDate(product.saleEndDate ?? product.dealEndDate ?? null);
    const isTimedSale = Boolean(
        product.isTimedSale ||
        product.promotionType === 'daily_deal' ||
        startDate ||
        endDate,
    );

    if (!salePrice || !isTimedSale) {
        return {
            state: 'none',
            basePrice,
            salePrice: null,
            startDate,
            endDate,
            discountPercent: 0,
            countdown: '',
        };
    }

    const now = Date.now();
    const discountPercent = Math.round(((basePrice - salePrice) / basePrice) * 100);

    if (startDate && now < startDate.getTime()) {
        return {
            state: 'upcoming',
            basePrice,
            salePrice,
            startDate,
            endDate,
            discountPercent,
            countdown: `Starts ${startDate.toLocaleString('vi-VN')}`,
        };
    }

    if (endDate && now > endDate.getTime()) {
        return {
            state: 'expired',
            basePrice,
            salePrice,
            startDate,
            endDate,
            discountPercent,
            countdown: `Ended ${endDate.toLocaleString('vi-VN')}`,
        };
    }

    return {
        state: 'active',
        basePrice,
        salePrice,
        startDate,
        endDate,
        discountPercent,
        countdown: endDate ? formatCountdown(endDate) : 'Sale live',
    };
};

const listingStatusLabel: Record<string, string> = {
    active: "Active",
    paused: "Pause",
    ended: "Ended",
    deleted: "Deleted",
    pending_review: "Pending review",
};

const listingStatusColor: Record<string, string> = {
    active: "bg-green-100 text-green-800",
    paused: "bg-yellow-100 text-yellow-800",
    ended: "bg-gray-100 text-gray-800",
    deleted: "bg-red-100 text-red-800",
    pending_review: "bg-blue-100 text-blue-800",
};

const legacyStatusToListingStatus: Record<string, string> = {
    available: "active",
    sold: "ended",
};

const getDisplayListingStatus = (product: Product) => {
    const listingStatus = product.listingStatus;
    if (listingStatus) return listingStatus;
    return legacyStatusToListingStatus[product.status] || "active";
};

export default function ProductManagement() {
    const [activeTab, setActiveTab] = useState<'all' | 'review'>('all');
    const [products, setProducts] = useState<Product[]>([]);
    const [loading, setLoading] = useState(false);
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const [total, setTotal] = useState(0);
    const [search, setSearch] = useState('');

    // View dialog
    const [viewProduct, setViewProduct] = useState<Product | null>(null);
    const [isViewOpen, setIsViewOpen] = useState(false);

    // Report dialog
    const [reportProduct, setReportProduct] = useState<Product | null>(null);
    const [isReportOpen, setIsReportOpen] = useState(false);
    const [reportReason, setReportReason] = useState(REPORT_REASONS[0]);
    const [reportMessage, setReportMessage] = useState('');
    const [reportLoading, setReportLoading] = useState(false);
    const [reviewLoadingId, setReviewLoadingId] = useState<string | null>(null);
    const viewingSaleInfo = viewProduct ? resolveSaleInfo(viewProduct) : null;
    const viewingListingStatus = viewProduct ? getDisplayListingStatus(viewProduct) : null;

    const fetchProducts = async () => {
        setLoading(true);
        try {
            const params: GetProductsParams = { page, limit: 10 };
            if (search) params.search = search;
            if (activeTab === 'review') {
                params.reviewQueue = true;
                params.listingStatus = 'pending_review';
            }
            const response = await getAllProducts(params);
            setProducts(response.data);
            setTotalPages(response.pagination.totalPages);
            setTotal(response.pagination.total);
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to load products');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => { fetchProducts(); }, [page, activeTab]);

    const handleSearch = () => { setPage(1); fetchProducts(); };
    const handleChangeTab = (tab: 'all' | 'review') => {
        setActiveTab(tab);
        setPage(1);
    };

    const handleViewClick = (product: Product) => {
        setViewProduct(product);
        setIsViewOpen(true);
    };

    const handleReportClick = (product: Product) => {
        setReportProduct(product);
        setReportReason(REPORT_REASONS[0]);
        setReportMessage('');
        setIsReportOpen(true);
    };

    const handleSubmitReport = async () => {
        if (!reportProduct) return;
        setReportLoading(true);
        try {
            await api.post(`/api/admin/products/${reportProduct._id}/report`, {
                reason: reportReason,
                message: reportMessage.trim(),
            });
            toast.success(`Warning sent to seller "${reportProduct.sellerId?.username}"`);
            setIsReportOpen(false);
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to send report');
        } finally {
            setReportLoading(false);
        }
    };

    const handleReviewAction = async (product: Product, action: 'approve' | 'reject') => {
        setReviewLoadingId(product._id);
        try {
            const note = action === 'reject'
                ? window.prompt('Lý do từ chối (optional):', '') || ''
                : '';
            await reviewPendingProduct(product._id, { action, note: note.trim() });
            toast.success(action === 'approve' ? 'Product approved' : 'Product rejected');
            fetchProducts();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to review product');
        } finally {
            setReviewLoadingId(null);
        }
    };

    return (
        <div className="container mx-auto py-8">
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h1 className="text-3xl font-bold">Product Management</h1>
                    <p className="text-gray-500 mt-1">
                        {activeTab === 'review' ? 'Pending review queue' : 'Total products'}: {total}
                    </p>
                </div>
            </div>

            {/* Tabs */}
            <div className="mb-4 inline-flex rounded-lg border bg-gray-50 p-1">
                <Button
                    variant={activeTab === 'all' ? 'default' : 'ghost'}
                    size="sm"
                    onClick={() => handleChangeTab('all')}
                    className="rounded-md"
                >
                    All Products
                </Button>
                <Button
                    variant={activeTab === 'review' ? 'default' : 'ghost'}
                    size="sm"
                    onClick={() => handleChangeTab('review')}
                    className="rounded-md"
                >
                    Pending Review (Low Score)
                </Button>
            </div>

            {/* Search */}
            <div className="flex gap-4 mb-6">
                <div className="flex-1">
                    <Input
                        placeholder="Search by product name..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
                    />
                </div>
                <Button onClick={handleSearch}>Search</Button>
            </div>

            {/* Table */}
            <div className="border rounded-lg">
                <Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>Image</TableHead>
                            <TableHead>Product Name</TableHead>
                            <TableHead>Seller</TableHead>
                            <TableHead>Category</TableHead>
                            <TableHead>Price</TableHead>
                            <TableHead>Sale Time</TableHead>
                            <TableHead>Stock</TableHead>
                            <TableHead>Variants</TableHead>
                            <TableHead>Status</TableHead>
                            <TableHead>Trust Score</TableHead>
                            <TableHead>Rating</TableHead>
                            <TableHead>Created At</TableHead>
                            <TableHead className="text-right">Actions</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {loading ? (
                            <TableRow>
                                <TableCell colSpan={13} className="text-center py-8">Loading...</TableCell>
                            </TableRow>
                        ) : products.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={13} className="text-center py-8">No products found</TableCell>
                            </TableRow>
                        ) : (
                            products.map((product) => {
                                const saleInfo = resolveSaleInfo(product);
                                const listingStatus = getDisplayListingStatus(product);
                                return (
                                <TableRow key={product._id} className={saleInfo.state === 'active' ? 'bg-red-50/30 hover:bg-red-50/50' : ''}>
                                    <TableCell>
                                        {product.images?.[0] ? (
                                            <div className="relative w-16 h-16">
                                                <img
                                                    src={product.images[0]}
                                                    alt={product.title}
                                                    className="w-16 h-16 object-cover rounded"
                                                    onError={(e) => { e.currentTarget.src = 'https://via.placeholder.com/64?text=No+Image'; }}
                                                />
                                            </div>
                                        ) : (
                                            <div className="w-16 h-16 bg-gray-200 rounded flex items-center justify-center text-xs text-gray-500">No Image</div>
                                        )}
                                    </TableCell>
                                    <TableCell className="font-medium max-w-[180px]">
                                        <div className="truncate flex items-center gap-2" title={product.title}>
                                            <span>{product.title}</span>
                                        </div>
                                    </TableCell>
                                    <TableCell>{product.sellerId?.username || 'N/A'}</TableCell>
                                    <TableCell>{product.categoryId?.name || '—'}</TableCell>
                                    <TableCell>
                                        {saleInfo.state === 'active' && saleInfo.salePrice ? (
                                            <div className="flex flex-col">
                                                <span className="text-xs text-gray-400 line-through">${saleInfo.basePrice.toFixed(2)}</span>
                                                <span className="font-semibold text-red-600">${saleInfo.salePrice.toFixed(2)}</span>
                                            </div>
                                        ) : (
                                            <span>${saleInfo.basePrice.toFixed(2)}</span>
                                        )}
                                    </TableCell>
                                    <TableCell>
                                        {saleInfo.state === 'active' && (
                                            <div className="space-y-1">
                                                <Badge className="bg-red-100 text-red-700 hover:bg-red-100 border border-red-200">
                                                    <Flame className="h-3 w-3 mr-1" />
                                                    -{saleInfo.discountPercent}%
                                                </Badge>
                                                <div className="text-[11px] text-red-600 font-medium flex items-center gap-1">
                                                    <Clock3 className="h-3 w-3" />
                                                    {saleInfo.countdown}
                                                </div>
                                            </div>
                                        )}
                                        {saleInfo.state === 'upcoming' && (
                                            <div className="space-y-1">
                                                <Badge className="bg-amber-100 text-amber-700 hover:bg-amber-100 border border-amber-200">Upcoming</Badge>
                                                <div className="text-[11px] text-amber-700 font-medium">{saleInfo.countdown}</div>
                                            </div>
                                        )}
                                        {saleInfo.state === 'expired' && (
                                            <Badge className="bg-gray-100 text-gray-600 hover:bg-gray-100 border border-gray-200">Expired</Badge>
                                        )}
                                        {saleInfo.state === 'none' && <span className="text-xs text-gray-400">-</span>}
                                    </TableCell>
                                    <TableCell>{product.quantity ?? 0}</TableCell>
                                    <TableCell>
                                        {(product as any).variants?.length > 0 ? (
                                            <Badge variant="outline" className="flex items-center gap-1 w-fit">
                                                <Layers className="h-3 w-3" />
                                                {(product as any).variants.length} variants
                                            </Badge>
                                        ) : (
                                            <span className="text-gray-400 text-sm">—</span>
                                        )}
                                    </TableCell>
                                    <TableCell>
                                        <span className={`px-2 py-1 rounded text-xs ${listingStatusColor[listingStatus] ?? 'bg-gray-100 text-gray-800'}`}>
                                            {listingStatusLabel[listingStatus] ?? listingStatus}
                                        </span>
                                    </TableCell>
                                    <TableCell>
                                        {product.sellerTrustScore != null ? (
                                            <div className="flex items-center gap-1">
                                                <span className={`font-semibold ${Number(product.sellerTrustScore) < 2.5 ? 'text-red-600' : Number(product.sellerTrustScore) < 4 ? 'text-amber-600' : 'text-green-600'}`}>
                                                    {Number(product.sellerTrustScore).toFixed(2)}
                                                </span>
                                                <span className="text-gray-400 text-xs">/5</span>
                                            </div>
                                        ) : (
                                            <span className="text-gray-400 text-sm">—</span>
                                        )}
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-1">
                                            <span className="text-yellow-500">★</span>
                                            <span className="font-medium">{(product.averageRating || 0).toFixed(1)}</span>
                                            <span className="text-gray-400 text-sm">({product.ratingCount || 0})</span>
                                        </div>
                                    </TableCell>
                                    <TableCell>{new Date(product.createdAt).toLocaleDateString('en-US')}</TableCell>
                                    <TableCell className="text-right">
                                        <div className="flex gap-2 justify-end">
                                            {activeTab === 'review' && listingStatus === 'pending_review' && (
                                                <>
                                                    <Button
                                                        size="sm"
                                                        onClick={() => handleReviewAction(product, 'approve')}
                                                        disabled={reviewLoadingId === product._id}
                                                        className="bg-green-600 hover:bg-green-700"
                                                    >
                                                        <CheckCircle2 className="h-3 w-3 mr-1" />
                                                        Approve
                                                    </Button>
                                                    <Button
                                                        size="sm"
                                                        variant="outline"
                                                        onClick={() => handleReviewAction(product, 'reject')}
                                                        disabled={reviewLoadingId === product._id}
                                                        className="text-red-600 border-red-200 hover:bg-red-50"
                                                    >
                                                        <XCircle className="h-3 w-3 mr-1" />
                                                        Reject
                                                    </Button>
                                                </>
                                            )}
                                            <Button size="sm" variant="outline" onClick={() => handleViewClick(product)}>
                                                <Eye className="h-3 w-3 mr-1" />
                                                View
                                            </Button>
                                            <Button size="sm" variant="destructive" onClick={() => handleReportClick(product)}>
                                                <Flag className="h-3 w-3 mr-1" />
                                                Report
                                            </Button>
                                        </div>
                                    </TableCell>
                                </TableRow>
                            )})
                        )}
                    </TableBody>
                </Table>
            </div>

            {/* Pagination */}
            <div className="flex justify-center gap-2 mt-6">
                <Button variant="outline" onClick={() => setPage(p => Math.max(1, p - 1))} disabled={page === 1}>
                    Previous
                </Button>
                <span className="flex items-center px-4">Page {page} / {totalPages}</span>
                <Button variant="outline" onClick={() => setPage(p => Math.min(totalPages, p + 1))} disabled={page === totalPages}>
                    Next
                </Button>
            </div>

            {/* View Dialog */}
            <Dialog open={isViewOpen} onOpenChange={setIsViewOpen}>
                <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle>Product Details</DialogTitle>
                        <DialogDescription>Complete product information</DialogDescription>
                    </DialogHeader>
                    {viewProduct && (
                        <div className="space-y-5 py-2">
                            {/* Images */}
                            {viewProduct.images?.length > 0 ? (
                                <div className="flex gap-2 flex-wrap">
                                    {viewProduct.images.map((url, i) => (
                                        <img key={i} src={url} alt="" className="w-24 h-24 object-cover rounded border" />
                                    ))}
                                </div>
                            ) : (
                                <div className="w-24 h-24 bg-gray-100 rounded border flex items-center justify-center text-xs text-gray-400">No Image</div>
                            )}

                            {/* Title & Description */}
                            <div>
                                <h3 className="text-lg font-bold">{viewProduct.title}</h3>
                                {viewProduct.description && (
                                    <p className="text-sm text-gray-600 mt-1">{viewProduct.description}</p>
                                )}
                            </div>

                            {/* Basic Info */}
                            <div className="grid grid-cols-2 gap-4 text-sm">
                                <div><span className="text-gray-500">Seller:</span><span className="ml-2 font-medium">{viewProduct.sellerId?.username || '—'}</span></div>
                                <div><span className="text-gray-500">Category:</span><span className="ml-2">{viewProduct.categoryId?.name || '—'}</span></div>
                                <div>
                                    <span className="text-gray-500">Price:</span>
                                    {viewingSaleInfo?.state === 'active' && viewingSaleInfo.salePrice ? (
                                        <span className="ml-2 inline-flex flex-col align-middle">
                                            <span className="text-xs text-gray-400 line-through">${viewingSaleInfo.basePrice.toFixed(2)}</span>
                                            <span className="font-semibold text-red-600">${viewingSaleInfo.salePrice.toFixed(2)}</span>
                                        </span>
                                    ) : (
                                        <span className="ml-2 font-semibold">${viewingSaleInfo?.basePrice.toFixed(2) ?? viewProduct.price.toFixed(2)}</span>
                                    )}
                                </div>
                                <div><span className="text-gray-500">Stock:</span><span className="ml-2 font-semibold">{viewProduct.quantity ?? 0}</span></div>
                                <div>
                                    <span className="text-gray-500">Sale:</span>
                                    {viewingSaleInfo?.state === 'active' && (
                                        <span className="ml-2 inline-flex items-center gap-1 rounded-full bg-red-100 px-2 py-0.5 text-xs font-semibold text-red-700">
                                            <Flame className="h-3 w-3" />
                                            Active -{viewingSaleInfo.discountPercent}%
                                        </span>
                                    )}
                                    {viewingSaleInfo?.state === 'upcoming' && (
                                        <span className="ml-2 inline-flex items-center rounded-full bg-amber-100 px-2 py-0.5 text-xs font-semibold text-amber-700">
                                            Upcoming
                                        </span>
                                    )}
                                    {viewingSaleInfo?.state === 'expired' && (
                                        <span className="ml-2 inline-flex items-center rounded-full bg-gray-100 px-2 py-0.5 text-xs font-semibold text-gray-600">
                                            Expired
                                        </span>
                                    )}
                                    {viewingSaleInfo?.state === 'none' && <span className="ml-2 text-gray-400">-</span>}
                                </div>
                                <div>
                                    <span className="text-gray-500">Sale Time:</span>
                                    <span className={`ml-2 text-xs ${viewingSaleInfo?.state === 'active' ? 'text-red-600 font-semibold' : 'text-gray-500'}`}>
                                        {viewingSaleInfo?.countdown || '-'}
                                    </span>
                                </div>
                                <div>
                                    <span className="text-gray-500">Sale Window:</span>
                                    <span className="ml-2 text-xs text-gray-600">
                                        {viewingSaleInfo?.startDate && viewingSaleInfo?.endDate
                                            ? `${viewingSaleInfo.startDate.toLocaleString('vi-VN')} - ${viewingSaleInfo.endDate.toLocaleString('vi-VN')}`
                                            : '-'}
                                    </span>
                                </div>
                                <div><span className="text-gray-500">Condition:</span><span className="ml-2">{viewProduct.condition || '—'}</span></div>
                                <div>
                                    <span className="text-gray-500">Status:</span>
                                    <span className={`ml-2 px-2 py-0.5 rounded text-xs ${listingStatusColor[viewingListingStatus || ""] ?? 'bg-gray-100 text-gray-800'}`}>
                                        {listingStatusLabel[viewingListingStatus || ""] ?? viewingListingStatus}
                                    </span>
                                </div>
                                <div>
                                    <span className="text-gray-500">Rating:</span>
                                    <span className="ml-2">★ {(viewProduct.averageRating || 0).toFixed(1)} ({viewProduct.ratingCount || 0} reviews)</span>
                                </div>
                                <div><span className="text-gray-500">Created At:</span><span className="ml-2">{new Date(viewProduct.createdAt).toLocaleDateString('en-US')}</span></div>
                            </div>

                            {/* Variants */}
                            {(viewProduct as any).variants?.length > 0 && (
                                <div>
                                    <h4 className="font-semibold mb-3 flex items-center gap-2">
                                        <Layers className="h-4 w-4" />
                                        Product Variants
                                    </h4>
                                    <div className="space-y-4">
                                        {(viewProduct as any).variants.map((variant: any) => (
                                            <div key={variant.name}>
                                                <p className="text-sm font-medium text-gray-700 mb-2">{variant.name}</p>
                                                <div className="flex flex-wrap gap-2">
                                                    {variant.options.map((opt: any) => (
                                                        <div
                                                            key={opt.value}
                                                            className="border rounded-md px-3 py-2 text-sm border-solid bg-white"
                                                        >
                                                            <div className="font-medium">{opt.value}</div>
                                                            <div className="text-xs text-gray-500 space-x-2">
                                                                {opt.sku && <span>SKU: {opt.sku}</span>}
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                            {(viewProduct as any).variantCombinations?.length > 0 && (
                                <div>
                                    <h4 className="font-semibold mb-3">Combination Inventory</h4>
                                    <div className="space-y-2">
                                        {(viewProduct as any).variantCombinations.map((combo: any) => (
                                            <div
                                                key={combo.key}
                                                className="flex items-center justify-between border rounded-md px-3 py-2 text-sm"
                                            >
                                                <span>{(combo.selections || []).map((s: any) => s.value).join(' / ')}</span>
                                                <span className="font-semibold">
                                                    Price: ${Number(combo.price ?? (viewProduct as any).price ?? 0).toFixed(2)} | Stock: {combo.quantity || 0}
                                                </span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsViewOpen(false)}>Close</Button>
                        <Button variant="destructive" onClick={() => { setIsViewOpen(false); if (viewProduct) handleReportClick(viewProduct); }}>
                            <Flag className="h-4 w-4 mr-1" />
                            Report this product
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Report Dialog */}
            <Dialog open={isReportOpen} onOpenChange={setIsReportOpen}>
                <DialogContent className="max-w-lg">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <Flag className="h-5 w-5 text-red-500" />
                            Report Product
                        </DialogTitle>
                        <DialogDescription>
                            A warning will be sent directly to the seller via system notifications
                        </DialogDescription>
                    </DialogHeader>

                    {reportProduct && (
                        <div className="space-y-4 py-2">
                            <div className="p-3 bg-gray-50 rounded-md text-sm">
                                <div className="font-medium">{reportProduct.title}</div>
                                <div className="text-gray-500">Seller: {reportProduct.sellerId?.username || '—'}</div>
                            </div>

                            <div className="grid gap-2">
                                <Label>Reason *</Label>
                                <select
                                    className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                                    value={reportReason}
                                    onChange={(e) => setReportReason(e.target.value)}
                                >
                                    {REPORT_REASONS.map(r => (
                                        <option key={r} value={r}>{r}</option>
                                    ))}
                                </select>
                            </div>

                            <div className="grid gap-2">
                                <Label>Details (optional)</Label>
                                <Textarea
                                    rows={4}
                                    placeholder="Describe the product violation in detail..."
                                    value={reportMessage}
                                    onChange={(e) => setReportMessage(e.target.value)}
                                />
                            </div>
                        </div>
                    )}

                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsReportOpen(false)}>Cancel</Button>
                        <Button variant="destructive" onClick={handleSubmitReport} disabled={reportLoading}>
                            {reportLoading ? 'Sending...' : 'Send warning to seller'}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useState, useEffect } from 'react';
import {
    getPendingPromotionRequests,
    approvePromotionRequest,
    rejectPromotionRequest,
    type PromotionRequest,
} from '@/api/promotions';
import { toast } from 'sonner';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
    Card,
    CardContent,
    CardHeader,
    CardTitle,
} from '@/components/ui/card';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { CheckCircle2, XCircle, Package, Tag } from 'lucide-react';

export default function AdminPromotionRequestsPage() {
    const [requests, setRequests] = useState<PromotionRequest[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedRequest, setSelectedRequest] = useState<PromotionRequest | null>(null);
    const [actionType, setActionType] = useState<'approve' | 'reject' | null>(null);
    const [adminNotes, setAdminNotes] = useState('');
    const [rejectionReason, setRejectionReason] = useState('');
    const [submitting, setSubmitting] = useState(false);

    const fetchRequests = async () => {
        try {
            setLoading(true);
            const response = await getPendingPromotionRequests();
            setRequests(response.data);
        } catch (error: any) {
            console.error('Failed to load requests:', error);
            toast.error('Failed to load promotion requests');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchRequests();
    }, []);

    const handleApprove = async () => {
        if (!selectedRequest) return;
        setSubmitting(true);

        try {
            await approvePromotionRequest(selectedRequest._id, adminNotes);
            toast.success('Promotion request approved!');
            fetchRequests();
            closeDialog();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to approve request');
        } finally {
            setSubmitting(false);
        }
    };

    const handleReject = async () => {
        if (!selectedRequest || !rejectionReason.trim()) {
            toast.error('Rejection reason is required');
            return;
        }
        setSubmitting(true);

        try {
            await rejectPromotionRequest(selectedRequest._id, rejectionReason, adminNotes);
            toast.success('Promotion request rejected');
            fetchRequests();
            closeDialog();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to reject request');
        } finally {
            setSubmitting(false);
        }
    };

    const openDialog = (request: PromotionRequest, action: 'approve' | 'reject') => {
        setSelectedRequest(request);
        setActionType(action);
        setAdminNotes('');
        setRejectionReason('');
    };

    const closeDialog = () => {
        setSelectedRequest(null);
        setActionType(null);
        setAdminNotes('');
        setRejectionReason('');
    };

    const formatDate = (dateString: string) => {
        return new Date(dateString).toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit',
        });
    };

    const EligibilityBadge = ({ checks }: { checks: PromotionRequest['eligibilityChecks'] }) => {
        if (checks.allPassed) {
            return (
                <Badge className="bg-green-600">
                    <CheckCircle2 className="w-3 h-3 mr-1" />
                    All Checks Passed
                </Badge>
            );
        }
        return (
            <Badge variant="destructive">
                <XCircle className="w-3 h-3 mr-1" />
                Failed Checks
            </Badge>
        );
    };

    return (
        <div className="container mx-auto py-8">
            <div className="mb-6">
                <h1 className="text-3xl font-bold">Promotion Requests</h1>
                <p className="text-gray-600 mt-1">
                    Review and approve promotion requests from sellers
                </p>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle>Pending Requests ({requests.length})</CardTitle>
                </CardHeader>
                <CardContent className="p-0">
                    {loading ? (
                        <div className="text-center py-12">
                            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900 mx-auto"></div>
                            <p className="mt-4 text-gray-600">Loading...</p>
                        </div>
                    ) : requests.length === 0 ? (
                        <div className="text-center py-12">
                            <Package className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                            <p className="text-gray-600">No pending requests</p>
                        </div>
                    ) : (
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Product</TableHead>
                                    <TableHead>Seller</TableHead>
                                    <TableHead>Type</TableHead>
                                    <TableHead>Pricing</TableHead>
                                    <TableHead>Eligibility</TableHead>
                                    <TableHead>Submitted</TableHead>
                                    <TableHead className="text-right">Actions</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {requests.map((request) => (
                                    <TableRow key={request._id}>
                                        <TableCell>
                                            <div className="flex items-center gap-3">
                                                {request.product.image && (
                                                    <img
                                                        src={request.product.image}
                                                        alt={request.product.title}
                                                        className="w-12 h-12 object-cover rounded"
                                                    />
                                                )}
                                                <div>
                                                    <p className="font-medium line-clamp-1">
                                                        {request.product.title}
                                                    </p>
                                                    <p className="text-xs text-gray-500">
                                                        {request.product.condition}
                                                    </p>
                                                </div>
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            <div>
                                                <p className="font-medium text-sm">{request.seller.username}</p>
                                                <p className="text-xs text-gray-500">{request.seller.email}</p>
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            {request.requestType === 'outlet' ? (
                                                <Badge className="bg-orange-600">
                                                    <Package className="w-3 h-3 mr-1" />
                                                    Outlet
                                                </Badge>
                                            ) : (
                                                <Badge className="bg-red-600">
                                                    <Tag className="w-3 h-3 mr-1" />
                                                    Sale Time
                                                </Badge>
                                            )}
                                        </TableCell>
                                        <TableCell>
                                            <div className="space-y-1">
                                                <p className="line-through text-gray-500 text-xs">
                                                    ${request.originalPrice.toFixed(2)}
                                                </p>
                                                <p className="font-bold text-sm">
                                                    ${request.discountedPrice.toFixed(2)}
                                                </p>
                                                <Badge variant="outline" className="text-xs">
                                                    {request.discountPercent}% off
                                                </Badge>
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            <EligibilityBadge checks={request.eligibilityChecks} />
                                        </TableCell>
                                        <TableCell className="text-sm text-gray-600">
                                            {formatDate(request.createdAt)}
                                        </TableCell>
                                        <TableCell className="text-right">
                                            <div className="flex gap-2 justify-end">
                                                <Button
                                                    size="sm"
                                                    onClick={() => openDialog(request, 'approve')}
                                                    className="bg-green-600 hover:bg-green-700"
                                                >
                                                    Approve
                                                </Button>
                                                <Button
                                                    size="sm"
                                                    variant="destructive"
                                                    onClick={() => openDialog(request, 'reject')}
                                                >
                                                    Reject
                                                </Button>
                                            </div>
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    )}
                </CardContent>
            </Card>

            {/* Action Dialog */}
            <Dialog open={!!actionType} onOpenChange={() => closeDialog()}>
                <DialogContent className="max-w-2xl">
                    <DialogHeader>
                        <DialogTitle>
                            {actionType === 'approve' ? 'Approve' : 'Reject'} Promotion Request
                        </DialogTitle>
                        <DialogDescription>
                            {selectedRequest &&
                                `${selectedRequest.product.title} - ${selectedRequest.requestType === 'outlet' ? 'Brand Outlet' : 'Sale Time'}`}
                        </DialogDescription>
                    </DialogHeader>

                    {selectedRequest && (
                        <div className="space-y-4">
                            {/* Eligibility Details */}
                            <div className="p-4 bg-gray-50 rounded-lg space-y-2">
                                <h4 className="font-semibold text-sm">Eligibility Checks:</h4>
                                {selectedRequest.requestType === 'outlet' && (
                                    <>
                                        <div className="flex justify-between text-sm">
                                            <span>Condition NEW:</span>
                                            <span>
                                                {selectedRequest.eligibilityChecks.conditionNew ? '✅' : '❌'}
                                            </span>
                                        </div>
                                        <div className="flex justify-between text-sm">
                                            <span>Listing Age ≥60 days:</span>
                                            <span>
                                                {selectedRequest.eligibilityChecks.listingAgeMet
                                                    ? `✅ (${selectedRequest.eligibilityChecks.listingAge} days)`
                                                    : `❌ (${selectedRequest.eligibilityChecks.listingAge} days)`}
                                            </span>
                                        </div>
                                    </>
                                )}
                                <div className="flex justify-between text-sm">
                                    <span>Discount ≥30%:</span>
                                    <span>
                                        {selectedRequest.eligibilityChecks.discountMet
                                            ? `✅ (${selectedRequest.discountPercent}%)`
                                            : `❌ (${selectedRequest.discountPercent}%)`}
                                    </span>
                                </div>
                                <div className="flex justify-between text-sm">
                                    <span>Seller Verified:</span>
                                    <span>
                                        {selectedRequest.eligibilityChecks.sellerVerified ? '✅' : '❌'}
                                    </span>
                                </div>
                            </div>

                            {/* Sale Time Info */}
                            {selectedRequest.requestType === 'daily_deal' && (
                                <div className="p-4 bg-blue-50 rounded-lg space-y-2">
                                    <h4 className="font-semibold text-sm">Deal Details:</h4>
                                    <p className="text-sm">
                                        Start: {selectedRequest.startDate && formatDate(selectedRequest.startDate)}
                                    </p>
                                    <p className="text-sm">
                                        End: {selectedRequest.endDate && formatDate(selectedRequest.endDate)}
                                    </p>
                                    <p className="text-sm">Quantity Limit: {selectedRequest.quantityLimit}</p>
                                </div>
                            )}

                            {/* Admin Notes */}
                            <div>
                                <Label htmlFor="adminNotes">Admin Notes (Optional)</Label>
                                <Textarea
                                    id="adminNotes"
                                    value={adminNotes}
                                    onChange={(e) => setAdminNotes(e.target.value)}
                                    placeholder="Internal notes about this decision..."
                                    rows={3}
                                />
                            </div>

                            {/* Rejection Reason */}
                            {actionType === 'reject' && (
                                <div>
                                    <Label htmlFor="rejectionReason">Rejection Reason *</Label>
                                    <Textarea
                                        id="rejectionReason"
                                        value={rejectionReason}
                                        onChange={(e) => setRejectionReason(e.target.value)}
                                        placeholder="Explain why this request is being rejected..."
                                        rows={3}
                                        required
                                    />
                                </div>
                            )}

                            {/* Actions */}
                            <div className="flex justify-end gap-2 pt-4">
                                <Button variant="outline" onClick={closeDialog}>
                                    Cancel
                                </Button>
                                {actionType === 'approve' ? (
                                    <Button
                                        onClick={handleApprove}
                                        disabled={submitting}
                                        className="bg-green-600 hover:bg-green-700"
                                    >
                                        {submitting ? 'Approving...' : 'Confirm Approval'}
                                    </Button>
                                ) : (
                                    <Button
                                        onClick={handleReject}
                                        disabled={submitting || !rejectionReason.trim()}
                                        variant="destructive"
                                    >
                                        {submitting ? 'Rejecting...' : 'Confirm Rejection'}
                                    </Button>
                                )}
                            </div>
                        </div>
                    )}
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useState, useEffect } from "react";
import { toast } from "sonner";
import {
  Flag,
  Eye,
  CheckCircle,
  XCircle,
  Clock,
  ShieldAlert,
  Search,
  Users,
  BarChart3,
  RefreshCw,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  adminGetAllReports,
  adminVerifyReport,
  adminGetBuyerStats,
  adminClearBuyerMonitoring,
  REPORT_REASONS,
  type Report,
  type ReportStatus,
} from "@/api/reportApi";

const STATUS_OPTIONS: ReportStatus[] = ["PENDING", "VALID", "REJECTED"];

const STATUS_VARIANT: Record<ReportStatus, "default" | "secondary" | "destructive"> = {
  PENDING: "secondary",
  VALID: "default",
  REJECTED: "destructive",
};

const STATUS_ICON: Record<ReportStatus, React.ReactNode> = {
  PENDING: <Clock className="h-3.5 w-3.5" />,
  VALID: <CheckCircle className="h-3.5 w-3.5" />,
  REJECTED: <XCircle className="h-3.5 w-3.5" />,
};

export default function AdminReportManagement() {
  const [activeTab, setActiveTab] = useState<"reports" | "buyers">("reports");

  // Reports list
  const [reports, setReports] = useState<Report[]>([]);
  const [totalReports, setTotalReports] = useState(0);
  const [page, setPage] = useState(1);
  const [statusFilter, setStatusFilter] = useState<ReportStatus | "">("");
  const [sellerSearch, setSellerSearch] = useState("");
  const [loadingReports, setLoadingReports] = useState(true);

  // Detail dialog
  const [selectedReport, setSelectedReport] = useState<Report | null>(null);
  const [verifyStatus, setVerifyStatus] = useState<"VALID" | "REJECTED">("VALID");
  const [adminNote, setAdminNote] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [dialogOpen, setDialogOpen] = useState(false);

  // Buyer stats
  const [buyerStats, setBuyerStats] = useState<any[]>([]);
  const [totalBuyers, setTotalBuyers] = useState(0);
  const [monitoringOnly, setMonitoringOnly] = useState(false);
  const [loadingBuyers, setLoadingBuyers] = useState(false);
  const [clearingId, setClearingId] = useState<string | null>(null);

  useEffect(() => {
    fetchReports();
  }, [page, statusFilter]);

  useEffect(() => {
    if (activeTab === "buyers") fetchBuyerStats();
  }, [activeTab, monitoringOnly]);

  const fetchReports = async () => {
    try {
      setLoadingReports(true);
      const result = await adminGetAllReports({
        status: statusFilter || undefined,
        page,
        limit: 15,
      });
      setReports(result.reports);
      setTotalReports(result.total);
    } catch {
      toast.error("Failed to load reports");
    } finally {
      setLoadingReports(false);
    }
  };

  const fetchBuyerStats = async () => {
    try {
      setLoadingBuyers(true);
      const result = await adminGetBuyerStats({
        underMonitoring: monitoringOnly || undefined,
        limit: 30,
      });
      setBuyerStats(result.stats);
      setTotalBuyers(result.total);
    } catch {
      toast.error("Failed to load buyer stats");
    } finally {
      setLoadingBuyers(false);
    }
  };

  const openVerifyDialog = (report: Report) => {
    setSelectedReport(report);
    setVerifyStatus("VALID");
    setAdminNote(report.adminNote || "");
    setDialogOpen(true);
  };

  const handleVerify = async () => {
    if (!selectedReport) return;
    if (!adminNote.trim()) return toast.error("Admin note is required");
    try {
      setSubmitting(true);
      await adminVerifyReport(selectedReport._id, { status: verifyStatus, adminNote });
      toast.success(`Report marked as ${verifyStatus}`);
      setDialogOpen(false);
      fetchReports();
    } catch (err: any) {
      toast.error(err.response?.data?.message || "Failed to verify report");
    } finally {
      setSubmitting(false);
    }
  };

  const handleClearMonitoring = async (buyerId: string) => {
    try {
      setClearingId(buyerId);
      await adminClearBuyerMonitoring(buyerId);
      toast.success("Monitoring mode cleared");
      fetchBuyerStats();
    } catch {
      toast.error("Failed to clear monitoring");
    } finally {
      setClearingId(null);
    }
  };

  const filteredReports = sellerSearch
    ? reports.filter((r) =>
        r.seller?.username?.toLowerCase().includes(sellerSearch.toLowerCase()) ||
        r.seller?._id?.includes(sellerSearch)
      )
    : reports;

  return (
    <div className="p-6 max-w-7xl mx-auto">
      {/* Header */}
      <div className="mb-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-red-100 flex items-center justify-center">
            <Flag className="h-5 w-5 text-red-600" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Report Management</h1>
            <p className="text-sm text-gray-500">{totalReports} total reports</p>
          </div>
        </div>

        <div className="flex gap-1 bg-gray-100 rounded-xl p-1">
          <button
            onClick={() => setActiveTab("reports")}
            className={`flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === "reports" ? "bg-white shadow-sm text-gray-900" : "text-gray-600 hover:text-gray-800"
            }`}
          >
            <Flag className="h-4 w-4" /> Reports
          </button>
          <button
            onClick={() => setActiveTab("buyers")}
            className={`flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === "buyers" ? "bg-white shadow-sm text-gray-900" : "text-gray-600 hover:text-gray-800"
            }`}
          >
            <Users className="h-4 w-4" /> Buyer Accuracy
          </button>
        </div>
      </div>

      {activeTab === "reports" && (
        <>
          {/* Filters */}
          <div className="mb-5 flex flex-wrap gap-3 items-center">
            <div className="flex gap-1 bg-gray-100 rounded-lg p-1">
              <button
                onClick={() => { setStatusFilter(""); setPage(1); }}
                className={`px-3 py-1.5 rounded-md text-sm transition-all ${!statusFilter ? "bg-white shadow-sm font-medium" : "text-gray-600"}`}
              >
                All
              </button>
              {STATUS_OPTIONS.map((s) => (
                <button
                  key={s}
                  onClick={() => { setStatusFilter(s); setPage(1); }}
                  className={`flex items-center gap-1 px-3 py-1.5 rounded-md text-sm transition-all ${
                    statusFilter === s ? "bg-white shadow-sm font-medium" : "text-gray-600"
                  }`}
                >
                  {STATUS_ICON[s]} {s}
                </button>
              ))}
            </div>

            <div className="flex items-center gap-2 bg-white border rounded-lg px-3 py-1.5">
              <Search className="h-4 w-4 text-gray-400" />
              <input
                className="text-sm outline-none w-40"
                placeholder="Search seller..."
                value={sellerSearch}
                onChange={(e) => setSellerSearch(e.target.value)}
              />
            </div>

            <button
              onClick={fetchReports}
              className="flex items-center gap-1.5 px-3 py-1.5 text-sm text-gray-600 hover:text-gray-800 bg-white border rounded-lg"
            >
              <RefreshCw className="h-4 w-4" /> Refresh
            </button>
          </div>

          {/* Reports grid */}
          {loadingReports ? (
            <div className="py-16 text-center text-gray-400">Loading reports...</div>
          ) : filteredReports.length === 0 ? (
            <Card className="py-16 text-center border-0 shadow-sm">
              <Flag className="h-10 w-10 mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500">No reports found</p>
            </Card>
          ) : (
            <div className="space-y-3">
              {filteredReports.map((report) => (
                <Card key={report._id} className="p-4 border-0 shadow-sm hover:shadow-md transition-shadow">
                  <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                    <div className="flex-1 space-y-2">
                      <div className="flex items-center gap-2 flex-wrap">
                        <Badge variant={STATUS_VARIANT[report.status]} className="flex items-center gap-1">
                          {STATUS_ICON[report.status]} {report.status}
                        </Badge>
                        <span className="text-sm font-semibold text-gray-900">
                          {REPORT_REASONS.find((r) => r.value === report.reason)?.icon}{" "}
                          {REPORT_REASONS.find((r) => r.value === report.reason)?.label}
                        </span>
                        <span className="text-xs text-gray-400">
                          {new Date(report.createdAt).toLocaleString()}
                        </span>
                      </div>

                      <div className="flex flex-wrap gap-x-6 gap-y-1 text-sm text-gray-700">
                        <span>
                          Buyer: <b>{report.buyer?.username || "N/A"}</b>
                        </span>
                        <span>
                          Seller: <b>{report.seller?.username || "N/A"}</b>
                        </span>
                        {report.product && (
                          <span className="text-gray-500">Product: {report.product.title}</span>
                        )}
                      </div>

                      <p className="text-sm text-gray-600 line-clamp-2">{report.description}</p>

                      {report.evidenceUrl && (
                        <a
                          href={report.evidenceUrl}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="text-xs text-blue-600 hover:underline"
                        >
                          🔗 View Evidence
                        </a>
                      )}

                      {report.adminNote && (
                        <p className="text-xs text-gray-500 bg-gray-50 rounded px-2 py-1">
                          Admin note: {report.adminNote}
                        </p>
                      )}
                    </div>

                    <div className="shrink-0">
                      {report.status === "PENDING" ? (
                        <Button size="sm" onClick={() => openVerifyDialog(report)}>
                          <Eye className="h-4 w-4 mr-1" /> Review
                        </Button>
                      ) : (
                        <Button size="sm" variant="outline" onClick={() => openVerifyDialog(report)}>
                          <Eye className="h-4 w-4 mr-1" /> View
                        </Button>
                      )}
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          )}

          {/* Pagination */}
          {totalReports > 15 && (
            <div className="mt-6 flex items-center justify-center gap-2">
              <Button variant="outline" size="sm" disabled={page === 1} onClick={() => setPage((p) => p - 1)}>
                Previous
              </Button>
              <span className="text-sm text-gray-600">
                Page {page} / {Math.ceil(totalReports / 15)}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= Math.ceil(totalReports / 15)}
                onClick={() => setPage((p) => p + 1)}
              >
                Next
              </Button>
            </div>
          )}
        </>
      )}

      {activeTab === "buyers" && (
        <>
          <div className="mb-5 flex items-center gap-3">
            <label className="flex items-center gap-2 text-sm cursor-pointer">
              <input
                type="checkbox"
                className="h-4 w-4 rounded"
                checked={monitoringOnly}
                onChange={(e) => setMonitoringOnly(e.target.checked)}
              />
              Show only buyers under monitoring
            </label>
            <span className="text-sm text-gray-500">({totalBuyers} total)</span>
          </div>

          {loadingBuyers ? (
            <div className="py-16 text-center text-gray-400">Loading buyer stats...</div>
          ) : buyerStats.length === 0 ? (
            <Card className="py-16 text-center border-0 shadow-sm">
              <BarChart3 className="h-10 w-10 mx-auto mb-3 text-gray-300" />
              <p className="text-gray-500">No buyer statistics found</p>
            </Card>
          ) : (
            <div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-3">
              {buyerStats.map((stat: any) => (
                <Card
                  key={stat._id}
                  className={`p-4 border-0 shadow-sm ${stat.underMonitoring ? "ring-2 ring-red-300" : ""}`}
                >
                  <div className="flex items-start justify-between gap-2 mb-3">
                    <div>
                      <p className="font-semibold text-sm text-gray-900">
                        {stat.buyer?.username || "Unknown"}
                      </p>
                      <p className="text-xs text-gray-400">{stat.buyer?.email}</p>
                    </div>
                    {stat.underMonitoring && (
                      <Badge variant="destructive" className="flex items-center gap-1 shrink-0">
                        <ShieldAlert className="h-3 w-3" /> Monitoring
                      </Badge>
                    )}
                  </div>

                  <div className="grid grid-cols-4 gap-2 text-center mb-3">
                    {[
                      { label: "Total", value: stat.totalReports, color: "text-gray-700" },
                      { label: "Valid", value: stat.validReports, color: "text-emerald-600" },
                      { label: "Rejected", value: stat.rejectedReports, color: "text-red-600" },
                      {
                        label: "Accuracy",
                        value: `${(stat.accuracyScore * 100).toFixed(0)}%`,
                        color:
                          stat.accuracyScore >= 0.6
                            ? "text-emerald-600"
                            : stat.accuracyScore >= 0.3
                            ? "text-amber-600"
                            : "text-red-600",
                      },
                    ].map((item) => (
                      <div key={item.label}>
                        <p className={`text-lg font-bold ${item.color}`}>{item.value}</p>
                        <p className="text-xs text-gray-500">{item.label}</p>
                      </div>
                    ))}
                  </div>

                  {/* Accuracy bar */}
                  <div className="mb-3">
                    <div className="h-1.5 rounded-full bg-gray-100 overflow-hidden">
                      <div
                        className={`h-full rounded-full transition-all ${
                          stat.accuracyScore >= 0.6
                            ? "bg-emerald-500"
                            : stat.accuracyScore >= 0.3
                            ? "bg-amber-400"
                            : "bg-red-500"
                        }`}
                        style={{ width: `${Math.min(stat.accuracyScore * 100, 100)}%` }}
                      />
                    </div>
                  </div>

                  {stat.underMonitoring && (
                    <Button
                      size="sm"
                      variant="outline"
                      className="w-full text-xs"
                      disabled={clearingId === stat.buyer?._id}
                      onClick={() => handleClearMonitoring(stat.buyer?._id)}
                    >
                      {clearingId === stat.buyer?._id ? "Clearing..." : "Clear Monitoring Mode"}
                    </Button>
                  )}
                </Card>
              ))}
            </div>
          )}
        </>
      )}

      {/* Verify Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Flag className="h-5 w-5 text-red-500" />
              {selectedReport?.status === "PENDING" ? "Review Report" : "Report Detail"}
            </DialogTitle>
          </DialogHeader>

          {selectedReport && (
            <div className="space-y-4">
              {/* Info */}
              <div className="rounded-lg bg-gray-50 p-4 text-sm space-y-1.5">
                <div className="flex items-center gap-2 mb-2">
                  <Badge variant={STATUS_VARIANT[selectedReport.status]}>{selectedReport.status}</Badge>
                  <span className="font-medium">
                    {REPORT_REASONS.find((r) => r.value === selectedReport.reason)?.icon}{" "}
                    {REPORT_REASONS.find((r) => r.value === selectedReport.reason)?.label}
                  </span>
                </div>
                <p><b>Buyer:</b> {selectedReport.buyer?.username} ({selectedReport.buyer?.email})</p>
                <p><b>Seller:</b> {selectedReport.seller?.username} ({selectedReport.seller?.email})</p>
                {selectedReport.product && <p><b>Product:</b> {selectedReport.product.title}</p>}
                {selectedReport.order && (
                  <p><b>Order:</b> #{selectedReport.order._id?.slice(-8)?.toUpperCase()}</p>
                )}
                <p className="mt-2"><b>Description:</b></p>
                <p className="text-gray-700 bg-white p-2 rounded border">{selectedReport.description}</p>
                {selectedReport.evidenceUrl && (
                  <a href={selectedReport.evidenceUrl} target="_blank" rel="noopener noreferrer"
                    className="text-blue-600 hover:underline text-xs">
                    🔗 View Evidence
                  </a>
                )}
                <p className="text-xs text-gray-400">
                  Submitted: {new Date(selectedReport.createdAt).toLocaleString()}
                </p>
              </div>

              {/* Decision (only for PENDING) */}
              {selectedReport.status === "PENDING" && (
                <>
                  <div className="grid grid-cols-2 gap-3">
                    {(["VALID", "REJECTED"] as const).map((s) => (
                      <button
                        key={s}
                        onClick={() => setVerifyStatus(s)}
                        className={`p-3 rounded-lg border-2 flex items-center gap-2 ${
                          verifyStatus === s
                            ? s === "VALID"
                              ? "border-emerald-500 bg-emerald-50 text-emerald-800"
                              : "border-red-500 bg-red-50 text-red-800"
                            : "border-gray-200 text-gray-600"
                        } text-sm font-medium transition-all`}
                      >
                        {s === "VALID" ? (
                          <CheckCircle className="h-4 w-4" />
                        ) : (
                          <XCircle className="h-4 w-4" />
                        )}
                        Mark as {s}
                      </button>
                    ))}
                  </div>

                  {verifyStatus === "VALID" && (
                    <div className="text-xs text-amber-700 bg-amber-50 rounded-lg p-3 border border-amber-200">
                      ⚠️ <b>Marking as VALID</b> will increase the seller's complaint count, which affects
                      their Trust Score (Dispute Score). If the seller has ≥3 valid reports in 30 days, they
                      will be risk-flagged automatically.
                    </div>
                  )}

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1.5">
                      Admin Note <span className="text-red-500">*</span>
                    </label>
                    <Textarea
                      rows={3}
                      value={adminNote}
                      onChange={(e) => setAdminNote(e.target.value)}
                      placeholder="Explain your decision..."
                    />
                  </div>

                  <div className="flex justify-end gap-2">
                    <Button variant="outline" onClick={() => setDialogOpen(false)}>
                      Cancel
                    </Button>
                    <Button
                      onClick={handleVerify}
                      disabled={submitting}
                      className={verifyStatus === "VALID" ? "bg-emerald-600 hover:bg-emerald-700" : "bg-red-600 hover:bg-red-700"}
                    >
                      {submitting ? "Submitting..." : `Confirm ${verifyStatus}`}
                    </Button>
                  </div>
                </>
              )}

              {selectedReport.status !== "PENDING" && (
                <div className="flex justify-end">
                  <Button variant="outline" onClick={() => setDialogOpen(false)}>
                    Close
                  </Button>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useEffect, useState } from "react";
import { DollarSign, Truck, TrendingUp, BarChart3, Calendar, Users } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import api from "@/lib/axios";

interface MonthlyBucket {
  month: string;
  commission: number;
  shipping: number;
  total: number;
}

interface TopSeller {
  _id: string;
  username: string;
  commission: number;
  orders: number;
}

interface AdminRevenueStats {
  totalCommission: number;
  totalShipping: number;
  totalRevenue: number;
  totalOrders: number;
  monthly: MonthlyBucket[];
  topSellers: TopSeller[];
}

function getDateRange(range: string): { startDate?: string; endDate?: string } {
  if (range === "all") return {};
  const days = range === "7days" ? 7 : range === "30days" ? 30 : range === "90days" ? 90 : 365;
  const start = new Date();
  start.setDate(start.getDate() - days);
  return { startDate: start.toISOString() };
}

export default function AdminRevenue() {
  const [timeRange, setTimeRange] = useState("30days");
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState<AdminRevenueStats>({
    totalCommission: 0,
    totalShipping: 0,
    totalRevenue: 0,
    totalOrders: 0,
    monthly: [],
    topSellers: [],
  });

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const params = getDateRange(timeRange);
        const res = await api.get("/api/revenue/admin", { params });
        setStats(res.data);
      } catch (err) {
        console.error("[AdminRevenue] Fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [timeRange]);

  const maxMonthTotal = Math.max(...stats.monthly.map((m) => m.total), 1);

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">System Revenue</h1>
          <p className="text-gray-600">Platform commission and shipping income</p>
        </div>
        <Select value={timeRange} onValueChange={setTimeRange}>
          <SelectTrigger className="w-[180px] cursor-pointer">
            <Calendar className="h-4 w-4 mr-2" />
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem className="cursor-pointer" value="7days">Past 7 Days</SelectItem>
            <SelectItem className="cursor-pointer" value="30days">Past 30 Days</SelectItem>
            <SelectItem className="cursor-pointer" value="90days">Past 90 Days</SelectItem>
            <SelectItem className="cursor-pointer" value="year">This Year</SelectItem>
            <SelectItem className="cursor-pointer" value="all">All Time</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <DollarSign className="h-4 w-4 text-green-500" />
              Total System Revenue
            </CardTitle>
          </CardHeader>
          <CardContent>
            {loading ? (
              <div className="h-8 bg-muted animate-pulse rounded" />
            ) : (
              <>
                <div className="text-2xl font-bold text-green-600">${stats.totalRevenue.toFixed(2)}</div>
                <p className="text-xs text-muted-foreground mt-1">Commission + Shipping</p>
              </>
            )}
          </CardContent>
        </Card>

