                <div><p className="text-xs text-gray-400 mb-0.5">Submitted</p><p className="font-medium">{new Date(selected.createdAt).toLocaleDateString('en-US')}</p></div>
                {cur.address && cur.address !== '—' && (
                  <div className="col-span-2"><p className="text-xs text-gray-400 mb-0.5">Address</p><p className="font-medium">{cur.address}</p></div>
                )}
              </div>

              {cur.description && (
                <div>
                  <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-1">Shop Description</p>
                  <p className="text-sm text-gray-700 bg-gray-50 rounded-xl p-3 border leading-relaxed">{cur.description}</p>
                </div>
              )}
              {selected.adminNote && (
                <div>
                  <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-1">Admin Note</p>
                  <p className="text-sm text-gray-700 bg-blue-50 rounded-xl p-3 border border-blue-100">{selected.adminNote}</p>
                </div>
              )}
            </div>
            <div className="px-6 py-4 border-t border-gray-100 flex justify-end gap-2 flex-shrink-0">
              <Button variant="outline" size="sm" onClick={closeModal}>Close</Button>
              <button
                className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-medium text-white transition-colors ${selected.user?.status === 'banned' ? 'bg-gray-500 hover:bg-gray-600' : 'bg-red-600 hover:bg-red-700'}`}
                onClick={() => { setBanNote(''); setMode('ban'); }}
              >
                <Ban className="h-3.5 w-3.5" />
                {selected.user?.status === 'banned' ? 'Unban' : 'Ban'}
              </button>
              <button
                className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-medium bg-orange-500 hover:bg-orange-600 text-white transition-colors"
                onClick={() => { setReportReason(REPORT_REASONS[0]); setReportMessage(''); setMode('report'); }}
              >
                <Flag className="h-3.5 w-3.5" /> Report
              </button>
            </div>
          </>
          );
        })()}
      </Modal>

      {/* ── Ban Modal ── */}
      <Modal open={mode === 'ban'} onClose={closeModal}>
        {selected && (
          <>
            <ModalHeader
              title={<span className="flex items-center gap-2 text-red-700"><Ban className="h-4 w-4" />{selected.user?.status === 'banned' ? 'Unban seller' : 'Ban seller'}</span>}
              subtitle={selected.user?.status === 'banned'
                ? `Restore access for "${selected.shopName}" (@${selected.user?.username})?`
                : `Ban "${selected.shopName}" (@${selected.user?.username})?`}
              onClose={closeModal}
            />
            <div className="px-6 py-4">
              {selected.user?.status !== 'banned' && (
                <div className="space-y-2">
                  <Label>Reason (optional)</Label>
                  <Textarea value={banNote} onChange={(e) => setBanNote(e.target.value)}
                    placeholder="e.g. Violated platform terms of service" rows={3} />
                </div>
              )}
            </div>
            <div className="px-6 py-4 border-t border-gray-100 flex justify-end gap-2">
              <Button variant="outline" onClick={closeModal}>Cancel</Button>
              <Button
                className={selected.user?.status === 'banned' ? 'bg-gray-600 hover:bg-gray-700' : 'bg-red-600 hover:bg-red-700'}
                onClick={handleBan} disabled={banLoading}>
                {banLoading ? 'Processing...' : selected.user?.status === 'banned' ? 'Confirm Unban' : 'Confirm Ban'}
              </Button>
            </div>
          </>
        )}
      </Modal>

      {/* ── Report Modal — same pattern as report product ── */}
      <Modal open={mode === 'report'} onClose={closeModal}>
        {selected && (
          <>
            <ModalHeader
              title={<span className="flex items-center gap-2"><Flag className="h-4 w-4 text-orange-500" />Report Seller</span>}
              subtitle="A warning will be sent directly to the seller via system notifications"
              onClose={closeModal}
            />
            <div className="px-6 py-4 space-y-4">
              {/* Seller info chip */}
              <div className="p-3 bg-gray-50 rounded-xl border text-sm">
                <p className="font-medium">{selected.shopName}</p>
                <p className="text-gray-500">@{selected.user?.username}</p>
              </div>

              <div className="space-y-1.5">
                <Label>Reason <span className="text-red-500">*</span></Label>
                <select
                  className="w-full border border-input rounded-lg px-3 py-2 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-orange-400"
                  value={reportReason}
                  onChange={(e) => setReportReason(e.target.value)}
                >
                  {REPORT_REASONS.map((r) => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              <div className="space-y-1.5">
                <Label>Details (optional)</Label>
                <Textarea rows={4} placeholder="Describe the violation in detail..."
                  value={reportMessage} onChange={(e) => setReportMessage(e.target.value)} />
              </div>
            </div>
            <div className="px-6 py-4 border-t border-gray-100 flex justify-end gap-2">
              <Button variant="outline" onClick={closeModal}>Cancel</Button>
              <Button className="bg-orange-500 hover:bg-orange-600"
                onClick={handleReport} disabled={reportLoading}>
                {reportLoading ? 'Sending...' : 'Send warning to seller'}
              </Button>
            </div>
          </>
        )}
      </Modal>
    </div>
  );
}

﻿import { useAuth } from '@/hooks/use-auth';
import { getUserCapabilities, ROLE_PERMISSIONS, type UserRole } from '@/lib/permissions';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Shield, CheckCircle2 } from 'lucide-react';

export default function PermissionsPage() {
  const { user } = useAuth();

  if (!user) {
    return (
      <div className="container mx-auto py-8">
        <p>Please sign in to view your permissions.</p>
      </div>
    );
  }

  const userRole = user.role as UserRole;
  const capabilities = getUserCapabilities(userRole);
  const permissions = ROLE_PERMISSIONS[userRole] || [];

  const getRoleBadgeColor = (role: string) => {
    switch (role) {
      case 'admin':
        return 'bg-red-100 text-red-800';
      case 'seller':
        return 'bg-blue-100 text-blue-800';
      case 'buyer':
        return 'bg-green-100 text-green-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  const getRoleLabel = (role: string) => {
    const labels: Record<string, string> = {
      admin: 'Administrator',
      seller: 'Seller',
      buyer: 'Buyer',
    };
    return labels[role] || role;
  };

  return (
    <div className="container mx-auto py-8">
      <div className="mb-8">
        <div className="flex items-center gap-3 mb-2">
          <Shield className="h-8 w-8 text-blue-600" />
          <h1 className="text-3xl font-bold">My Permissions</h1>
        </div>
        <p className="text-gray-600">View all permissions and capabilities for account {user.username}</p>
      </div>

      <Card className="mb-6">
        <CardHeader>
          <CardTitle>Current Role</CardTitle>
          <CardDescription>Your active role in the system</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex items-center gap-3">
            <Badge className={getRoleBadgeColor(userRole)}>{getRoleLabel(userRole)}</Badge>
            <span className="text-gray-600">{user.email}</span>
          </div>
        </CardContent>
      </Card>

      <Card className="mb-6">
        <CardHeader>
          <CardTitle>Capabilities</CardTitle>
          <CardDescription>What you can do in the system</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid gap-3">
            {capabilities.map((capability, index) => (
              <div key={index} className="flex items-start gap-3">
                <CheckCircle2 className="h-5 w-5 text-green-600 mt-0.5 flex-shrink-0" />
                <span className="text-gray-700">{capability}</span>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Detailed Permissions</CardTitle>
          <CardDescription>Access permissions by resource</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid gap-4">
            {permissions.map((permission, index) => (
              <div key={index} className="border rounded-lg p-4">
                <h3 className="font-semibold text-lg mb-2 capitalize">{permission.resource.replace(/-/g, ' ')}</h3>
                <div className="flex flex-wrap gap-2">
                  {permission.actions.map((action, actionIndex) => (
                    <Badge key={actionIndex} variant="outline">
                      {action}
                    </Badge>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {userRole === 'admin' && (
        <Card className="mt-6">
          <CardHeader>
            <CardTitle>Role Permission Comparison</CardTitle>
            <CardDescription>View capabilities for all roles in the system</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="grid md:grid-cols-3 gap-4">
              {(['admin', 'seller', 'buyer'] as UserRole[]).map((role) => (
                <div key={role} className="border rounded-lg p-4">
                  <Badge className={`${getRoleBadgeColor(role)} mb-3`}>{getRoleLabel(role)}</Badge>
                  <div className="space-y-2">
                    {getUserCapabilities(role).map((cap, idx) => (
                      <div key={idx} className="text-sm text-gray-600 flex items-start gap-2">
                        <CheckCircle2 className="h-4 w-4 text-green-600 mt-0.5 flex-shrink-0" />
                        <span>{cap}</span>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useEffect, useState, useCallback } from "react";
import { toast } from "sonner";
import { Send, ChevronDown, ChevronUp } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  adminGetDisputes,
  adminNotifyBuyer,
  type AdminDisputeItem,
} from "@/api/deliveryDispute";

const STATUS_CONFIG: Record<string, { label: string; className: string }> = {
  PENDING_SHIPPER: { label: "Pending Shipper", className: "bg-orange-100 text-orange-700" },
  SHIPPER_RESPONDED: { label: "Shipper Responded", className: "bg-blue-100 text-blue-700" },
  REPORTED_TO_ADMIN: { label: "Reported to Admin", className: "bg-red-100 text-red-700" },
  CONFIRMED: { label: "Confirmed", className: "bg-green-100 text-green-700" },
};

export default function AdminDeliveryReports() {
  const [disputes, setDisputes] = useState<AdminDisputeItem[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [pages, setPages] = useState(1);
  const [statusFilter, setStatusFilter] = useState("all");
  const [loading, setLoading] = useState(true);

  // Per-dispute expand + notify state
  const [expanded, setExpanded] = useState<Record<string, boolean>>({});
  const [notifyNote, setNotifyNote] = useState<Record<string, string>>({});
  const [notifyLoading, setNotifyLoading] = useState<string | null>(null);

  const fetchDisputes = useCallback(async () => {
    setLoading(true);
    try {
      const params: Record<string, any> = { page };
      if (statusFilter !== "all") params.status = statusFilter;
      const res = await adminGetDisputes(params);
      setDisputes(res.data.disputes);
      setTotal(res.data.total);
      setPages(res.data.pages);
    } catch {
      toast.error("Failed to load reports");
    } finally {
      setLoading(false);
    }
  }, [page, statusFilter]);

  useEffect(() => {
    fetchDisputes();
  }, [fetchDisputes]);

  const handleNotify = async (dispute: AdminDisputeItem) => {
    const note = notifyNote[dispute._id]?.trim();
    if (!note) {
      toast.error("Please enter a message for the buyer");
      return;
    }
    setNotifyLoading(dispute._id);
    try {
      await adminNotifyBuyer(dispute._id, note);
      toast.success("Notification sent to buyer");
      setDisputes((prev) =>
        prev.map((d) =>
          d._id === dispute._id
            ? { ...d, adminNote: note, adminNotifiedAt: new Date().toISOString() }
            : d,
        ),
      );
      setNotifyNote((prev) => ({ ...prev, [dispute._id]: "" }));
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to send notification");
    } finally {
      setNotifyLoading(null);
    }
  };

  const toggleExpand = (id: string) =>
    setExpanded((prev) => ({ ...prev, [id]: !prev[id] }));

  return (
    <div className="p-6">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Delivery Reports</h1>
          <p className="text-sm text-gray-500 mt-1">{total} total reports</p>
        </div>
        <Select value={statusFilter} onValueChange={(v) => { setStatusFilter(v); setPage(1); }}>
          <SelectTrigger className="w-52">
            <SelectValue placeholder="Filter by status" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">All Status</SelectItem>
            <SelectItem value="PENDING_SHIPPER">Pending Shipper</SelectItem>
            <SelectItem value="SHIPPER_RESPONDED">Shipper Responded</SelectItem>
            <SelectItem value="REPORTED_TO_ADMIN">Reported to Admin</SelectItem>
            <SelectItem value="CONFIRMED">Confirmed</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {loading ? (
        <div className="text-center py-16 text-gray-400">Loading...</div>
      ) : disputes.length === 0 ? (
        <div className="text-center py-16 text-gray-400">No delivery reports found.</div>
      ) : (
        <div className="space-y-3">
          {disputes.map((dispute) => {
            const cfg = STATUS_CONFIG[dispute.status] || { label: dispute.status, className: "" };
            const isExpanded = expanded[dispute._id];
            const addr = dispute.order?.shippingAddress;

            return (
              <div key={dispute._id} className="bg-white border rounded-xl overflow-hidden shadow-sm">
                {/* Header row */}
                <div
                  className="flex items-center justify-between px-5 py-4 cursor-pointer hover:bg-gray-50"
                  onClick={() => toggleExpand(dispute._id)}
                >
                  <div className="flex items-center gap-4">
                    <span className="font-mono text-xs text-gray-500">
                      #{(dispute.order?._id || "").slice(-8).toUpperCase()}
                    </span>
                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${cfg.className}`}>
                      {cfg.label}
                    </span>
                    {dispute.adminNotifiedAt && (
                      <span className="text-xs text-green-600 font-medium">✓ Admin notified</span>
                    )}
                  </div>
                  <div className="flex items-center gap-6 text-sm text-gray-600">
                    <span>Buyer: <b>{dispute.buyer?.username}</b></span>
                    <span>Shipper: <b>{dispute.shipper?.username}</b></span>
                    <span>${dispute.order?.totalAmount?.toFixed(2)}</span>
                    <span className="text-xs text-gray-400">
                      {new Date(dispute.createdAt).toLocaleDateString()}
                    </span>
                    {isExpanded ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
                  </div>
                </div>

                {/* Expanded detail */}
                {isExpanded && (
                  <div className="border-t px-5 py-4 space-y-4 bg-gray-50">
                    {/* Thông tin giao hàng */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3 text-sm">
                      <div>
                        <p className="text-xs text-gray-400 mb-0.5">Buyer Email</p>
                        <p className="font-medium">{dispute.buyer?.email}</p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-400 mb-0.5">Shipper Email</p>
                        <p className="font-medium">{dispute.shipper?.email}</p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-400 mb-0.5">Delivery Address</p>
                        <p className="font-medium">
                          {[addr?.district, addr?.city].filter(Boolean).join(", ") || "—"}
                        </p>
                      </div>
                      <div>
                        <p className="text-xs text-gray-400 mb-0.5">Order Status</p>
                        <p className="font-medium">{dispute.order?.status}</p>
                      </div>
                    </div>

                    {/* Buyer note */}
                    {dispute.buyerNote && (
                      <div className="p-3 bg-red-50 border border-red-200 rounded-lg">
                        <p className="text-xs font-semibold text-red-600 mb-1">Buyer's report:</p>
                        <p className="text-sm text-red-800">{dispute.buyerNote}</p>
                      </div>
                    )}

                    {/* Shipper response */}
                    {dispute.shipperNote && (
                      <div className="p-3 bg-blue-50 border border-blue-200 rounded-lg">
                        <p className="text-xs font-semibold text-blue-600 mb-1">Shipper's response:</p>
                        <p className="text-sm text-blue-800">{dispute.shipperNote}</p>
                        {dispute.shipperImages?.length > 0 && (
                          <div className="flex gap-2 mt-2 flex-wrap">
                            {dispute.shipperImages.map((url, i) => (
                              <a key={i} href={url} target="_blank" rel="noreferrer">
                                <img
                                  src={url}
                                  alt={`Evidence ${i + 1}`}
                                  className="h-20 w-20 object-cover rounded-md border border-blue-200 hover:opacity-80"
                                />
                              </a>
                            ))}
                          </div>
                        )}
                      </div>
                    )}

                    {/* Admin note đã gửi */}
                    {dispute.adminNote && (
                      <div className="p-3 bg-purple-50 border border-purple-200 rounded-lg">
                        <p className="text-xs font-semibold text-purple-600 mb-1">
                          Your previous message to buyer
                          {dispute.adminNotifiedAt && (
                            <span className="font-normal ml-2">
                              — sent {new Date(dispute.adminNotifiedAt).toLocaleString()}
                            </span>
                          )}
                          :
                        </p>
                        <p className="text-sm text-purple-800">{dispute.adminNote}</p>
                      </div>
                    )}

                    {/* Admin notify form — chỉ hiện khi status REPORTED_TO_ADMIN */}
                    {dispute.status === "REPORTED_TO_ADMIN" && (
                      <div className="space-y-2">
                        <p className="text-sm font-semibold text-gray-700">
                          Send message to buyer:
                        </p>
                        <Textarea
                          placeholder="Write your message to the buyer (e.g. investigation result, instructions)..."
                          value={notifyNote[dispute._id] || ""}
                          onChange={(e) =>
                            setNotifyNote((prev) => ({ ...prev, [dispute._id]: e.target.value }))
                          }
                          rows={3}
                        />
                        <Button
                          size="sm"
                          className="bg-purple-600 hover:bg-purple-700 text-white"
                          disabled={notifyLoading === dispute._id}
                          onClick={() => handleNotify(dispute)}
                        >
                          <Send className="h-3.5 w-3.5 mr-1.5" />
                          {notifyLoading === dispute._id ? "Sending..." : "Send Notification to Buyer"}
                        </Button>
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Pagination */}
      {pages > 1 && (
        <div className="flex justify-center gap-2 mt-6">
          <Button variant="outline" size="sm" disabled={page <= 1} onClick={() => setPage((p) => p - 1)}>
            Previous
          </Button>
          <span className="px-3 py-1 text-sm text-gray-600">{page} / {pages}</span>
          <Button variant="outline" size="sm" disabled={page >= pages} onClick={() => setPage((p) => p + 1)}>
            Next
          </Button>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from "react";
import { Badge } from "@/components/ui/badge";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import api from "@/lib/axios";

interface Shipper {
  _id: string;
  username: string;
  email: string;
  status: string;
  isAvailable: boolean;
  shipperStatus: string;
  maxOrders: number;
  assignedProvince: string;
  createdAt: string;
  totalAccepted: number;
  delivered: number;
  completed: number;
  inTransit: number;
}

interface ShipperOrder {
  _id: string;
  status: string;
  totalAmount: number;
  createdAt: string;
  buyer?: { username: string };
  seller?: { username: string; sellerInfo?: { shopName?: string } };
  shipper?: { username: string };
}

type TabType = "shippers" | "orders";

const SHIPPER_STATUS_CONFIG: Record<string, { label: string; cls: string }> = {
  available:          { label: "Available",         cls: "bg-green-100 text-green-700 border-green-200" },
  pending_acceptance: { label: "Pending Pickup",    cls: "bg-blue-100 text-blue-700 border-blue-200" },
  shipping:           { label: "Shipping",          cls: "bg-purple-100 text-purple-700 border-purple-200" },
};

const ACCOUNT_STATUS_CONFIG: Record<string, { label: string; cls: string }> = {
  active:    { label: "Active",    cls: "bg-green-100 text-green-700" },
  banned:    { label: "Banned",    cls: "bg-red-100 text-red-700" },
  suspended: { label: "Suspended", cls: "bg-yellow-100 text-yellow-700" },
};

const ORDER_STATUS_CONFIG: Record<string, string> = {
  shipping:  "bg-purple-100 text-purple-700",
  delivered: "bg-green-100 text-green-700",
  completed: "bg-blue-100 text-blue-700",
  cancelled: "bg-red-100 text-red-700",
  pending_acceptance: "bg-blue-50 text-blue-600",
  queued:    "bg-gray-100 text-gray-600",
};

export default function AdminShipperManagement() {
  const [activeTab, setActiveTab] = useState<TabType>("shippers");
  const [shippers, setShippers] = useState<Shipper[]>([]);
  const [provinces, setProvinces] = useState<string[]>([]);
  const [provinceFilter, setProvinceFilter] = useState("all");
  const [orders, setOrders] = useState<ShipperOrder[]>([]);
  const [orderStatus, setOrderStatus] = useState("all");
  const [shipperId, setShipperId] = useState("all");
  const [loading, setLoading] = useState(false);

  const fetchShippers = () => {
    setLoading(true);
    api
      .get("/api/admin/shippers")
      .then((res) => setShippers(res.data.shippers))
      .catch(() => {})
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    fetchShippers();
    api
      .get("/api/admin/shippers/provinces")
      .then((res) => setProvinces(res.data.provinces))
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (activeTab === "orders") {
      setLoading(true);
      const params: Record<string, string> = {};
      if (orderStatus !== "all") params.status = orderStatus;
      if (shipperId !== "all") params.shipperId = shipperId;
      api
        .get("/api/admin/shipper-orders", { params })
        .then((res) => setOrders(res.data.orders))
        .catch(() => {})
        .finally(() => setLoading(false));
    }
  }, [activeTab, orderStatus, shipperId]);

  const filteredShippers =
    provinceFilter === "all"
      ? shippers
      : shippers.filter((s) => s.assignedProvince === provinceFilter);

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Shipper Management</h1>
        <p className="text-sm text-muted-foreground mt-1">Manage shipper availability and monitor delivery orders</p>
      </div>

      {/* Tabs */}
      <div className="flex gap-2">
        {(["shippers", "orders"] as TabType[]).map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
              activeTab === tab
                ? "bg-primary text-white"
                : "bg-gray-100 text-gray-600 hover:bg-gray-200"
            }`}
          >
            {tab === "shippers" ? "Shippers" : "Shipper Orders"}
          </button>
        ))}
      </div>

      {/* ── Shippers Tab ── */}
      {activeTab === "shippers" && (
        <div className="space-y-4">
          {/* Province filter */}
          <div className="flex gap-3">
            <Select value={provinceFilter} onValueChange={setProvinceFilter}>
              <SelectTrigger className="w-56">
                <SelectValue placeholder="Tất cả tỉnh/thành" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Tất cả tỉnh/thành</SelectItem>
                {provinces.map((p) => (
                  <SelectItem key={p} value={p}>
                    {p}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="bg-white rounded-2xl border border-border/60 shadow-sm overflow-hidden">
            {loading ? (
              <div className="text-center py-12 text-muted-foreground">Loading...</div>
            ) : (
              <table className="w-full text-sm">
                <thead>
                  <tr className="bg-gray-50 border-b text-xs uppercase tracking-wide text-muted-foreground">
                    <th className="text-left px-5 py-3">Shipper</th>
                    <th className="text-left px-5 py-3">Tỉnh/Thành</th>
                    <th className="text-left px-5 py-3">Account</th>
                    <th className="text-right px-5 py-3">Accepted</th>
                    <th className="text-right px-5 py-3">Delivered</th>
                    <th className="text-right px-5 py-3">In Transit</th>
                    <th className="text-center px-5 py-3">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border/40">
                  {filteredShippers.length === 0 ? (
                    <tr>
                      <td colSpan={7} className="text-center py-10 text-muted-foreground">
                        No shippers found
                      </td>
                    </tr>
                  ) : (
                    filteredShippers.map((s) => {
                      const acct = ACCOUNT_STATUS_CONFIG[s.status] ?? { label: s.status, cls: "bg-gray-100 text-gray-600" };

                      return (
                        <tr key={s._id} className="hover:bg-gray-50 transition-colors">
                          <td className="px-5 py-3.5">
                            <p className="font-semibold text-foreground">{s.username}</p>
                            <p className="text-xs text-muted-foreground">{s.email}</p>
                          </td>
                          <td className="px-5 py-3.5">
                            <span className="text-xs text-muted-foreground">
                              {s.assignedProvince || "—"}
                            </span>
                          </td>
                          <td className="px-5 py-3.5">
                            <span className={`inline-flex px-2.5 py-1 rounded-full text-xs font-medium ${acct.cls}`}>
                              {acct.label}
                            </span>
                          </td>
                          <td className="px-5 py-3.5 text-right font-medium">{s.totalAccepted}</td>
                          <td className="px-5 py-3.5 text-right text-green-600 font-medium">{s.delivered}</td>
                          <td className="px-5 py-3.5 text-right text-purple-600 font-medium">{s.inTransit}</td>
                          <td className="px-5 py-3.5 text-center">
                            {(() => {
                              const cfg = SHIPPER_STATUS_CONFIG[s.shipperStatus] ?? { label: s.shipperStatus, cls: "bg-gray-100 text-gray-600 border-gray-200" };
                              return (
                                <span className={`inline-flex px-2.5 py-1 rounded-full text-xs font-medium border ${cfg.cls}`}>
                                  {cfg.label}
                                </span>
                              );
                            })()}
                          </td>
                        </tr>
                      );
                    })
                  )}
                </tbody>
              </table>
            )}
          </div>
        </div>
      )}

      {/* ── Orders Tab ── */}
      {activeTab === "orders" && (
        <div className="space-y-4">
          <div className="flex gap-3">
            <Select value={orderStatus} onValueChange={setOrderStatus}>
              <SelectTrigger className="w-48">
                <SelectValue placeholder="All Status" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Status</SelectItem>
                <SelectItem value="pending_acceptance">Pending Acceptance</SelectItem>
                <SelectItem value="shipping">Shipping</SelectItem>
                <SelectItem value="delivered">Delivered</SelectItem>
                <SelectItem value="completed">Completed</SelectItem>
              </SelectContent>
            </Select>

            <Select value={shipperId} onValueChange={setShipperId}>
              <SelectTrigger className="w-52">
                <SelectValue placeholder="All Shippers" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All Shippers</SelectItem>
                {shippers.map((s) => (
                  <SelectItem key={s._id} value={s._id}>
                    {s.username}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div className="bg-white rounded-2xl border border-border/60 shadow-sm overflow-hidden">
            {loading ? (
              <div className="text-center py-12 text-muted-foreground">Loading...</div>
            ) : (
              <table className="w-full text-sm">
                <thead>
                  <tr className="bg-gray-50 border-b text-xs uppercase tracking-wide text-muted-foreground">
                    <th className="text-left px-5 py-3">Order ID</th>
                    <th className="text-left px-5 py-3">Buyer</th>
                    <th className="text-left px-5 py-3">Seller</th>
                    <th className="text-left px-5 py-3">Shipper</th>
                    <th className="text-right px-5 py-3">Amount</th>
                    <th className="text-left px-5 py-3">Status</th>
                    <th className="text-left px-5 py-3">Date</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border/40">
                  {orders.length === 0 ? (
                    <tr>
                      <td colSpan={7} className="text-center py-10 text-muted-foreground">
                        No orders found
                      </td>
                    </tr>
                  ) : (
                    orders.map((o) => {
                      const statusCls = ORDER_STATUS_CONFIG[o.status] ?? "bg-gray-100 text-gray-600";
                      return (
                        <tr key={o._id} className="hover:bg-gray-50 transition-colors">
                          <td className="px-5 py-3.5 font-mono text-xs text-muted-foreground">
                            #{o._id.slice(-8).toUpperCase()}
                          </td>
                          <td className="px-5 py-3.5">{o.buyer?.username || "—"}</td>
                          <td className="px-5 py-3.5">
                            {o.seller?.sellerInfo?.shopName || o.seller?.username || "—"}
                          </td>
                          <td className="px-5 py-3.5">{o.shipper?.username || "—"}</td>
                          <td className="px-5 py-3.5 text-right font-medium">
                            ${o.totalAmount.toFixed(2)}
                          </td>
                          <td className="px-5 py-3.5">
                            <Badge variant="outline" className={`text-xs ${statusCls}`}>
                              {o.status.replace(/_/g, " ")}
                            </Badge>
                          </td>
                          <td className="px-5 py-3.5 text-muted-foreground">
                            {new Date(o.createdAt).toLocaleDateString()}
                          </td>
                        </tr>
                      );
                    })
                  )}
                </tbody>
              </table>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

﻿// src/pages/admin/user-management.tsx
import { useState, useEffect } from 'react';
import {
    getAllUsers,
    banUser,
    unbanUser,
    deleteUser,
    getBanAppeals,
    reviewBanAppeal,
    type User,
    type BanAppeal,
    type GetUsersParams
} from '@/api/admin';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import { Textarea } from '@/components/ui/textarea';
import { toast } from 'sonner';

export default function UserManagement() {
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(false);
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const [search, setSearch] = useState('');
    const [roleFilter, setRoleFilter] = useState('all');
    const [statusFilter, setStatusFilter] = useState('all');

    const handleRoleFilterChange = (value: string) => { setPage(1); setRoleFilter(value); };
    const handleStatusFilterChange = (value: string) => { setPage(1); setStatusFilter(value); };

    // Ban dialog state
    const [banDialogOpen, setBanDialogOpen] = useState(false);
    const [selectedUser, setSelectedUser] = useState<User | null>(null);
    const [banReason, setBanReason] = useState('');
    const [appeals, setAppeals] = useState<BanAppeal[]>([]);
    const [appealsLoading, setAppealsLoading] = useState(false);
    const [reviewDialogOpen, setReviewDialogOpen] = useState(false);
    const [selectedAppeal, setSelectedAppeal] = useState<BanAppeal | null>(null);
    const [reviewAction, setReviewAction] = useState<'approve' | 'reject'>('approve');
    const [reviewNote, setReviewNote] = useState('');
    const [actionLoading, setActionLoading] = useState(false);

    // Fetch users
    const fetchUsers = async () => {
        setLoading(true);
        try {
            const params: GetUsersParams = {
                page,
                limit: 10,
                // When selecting 'all' or 'admin', do not exclude admin accounts
                excludeAdmin: roleFilter !== 'all' && roleFilter !== 'admin',
            };

            if (search) params.search = search;
            if (roleFilter !== 'all') params.role = roleFilter;
            if (statusFilter !== 'all') params.status = statusFilter;

            const response = await getAllUsers(params);
            setUsers(response.data);
            setTotalPages(response.pagination.totalPages);
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to load users');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchUsers();
    }, [page, roleFilter, statusFilter]);

    const fetchAppeals = async () => {
        setAppealsLoading(true);
        try {
            const response = await getBanAppeals({ status: 'pending', limit: 20 });
            setAppeals(response.data);
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to load ban appeals');
        } finally {
            setAppealsLoading(false);
        }
    };

    useEffect(() => {
        fetchAppeals();
    }, []);

    const refreshAdminData = async () => {
        await Promise.all([fetchUsers(), fetchAppeals()]);
    };

    // Handle search
    const handleSearch = () => {
        setPage(1);
        fetchUsers();
    };

    // Handle ban user
    const handleBanUser = async () => {
        if (!selectedUser || !banReason.trim()) {
            toast.error('Please enter a reason for banning this account');
            return;
        }

        try {
            setActionLoading(true);
            await banUser(selectedUser._id, banReason);
            toast.success('Account banned successfully');
            setBanDialogOpen(false);
            setBanReason('');
            setSelectedUser(null);
            await refreshAdminData();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to ban account');
        } finally {
            setActionLoading(false);
        }
    };

    // Handle unban user
    const handleUnbanUser = async (user: User) => {
        try {
            setActionLoading(true);
            await unbanUser(user._id);
            toast.success('Account unbanned successfully');
            await refreshAdminData();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to unban account');
        } finally {
            setActionLoading(false);
        }
    };

    // Handle delete user
    const handleDeleteUser = async (user: User) => {
        if (!confirm(`Are you sure you want to delete user ${user.username}?`)) {
            return;
        }

        try {
            setActionLoading(true);
            await deleteUser(user._id);
            toast.success('User deleted successfully');
            await refreshAdminData();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to delete user');
        } finally {
            setActionLoading(false);
        }
    };

    const handleReviewAppeal = async () => {
        if (!selectedAppeal) return;
        try {
            setActionLoading(true);
            await reviewBanAppeal(selectedAppeal._id, reviewAction, reviewNote.trim());
            toast.success(
                reviewAction === 'approve'
                    ? 'Appeal approved. Account restored.'
                    : 'Appeal rejected.'
            );
            setReviewDialogOpen(false);
            setSelectedAppeal(null);
            setReviewNote('');
            await refreshAdminData();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to review appeal');
        } finally {
            setActionLoading(false);
        }
    };

    // Get status badge
    const getStatusBadge = (status: string) => {
        const variants: Record<string, 'default' | 'secondary' | 'destructive' | 'outline'> = {
            active: 'default',
            banned: 'destructive',
            suspended: 'secondary',
            restricted: 'outline',
        };
        return <Badge variant={variants[status] || 'default'}>{status}</Badge>;
    };

    // Get role badge
    const getRoleBadge = (role: string) => {
        const variants: Record<string, 'default' | 'secondary' | 'outline'> = {
            admin: 'default',
            seller: 'secondary',
            buyer: 'outline',
        };
        return <Badge variant={variants[role] || 'outline'}>{role}</Badge>;
    };

    return (
        <div className="container mx-auto py-8">
            <h1 className="text-3xl font-bold mb-6">User Management</h1>

            {/* Filters */}
            <div className="flex gap-4 mb-6">
                <div className="flex-1">
                    <Input
                        placeholder="Search by username or email..."
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
                    />
                </div>
                <Select value={roleFilter} onValueChange={handleRoleFilterChange}>
                    <SelectTrigger className="w-[180px]">
                        <SelectValue placeholder="Filter by role" />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="all">All roles</SelectItem>
                        <SelectItem value="buyer">Buyer</SelectItem>
                        <SelectItem value="seller">Seller</SelectItem>
                        <SelectItem value="admin">Admin</SelectItem>
                    </SelectContent>
                </Select>
                <Select value={statusFilter} onValueChange={handleStatusFilterChange}>
                    <SelectTrigger className="w-[180px]">
                        <SelectValue placeholder="Filter by status" />
                    </SelectTrigger>
                    <SelectContent>
                        <SelectItem value="all">All statuses</SelectItem>
                        <SelectItem value="active">Active</SelectItem>
                        <SelectItem value="banned">Banned</SelectItem>
                    </SelectContent>
                </Select>

                <Button onClick={handleSearch}>Search</Button>
            </div>

            {/* Users Table */}
            <div className="border rounded-lg">
                <Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>Username</TableHead>
                            <TableHead>Email</TableHead>
                            <TableHead>Role</TableHead>
                            <TableHead>Status</TableHead>
                            <TableHead>Reputation</TableHead>
                            <TableHead>Created At</TableHead>
                            <TableHead className="text-right">Actions</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {loading ? (
                            <TableRow>
                                <TableCell colSpan={7} className="text-center py-8">
                                    Loading...
                                </TableCell>
                            </TableRow>
                        ) : users.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={7} className="text-center py-8">
                                    No users found
                                </TableCell>
                            </TableRow>
                        ) : (
                            users.map((user) => (
                                <TableRow key={user._id}>
                                    <TableCell className="font-medium">{user.username}</TableCell>
                                    <TableCell>{user.email}</TableCell>
                                    <TableCell>{getRoleBadge(user.role)}</TableCell>
                                    <TableCell>{getStatusBadge(user.status)}</TableCell>
                                    <TableCell>{user.reputationScore}</TableCell>
                                    <TableCell>{new Date(user.createdAt).toLocaleDateString('en-US')}</TableCell>
                                    <TableCell className="text-right">
                                        <div className="flex gap-2 justify-end">
                                            {user.status === 'banned' ? (
                                                <Button
                                                    size="sm"
                                                    variant="outline"
                                                    onClick={() => handleUnbanUser(user)}
                                                    disabled={actionLoading}
                                                >
                                                    Unban
                                                </Button>
                                            ) : (
                                                <Button
                                                    size="sm"
                                                    variant="destructive"
                                                    onClick={() => {
                                                        setSelectedUser(user);
                                                        setBanDialogOpen(true);
                                                    }}
                                                    disabled={actionLoading}
                                                >
                                                    Ban
                                                </Button>
                                            )}
                                            <Button
                                                size="sm"
                                                variant="outline"
                                                onClick={() => handleDeleteUser(user)}
                                                disabled={actionLoading}
                                            >
                                                Delete
                                            </Button>
                                        </div>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </div>

            {/* Pagination */}
            <div className="flex justify-center gap-2 mt-6">
                <Button
                    variant="outline"
                    onClick={() => setPage((p) => Math.max(1, p - 1))}
                    disabled={page === 1}
                >
                    Previous
                </Button>
                <span className="flex items-center px-4">
                    Page {page} / {totalPages}
                </span>
                <Button
                    variant="outline"
                    onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                    disabled={page === totalPages}
                >
                    Next
                </Button>
            </div>

            {/* Pending Appeals */}
            <div className="mt-10">
                <h2 className="text-2xl font-semibold mb-4">Pending Ban Appeals</h2>
                <div className="border rounded-lg">
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>User</TableHead>
                                <TableHead>Email</TableHead>
                                <TableHead>Ban Reason</TableHead>
                                <TableHead>Appeal Reason</TableHead>
                                <TableHead>Submitted At</TableHead>
                                <TableHead className="text-right">Actions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {appealsLoading ? (
                                <TableRow>
                                    <TableCell colSpan={6} className="text-center py-8">Loading...</TableCell>
                                </TableRow>
                            ) : appeals.length === 0 ? (
                                <TableRow>
                                    <TableCell colSpan={6} className="text-center py-8">No pending appeals</TableCell>
                                </TableRow>
                            ) : (
                                appeals.map((appeal) => (
                                    <TableRow key={appeal._id}>
                                        <TableCell className="font-medium">{appeal.userId?.username || 'Unknown'}</TableCell>
                                        <TableCell>{appeal.userId?.email || 'N/A'}</TableCell>
                                        <TableCell className="max-w-[220px]">
                                            <p className="line-clamp-2 text-sm text-gray-700">
                                                {appeal.banReasonSnapshot || appeal.userId?.banReason || '-'}
                                            </p>
                                        </TableCell>
                                        <TableCell className="max-w-[320px]">
                                            <p className="line-clamp-3 text-sm">
                                                {appeal.appealReason}
                                            </p>
                                        </TableCell>
                                        <TableCell>{new Date(appeal.createdAt).toLocaleString('en-US')}</TableCell>
                                        <TableCell className="text-right">
                                            <div className="flex gap-2 justify-end">
                                                <Button
                                                    size="sm"
                                                    onClick={() => {
                                                        setSelectedAppeal(appeal);
                                                        setReviewAction('approve');
                                                        setReviewNote('');
                                                        setReviewDialogOpen(true);
                                                    }}
                                                    disabled={actionLoading}
                                                >
                                                    Approve
                                                </Button>
                                                <Button
                                                    size="sm"
                                                    variant="destructive"
                                                    onClick={() => {
                                                        setSelectedAppeal(appeal);
                                                        setReviewAction('reject');
                                                        setReviewNote('');
                                                        setReviewDialogOpen(true);
                                                    }}
                                                    disabled={actionLoading}
                                                >
                                                    Reject
                                                </Button>
                                            </div>
                                        </TableCell>
                                    </TableRow>
                                ))
                            )}
                        </TableBody>
                    </Table>
                </div>
            </div>

            {/* Ban Dialog */}
            <Dialog open={banDialogOpen} onOpenChange={setBanDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Ban Account</DialogTitle>
                        <DialogDescription>
                            You are banning account: <strong>{selectedUser?.username}</strong>
                        </DialogDescription>
                    </DialogHeader>
                    <div className="py-4">
                        <Textarea
                            placeholder="Enter ban reason..."
                            value={banReason}
                            onChange={(e) => setBanReason(e.target.value)}
                            rows={4}
                        />
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setBanDialogOpen(false)}>
                            Cancel
                        </Button>
                        <Button variant="destructive" onClick={handleBanUser} disabled={actionLoading}>
                            {actionLoading ? 'Processing...' : 'Ban Account'}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Review Appeal Dialog */}
            <Dialog open={reviewDialogOpen} onOpenChange={setReviewDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>
                            {reviewAction === 'approve' ? 'Approve Appeal' : 'Reject Appeal'}
                        </DialogTitle>
                        <DialogDescription>
                            User: <strong>{selectedAppeal?.userId?.username || 'N/A'}</strong>
                        </DialogDescription>
                    </DialogHeader>
                    <div className="space-y-3 py-2">
                        <p className="text-sm text-gray-600">
                            Appeal reason: {selectedAppeal?.appealReason || '-'}
                        </p>
                        <Textarea
                            placeholder="Admin note (optional)..."
                            value={reviewNote}
                            onChange={(e) => setReviewNote(e.target.value)}
                            rows={4}
                        />
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setReviewDialogOpen(false)}>
                            Cancel
                        </Button>
                        <Button
                            variant={reviewAction === 'approve' ? 'default' : 'destructive'}
                            onClick={handleReviewAppeal}
                            disabled={actionLoading}
                        >
                            {actionLoading
                                ? 'Processing...'
                                : reviewAction === 'approve'
                                    ? 'Approve & Unban'
                                    : 'Reject Appeal'}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}

import { useEffect, useState } from "react";
import {
  approveVoucherRequest,
  getAdminVoucherRequests,
  rejectVoucherRequest,
  type VoucherRequest,
} from "@/api/vouchers";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";

const statusBadge = (status: string) => {
  if (status === "approved") return <Badge className="bg-green-600">Approved</Badge>;
  if (status === "rejected") return <Badge variant="destructive">Rejected</Badge>;
  if (status === "cancelled") return <Badge variant="outline">Cancelled</Badge>;
  return <Badge variant="secondary">Pending</Badge>;
};

export default function AdminVoucherRequestsPage() {
  const [requests, setRequests] = useState<VoucherRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [status, setStatus] = useState("pending");
  const [selected, setSelected] = useState<VoucherRequest | null>(null);
  const [action, setAction] = useState<"approve" | "reject" | null>(null);
  const [adminNotes, setAdminNotes] = useState("");
  const [rejectionReason, setRejectionReason] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const loadRequests = async () => {
    try {
      setLoading(true);
      const response = await getAdminVoucherRequests({ status });
      setRequests(response.data);
    } catch (error) {
      toast.error("Failed to load voucher requests");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadRequests();
  }, [status]);

  const openDialog = (request: VoucherRequest, type: "approve" | "reject") => {
    setSelected(request);
    setAction(type);
    setAdminNotes("");
    setRejectionReason("");
  };

  const closeDialog = () => {
    setSelected(null);
    setAction(null);
    setAdminNotes("");
    setRejectionReason("");
  };

  const handleApprove = async () => {
    if (!selected) return;
    setSubmitting(true);
    try {
      await approveVoucherRequest(selected._id, adminNotes || undefined);
      toast.success("Voucher request approved");
      closeDialog();
      await loadRequests();
    } catch (error: any) {
      toast.error(error?.response?.data?.message || "Failed to approve request");
    } finally {
      setSubmitting(false);
    }
  };

  const handleReject = async () => {
    if (!selected) return;
    if (!rejectionReason.trim()) {
      toast.error("Rejection reason is required");
      return;
    }
    setSubmitting(true);
    try {
      await rejectVoucherRequest(
        selected._id,
        rejectionReason.trim(),
        adminNotes || undefined,
      );
      toast.success("Voucher request rejected");
      closeDialog();
      await loadRequests();
    } catch (error: any) {
      toast.error(error?.response?.data?.message || "Failed to reject request");
    } finally {
      setSubmitting(false);
    }
  };

  const renderSeller = (seller: VoucherRequest["seller"]) => {
    if (!seller) return "Unknown seller";
    if (typeof seller === "string") return seller;
    const username = seller.username || "Unknown";
    const email = seller.email ? ` (${seller.email})` : "";
    return `${username}${email}`;
  };

  return (
    <div className="container mx-auto py-8 space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Voucher Requests</h1>
        <p className="text-gray-600 mt-1">
          Approve or reject seller voucher requests.
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Requests</CardTitle>
          <CardDescription>Filter and review voucher requests</CardDescription>
          <div className="pt-2">
            <select
              value={status}
              onChange={(e) => setStatus(e.target.value)}
              className="h-10 rounded-md border border-input bg-background px-3 text-sm"
            >
              <option value="pending">Pending</option>
              <option value="approved">Approved</option>
              <option value="rejected">Rejected</option>
              <option value="cancelled">Cancelled</option>
              <option value="all">All</option>
            </select>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          {loading ? (
            <div className="text-center py-10 text-gray-500">Loading requests...</div>
          ) : requests.length === 0 ? (
            <div className="text-center py-10 text-gray-500">No requests</div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Seller</TableHead>
                  <TableHead>Code</TableHead>
                  <TableHead>Type</TableHead>
                  <TableHead>Value</TableHead>
                  <TableHead>Period</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead className="text-right">Action</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {requests.map((request) => (
                  <TableRow key={request._id}>
                    <TableCell>{renderSeller(request.seller)}</TableCell>
                    <TableCell className="font-medium">{request.code}</TableCell>
                    <TableCell>{request.type}</TableCell>
                    <TableCell>
                      {request.type === "percentage"
                        ? `${request.value}%`
                        : `$${request.value}`}
                    </TableCell>
                    <TableCell>
                      {new Date(request.startDate).toLocaleDateString()} -{" "}
                      {new Date(request.endDate).toLocaleDateString()}
                    </TableCell>
                    <TableCell>{statusBadge(request.status)}</TableCell>
                    <TableCell className="text-right">
                      {request.status === "pending" ? (
                        <div className="flex justify-end gap-2">
                          <Button size="sm" onClick={() => openDialog(request, "approve")}>
                            Approve
                          </Button>
                          <Button
                            size="sm"
                            variant="destructive"
                            onClick={() => openDialog(request, "reject")}
                          >
                            Reject
                          </Button>
                        </div>
                      ) : (
                        "-"
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      <Dialog open={!!action} onOpenChange={closeDialog}>
        <DialogContent className="max-w-xl">
          <DialogHeader>
            <DialogTitle>
              {action === "approve" ? "Approve Voucher Request" : "Reject Voucher Request"}
            </DialogTitle>
            <DialogDescription>
              {selected ? `${selected.code} - ${selected.type}` : ""}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3 text-sm">
              <div>
                <span className="text-gray-500">Value:</span>{" "}
                <strong>
                  {selected?.type === "percentage"
                    ? `${selected?.value}%`
                    : `$${selected?.value}`}
                </strong>
              </div>
              <div>
                <span className="text-gray-500">Min order:</span>{" "}
                <strong>${selected?.minOrderValue || 0}</strong>
              </div>
              <div>
                <span className="text-gray-500">Per-user limit:</span>{" "}
                <strong>{selected?.perUserLimit || 1}</strong>
              </div>
              <div>
                <span className="text-gray-500">Usage limit:</span>{" "}
                <strong>{selected?.usageLimit ?? "unlimited"}</strong>
              </div>
            </div>

            <div>
              <Label htmlFor="admin-notes">Admin notes (optional)</Label>
              <Textarea
                id="admin-notes"
                rows={3}
                value={adminNotes}
                onChange={(e) => setAdminNotes(e.target.value)}
              />
            </div>

            {action === "reject" && (
              <div>
                <Label htmlFor="rejection-reason">Rejection reason *</Label>
                <Textarea
                  id="rejection-reason"
                  rows={3}
                  value={rejectionReason}
                  onChange={(e) => setRejectionReason(e.target.value)}
                />
              </div>
            )}

            <div className="flex justify-end gap-2">
              <Button variant="outline" onClick={closeDialog}>
                Cancel
              </Button>
              {action === "approve" ? (
                <Button onClick={handleApprove} disabled={submitting}>
                  {submitting ? "Approving..." : "Confirm Approval"}
                </Button>
              ) : (
                <Button
                  variant="destructive"
                  onClick={handleReject}
                  disabled={submitting || !rejectionReason.trim()}
                >
                  {submitting ? "Rejecting..." : "Confirm Rejection"}
                </Button>
              )}
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useEffect, useState } from "react";
import {
  createAdminGlobalVoucher,
  getAdminGlobalVouchers,
  setAdminGlobalVoucherStatus,
  type Voucher,
  type VoucherType,
} from "@/api/vouchers";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";

const defaultForm = {
  code: "",
  type: "percentage" as VoucherType,
  value: "",
  minOrderValue: "0",
  maxDiscountAmount: "",
  usageLimit: "",
  perUserLimit: "1",
  startDate: "",
  endDate: "",
};

export default function AdminGlobalVouchersPage() {
  const [form, setForm] = useState(defaultForm);
  const [submitting, setSubmitting] = useState(false);
  const [loading, setLoading] = useState(false);
  const [vouchers, setVouchers] = useState<Voucher[]>([]);

  const loadVouchers = async () => {
    try {
      setLoading(true);
      const response = await getAdminGlobalVouchers();
      setVouchers(response.data || []);
    } catch (error) {
      toast.error("Failed to load global vouchers");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadVouchers();
  }, []);

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    if (!form.code.trim() || !form.endDate || !form.value) {
      toast.error("Code, value and end date are required");
      return;
    }

    if (form.startDate && form.endDate && new Date(form.startDate) >= new Date(form.endDate)) {
      toast.error("Start date must be before end date");
      return;
    }

    try {
      setSubmitting(true);
      await createAdminGlobalVoucher({
        code: form.code.trim().toUpperCase(),
        type: form.type,
        value: Number(form.value),
        minOrderValue: Number(form.minOrderValue) || 0,
        maxDiscountAmount: form.maxDiscountAmount ? Number(form.maxDiscountAmount) : null,
        usageLimit: form.usageLimit ? Number(form.usageLimit) : null,
        perUserLimit: Number(form.perUserLimit) || 1,
        startDate: form.startDate || undefined,
        endDate: form.endDate,
      });
      toast.success("Global voucher created");
      setForm(defaultForm);
      await loadVouchers();
    } catch (error: any) {
      toast.error(error?.response?.data?.message || "Failed to create voucher");
    } finally {
      setSubmitting(false);
    }
  };

  const handleToggleStatus = async (voucher: Voucher) => {
    try {
      await setAdminGlobalVoucherStatus(voucher._id, !voucher.isActive);
      toast.success("Voucher status updated");
      await loadVouchers();
    } catch (error: any) {
      toast.error(error?.response?.data?.message || "Failed to update voucher");
    }
  };

  return (
    <div className="container mx-auto py-8 space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Global Voucher Management</h1>
        <p className="text-gray-600 mt-1">Create and manage vouchers that apply to all products.</p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Create Global Voucher</CardTitle>
          <CardDescription>Create voucher used globally across checkout.</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="code">Code</Label>
              <Input
                id="code"
                value={form.code}
                onChange={(e) => setForm((prev) => ({ ...prev, code: e.target.value.toUpperCase() }))}
                placeholder="GLOBAL20"
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="type">Type</Label>
              <select
                id="type"
                className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
                value={form.type}
                onChange={(e) => setForm((prev) => ({ ...prev, type: e.target.value as VoucherType }))}
              >
                <option value="percentage">Percentage</option>
                <option value="fixed">Fixed amount</option>
              </select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="value">Value</Label>
              <Input
                id="value"
                type="number"
                min={1}
                value={form.value}
                onChange={(e) => setForm((prev) => ({ ...prev, value: e.target.value }))}
                required
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="minOrderValue">Minimum order value</Label>
              <Input
                id="minOrderValue"
                type="number"
                min={0}
                value={form.minOrderValue}
                onChange={(e) => setForm((prev) => ({ ...prev, minOrderValue: e.target.value }))}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="maxDiscountAmount">Max discount amount (optional)</Label>
              <Input
                id="maxDiscountAmount"
                type="number"
                min={0}
                value={form.maxDiscountAmount}
                onChange={(e) => setForm((prev) => ({ ...prev, maxDiscountAmount: e.target.value }))}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="usageLimit">Total usage limit (optional)</Label>
              <Input
                id="usageLimit"
                type="number"
                min={1}
                value={form.usageLimit}
                onChange={(e) => setForm((prev) => ({ ...prev, usageLimit: e.target.value }))}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="perUserLimit">Per-user limit</Label>
              <Input
                id="perUserLimit"
                type="number"
                min={1}
                value={form.perUserLimit}
                onChange={(e) => setForm((prev) => ({ ...prev, perUserLimit: e.target.value }))}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="startDate">Start date (optional)</Label>
              <Input
                id="startDate"
                type="datetime-local"
                value={form.startDate}
                onChange={(e) => setForm((prev) => ({ ...prev, startDate: e.target.value }))}
              />
            </div>

            <div className="space-y-2 md:col-span-2">
              <Label htmlFor="endDate">End date</Label>
              <Input
                id="endDate"
                type="datetime-local"
                value={form.endDate}
                onChange={(e) => setForm((prev) => ({ ...prev, endDate: e.target.value }))}
                required
              />
            </div>

            <div className="md:col-span-2">
              <Button type="submit" disabled={submitting}>
                {submitting ? "Creating..." : "Create Global Voucher"}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Global Vouchers</CardTitle>
        </CardHeader>
        <CardContent className="p-0">
          {loading ? (
            <div className="text-center py-10 text-gray-500">Loading vouchers...</div>
          ) : vouchers.length === 0 ? (
            <div className="text-center py-10 text-gray-500">No global vouchers yet</div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Code</TableHead>
                  <TableHead>Discount</TableHead>
                  <TableHead>Usage</TableHead>
                  <TableHead>Per User</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead className="text-right">Action</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {vouchers.map((voucher) => (
                  <TableRow key={voucher._id}>
                    <TableCell className="font-medium">{voucher.code}</TableCell>
                    <TableCell>
                      {voucher.type === "percentage" ? `${voucher.value}%` : `$${voucher.value}`}
                    </TableCell>
                    <TableCell>
                      {voucher.usedCount}
                      {voucher.usageLimit ? ` / ${voucher.usageLimit}` : " / unlimited"}
                    </TableCell>
                    <TableCell>{voucher.perUserLimit}</TableCell>
                    <TableCell>
                      {voucher.isActive ? (
                        <Badge className="bg-green-600">Active</Badge>
                      ) : (
                        <Badge variant="outline">Inactive</Badge>
                      )}
                    </TableCell>
                    <TableCell className="text-right">
                      <Button
                        size="sm"
                        variant={voucher.isActive ? "outline" : "default"}
                        onClick={() => handleToggleStatus(voucher)}
                      >
                        {voucher.isActive ? "Disable" : "Enable"}
                      </Button>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { useSearchParams, Link } from "react-router-dom";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { verifyBanAppealToken, submitBanAppeal } from "@/api/ban-appeals";
import { toast } from "sonner";

export default function BanAppealPage() {
  const [searchParams] = useSearchParams();
  const token = useMemo(() => searchParams.get("token") || "", [searchParams]);

  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [valid, setValid] = useState(false);
  const [hasPendingAppeal, setHasPendingAppeal] = useState(false);
  const [username, setUsername] = useState("");
  const [banReason, setBanReason] = useState("");
  const [appealReason, setAppealReason] = useState("");
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    const verifyToken = async () => {
      if (!token) {
        setValid(false);
        setLoading(false);
        return;
      }
      try {
        const response = await verifyBanAppealToken(token);
        setValid(true);
        setUsername(response.data.username);
        setBanReason(response.data.banReason || "");
        setHasPendingAppeal(Boolean(response.data.hasPendingAppeal));
      } catch (error: any) {
        setValid(false);
        toast.error(error.response?.data?.message || "Invalid appeal link");
      } finally {
        setLoading(false);
      }
    };

    verifyToken();
  }, [token]);

  const handleSubmit = async () => {
    if (!appealReason.trim()) {
      toast.error("Please provide your appeal reason");
      return;
    }
    setSubmitting(true);
    try {
      await submitBanAppeal(token, appealReason.trim());
      setSubmitted(true);
      toast.success("Appeal submitted successfully");
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Failed to submit appeal");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="mx-auto max-w-2xl px-4 py-10">
      <Card>
        <CardHeader>
          <CardTitle>Account Ban Appeal</CardTitle>
          <CardDescription>
            Submit your explanation to admin for account review.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {loading && <p className="text-sm text-gray-500">Verifying appeal link...</p>}

          {!loading && !valid && (
            <Alert variant="destructive">
              <AlertTitle>Invalid link</AlertTitle>
              <AlertDescription>
                This appeal link is invalid or expired. Try signing in again to request a new link.
              </AlertDescription>
            </Alert>
          )}

          {!loading && valid && (
            <>
              <Alert>
                <AlertTitle>Banned account: {username}</AlertTitle>
                <AlertDescription>
                  {banReason ? `Ban reason: ${banReason}` : "No ban reason provided by admin."}
                </AlertDescription>
              </Alert>

              {hasPendingAppeal || submitted ? (
                <Alert>
                  <AlertTitle>Appeal already submitted</AlertTitle>
                  <AlertDescription>
                    Your appeal is pending review. Admin will review and notify you.
                  </AlertDescription>
                </Alert>
              ) : (
                <>
                  <Textarea
                    rows={7}
                    placeholder="Write why you think this account should be restored..."
                    value={appealReason}
                    onChange={(e) => setAppealReason(e.target.value)}
                  />
                  <div className="flex gap-2">
                    <Button onClick={handleSubmit} disabled={submitting}>
                      {submitting ? "Submitting..." : "Submit Appeal"}
                    </Button>
                    <Button variant="outline" asChild>
                      <Link to="/auth/sign-in">Back to Sign In</Link>
                    </Button>
                  </div>
                </>
              )}
            </>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useEffect, useRef } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useAuth } from '@/hooks/use-auth';
import { toast } from 'sonner';

export default function GoogleAuthSuccessPage() {
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const { setUser, setToken, fetchMe } = useAuth();
    const hasProcessed = useRef(false);

    useEffect(() => {
        const process = async () => {
            // Ngăn chặn chạy lại nếu đã xử lý rồi
            if (hasProcessed.current) {
                return;
            }

            const token = searchParams.get('token');
            const userStr = searchParams.get('user');
            const error = searchParams.get('error');

            if (error) {
                hasProcessed.current = true;
                toast.error('Google authentication failed', {
                    position: 'top-center',
                    closeButton: true,
                });
                navigate('/auth/sign-in');
                return;
            }

            if (token && userStr) {
                try {
                    const user = JSON.parse(decodeURIComponent(userStr));
                    hasProcessed.current = true;
                    setToken(token);
                    setUser(user);
                    await fetchMe();

                    toast.success('Signed in successfully with Google', {
                        position: 'top-center',
                        closeButton: true,
                    });

                    if (user?.role === 'shipper') window.location.href = '/shipper';
                    else if (user?.role === 'admin') window.location.href = '/admin';
                    else if (user?.role === 'seller') window.location.href = '/seller';
                    else navigate('/');
                } catch (error) {
                    hasProcessed.current = true;
                    console.error('Failed to parse user data:', error);
                    toast.error('Authentication failed', {
                        position: 'top-center',
                        closeButton: true,
                    });
                    navigate('/auth/sign-in');
                }
            } else {
                hasProcessed.current = true;
                toast.error('Missing authentication data', {
                    position: 'top-center',
                    closeButton: true,
                });
                navigate('/auth/sign-in');
            }
        };

        process();
    }, [searchParams, navigate, setUser, setToken, fetchMe]);

    return (
        <div className='flex h-full w-full items-center justify-center'>
            <div className='text-center'>
                <h2 className='text-xl font-semibold'>Processing Google Sign In...</h2>
                <p className='text-muted-foreground mt-2'>Please wait while we complete your authentication.</p>
            </div>
        </div>
    );
}

import { useEffect, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";
import api from "@/lib/axios";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Loader2, CheckCircle, XCircle } from "lucide-react";
import { toast } from "sonner";

const VerifyEmailPage = () => {
  const [searchParams] = useSearchParams();
  const token = searchParams.get("token");
  console.log(token)
  const navigate = useNavigate();
  const [status, setStatus] = useState<"loading" | "success" | "error">("loading");

  useEffect(() => {
    const verify = async () => {
      if (!token) {
        setStatus("error");
        return;
      }

      try {
        // Backend expects POST and uses req.query.token
        await api.post(`/api/auth/verify-email?token=${token}`);
        setStatus("success");
        toast.success("Email verified successfully!");
      } catch (error) {
        console.error("Verification failed", error);
        setStatus("error");
        toast.error("Verification failed or link expired.");
      }
    };

    if (status === "loading") {
      verify();
    }
  }, [token, status]);

  return (
    <div className="flex min-h-screen items-center justify-center bg-background p-4">
      <Card className="w-full max-w-md text-center">
        <CardHeader>
          <CardTitle>Email Verification</CardTitle>
          <CardDescription>
            {status === "loading" && "Verifying your email..."}
            {status === "success" && "Account verified!"}
            {status === "error" && "Verification failed"}
          </CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col items-center gap-6">
          {status === "loading" && (
            <Loader2 className="h-16 w-16 animate-spin text-primary" />
          )}

          {status === "success" && (
            <>
              <CheckCircle className="h-16 w-16 text-green-500" />
              <p>Your email has been verified. You can now access all features.</p>
              <Button onClick={() => navigate("/auth/sign-in")}>
                Go to Sign In
              </Button>
            </>
          )}

          {status === "error" && (
            <>
              <XCircle className="h-16 w-16 text-destructive" />
              <p>The verification link is invalid or has expired.</p>
              <Button variant="outline" onClick={() => navigate("/auth/sign-in")}>
                Back to Sign In
              </Button>
            </>
          )}
        </CardContent>
      </Card>
    </div>
  );
};

export default VerifyEmailPage;

