import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "@/hooks/use-auth";
import api from "@/lib/axios";
import axios from "axios";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";
import {
  ChevronLeft,
  CheckCircle2,
  Zap,
  ShieldAlert,
  TrendingUp,
  Star,
  Package,
  Clock,
  MailCheck,
  ImagePlus,
  X,
  Phone,
  MapPin,
} from "lucide-react";

const PROBATION_LIMITS = [
  { icon: Package, label: "Max 5 products/day" },
  { icon: Clock, label: "Max 10 orders/day" },
  { icon: ShieldAlert, label: "Cannot list high-risk categories" },
];

const UPGRADE_CONDITIONS = [
  { label: "≥ 20 successful orders" },
  { label: "Average rating ≥ 4.5 ⭐" },
  { label: "Return rate < 5%" },
  { label: "Account age > 30 days" },
  { label: "No serious reports" },
];

interface Province { code: number; name: string; }
interface District { code: number; name: string; }
interface Ward { code: number; name: string; }

export default function SellerApplyPage() {
  const navigate = useNavigate();
  const { user, fetchMe } = useAuth();

  const [form, setForm] = useState({
    shopName: "",
    phone: "",
    productDescription: "",
  });
  const [address, setAddress] = useState({
    city: "", cityName: "",
    district: "", districtName: "",
    ward: "", wardName: "",
    street: "",
    detail: "",
  });
  const [provinces, setProvinces] = useState<Province[]>([]);
  const [districts, setDistricts] = useState<District[]>([]);
  const [wards, setWards] = useState<Ward[]>([]);

  // 2 images
  const [images, setImages] = useState<{ file: File | null; preview: string; url: string }[]>([
    { file: null, preview: "", url: "" },
    { file: null, preview: "", url: "" },
  ]);
  const [uploadingIdx, setUploadingIdx] = useState<number | null>(null);

  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [checkingStatus, setCheckingStatus] = useState(true);

  useEffect(() => {
    if (!user) { navigate("/auth/sign-in"); return; }
    if (user.role === "seller") { navigate("/seller"); return; }
    if (user.role === "admin") { navigate("/"); return; }
    api.get("/api/seller-applications/my")
      .then((res) => { if (res.data.data) navigate("/seller"); })
      .catch(() => {})
      .finally(() => setCheckingStatus(false));
  }, [user, navigate]);

  useEffect(() => {
    axios.get("https://provinces.open-api.vn/api/p/").then((res) => setProvinces(res.data)).catch(() => {});
  }, []);

  const handleProvinceChange = async (code: string) => {
    const prov = provinces.find((p) => String(p.code) === code);
    setAddress((a) => ({ ...a, city: code, cityName: prov?.name || "", district: "", districtName: "", ward: "", wardName: "" }));
    setDistricts([]); setWards([]);
    try {
      const res = await axios.get(`https://provinces.open-api.vn/api/p/${code}?depth=2`);
      setDistricts(res.data.districts || []);
    } catch {}
  };

  const handleDistrictChange = async (code: string) => {
    const dist = districts.find((d) => String(d.code) === code);
    setAddress((a) => ({ ...a, district: code, districtName: dist?.name || "", ward: "", wardName: "" }));
    setWards([]);
    try {
      const res = await axios.get(`https://provinces.open-api.vn/api/d/${code}?depth=2`);
      setWards(res.data.wards || []);
    } catch {}
  };

  const handleWardChange = (code: string) => {
    const ward = wards.find((w) => String(w.code) === code);
    setAddress((a) => ({ ...a, ward: code, wardName: ward?.name || "" }));
  };

  const handleImageSelect = async (idx: number, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const preview = URL.createObjectURL(file);
    setImages((prev) => {
      const next = [...prev];
      next[idx] = { file, preview, url: "" };
      return next;
    });
    // Upload to Cloudinary
    setUploadingIdx(idx);
    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("upload_preset", import.meta.env.VITE_CLOUDINARY_UPLOAD_PRESET || "");
      const res = await axios.post(
        `https://api.cloudinary.com/v1_1/${import.meta.env.VITE_CLOUDINARY_CLOUD_NAME}/image/upload`,
        formData
      );
      setImages((prev) => {
        const next = [...prev];
        next[idx] = { file, preview, url: res.data.secure_url };
        return next;
      });
    } catch {
      toast.error("Image upload failed. Please try again.");
      setImages((prev) => {
        const next = [...prev];
        next[idx] = { file: null, preview: "", url: "" };
        return next;
      });
    } finally {
      setUploadingIdx(null);
    }
  };

  const removeImage = (idx: number) => {
    setImages((prev) => {
      const next = [...prev];
      next[idx] = { file: null, preview: "", url: "" };
      return next;
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user?.isEmailVerified) {
      toast.error("Please verify your email before registering as a seller");
      return;
    }
    if (form.productDescription.length < 20) {
      toast.error("Shop description must be at least 20 characters");
      return;
    }
    if (!form.phone.trim()) {
      toast.error("Please enter your phone number");
      return;
    }
    if (!address.cityName) {
      toast.error("Please select your city/province");
      return;
    }
    const uploadedUrls = images.map((img) => img.url).filter(Boolean);
    if (uploadedUrls.length < 2) {
      toast.error("Please upload both required business photos");
      return;
    }
    if (uploadingIdx !== null) {
      toast.error("Please wait for images to finish uploading");
      return;
    }

    setLoading(true);
    try {
      await api.post("/api/seller-applications", {
        shopName: form.shopName,
        phone: form.phone,
        productDescription: form.productDescription,
        shopAddress: {
          city: address.cityName,
          district: address.districtName,
          ward: address.wardName,
          street: address.street,
          detail: address.detail,
        },
        businessImages: uploadedUrls,
      });
      await fetchMe();
      setSuccess(true);
    } catch (err: any) {
      toast.error(err.response?.data?.message || "Registration failed, please try again.");
    } finally {
      setLoading(false);
    }
  };

  if (checkingStatus) {
    return (
      <div className="flex items-center justify-center min-h-[50vh]">
        <p className="text-muted-foreground">Checking status...</p>
      </div>
    );
  }

  if (success) {
    return (
      <div className="max-w-lg mx-auto mt-12 flex flex-col items-center gap-6 text-center px-4">
        <div className="relative">
          <div className="h-20 w-20 rounded-full bg-green-100 flex items-center justify-center">
            <CheckCircle2 className="h-10 w-10 text-green-600" />
          </div>
          <div className="absolute -top-1 -right-1 h-6 w-6 rounded-full bg-blue-500 flex items-center justify-center">
            <Zap className="h-3.5 w-3.5 text-white" />
          </div>
        </div>
        <div>
          <Badge className="mb-3 bg-blue-100 text-blue-700 hover:bg-blue-100">Auto-approved</Badge>
          <h2 className="text-2xl font-bold text-foreground mb-2">🎉 Congratulations! You are now a Seller</h2>
          <p className="text-muted-foreground text-sm leading-relaxed">
            Your account has been successfully upgraded. <strong>A confirmation email</strong> has been sent to your inbox.
          </p>
        </div>
        <div className="w-full rounded-xl border border-amber-200 bg-amber-50 p-4 text-left">
          <div className="flex items-center gap-2 mb-3">
            <ShieldAlert className="h-4 w-4 text-amber-600" />
            <span className="text-sm font-semibold text-amber-800">PROBATION Stage – Limits currently applied</span>
          </div>
          <div className="flex flex-col gap-2">
            {PROBATION_LIMITS.map((item) => {
              const Icon = item.icon;
              return (
                <div key={item.label} className="flex items-center gap-2 text-sm text-amber-700">
                  <Icon className="h-3.5 w-3.5 flex-shrink-0" />
                  <span>{item.label}</span>
                </div>
              );
            })}
          </div>
        </div>
        <div className="w-full rounded-xl border border-green-200 bg-green-50 p-4 text-left">
          <div className="flex items-center gap-2 mb-3">
            <TrendingUp className="h-4 w-4 text-green-700" />
            <span className="text-sm font-semibold text-green-800">Conditions to upgrade to NORMAL</span>
          </div>
          <div className="flex flex-col gap-1.5">
            {UPGRADE_CONDITIONS.map((c) => (
              <div key={c.label} className="flex items-center gap-2 text-sm text-green-700">
                <Star className="h-3 w-3 flex-shrink-0" />
                <span>{c.label}</span>
              </div>
            ))}
          </div>
          <p className="text-xs text-green-600 mt-3">The system automatically checks and upgrades daily.</p>
        </div>
        <Button id="go-to-seller-panel-btn" size="lg" className="w-full cursor-pointer" onClick={() => navigate("/seller")}>
          Go to Seller Panel
        </Button>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      <button
        onClick={() => navigate("/become-seller")}
        className="flex items-center gap-1 text-sm text-muted-foreground hover:text-foreground mb-6 cursor-pointer transition-colors"
      >
        <ChevronLeft className="h-4 w-4" />
        Go back
      </button>

      <div className="mb-8">
        <div className="flex items-center gap-2 mb-1">
          <h1 className="text-2xl font-bold text-foreground">Register to become a Seller</h1>
          <Badge className="bg-blue-100 text-blue-700 hover:bg-blue-100">
            <Zap className="h-3 w-3 mr-1" />
            Auto-approved
          </Badge>
        </div>
        <p className="text-muted-foreground text-sm">
          Fill in the information below. Your account will be upgraded <strong>instantly</strong> upon submission.
        </p>
      </div>

      {user && !user.isEmailVerified && (
        <div className="mb-6 flex items-start gap-3 rounded-xl border border-amber-200 bg-amber-50 px-4 py-3">
          <MailCheck className="h-5 w-5 text-amber-600 flex-shrink-0 mt-0.5" />
          <p className="text-sm text-amber-700">
            Please <strong>verify your email</strong> before registering as a seller. Check your inbox.
          </p>
        </div>
      )}

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* ── Section 1: Basic Info ── */}
        <div className="bg-white rounded-2xl border border-border/60 p-6 space-y-5">
          <h2 className="text-sm font-semibold text-foreground uppercase tracking-wide">Shop Information</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex flex-col gap-1.5">
              <Label htmlFor="shopName">Shop name <span className="text-destructive">*</span></Label>
              <Input
                id="shopName"
                placeholder="e.g. ABC Fashion Store"
                value={form.shopName}
                onChange={(e) => setForm((p) => ({ ...p, shopName: e.target.value }))}
                required
                disabled={!user?.isEmailVerified}
              />
            </div>

            <div className="flex flex-col gap-1.5">
              <Label htmlFor="phone">
                <Phone className="inline h-3.5 w-3.5 mr-1" />
                Phone number <span className="text-destructive">*</span>
              </Label>
              <Input
                id="phone"
                type="tel"
                placeholder="e.g. 0912345678"
                value={form.phone}
                onChange={(e) => setForm((p) => ({ ...p, phone: e.target.value }))}
                required
                disabled={!user?.isEmailVerified}
              />
            </div>
          </div>

          <div className="flex flex-col gap-1.5">
            <Label htmlFor="productDescription">Shop description <span className="text-destructive">*</span></Label>
            <Textarea
              id="productDescription"
              placeholder="Describe your shop and what you sell. e.g. Premium women's fashion, luxury handbags..."
              value={form.productDescription}
              onChange={(e) => setForm((p) => ({ ...p, productDescription: e.target.value }))}
              required
              rows={3}
              disabled={!user?.isEmailVerified}
            />
            <p className="text-xs text-muted-foreground">
              Minimum 20 characters. Current: {form.productDescription.length} characters.
            </p>
          </div>
        </div>

        {/* ── Section 2: Address ── */}
        <div className="bg-white rounded-2xl border border-border/60 p-6 space-y-4">
          <h2 className="text-sm font-semibold text-foreground uppercase tracking-wide flex items-center gap-2">
            <MapPin className="h-4 w-4" />
            Shop Address
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div className="flex flex-col gap-1.5">
              <Label>Province / City <span className="text-destructive">*</span></Label>
              <Select value={address.city} onValueChange={handleProvinceChange} disabled={!user?.isEmailVerified}>
                <SelectTrigger className="cursor-pointer">
                  <SelectValue placeholder="Select province" />
                </SelectTrigger>
                <SelectContent>
                  {provinces.map((p) => (
                    <SelectItem key={p.code} value={String(p.code)}>{p.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="flex flex-col gap-1.5">
              <Label>District</Label>
              <Select value={address.district} onValueChange={handleDistrictChange} disabled={!address.city || !user?.isEmailVerified}>
                <SelectTrigger className="cursor-pointer">
                  <SelectValue placeholder="Select district" />
                </SelectTrigger>
                <SelectContent>
                  {districts.map((d) => (
                    <SelectItem key={d.code} value={String(d.code)}>{d.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="flex flex-col gap-1.5">
              <Label>Ward</Label>
              <Select value={address.ward} onValueChange={handleWardChange} disabled={!address.district || !user?.isEmailVerified}>
                <SelectTrigger className="cursor-pointer">
                  <SelectValue placeholder="Select ward" />
                </SelectTrigger>
                <SelectContent>
                  {wards.map((w) => (
                    <SelectItem key={w.code} value={String(w.code)}>{w.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex flex-col gap-1.5">
              <Label htmlFor="street">Street / House number</Label>
              <Input
                id="street"
                placeholder="e.g. 123 Nguyen Hue"
                value={address.street}
                onChange={(e) => setAddress((a) => ({ ...a, street: e.target.value }))}
                disabled={!user?.isEmailVerified}
              />
            </div>
            <div className="flex flex-col gap-1.5">
              <Label htmlFor="detail">Address detail</Label>
              <Input
                id="detail"
                placeholder="e.g. Floor 2, Building A"
                value={address.detail}
                onChange={(e) => setAddress((a) => ({ ...a, detail: e.target.value }))}
                disabled={!user?.isEmailVerified}
              />
            </div>
          </div>
        </div>

        {/* ── Section 3: Business Photos ── */}
        <div className="bg-white rounded-2xl border border-border/60 p-6 space-y-4">
          <div>
            <h2 className="text-sm font-semibold text-foreground uppercase tracking-wide">Business Photos</h2>
            <p className="text-xs text-muted-foreground mt-1">
              Upload 2 photos of your business (storefront, products, etc.) to verify your shop.
            </p>
          </div>

          <div className="grid grid-cols-2 gap-4">
            {images.map((img, idx) => (
              <div key={idx} className="flex flex-col gap-2">
                <p className="text-xs font-medium text-muted-foreground">Photo {idx + 1} <span className="text-destructive">*</span></p>
                {img.preview ? (
                  <div className="relative group aspect-video rounded-xl overflow-hidden border border-border bg-gray-50">
                    <img src={img.preview} alt={`Business photo ${idx + 1}`} className="w-full h-full object-cover" />
                    {uploadingIdx === idx && (
                      <div className="absolute inset-0 bg-black/40 flex items-center justify-center">
                        <p className="text-white text-xs font-medium">Uploading...</p>
                      </div>
                    )}
                    {uploadingIdx !== idx && (
                      <button
                        type="button"
                        onClick={() => removeImage(idx)}
                        className="absolute top-2 right-2 bg-red-500 text-white rounded-full w-6 h-6 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity shadow-sm"
                      >
                        <X className="w-3.5 h-3.5" />
                      </button>
                    )}
                    {img.url && (
                      <div className="absolute bottom-2 right-2 bg-green-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full">
                        ✓
                      </div>
                    )}
                  </div>
                ) : (
                  <label className={`aspect-video rounded-xl border-2 border-dashed flex flex-col items-center justify-center gap-2 cursor-pointer transition-colors ${!user?.isEmailVerified ? "opacity-50 cursor-not-allowed" : "border-border hover:border-orange-400 hover:bg-orange-50"}`}>
                    <ImagePlus className="h-8 w-8 text-muted-foreground" />
                    <span className="text-xs text-muted-foreground">Click to upload</span>
                    <input
                      type="file"
                      accept="image/*"
                      className="hidden"
                      disabled={!user?.isEmailVerified}
                      onChange={(e) => handleImageSelect(idx, e)}
                    />
                  </label>
                )}
              </div>
            ))}
          </div>
        </div>

        <Separator />

        {/* Info box */}
        <div className="rounded-xl border border-border bg-muted/30 p-4">
          <p className="text-xs font-semibold text-foreground mb-2">
            ℹ️ After registration, you will be in the <strong>PROBATION</strong> stage:
          </p>
          <ul className="text-xs text-muted-foreground space-y-1 pl-4 list-disc">
            <li>Cannot list high-risk categories</li>
            <li>Existing products (if any) remain visible as normal</li>
          </ul>
          <p className="text-xs text-muted-foreground mt-2">
            The system automatically upgrades to <strong>NORMAL</strong> when conditions are met.
          </p>
        </div>

        <Button
          type="submit"
          id="submit-seller-application-btn"
          size="lg"
          disabled={loading || !user?.isEmailVerified || uploadingIdx !== null}
          className="w-full cursor-pointer"
        >
          {loading ? "Processing..." : "Register as Seller now"}
        </Button>
      </form>
    </div>
  );
}

import React, { useState, useMemo } from "react";
import CartItem from "@/components/cart/cart-item";
import CartSubtotal from "@/components/cart/cart-subtotal";
import { useCart } from "@/contexts/cart-context";
import { ShoppingBag, Store } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useNavigate } from "react-router-dom";

const CartPage = () => {
  const cartContext = useCart();
  const [selectedItemIds, setSelectedItemIds] = useState<string[]>([]);
  const navigate = useNavigate();

  const items = useMemo(() => cartContext.cart?.items || [], [cartContext.cart?.items]);

  const { activeItems, savedItems } = useMemo(() => {
    const active: typeof items = [];
    const saved: typeof items = [];
    items.forEach((item) => {
      if (item.savedForLater) saved.push(item);
      else active.push(item);
    });
    return { activeItems: active, savedItems: saved };
  }, [items]);

  const isItemPurchasable = React.useCallback(
    (item: (typeof items)[number]) => {
      if (item.savedForLater) return false;
      if (item.availabilityStatus) {
        return item.availabilityStatus === "ok";
      }
      const availableStock = item.availableStock ?? 0;
      return !item.isOutOfStock && item.quantity <= availableStock;
    },
    [],
  );

  // Group ONLY active items by seller
  const groupedItems = useMemo(() => {
    const groups: Record<string, { sellerName: string; items: typeof items }> =
      {};
    activeItems.forEach((item) => {
      const sellerId = item.seller?._id || "unknown";
      if (!groups[sellerId]) {
        groups[sellerId] = {
          sellerName: item.seller?.username || "Unknown Seller",
          items: [],
        };
      }
      groups[sellerId].items.push(item);
    });
    return groups;
  }, [activeItems]);

  const purchasableItems = useMemo(
    () => items.filter((item) => isItemPurchasable(item)),
    [items, isItemPurchasable],
  );

  const purchasableItemIds = useMemo(
    () => purchasableItems.map((item) => item._id),
    [purchasableItems],
  );

  const isAllSelected =
    purchasableItems.length > 0 &&
    selectedItemIds.length === purchasableItems.length;

  const handleToggleSelectAll = () => {
    if (isAllSelected) {
      setSelectedItemIds([]);
    } else {
      setSelectedItemIds(purchasableItems.map((item) => item._id));
    }
  };

  const handleToggleSellerSelection = (sellerId: string) => {
    const sellerItems = groupedItems[sellerId].items;
    const sellerPurchasableIds = sellerItems
      .filter((item) => isItemPurchasable(item))
      .map((item) => item._id);

    const allSellerPurchasableSelected = sellerPurchasableIds.every((id) =>
      selectedItemIds.includes(id),
    );

    if (allSellerPurchasableSelected) {
      // Deselect all for this seller
      setSelectedItemIds((prev) =>
        prev.filter((id) => !sellerPurchasableIds.includes(id)),
      );
    } else {
      // Select all for this seller
      setSelectedItemIds((prev) => {
        const next = new Set([...prev, ...sellerPurchasableIds]);
        return Array.from(next);
      });
    }
  };

  const handleToggleItem = (itemId: string) => {
    const item = items.find((x) => x._id === itemId);
    const isPurchasable = !!item && isItemPurchasable(item);
    if (!isPurchasable) return;

    setSelectedItemIds((prev) =>
      prev.includes(itemId)
        ? prev.filter((id) => id !== itemId)
        : [...prev, itemId],
    );
  };

  React.useEffect(() => {
    const allowedIds = new Set(purchasableItemIds);
    setSelectedItemIds((prev) => {
      const next = prev.filter((id) => allowedIds.has(id));
      if (
        next.length === prev.length &&
        next.every((id, idx) => id === prev[idx])
      ) {
        return prev;
      }
      return next;
    });
  }, [purchasableItemIds]);

  const selectedItems = useMemo(() => {
    return activeItems.filter((item) => selectedItemIds.includes(item._id));
  }, [activeItems, selectedItemIds]);

  const selectedTotalPrice = useMemo(() => {
    return selectedItems.reduce(
      (total, item) => total + item.priceSnapShot * item.quantity,
      0,
    );
  }, [selectedItems]);

  const selectedCount = useMemo(() => {
    return selectedItems.reduce((total, item) => total + item.quantity, 0);
  }, [selectedItems]);

  const handleCheckout = () => {
    if (!selectedItemIds.length) return;
    navigate("/checkout", {
      state: {
        source: "cart",
        cartItemIds: selectedItemIds,
      },
    });
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <h1 className="font-bold text-4xl text-gray-900 mb-8">Shopping Cart</h1>

      <div className="grid grid-cols-12 gap-8 mt-4">
        <div className="col-span-12 lg:col-span-8">
          {/* Global Select All Section */}
          {activeItems.length > 0 && (
            <div className="flex items-center gap-3 bg-white p-4 rounded-xl border border-gray-200 shadow-sm mb-4">
              <input
                type="checkbox"
                id="select-all-global"
                checked={isAllSelected}
                onChange={handleToggleSelectAll}
                className="w-5 h-5 rounded border-gray-300 accent-blue-600 focus:ring-blue-500 cursor-pointer"
              />
              <label
                htmlFor="select-all-global"
                className="text-base font-bold text-gray-800 cursor-pointer select-none"
              >
                Select all items ({purchasableItems.length})
              </label>
            </div>
          )}

          {/* Cart Items Grouped by Seller */}
          <div className="space-y-8">
            {Object.keys(groupedItems).length > 0 ? (
              Object.entries(groupedItems).map(([sellerId, group]) => {
                const sellerPurchasableIds = group.items
                  .filter((item) => isItemPurchasable(item))
                  .map((item) => item._id);

                const isSellerAllSelected =
                  sellerPurchasableIds.length > 0 &&
                  sellerPurchasableIds.every((id) =>
                    selectedItemIds.includes(id),
                  );

                return (
                  <div
                    key={sellerId}
                    className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden"
                  >
                    {/* Seller Header */}
                    <div className="flex items-center gap-3 p-4 bg-gray-50/50 border-b border-gray-100">
                      <input
                        type="checkbox"
                        id={`select-seller-${sellerId}`}
                        checked={isSellerAllSelected}
                        onChange={() => handleToggleSellerSelection(sellerId)}
                        disabled={sellerPurchasableIds.length === 0}
                        className="w-5 h-5 rounded border-gray-300 accent-blue-600 focus:ring-blue-500 cursor-pointer disabled:opacity-30"
                      />
                      <label
                        htmlFor={`select-seller-${sellerId}`}
                        className="flex items-center gap-2 font-bold text-gray-900 cursor-pointer select-none"
                      >
                        <Store className="h-4 w-4 text-blue-600" />
                        {group.sellerName}
                      </label>
                    </div>

                    {/* Group Items */}
                    <div className="p-4 space-y-4">
                      {group.items.map((item) => (
                        <CartItem
                          key={item._id}
                          item={item}
                          isSelected={selectedItemIds.includes(item._id)}
                          onToggle={() => handleToggleItem(item._id)}
                        />
                      ))}
                    </div>
                  </div>
                );
              })
            ) : (
              <div className="flex flex-col bg-white p-12 rounded-xl border border-gray-200 shadow-sm text-center items-center gap-2">
                <ShoppingBag className="h-20 w-20 text-gray-200" />
                <p className="text-xl text-gray-500">Your cart is empty</p>
                <Button
                  className="cursor-pointer"
                  onClick={() =>
                    navigate("/products?minPrice=0&maxPrice=10000000")
                  }
                >
                  Browse Product
                </Button>
              </div>
            )}
          </div>

          {/* Saved for Later Section */}
          {savedItems.length > 0 && (
            <div className="mt-8">
              <h2 className="text-2xl font-bold text-gray-900 mb-4">Saved for Later ({savedItems.length})</h2>
              <div className="space-y-4">
                {savedItems.map((item) => (
                  <CartItem
                    key={item._id}
                    item={item}
                    isSelected={false}
                    onToggle={() => {}}
                  />
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="col-span-12 lg:col-span-4 sticky top-5 h-fit">
          <CartSubtotal
            itemCount={selectedCount}
            totalItemPrice={selectedTotalPrice}
            onCheckout={handleCheckout}
            checkoutDisabled={!selectedItemIds.length}
          />
        </div>
      </div>
    </div>
  );
};

export default CartPage;

import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import api from "@/lib/axios";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { AlertCircle, Package, ArrowRight } from "lucide-react";

export default function ComplaintsReturnsPage() {
    const [activeTab, setActiveTab] = useState<"complaints" | "returns">("returns");
    const [returns, setReturns] = useState<any[]>([]);
    const [complaints, setComplaints] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);
        try {
            const [returnsRes, complaintsRes] = await Promise.all([
                api.get("/api/refund/buyer").catch(() => ({ data: { data: [] } })),
                api.get("/api/complaints/my").catch(() => ({ data: { data: [] } }))
            ]);
            
            setReturns(returnsRes.data?.data || []);
            setComplaints(complaintsRes.data?.data || []);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <h1 className="text-2xl font-bold">Returns & Complaints</h1>
            
            {/* Tabs */}
            <div className="flex space-x-2 border-b">
                <button
                    onClick={() => setActiveTab("returns")}
                    className={`px-4 py-2 border-b-2 font-medium text-sm transition-colors ${
                        activeTab === "returns" 
                        ? "border-blue-600 text-blue-600" 
                        : "border-transparent text-gray-500 hover:text-gray-700"
                    }`}
                >
                    Returns & Refunds ({returns.length})
                </button>
                <button
                    onClick={() => setActiveTab("complaints")}
                    className={`px-4 py-2 border-b-2 font-medium text-sm transition-colors ${
                        activeTab === "complaints" 
                        ? "border-blue-600 text-blue-600" 
                        : "border-transparent text-gray-500 hover:text-gray-700"
                    }`}
                >
                    Complaints ({complaints.length})
                </button>
            </div>

            {loading ? (
                <div className="py-12 text-center text-gray-500">Loading...</div>
            ) : (
                <div className="space-y-4">
                    {activeTab === "returns" && (
                        returns.length === 0 ? (
                            <div className="text-center py-12 text-gray-500 border rounded-lg bg-gray-50">
                                <Package className="mx-auto h-8 w-8 mb-2 text-gray-400" />
                                No return requests found.
                            </div>
                        ) : (
                            returns.map((r) => (
                                <Card key={r._id} className="p-5 flex flex-col sm:flex-row gap-4 justify-between hover:shadow-md transition-shadow">
                                    <div className="space-y-2">
                                        <div className="flex items-center gap-3">
                                            <span className="font-semibold text-lg hover:underline cursor-pointer">Order #{r.order?._id?.slice(-8) || "N/A"}</span>
                                            <Badge variant={r.status === "REJECTED" ? "destructive" : r.status === "APPROVED" || r.status === "AUTO_APPROVED" || r.status === "ADMIN_APPROVED" ? "default" : "secondary"} className="uppercase">
                                                {r.status.replace("_", " ")}
                                            </Badge>
                                        </div>
                                        <p className="text-sm text-gray-600">Reason: {r.reason}</p>
                                        <p className="text-xs text-gray-400">Requested on: {new Date(r.requestedAt).toLocaleDateString()}</p>
                                    </div>
                                    <div className="flex items-center sm:items-end">
                                        <Link 
                                            to={`/purchases/${typeof r.order === 'object' ? r.order._id : r.order}/return`}
                                            className="text-blue-600 hover:underline text-sm font-medium flex items-center gap-1"
                                        >
                                            View Details <ArrowRight className="h-4 w-4" />
                                        </Link>
                                    </div>
                                </Card>
                            ))
                        )
                    )}

                    {activeTab === "complaints" && (
                        complaints.length === 0 ? (
                            <div className="text-center py-12 text-gray-500 border rounded-lg bg-gray-50">
                                <AlertCircle className="mx-auto h-8 w-8 mb-2 text-gray-400" />
                                No complaints found.
                            </div>
                        ) : (
                            complaints.map((c) => (
                                <Card key={c.id} className="p-5 flex flex-col sm:flex-row gap-4 justify-between hover:shadow-md transition-shadow">
                                    <div className="space-y-2">
                                        <div className="flex items-center gap-3">
                                            <span className="font-semibold text-lg hover:underline cursor-pointer">Order #{c.orderId?.slice(-8) || "N/A"}</span>
                                            <Badge variant="secondary" className="uppercase">{c.status}</Badge>
                                        </div>
                                        <p className="text-sm text-gray-800 font-medium">Reason: {c.reason}</p>
                                        <p className="text-sm text-gray-600 line-clamp-2">{c.content}</p>
                                        <p className="text-xs text-gray-400">Created on: {c.createdAt}</p>
                                    </div>
                                    <div className="flex items-center sm:items-end">
                                        <Link 
                                            to={c.orderId ? `/purchases/${c.orderId}` : `/my-ebay/activity/purchases`} 
                                            className="text-blue-600 hover:underline text-sm font-medium flex items-center gap-1"
                                        >
                                            View Order <ArrowRight className="h-4 w-4" />
                                        </Link>
                                    </div>
                                </Card>
                            ))
                        )
                    )}
                </div>
            )}
        </div>
    );
}

import { useEffect, useState, useContext } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Alert, AlertDescription } from '@/components/ui/alert';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { Clock, CheckCircle, XCircle, AlertCircle, Star } from 'lucide-react';
import { toast } from 'sonner';
import { getBuyerRequests, respondToRequest, applyRevision } from '@/api/feedbackRevision';
import { formatDateTime } from '@/lib/utils';
import { SocketContext } from '@/hooks/use-socket';

export default function BuyerFeedbackRequestsPage() {
    const [requests, setRequests] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const socketCtx = useContext(SocketContext);

    // Dialog state
    const [selectedRequest, setSelectedRequest] = useState<any>(null);
    const [dialogOpen, setDialogOpen] = useState(false);
    const [responding, setResponding] = useState(false);

    // Edit feedback state
    const [editDialogOpen, setEditDialogOpen] = useState(false);
    const [editingRequestId, setEditingRequestId] = useState<string | null>(null);
    const [newRating, setNewRating] = useState(5);
    const [newComment, setNewComment] = useState('');

    const loadRequests = async () => {
        try {
            const res = await getBuyerRequests();
            setRequests(res.data.data || []);
        } catch (err: any) {
            console.error(err);
            toast.error('Failed to load requests');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadRequests();
    }, []);

    // Listen for realtime feedback_revision_request notification to auto-reload
    useEffect(() => {
        const socket = socketCtx?.socket;
        if (!socket) return;

        const handleNotification = (notif: any) => {
            if (notif.type === 'feedback_revision_request') {
                loadRequests();
                toast.info('You have a new feedback revision request!');
            }
        };

        socket.on('notification', handleNotification);
        return () => {
            socket.off('notification', handleNotification);
        };
    }, [socketCtx?.socket]);


    const handleViewRequest = (request: any) => {
        setSelectedRequest(request);
        setDialogOpen(true);
    };

    const handleAccept = async () => {
        if (!selectedRequest) return;

        setResponding(true);
        try {
            await respondToRequest(selectedRequest._id, {
                responseType: 'accepted',
                message: 'I will revise my feedback'
            });

            toast.success('Request accepted! Please revise your feedback below.');

            // Save the requestId before closing/reloading so edit dialog can use it
            const reqId = selectedRequest._id;
            const currentReview = selectedRequest.review;
            setDialogOpen(false);
            await loadRequests();

            // Open edit dialog with saved state
            setEditingRequestId(reqId);
            setNewRating(currentReview?.rating || 5);
            setNewComment(currentReview?.comment || '');
            setEditDialogOpen(true);
        } catch (err: any) {
            console.error(err);
            toast.error(err.response?.data?.message || 'Failed to accept request');
        } finally {
            setResponding(false);
        }
    };

    const openEditDialog = (request: any) => {
        setEditingRequestId(request._id);
        setNewRating(request.review?.rating || 5);
        setNewComment(request.review?.comment || '');
        setEditDialogOpen(true);
    };

    const handleDecline = async () => {
        if (!selectedRequest) return;

        setResponding(true);
        try {
            await respondToRequest(selectedRequest._id, {
                responseType: 'declined',
                message: 'I decline to revise my feedback'
            });

            toast.success('Request declined');
            setDialogOpen(false);
            loadRequests();
        } catch (err: any) {
            console.error(err);
            toast.error(err.response?.data?.message || 'Failed to decline request');
        } finally {
            setResponding(false);
        }
    };

    const handleSubmitRevision = async () => {
        if (!editingRequestId) return;

        if (newRating < 1 || newRating > 5) {
            toast.error('Rating must be between 1 and 5');
            return;
        }

        try {
            await applyRevision(editingRequestId, {
                rating: newRating,
                comment: newComment
            });

            toast.success('Feedback revised successfully!');
            setEditDialogOpen(false);
            setEditingRequestId(null);
            loadRequests();
        } catch (err: any) {
            console.error(err);
            toast.error(err.response?.data?.message || 'Failed to revise feedback');
        }
    };

    const getStatusBadge = (status: string) => {
        switch (status) {
            case 'pending':
                return <Badge variant="secondary"><Clock className="w-3 h-3 mr-1" />Pending</Badge>;
            case 'accepted':
                return <Badge className="bg-green-500"><CheckCircle className="w-3 h-3 mr-1" />Accepted</Badge>;
            case 'declined':
                return <Badge variant="destructive"><XCircle className="w-3 h-3 mr-1" />Declined</Badge>;
            case 'expired':
                return <Badge variant="outline">Expired</Badge>;
            default:
                return <Badge>{status}</Badge>;
        }
    };

    if (loading) {
        return (
            <div className="p-6 max-w-7xl mx-auto">
                <p className="text-center text-muted-foreground">Loading...</p>
            </div>
        );
    }

    return (
        <div className="p-6 max-w-7xl mx-auto">
            <Card>
                <CardHeader>
                    <CardTitle className="text-2xl font-bold flex items-center gap-2">
                        Feedback Revision Requests
                        <Badge variant="secondary" className="ml-2">
                            {requests.filter(r => r.status === 'pending').length} Pending
                        </Badge>
                    </CardTitle>
                </CardHeader>

                <CardContent>
                    <Alert className="mb-6">
                        <AlertCircle className="h-4 w-4" />
                        <AlertDescription>
                            You are <strong>not required</strong> to revise your feedback.
                            Only do so if the seller has genuinely resolved the issue.
                        </AlertDescription>
                    </Alert>

                    {requests.length === 0 ? (
                        <div className="text-center py-12">
                            <AlertCircle className="w-12 h-12 mx-auto text-muted-foreground mb-4" />
                            <p className="text-muted-foreground">No revision requests</p>
                        </div>
                    ) : (
                        <div className="rounded-lg border">
                            <Table>
                                <TableHeader>
                                    <TableRow className="bg-gray-50/50">
                                        <TableHead>Seller</TableHead>
                                        <TableHead>Reason</TableHead>
                                        <TableHead>Status</TableHead>
                                        <TableHead>Requested</TableHead>
                                        <TableHead>Expires</TableHead>
                                        <TableHead>Actions</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {requests.map((request) => (
                                        <TableRow key={request._id}>
                                            <TableCell>
                                                {request.seller?.username || 'Unknown'}
                                            </TableCell>
                                            <TableCell className="capitalize">
                                                {request.reason?.replace('_', ' ') ?? '-'}
                                            </TableCell>
                                            <TableCell>
                                                {getStatusBadge(request.status)}
                                            </TableCell>
                                            <TableCell className="text-sm text-gray-600">
                                                {formatDateTime(request.createdAt)}
                                            </TableCell>
                                            <TableCell className="text-sm text-gray-600">
                                                {request.expiresAt && new Date(request.expiresAt) > new Date() ? (
                                                    formatDateTime(request.expiresAt)
                                                ) : request.expiresAt ? (
                                                    <span className="text-red-600">Expired</span>
                                                ) : (
                                                    <span className="text-muted-foreground">-</span>
                                                )}
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex gap-2">
                                                    <Button
                                                        variant="outline"
                                                        size="sm"
                                                        onClick={() => handleViewRequest(request)}
                                                    >
                                                        View
                                                    </Button>
                                                    {request.status === 'accepted' && (
                                                        <Button
                                                            size="sm"
                                                            className="bg-yellow-500 hover:bg-yellow-600 text-white"
                                                            onClick={() => openEditDialog(request)}
                                                        >
                                                            <Star className="w-3 h-3 mr-1" />
                                                            Revise
                                                        </Button>
                                                    )}
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        </div>
                    )}
                </CardContent>
            </Card>

            {/* View Request Dialog */}
            <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
                <DialogContent className="max-w-2xl">
                    <DialogHeader>
                        <DialogTitle>Feedback Revision Request</DialogTitle>
                        <DialogDescription>
                            From: {selectedRequest?.seller?.username}
                        </DialogDescription>
                    </DialogHeader>

                    {selectedRequest && (
                        <div className="space-y-4">
                            <div>
                                <Label>Reason</Label>
                                <p className="text-sm capitalize">{selectedRequest.reason?.replace('_', ' ') ?? '-'}</p>
                            </div>

                            <div>
                                <Label>Message from Seller</Label>
                                <p className="text-sm bg-muted p-3 rounded">{selectedRequest.message}</p>
                            </div>

                            {selectedRequest.resolutionType && (
                                <div>
                                    <Label>Resolution</Label>
                                    <p className="text-sm capitalize">{selectedRequest.resolutionType.replace('_', ' ')}</p>
                                    {selectedRequest.resolutionProof && (
                                        <p className="text-xs text-muted-foreground mt-1">{selectedRequest.resolutionProof}</p>
                                    )}
                                </div>
                            )}

                            {selectedRequest.status === 'pending' && (
                                <div className="flex gap-3 pt-4">
                                    <Button
                                        onClick={handleAccept}
                                        disabled={responding}
                                        className="flex-1 bg-green-600 hover:bg-green-700"
                                    >
                                        <CheckCircle className="w-4 h-4 mr-2" />
                                        Accept & Revise Feedback
                                    </Button>
                                    <Button
                                        onClick={handleDecline}
                                        disabled={responding}
                                        variant="outline"
                                        className="flex-1"
                                    >
                                        <XCircle className="w-4 h-4 mr-2" />
                                        Decline
                                    </Button>
                                </div>
                            )}
                        </div>
                    )}
                </DialogContent>
            </Dialog>

            {/* Edit Feedback Dialog */}
            <Dialog open={editDialogOpen} onOpenChange={setEditDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Revise Your Feedback</DialogTitle>
                        <DialogDescription>
                            Update your rating and comment
                        </DialogDescription>
                    </DialogHeader>

                    <div className="space-y-4">
                        <div>
                            <Label>Rating</Label>
                            <div className="flex gap-2 mt-2">
                                {[1, 2, 3, 4, 5].map((rating) => (
                                    <button
                                        key={rating}
                                        onClick={() => setNewRating(rating)}
                                        className={`p-2 ${newRating >= rating ? 'text-yellow-500' : 'text-gray-300'}`}
                                    >
                                        <Star className="w-8 h-8 fill-current" />
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div>
                            <Label>Comment</Label>
                            <Textarea
                                value={newComment}
                                onChange={(e) => setNewComment(e.target.value)}
                                rows={4}
                                placeholder="Update your feedback..."
                            />
                        </div>

                        <Button onClick={handleSubmitRevision} className="w-full">
                            Submit Revised Feedback
                        </Button>
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    );
}

// src/pages/purchases/leave-feedback-page.tsx
import { useEffect, useState, type FormEvent } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import api from "@/lib/axios";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import { Separator } from "@/components/ui/separator";
import { RatingStars } from "@/components/feedback/rating-stars";
import { useAuth } from "@/hooks/use-auth";
import { User as UserIcon, Heart } from "lucide-react";

type OrderItemProduct = {
  _id: string;
  title: string;
  price: number;
  imageUrl?: string;
};

type OrderItem = {
  productId: OrderItemProduct;
  title: string;
  price: number;
  quantity: number;
};

type Order = {
  _id: string;
  seller: {
    _id: string;
    username: string;
  };
  items: OrderItem[];
  createdAt: string;
};

type GetOrderResponse = {
  data: Order | Order[];
};

type ReviewCreated = {
  _id: string;
  order: string;
  product: {
    _id: string;
    title: string;
  };
  reviewer: {
    _id: string;
    username: string;
  };
  seller: {
    _id: string;
    username: string;
  };
  rating: number; // overall
  // 4 detailed seller ratings
  rating1?: number; // Accurate description
  rating2?: number; // Reasonable shipping cost
  rating3?: number; // Shipping speed
  rating4?: number; // Communication (nếu backend có)
  comment: string;
  type?: "positive" | "neutral" | "negative";
  createdAt: string;
  updatedAt: string;
  __v: number;
};

type PostReviewResponse = {
  data: ReviewCreated;
};

type GetProductReviewsResponse = {
  data: ReviewCreated[];
};

export default function LeaveFeedbackPage() {
  const { orderId, productId } = useParams<{
    orderId: string;
    productId: string;
  }>();

  const navigate = useNavigate();
  const { payload } = useAuth();
  const userId = payload?.userId;

  const [order, setOrder] = useState<Order | null>(null);
  const [item, setItem] = useState<OrderItem | null>(null);

  // Overall rating (How did it go?)
  const [ratingType, setRatingType] = useState<
    "positive" | "neutral" | "negative" | null
  >(null);
  const [overallRating, setOverallRating] = useState(0);

  // ===== Detailed seller ratings (4 dòng) =====
  const [accurateDescriptionRating, setAccurateDescriptionRating] = useState(0);
  const [shippingCostRating, setShippingCostRating] = useState(0);
  const [shippingSpeedRating, setShippingSpeedRating] = useState(0);
  const [communicationRating, setCommunicationRating] = useState(0);

  const [comment, setComment] = useState("");

  const [submitting, setSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  const [createdReview, setCreatedReview] = useState<ReviewCreated | null>(
    null,
  );
  const [existingReview, setExistingReview] = useState<ReviewCreated | null>(
    null,
  );

  const [showThankYouPage, setShowThankYouPage] = useState(false);
  const [showSaveSellerModal, setShowSaveSellerModal] = useState(false);

  // ===== LOAD ORDER + ITEM =====
  useEffect(() => {
    const fetchOrder = async () => {
      if (!orderId) return;

      try {
        const res = await api.get<GetOrderResponse>(`/api/orders/${orderId}`);
        // API trả về array — lấy phần tử đầu tiên
        const dataArr = res.data.data;
        const orderData = Array.isArray(dataArr) ? dataArr[0] : dataArr;
        setOrder(orderData);

        const found = orderData?.items?.find(
          (it) => it.productId?._id === productId,
        );
        if (found) setItem(found);
      } catch (error: unknown) {
        console.error("Failed to load order", error);
        setErrorMsg("Cannot load order information.");
      }
    };

    fetchOrder();
  }, [orderId, productId]);

  // ===== CHECK ĐÃ REVIEW CHƯA =====
  useEffect(() => {
    const checkExistingReview = async () => {
      if (!productId || !orderId || !userId) return;

      try {
        const res = await api.get<GetProductReviewsResponse>(
          `/api/reviews/product/${productId}`,
          { params: { page: 1, limit: 100 } },
        );

        const reviews = res.data.data || [];
        const found = reviews.find(
          (r) => r.order === orderId && r.reviewer?._id === userId,
        );

        if (found) {
          setExistingReview(found);
        }
      } catch (error) {
        console.error("Failed to check existing review", error);
      }
    };

    checkExistingReview();
  }, [productId, orderId, userId]);

  const handleSelectType = (type: "positive" | "neutral" | "negative") => {
    setRatingType(type);
    if (type === "positive") setOverallRating(5);
    if (type === "neutral") setOverallRating(3);
    if (type === "negative") setOverallRating(1);
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setErrorMsg(null);
    setCreatedReview(null);

    if (!orderId || !productId) {
      setErrorMsg("Order or product is missing.");
      return;
    }
    if (!ratingType || overallRating === 0) {
      setErrorMsg("Please select Positive, Neutral or Negative.");
      return;
    }
    if (!comment.trim()) {
      setErrorMsg("Please add a comment about your experience.");
      return;
    }

    try {
      setSubmitting(true);

      const res = await api.post<PostReviewResponse>("/api/reviews", {
        orderId,
        productId,
        rating: overallRating,
        comment,
        // map 4 detailed seller ratings sang field backend
        rating1: accurateDescriptionRating,
        rating2: shippingCostRating,
        rating3: shippingSpeedRating,
        rating4: communicationRating,
      });

      setCreatedReview(res.data.data);
      setShowThankYouPage(true);
      setShowSaveSellerModal(true);
    } catch (error: unknown) {
      console.error("Failed to submit review", error);

      if (axios.isAxiosError(error) && error.response) {
        const data = error.response.data as {
          message?: string;
          error?: string;
        };
        setErrorMsg(
          data.message ||
            data.error ||
            "Failed to submit feedback. Please try again.",
        );
      } else {
        setErrorMsg("Failed to submit feedback. Please try again.");
      }
    } finally {
      setSubmitting(false);
    }
  };

  const handleViewProductFeedback = () => {
    if (!productId) return;
    navigate(`/products/${productId}#product-reviews`);
  };

  const handleGoBackToOrders = () => {
    navigate("/my-ebay/activity/purchases");
  };

  const productTitle = item?.productId?.title || item?.title || "Product";
  const finalReview = createdReview || existingReview;
  const canLeaveFeedback = !finalReview;

  const isFormValid =
    !!ratingType && overallRating > 0 && comment.trim().length > 0;

  // ===== THANK YOU PAGE =====
  if (showThankYouPage) {
    return (
      <div className="px-8 py-6">
        <div className="mb-6 rounded-sm bg-emerald-600 px-4 py-2 text-sm font-medium text-white">
          Thank you for your feedback!
        </div>

        <div className="grid gap-6 md:grid-cols-[2fr,1fr]">
          <Card>
            <CardContent className="space-y-3 p-6">
              <h1 className="text-xl font-semibold">Leave feedback</h1>
              <p className="text-sm text-muted-foreground">
                Would you like to leave more feedback?
              </p>
              <p className="text-xs text-muted-foreground">
                Your feedback helps other members buy and sell on our site.
              </p>
              <Button className="mt-2 w-fit" onClick={handleGoBackToOrders}>
                Leave feedback
              </Button>
            </CardContent>
          </Card>

          <Card>
            <CardContent className="space-y-2 p-6 text-sm">
              <div className="font-semibold">Would you like to...</div>
              <button
                type="button"
                className="block text-blue-600 underline"
                onClick={() => navigate("/")}
              >
                Go to My efpt
              </button>
              <button
                type="button"
                className="block text-blue-600 underline"
                onClick={handleViewProductFeedback}
              >
                View feedback profile
              </button>
              <button
                type="button"
                className="block text-blue-600 underline"
                onClick={handleGoBackToOrders}
              >
                Leave more feedback
              </button>
            </CardContent>
          </Card>
        </div>

        {showSaveSellerModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
            <div className="relative w-full max-w-md rounded-2xl bg-white px-8 py-8 text-center shadow-lg">
              {/* nút X góc phải */}
              <button
                type="button"
                className="absolute right-4 top-4 text-xl leading-none text-gray-600 hover:text-black"
                onClick={() => setShowSaveSellerModal(false)}
              >
                ×
              </button>

              {/* tiêu đề + mô tả */}
              <h2 className="mb-2 text-lg font-semibold">
                We&apos;re glad it went well!
              </h2>
              <p className="mb-6 text-sm text-muted-foreground">
                You can save this seller to keep track of their new listings and
                easily buy from them again.
              </p>

              {/* avatar + tên seller */}
              <div className="mb-4 flex flex-col items-center gap-2">
                <div className="flex h-12 w-12 items-center justify-center rounded-full bg-gray-100">
                  <UserIcon className="h-6 w-6 text-gray-400" />
                </div>
                <div className="text-sm font-medium">
                  {order?.seller?.username ?? "seller"}
                </div>
              </div>

              {/* nút Save this seller: pill + icon tim */}
              <Button
                type="button"
                onClick={() => setShowSaveSellerModal(false)}
                className="mb-4 mx-auto flex w-60 items-center justify-center gap-2 rounded-full bg-blue-600 text-sm font-medium text-white hover:bg-blue-700"
              >
                <Heart className="h-4 w-4" />
                <span>Save this seller</span>
              </Button>

              {/* link No, thanks */}
              <button
                type="button"
                className="text-xs text-blue-600 underline"
                onClick={() => setShowSaveSellerModal(false)}
              >
                No, thanks
              </button>
            </div>
          </div>
        )}
      </div>
    );
  }

  // ===== FORM LEAVE FEEDBACK =====
  return (
    <div className="px-8 py-6">
      <h1 className="mb-4 text-2xl font-semibold">Leave feedback</h1>

      <Card>
        <CardContent className="space-y-6 p-6">
          {/* TOP ROW: image + seller + How did it go? */}
          <div className="flex flex-col gap-6 md:flex-row md:items-start md:justify-start">
            {/* LEFT: Product info */}
            <div className="flex gap-4 w-full md:w-auto">
              <div className="h-24 w-24 rounded bg-muted" />
              <div className="space-y-1 text-base">
                <div className="font-semibold">{productTitle}</div>
                <div className="text-sm text-muted-foreground">
                  Sold by{" "}
                  <span className="underline">
                    {order?.seller?.username ?? "seller"}
                  </span>
                </div>
              </div>
            </div>

            {/* RIGHT: How did it go */}
            <div className="w-full md:w-[500px] pl-10">
              <div className="mb-2 text-base font-semibold">
                How did it go?*
              </div>
              <p className="mb-3 text-sm text-muted-foreground">
                Rate your experience
              </p>

              <div className="flex gap-3 w-full">
                {(["positive", "neutral", "negative"] as const).map((type) => (
                  <button
                    key={type}
                    type="button"
                    onClick={() => handleSelectType(type)}
                    className={[
                      "flex-1 rounded-full border cursor-pointer",
                      "py-2 text-base font-medium",
                      "transition-all duration-150",
                      ratingType === type
                        ? "bg-blue-600 text-white border-blue-600"
                        : "bg-white border-gray-300 hover:bg-gray-100",
                    ].join(" ")}
                    style={{
                      height: "42px",
                    }}
                  >
                    {type.charAt(0).toUpperCase() + type.slice(1)}
                  </button>
                ))}
              </div>
            </div>
          </div>

          <Separator />

          {!canLeaveFeedback ? (
            <div className="space-y-4">
              <p className="text-sm text-muted-foreground">
                You already left feedback for this item.
              </p>
              <Button
                type="button"
                variant="outline"
                onClick={handleViewProductFeedback}
                disabled={!productId}
              >
                View your feedback
              </Button>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-10">
              {/* WHAT ELSE WOULD YOU ADD */}
              <div className="grid gap-6 md:grid-cols-[250px_auto]">
                <div>
                  <div className="text-base font-semibold">
                    What else would you add?*
                  </div>
                  <p className="text-sm text-muted-foreground">
                    Help the community with more details.
                  </p>
                </div>

                <div className="w-full">
                  <Textarea
                    rows={5}
                    maxLength={500}
                    className="bg-[#fdfbf2] w-full text-base p-2 rounded-md border"
                    value={comment}
                    onChange={(e) => setComment(e.target.value)}
                  />
                  <div className="mt-1 flex justify-end text-sm text-muted-foreground">
                    {comment.length} / 500
                  </div>
                </div>
              </div>

              {/* DETAILED SELLER RATINGS */}
              <div className="space-y-5">
                <div className="text-lg font-semibold">
                  Detailed seller ratings
                </div>

                <DetailRow
                  label="Accurate description"
                  description="How accurate was the item description?"
                >
                  <RatingStars
                    size={23}
                    value={accurateDescriptionRating}
                    onChange={setAccurateDescriptionRating}
                  />
                </DetailRow>

                <DetailRow
                  label="Reasonable shipping cost"
                  description="Was the shipping cost fair?"
                >
                  <RatingStars
                    size={23}
                    value={shippingCostRating}
                    onChange={setShippingCostRating}
                  />
                </DetailRow>

                <DetailRow
                  label="Shipping speed"
                  description="How quickly did the item arrive?"
                >
                  <RatingStars
                    size={23}
                    value={shippingSpeedRating}
                    onChange={setShippingSpeedRating}
                  />
                </DetailRow>

                <DetailRow
                  label="Communication"
                  description="How was the communication with the seller?"
                >
                  <RatingStars
                    size={23}
                    value={communicationRating}
                    onChange={setCommunicationRating}
                  />
                </DetailRow>
              </div>

              {/* Error */}
              {errorMsg && <p className="text-base text-red-500">{errorMsg}</p>}

              {/* FOOTER BUTTON – left aligned */}
              <div className="border-t pt-6">
                <Button
                  type="submit"
                  disabled={submitting || !isFormValid}
                  className={
                    "px-10 py-3 text-base font-medium rounded-full " +
                    (!isFormValid
                      ? "cursor-not-allowed bg-gray-300 text-gray-500"
                      : "bg-blue-600 text-white hover:bg-blue-700")
                  }
                >
                  {submitting ? "Submitting..." : "Leave feedback"}
                </Button>
              </div>
            </form>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

type DetailRowProps = {
  label: string;
  description?: string;
  children: React.ReactNode;
};

function DetailRow({ label, description, children }: DetailRowProps) {
  return (
    <div className="grid items-center gap-4 md:grid-cols-3">
      <div className="md:col-span-1 space-y-1">
        <div className="text-sm font-medium">{label}</div>
        {description && (
          <div className="text-xs text-muted-foreground">{description}</div>
        )}
      </div>
      <div className="md:col-span-2">
        <div className="flex justify-start md:justify-start">{children}</div>
      </div>
    </div>
  );
}

import { Messages } from "@/components/chat/messages";
import ConversationList from "@/components/chat/conversation-list";
import { Card } from "@/components/ui/card";
import { MessageContext, type Conversation, type Message } from "@/hooks/use-message";
import { useState, useEffect } from "react";
import type { ProductDetail } from "@/pages/product-detail";
import { useSearchParams } from "react-router-dom";
import { useAuth } from "@/hooks/use-auth";

export default function MessagesPage() {
    const [participants, setParticipantsState] = useState<string[]>([]);
    const [conversation, setConversation] = useState<Conversation | undefined>();
    const [messages, setMessages] = useState<Message[] | undefined>();
    const [productRef, setProductRef] = useState<string | undefined>();
    const [product, setProduct] = useState<ProductDetail | undefined>();
    const [searchParams] = useSearchParams();
    const { payload } = useAuth();

    const setParticipants = (newParticipants: string[]) => {
        setParticipantsState(newParticipants);
    };

    // Auto-open conversation when sellerId is in URL params
    useEffect(() => {
        const sellerId = searchParams.get("sellerId");
        if (sellerId && payload?.userId && sellerId !== payload.userId) {
            setParticipantsState([payload.userId, sellerId]);
        }
    }, [searchParams, payload?.userId]);

    return (
        <MessageContext.Provider
            value={{
                participants,
                setParticipants,
                conversation,
                setConversation,
                messages,
                setMessages,
                productRef,
                setProductRef,
                product,
            }}
        >
            <div className="container mx-auto p-6">
                <h1 className="text-3xl font-bold mb-6">Messages</h1>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 min-h-[600px]">
                    {/* Conversation List - Left Sidebar */}
                    <Card className="md:col-span-1 p-4">
                        <h2 className="text-lg font-semibold mb-4">Conversations</h2>
                        <ConversationList />
                    </Card>

                    {/* Messages Panel - Main Content */}
                    <Card className="md:col-span-2">
                        <Messages />
                    </Card>
                </div>
            </div>
        </MessageContext.Provider>
    );
}

import { useState, useEffect } from "react";
import { useNavigate, useParams, useSearchParams } from "react-router-dom";
import api from "@/lib/axios";
import { getOrderDetails } from "@/api/orders";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Textarea } from "@/components/ui/textarea";
import { Input } from "@/components/ui/input";
import { toast } from "sonner";
import { ArrowLeft, ImagePlus, X, AlertCircle } from "lucide-react";

const COMPLAINT_REASONS = [
    { value: "question", label: "I have a question about the item"},
    { value: "late", label: "Late delivery"},
    { value: "return", label: "Issues with return/refund"},
    { value: "fraud", label: "Fraud or scam suspicion"},
    { value: "cancel", label: "Cancellation dispute"},
];

export default function CreateComplaintPage() {
    const navigate = useNavigate();
    const { orderId, productId: routeProductId } = useParams();
    const [searchParams] = useSearchParams();
    const productId = routeProductId || searchParams.get("productId");

    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [order, setOrder] = useState<any>(null);
    const [product, setProduct] = useState<any>(null);

    // Form state
    const [reason, setReason] = useState(searchParams.get("reason") || "");
    const [content, setContent] = useState("");
    const [images, setImages] = useState<File[]>([]);
    const [imagePreviews, setImagePreviews] = useState<string[]>([]);

    useEffect(() => {
        if (orderId) fetchOrderDetails();
        if (productId) fetchProductDetails();
    }, [orderId, productId]);

    const fetchOrderDetails = async () => {
        try {
            setLoading(true);
            if (!orderId) return;
            const res = await getOrderDetails(orderId, { role: "buyer" });
            const orderData = Array.isArray(res.data) 
                ? res.data.find((o: any) => o._id === orderId) || res.data[0] 
                : res.data;
            setOrder(orderData);
        } catch (err: any) {
            toast.error("Failed to load order details");
            navigate("/my-ebay/activity/purchases");
        } finally {
            setLoading(false);
        }
    };

    const fetchProductDetails = async () => {
        try {
            const res = await api.get(`/api/products/${productId}`);
            setProduct(res.data.data || res.data);
        } catch (err) {
            console.error("Failed to fetch product", err);
        }
    };

    const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || []);
        if (images.length + files.length > 3) {
            toast.error("You can upload up to 3 images.");
            return;
        }
        const newImages = [...images, ...files];
        setImages(newImages);
        const newPreviews = files.map((file) => URL.createObjectURL(file));
        setImagePreviews([...imagePreviews, ...newPreviews]);
    };

    const removeImage = (index: number) => {
        const newImages = [...images];
        newImages.splice(index, 1);
        setImages(newImages);

        const newPreviews = [...imagePreviews];
        URL.revokeObjectURL(newPreviews[index]);
        newPreviews.splice(index, 1);
        setImagePreviews(newPreviews);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!reason) return toast.error("Please select a reason");
        if (content.length < 10) return toast.error("Please provide more detail (min 10 chars)");
        if (images.length === 0) return toast.error("Please upload at least one image as evidence");

        try {
            setSubmitting(true);
            
            // 1. Upload images
            const formData = new FormData();
            images.forEach((img) => formData.append("images", img));
            const uploadRes = await api.post("/api/upload/complaint-images", formData, {
                headers: { "Content-Type": "multipart/form-data" },
            });
            const imageUrls = uploadRes.data.urls || [];

            // 2. Create complaint
            await api.post("/api/complaints", {
                orderId,
                sellerId: order.seller?._id,
                reason,
                content,
                attachments: imageUrls.map((url: string) => ({ url }))
            });

            toast.success("Complaint submitted successfully!");
            navigate("/my-ebay/complaints");
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to submit complaint");
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) return <div className="p-8 text-center">Loading...</div>;

    return (
        <div className="mx-auto max-w-2xl py-8 px-4">
            <Button variant="ghost" onClick={() => navigate(-1)} className="mb-4">
                <ArrowLeft className="mr-2 h-4 w-4" /> Back
            </Button>

            <Card>
                <CardHeader>
                    <CardTitle className="text-2xl">Open a Complaint</CardTitle>
                    <div className="mt-2 flex items-center gap-4 p-4 bg-muted/30 rounded-lg">
                        {product?.image || product?.images?.[0] ? (
                            <img src={product.image || product.images[0]} className="h-16 w-16 object-cover rounded shadow-sm border bg-white" />
                        ) : (
                            <div className="h-16 w-16 bg-muted rounded flex items-center justify-center text-[10px] text-muted-foreground uppercase font-bold border">No Image</div>
                        )}
                        <div>
                            <p className="font-bold text-base leading-snug line-clamp-1">{product?.title || "Product Purchase"}</p>
                            <p className="text-xs text-muted-foreground mt-1">
                                Order #{orderId?.slice(-8)} • Seller: <span className="text-blue-600 font-medium">{order?.seller?.username}</span>
                            </p>
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-3">
                            <Label className="font-semibold">Reason for complaint</Label>
                            <RadioGroup value={reason} onValueChange={setReason}>
                                {COMPLAINT_REASONS.map((r) => (
                                    <div key={r.value} className="flex items-center space-x-2">
                                        <RadioGroupItem value={r.value} id={r.value} />
                                        <Label htmlFor={r.value} className="font-normal cursor-pointer">{r.label}</Label>
                                    </div>
                                ))}
                            </RadioGroup>
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="content" className="font-semibold">Details</Label>
                            <Textarea 
                                id="content" 
                                placeholder="Describe the issue in detail..."
                                value={content}
                                onChange={(e) => setContent(e.target.value)}
                                rows={5}
                            />
                        </div>

                        <div className="space-y-4">
                            <Label className="font-semibold">Evidence (1-3 images)</Label>
                            <div className="flex flex-wrap gap-4 mt-2">
                                {imagePreviews.map((preview, idx) => (
                                    <div key={idx} className="relative w-24 h-24 border rounded bg-muted">
                                        <img src={preview} className="object-cover w-full h-full" />
                                        <button type="button" onClick={() => removeImage(idx)} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1"><X className="w-3 h-3" /></button>
                                    </div>
                                ))}
                                {images.length < 3 && (
                                    <label className="w-24 h-24 border-2 border-dashed rounded flex flex-col items-center justify-center cursor-pointer hover:bg-muted/50">
                                        <ImagePlus className="w-6 h-6 text-muted-foreground" />
                                        <span className="text-[10px] mt-1">Add Photo</span>
                                        <Input type="file" accept="image/*" multiple className="hidden" onChange={handleImageChange} />
                                    </label>
                                )}
                            </div>
                        </div>

                        <div className="bg-amber-50 p-4 rounded-lg flex gap-3 text-amber-800 text-sm border border-amber-200">
                            <AlertCircle className="h-5 w-5 shrink-0" />
                            <div>
                                <p className="font-semibold">Rules & Process:</p>
                                <ul className="list-disc list-inside mt-1 space-y-1">
                                    <li>Seller has 48 hours to respond.</li>
                                    <li>If not resolved, you can escalate to Admin.</li>
                                    <li>You can only open 3 complaints per month.</li>
                                </ul>
                            </div>
                        </div>

                        <Button type="submit" className="w-full" disabled={submitting}>
                            {submitting ? "Submitting..." : "Submit Complaint"}
                        </Button>
                    </form>
                </CardContent>
            </Card>
        </div>
    );
}

import { useEffect, useRef } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { motion, useAnimation } from "framer-motion";
import {
  CheckCircle2,
  ShoppingBag,
  Settings2,
  Truck,
  PackageCheck,
  Star,
  ShoppingCart,
  ReceiptText,
  MapPin,
  CreditCard,
} from "lucide-react";
import { Button } from "@/components/ui/button";

type CheckoutSuccessState = {
  orderGroupId?: string;
  orders?: {
    _id: string;
    totalAmount: number;
    subtotalAmount?: number;
    discountAmount?: number;
    status: string;
  }[];
  totalAmount?: number;
  subtotalAmount?: number;
  discountAmount?: number;
  shippingMethod?: string;
  shippingPrice?: number;
  shippingAddress?: {
    fullName: string;
    phone: string;
    country?: string;
    city?: string;
    district?: string;
    ward?: string;
    street?: string;
    detail?: string;
  };
  paymentMethod?: string;
};

function Particle({ x, y, color }: { x: number; y: number; color: string }) {
  return (
    <motion.div
      className="absolute w-2 h-2 rounded-full"
      style={{ left: "50%", top: "20%", backgroundColor: color }}
      initial={{ x: 0, y: 0, opacity: 1, scale: 1 }}
      animate={{ x, y, opacity: 0, scale: 0 }}
      transition={{
        duration: 1.2,
        ease: "easeOut",
        delay: Math.random() * 0.4,
      }}
    />
  );
}

const PARTICLES = Array.from({ length: 24 }, (_, i) => ({
  id: i,
  x: (Math.random() - 0.5) * 300,
  y: -(Math.random() * 250 + 50),
  color: ["#3b82f6", "#60a5fa", "#93c5fd", "#1d4ed8", "#bfdbfe", "#2563eb"][
    i % 6
  ],
}));

const STEPS = [
  { key: "created", label: "Order Placed", Icon: ShoppingBag },
  { key: "packaging", label: "Packaging", Icon: Settings2 },
  { key: "ready_to_ship", label: "Waiting", Icon: PackageCheck },
  { key: "shipping", label: "Shipping", Icon: Truck },
  { key: "delivered", label: "Delivered", Icon: PackageCheck },
  { key: "completed", label: "Completed", Icon: Star },
];

const STATUS_RANK: Record<string, number> = {
  created: 0,
  packaging: 1,
  ready_to_ship: 2,
  shipping: 3,
  delivered: 4,
  completed: 5,
};

const FadeIn = ({
  children,
  delay = 0,
  y = 24,
}: {
  children: React.ReactNode;
  delay?: number;
  y?: number;
}) => (
  <motion.div
    initial={{ opacity: 0, y }}
    animate={{ opacity: 1, y: 0 }}
    transition={{ duration: 0.55, delay, ease: [0.22, 1, 0.36, 1] }}
  >
    {children}
  </motion.div>
);

export default function CheckoutSuccessPage() {
  const navigate = useNavigate();
  const location = useLocation();

  const state = location.state as CheckoutSuccessState | null;

  const orders = state?.orders ?? [];
  const total =
    state?.totalAmount ?? orders.reduce((s, o) => s + o.totalAmount, 0);
  const subtotal = state?.subtotalAmount ?? total;
  const discount = state?.discountAmount ?? 0;
  const shippingPrice = state?.shippingPrice ?? 0;
  const shippingAddress = state?.shippingAddress;
  const shippingMethod = state?.shippingMethod;
  const paymentMethod = state?.paymentMethod ?? "COD";
  const orderGroupId = state?.orderGroupId ?? orders[0]?._id ?? "";

  const overallStatus = (() => {
    if (orders.length === 0) return "packaging";
    let minRank = 4;
    for (const o of orders) {
      const rank = STATUS_RANK[o.status?.toLowerCase()] ?? 0;
      if (rank < minRank) minRank = rank;
    }
    return STEPS[minRank]?.key ?? "packaging";
  })();

  const overallRank = STATUS_RANK[overallStatus] ?? 0;

  const getStepState = (stepKey: string): "done" | "active" | "pending" => {
    const rank = STATUS_RANK[stepKey] ?? 0;
    if (rank < overallRank) return "done";
    if (rank === overallRank) return "active";
    return "pending";
  };

  const shortId = orderGroupId ? orderGroupId.slice(0, 8).toUpperCase() : "—";

  const particleControls = useAnimation();
  const triggered = useRef(false);
  useEffect(() => {
    if (!triggered.current) {
      triggered.current = true;
      particleControls.start("visible");
    }
  }, [particleControls]);

  return (
    <div className="min-h-screen flex items-center justify-center px-4 py-8">
      {/* ─── Confetti (fixed overlay) ─── */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden">
        {PARTICLES.map((p) => (
          <Particle key={p.id} x={p.x} y={p.y} color={p.color} />
        ))}
      </div>

      <motion.div
        className="w-full max-w-2xl"
        initial="hidden"
        animate="visible"
        variants={{
          hidden: {},
          visible: { transition: { staggerChildren: 0.12 } },
        }}
      >
        {/* ─── Checkmark ─── */}
        <FadeIn delay={0.1}>
          <div className="flex justify-center mb-8">
            <div className="relative">
              <motion.div
                className="absolute inset-0 rounded-full"
                initial={{ scale: 0.8, opacity: 0.6 }}
                animate={{ scale: 1.75, opacity: 0 }}
                transition={{
                  duration: 1.4,
                  repeat: Infinity,
                  ease: "easeOut",
                }}
              />
              <motion.div
                className="relative w-24 h-24 rounded-full bg-blue-600 flex items-center justify-center shadow-2xl shadow-blue-200"
                initial={{ scale: 0, rotate: -30 }}
                animate={{ scale: 1, rotate: 0 }}
                transition={{
                  type: "spring",
                  stiffness: 220,
                  damping: 14,
                  delay: 0.15,
                }}
              >
                <motion.div
                  initial={{ opacity: 0, scale: 0.5 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ delay: 0.45, duration: 0.35 }}
                >
                  <CheckCircle2 className="w-14 h-14 text-white stroke-[1.5]" />
                </motion.div>
              </motion.div>
            </div>
          </div>
        </FadeIn>

        {/* ─── Title ─── */}
        <FadeIn delay={0.25}>
          <div className="text-center mb-3">
            <h1 className="text-5xl md:text-6xl font-bold text-blue-900 mb-2">
              Place Order Successfully!
            </h1>
            <p className="text-xl text-blue-400">
              Thank you for shopping with us!
            </p>
          </div>
        </FadeIn>

        {/* ─── MERGED CARD: Info + Progress ─── */}
        <FadeIn delay={0.4} y={20}>
          <div className="bg-white rounded-2xl shadow-lg p-8 mb-6">
            {/* 4-col info row */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              {[
                {
                  icon: <ReceiptText className="w-6 h-6 text-blue-600" />,
                  label: "Order ID",
                  value: `#${shortId}`,
                  mono: true,
                  valueClass: "text-lg font-semibold text-blue-900",
                },
                {
                  icon: (
                    <Settings2 className="w-6 h-6 text-blue-600 animate-spin [animation-duration:4s]" />
                  ),
                  label: "Status",
                  value:
                    overallStatus === "packaging"
                      ? "Packaging"
                      : overallStatus === "created"
                        ? "Order Placed"
                        : overallStatus === "shipping"
                          ? "Shipping"
                          : overallStatus === "delivered"
                            ? "Delivered"
                            : "Completed",
                  mono: false,
                  valueClass: "text-lg font-semibold text-blue-600",
                },
                {
                  icon: <Truck className="w-6 h-6 text-blue-600" />,
                  label: "Delivery",
                  value:
                    shippingMethod === "standard" ? "5-7 days" : "3–4 days",
                  mono: false,
                  valueClass: "text-lg font-semibold text-blue-900",
                },
                {
                  icon: <CreditCard className="w-6 h-6 text-blue-600" />,
                  label: "Payment",
                  value: paymentMethod === "cod" ? "COD" : "Online Payment",
                  mono: false,
                  valueClass: "text-lg font-semibold text-blue-900",
                },
              ].map((card, i) => (
                <motion.div
                  key={card.label}
                  className="flex flex-col items-center text-center"
                  initial={{ opacity: 0, y: 12 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.5 + i * 0.1 }}
                >
                  <div className="w-12 h-12 rounded-full bg-blue-50 flex items-center justify-center mb-3">
                    {card.icon}
                  </div>
                  <p className="text-sm text-muted-foreground mb-1">
                    {card.label}
                  </p>
                  <p
                    className={`${card.valueClass} ${card.mono ? "font-mono" : ""}`}
                  >
                    {card.value}
                  </p>
                </motion.div>
              ))}
            </div>

            {/* Divider */}
            <div className="mt-8 pt-8 border-t border-blue-50">
              <h3 className="font-semibold text-blue-900 mb-6 text-xl">
                Order Progress
              </h3>

              {/* Horizontal step list */}
              <div className="relative flex items-start justify-between font-sans">
                {/* Connector line */}
                <div className="absolute top-[28px] left-8 right-8 h-0.5 bg-blue-100 z-0" />

                {STEPS.map((step, index) => {
                  const stepState = getStepState(step.key);
                  const isDone = stepState === "done";
                  const isActive = stepState === "active";
                  const { Icon } = step;

                  return (
                    <motion.div
                      key={step.key}
                      className="relative z-10 flex flex-col items-center gap-3 flex-1"
                      initial={{ opacity: 0, y: 10 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: 0.6 + index * 0.1 }}
                    >
                      {isDone ? (
                        <div className="h-14 w-14 rounded-full bg-blue-600 border-2 border-blue-600 flex items-center justify-center shadow-md shadow-blue-200">
                          <Icon className="h-6 w-6 text-white" />
                        </div>
                      ) : isActive ? (
                        <motion.div
                          className="h-14 w-14 rounded-full bg-blue-50 border-2 border-blue-500 flex items-center justify-center ring-4 ring-blue-100"
                          animate={{ scale: [1, 1.06, 1] }}
                          transition={{ repeat: Infinity, duration: 1.8 }}
                        >
                          <Icon className="h-6 w-6 text-blue-600" />
                        </motion.div>
                      ) : (
                        <div className="h-14 w-14 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center">
                          <Icon className="h-6 w-6 text-slate-300" />
                        </div>
                      )}
                      <span
                        className={`text-sm font-semibold text-center leading-tight tracking-wide ${
                          isDone
                            ? "text-blue-700"
                            : isActive
                              ? "text-blue-600"
                              : "text-slate-300"
                        }`}
                      >
                        {step.label}
                      </span>
                    </motion.div>
                  );
                })}
              </div>
            </div>
          </div>
        </FadeIn>

        {/* ─── Order Summary ─── */}
        <FadeIn delay={0.65} y={20}>
          <div className="bg-white rounded-2xl shadow-lg p-8 mb-6">
            <h3 className="font-semibold text-blue-900 mb-4 text-xl">
              Order Summary
            </h3>
            <div className="space-y-3 mb-6 pb-6 border-b border-blue-50 text-sm">
              <div className="flex justify-between">
                <span className="text-muted-foreground text-lg">Products</span>
                <span className="text-blue-900 text-lg">
                  ${subtotal.toFixed(2)}
                </span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground text-lg">Shipping</span>
                <span
                  className={
                    shippingPrice > 0
                      ? "text-blue-900 font-medium text-lg"
                      : "text-emerald-600 font-medium text-lg"
                  }
                >
                  {shippingPrice > 0 ? `$${shippingPrice.toFixed(2)}` : "Free"}
                </span>
              </div>
              {discount > 0 && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground text-lg">
                    Discount
                  </span>
                  <span className="text-blue-600 font-medium text-md">
                    −${discount.toFixed(2)}
                  </span>
                </div>
              )}
            </div>
            <div className="flex justify-between text-xl font-bold">
              <span className="text-blue-900">Total</span>
              <span className="text-blue-700 text-2xl font-extrabold">
                ${total.toFixed(2)}
              </span>
            </div>
          </div>
        </FadeIn>

        {/* ─── Shipping Address ─── */}
        {shippingAddress && (
          <FadeIn delay={0.7} y={20}>
            <div className="bg-white rounded-2xl shadow-lg p-8 mb-6">
              <h3 className="font-semibold text-blue-900 mb-4 text-xl flex items-center gap-2">
                <MapPin className="w-5 h-5" />
                Shipping Address
              </h3>
              <div className="bg-blue-50/50 rounded-lg p-4 border border-blue-100">
                <p className="font-bold text-lg text-blue-900">
                  {shippingAddress.fullName}
                </p>
                <p className="text-muted-foreground">{shippingAddress.phone}</p>
                <p className="mt-2 text-blue-800/80 leading-relaxed">
                  {shippingAddress.detail && `${shippingAddress.detail}, `}
                  {shippingAddress.street && `${shippingAddress.street}, `}
                  {shippingAddress.ward && `${shippingAddress.ward}, `}
                  {shippingAddress.district && `${shippingAddress.district}, `}
                  {shippingAddress.city}
                </p>
              </div>
            </div>
          </FadeIn>
        )}

        {/* ─── CTA Buttons ─── */}
        <FadeIn delay={0.8} y={16}>
          <div className="flex flex-col sm:flex-row gap-4 justify-center mb-10">
            <Button
              size="lg"
              className="px-8 rounded-full text-md cursor-pointer cursor-pointer font-semibold bg-blue-600 hover:bg-blue-700 text-white shadow-lg shadow-blue-200"
              onClick={() =>
                navigate(
                  orderGroupId
                    ? `/purchases/${orderGroupId}`
                    : "/my-ebay/activity/purchases",
                )
              }
            >
              <ReceiptText className="w-4 h-4 mr-2" />
              Track Order
            </Button>
            <Button
              size="lg"
              variant="outline"
              className="px-8 rounded-full text-md cursor-pointer cursor-pointer font-semibold border-2 border-blue-200 text-blue-700 hover:bg-blue-50 hover:text-blue-500"
              onClick={() => navigate("/products")}
            >
              <ShoppingCart className="w-4 h-4 mr-2" />
              Continue Shopping
            </Button>
          </div>
        </FadeIn>

        {/* ─── Footer note ─── */}
        <FadeIn delay={0.9}>
          <div className="text-center">
            <p className="text-sm text-muted-foreground">
              Have questions?{" "}
              <button
                className="text-blue-600 hover:underline font-medium"
                onClick={() => navigate("/contact")}
              >
                Contact us
              </button>
            </p>
          </div>
        </FadeIn>
      </motion.div>
    </div>
  );
}

