type CheckoutLocationState = {
  source?: "cart" | "buy_now";
  cartItemIds?: string[];
  items?: {
    productId: string;
    quantity: number;
    selectedVariants?: { name: string; value: string }[];
  }[];
};

const buildPayloadFromState = (
  rawState: CheckoutLocationState | null | undefined,
): CheckoutPreviewPayload => {
  const source = rawState?.source === "buy_now" ? "buy_now" : "cart";

  if (source === "buy_now") {
    return {
      source,
      items: Array.isArray(rawState?.items) ? rawState?.items : [],
    };
  }

  return {
    source,
    cartItemIds: Array.isArray(rawState?.cartItemIds)
      ? rawState?.cartItemIds
      : undefined,
  };
};

export default function CheckoutPage() {
  const location = useLocation();
  const navigate = useNavigate();
  const { refreshCart } = useCart();

  const payload = useMemo(
    () => buildPayloadFromState(location.state as CheckoutLocationState),
    [location.state],
  );

  const [preview, setPreview] = useState<CheckoutPreviewResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [processing, setProcessing] = useState(false);
  const [addresses, setAddresses] = useState<Address[]>([]);
  const [selectedAddressId, setSelectedAddressId] = useState<string>("");

  const [shippingMethod, setShippingMethod] = useState<string>("standard");
  const [paymentMethod, setPaymentMethod] = useState<string>("cod");
  // notes keyed by sellerId for each suborder
  const [sellerNotes, setSellerNotes] = useState<Record<string, string>>({});
  const [globalVoucherInput, setGlobalVoucherInput] = useState("");
  const [globalVoucherCode, setGlobalVoucherCode] = useState("");
  const [sellerVoucherInputs, setSellerVoucherInputs] = useState<
    Record<string, string>
  >({});
  const [sellerVoucherCodes, setSellerVoucherCodes] = useState<
    Record<string, string>
  >({});
  const [globalVoucherOptions, setGlobalVoucherOptions] = useState<Voucher[]>(
    [],
  );
  const [sellerVoucherOptions, setSellerVoucherOptions] = useState<
    Record<string, Voucher[]>
  >({});
  const [loadingVoucherOptions, setLoadingVoucherOptions] = useState(false);

  // Address CRUD state
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isAddressListModalOpen, setIsAddressListModalOpen] = useState(false);
  const [selectedAddressForEdit, setSelectedAddressForEdit] =
    useState<Address | null>(null);
  const [confirmDialogOpen, setConfirmDialogOpen] = useState(false);
  const [confirmDialogAction, setConfirmDialogAction] = useState<
    "setDefault" | "delete" | null
  >(null);
  const [pendingAddressId, setPendingAddressId] = useState<string | null>(null);
  const [isActionLoading, setIsActionLoading] = useState(false);

  const sellerVoucherPayload = useMemo(
    () =>
      Object.entries(sellerVoucherCodes)
        .filter(([, code]) => Boolean(code.trim()))
        .map(([sellerId, code]) => ({
          sellerId,
          code: code.trim().toUpperCase(),
        })),
    [sellerVoucherCodes],
  );

  const checkoutRequestBody = useMemo(
    () => ({
      ...payload,
      globalVoucherCode: globalVoucherCode || undefined,
      sellerVoucherCodes: sellerVoucherPayload,
      sellerNotes,
    }),
    [payload, globalVoucherCode, sellerVoucherPayload, sellerNotes],
  );

  const loadPreview = async () => {
    try {
      // only show the full-screen loading indicator if we don't
      // already have a preview. otherwise the UI will flash/refresh
      // when the user is typing in seller notes.
      if (!preview) {
        setLoading(true);
      }
      const data = await previewCheckout(checkoutRequestBody);
      setPreview(data);
    } catch (error: any) {
      toast.error(error.response?.data?.message || "Failed to load checkout");
      setPreview(null);
    } finally {
      setLoading(false);
    }
  };

  const loadAddresses = async () => {
    try {
      const res = await getAddresses();
      setAddresses(res.data || []);
      const defaultAddr = res.data?.find((a: Address) => a.isDefault);
      if (defaultAddr) setSelectedAddressId(defaultAddr._id);
      else if (res.data?.length > 0) setSelectedAddressId(res.data[0]._id);
    } catch (err) {
      console.error("Failed to load addresses", err);
    }
  };

  const loadVoucherOptions = async (previewData: CheckoutPreviewResponse) => {
    if (!previewData?.groups?.length) {
      setGlobalVoucherOptions([]);
      setSellerVoucherOptions({});
      return;
    }

    try {
      setLoadingVoucherOptions(true);
      const globalPromise = getAvailableVouchers({
        scope: "global",
        subtotal: previewData.totals.subtotalAmount,
      });
      const sellerPromises = previewData.groups.map((group) =>
        getAvailableVouchers({
          scope: "seller",
          sellerId: group.sellerId,
          subtotal: group.subtotalAmount,
        }),
      );

      const [globalRes, ...sellerRes] = await Promise.all([
        globalPromise,
        ...sellerPromises,
      ]);

      const sellerMap: Record<string, Voucher[]> = {};
      previewData.groups.forEach((group, index) => {
        sellerMap[group.sellerId] = sellerRes[index]?.data || [];
      });

      setGlobalVoucherOptions(globalRes.data || []);
      setSellerVoucherOptions(sellerMap);
    } catch {
      setGlobalVoucherOptions([]);
      setSellerVoucherOptions({});
    } finally {
      setLoadingVoucherOptions(false);
    }
  };

  useEffect(() => {
    loadPreview();
  }, [
    payload.source,
    JSON.stringify(payload.cartItemIds || []),
    JSON.stringify(payload.items || []),
    globalVoucherCode,
    JSON.stringify(sellerVoucherPayload),
    JSON.stringify(sellerNotes), // recalc when seller notes change
  ]);

  useEffect(() => {
    loadAddresses();
  }, []);

  useEffect(() => {
    if (!preview) return;
    loadVoucherOptions(preview);
  }, [
    preview?.totals.subtotalAmount,
    JSON.stringify(
      preview?.groups?.map((g) => [g.sellerId, g.subtotalAmount]) || [],
    ),
  ]);

  const shippingCosts: Record<string, number> = {
    standard: 5.0,
    express: 15.0,
  };

  const totalAmount =
    Number(preview?.totals.totalAmount || 0) +
    Number(shippingCosts[shippingMethod] || 0);

  const handleConfirmPayment = async () => {
    if (!preview?.canProceed) return;
    if (!selectedAddressId) {
      toast.error("Please select a shipping address");
      return;
    }

    const selectedAddress = addresses.find((a) => a._id === selectedAddressId);
    if (!selectedAddress) {
      toast.error("Address details not found");
      return;
    }

    try {
      setProcessing(true);
      const requestBody: CheckoutConfirmPayload = {
        ...checkoutRequestBody,
        paymentSimulation: "success",
        shippingAddress: {
          fullName: selectedAddress.fullName,
          phone: selectedAddress.phone,
          country: selectedAddress.country,
          city: selectedAddress.city,
          district: selectedAddress.district,
          ward: selectedAddress.ward,
          street: selectedAddress.street,
          detail: selectedAddress.detail,
        },
        shippingPrice: shippingCosts[shippingMethod] || 0,
        paymentMethod: paymentMethod,
        sellerNotes: sellerNotes,
      };
      const result = await confirmCheckout(requestBody);

      if (
        result.paymentStatus === "processing" ||
        result.paymentStatus === "paid" ||
        result.paymentStatus === "unpaid"
      ) {
        toast.success("Payment successful.");
        await refreshCart();
        navigate("/checkout/success", {
          state: {
            orders: result.orders || [],
            totalAmount: totalAmount || 0,
            subtotalAmount: preview?.totals.subtotalAmount || 0,
            discountAmount: preview?.totals.discountAmount || 0,
            shippingPrice: shippingCosts[shippingMethod] || 0,
            shippingMethod,
            shippingAddress: {
              fullName: selectedAddress.fullName,
              phone: selectedAddress.phone,
              country: selectedAddress.country,
              city: selectedAddress.city,
              district: selectedAddress.district,
              ward: selectedAddress.ward,
              street: selectedAddress.street,
              detail: selectedAddress.detail,
            },
            paymentMethod: paymentMethod,
            orderGroupId: result.orders?.[0]?._id,
          },
        });
      } else {
        toast.error("Payment failed.");
        await refreshCart();
        navigate(result.redirectTo || "/my-ebay/activity/purchases");
      }
    } catch (error: any) {
      const message =
        error.response?.data?.message || "Failed to confirm payment";
      toast.error(message);
      await loadPreview();
    } finally {
      setProcessing(false);
    }
  };

  const handleApplyGlobalVoucher = () => {
    const code = globalVoucherInput.trim().toUpperCase();
    setGlobalVoucherCode(code);
  };

  const handleClearGlobalVoucher = () => {
    setGlobalVoucherInput("");
    setGlobalVoucherCode("");
  };

  const handleSelectGlobalVoucher = (voucher: Voucher) => {
    setGlobalVoucherInput(voucher.code);
    setGlobalVoucherCode(voucher.code);
  };

  const handleApplySellerVoucher = (sellerId: string) => {
    const code = (sellerVoucherInputs[sellerId] || "").trim().toUpperCase();
    setSellerVoucherCodes((prev) => ({ ...prev, [sellerId]: code }));
  };

  const handleClearSellerVoucher = (sellerId: string) => {
    setSellerVoucherInputs((prev) => ({ ...prev, [sellerId]: "" }));
    setSellerVoucherCodes((prev) => {
      const next = { ...prev };
      delete next[sellerId];
      return next;
    });
  };

  const handleSelectSellerVoucher = (sellerId: string, voucher: Voucher) => {
    setSellerVoucherInputs((prev) => ({ ...prev, [sellerId]: voucher.code }));
    setSellerVoucherCodes((prev) => ({ ...prev, [sellerId]: voucher.code }));
  };

  const handleOpenAddAddress = () => {
    setSelectedAddressForEdit(null);
    setIsModalOpen(true);
  };

  const handleOpenEditAddress = (e: React.MouseEvent, addr: Address) => {
    e.stopPropagation();
    setSelectedAddressForEdit(addr);
    setIsModalOpen(true);
  };

  const handleAddressSubmit = async (payload: any) => {
    try {
      if (selectedAddressForEdit) {
        await updateAddress(selectedAddressForEdit._id, payload);
      } else {
        await createAddress(payload);
      }
      await loadAddresses();
      setIsModalOpen(false);
    } catch (error) {
      console.error("Failed to save address", error);
      throw error; // Let AddressForm handle the error toast if it does, or catch here
    }
  };

  const handleConfirmAction = async () => {
    if (!pendingAddressId || !confirmDialogAction) return;
    try {
      setIsActionLoading(true);
      if (confirmDialogAction === "delete") {
        await deleteAddress(pendingAddressId);
        toast.success("Address deleted successfully");
        if (selectedAddressId === pendingAddressId) {
          setSelectedAddressId("");
        }
      } else if (confirmDialogAction === "setDefault") {
        await setDefaultAddress(pendingAddressId);
        toast.success("Default address set successfully");
      }
      await loadAddresses();
      setConfirmDialogOpen(false);
    } catch (error) {
      toast.error(`Failed to ${confirmDialogAction} address`);
    } finally {
      setIsActionLoading(false);
      setPendingAddressId(null);
      setConfirmDialogAction(null);
    }
  };

  const openDeleteConfirm = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setPendingAddressId(id);
    setConfirmDialogAction("delete");
    setConfirmDialogOpen(true);
  };

  const selectedAddress = addresses.find(
    (a: Address) => a._id === selectedAddressId,
  );

  // show a full‑page loader only when we truly have **no** preview yet.
  // subsequent preview requests (triggered by typing seller notes, etc.)
  // will set `loading` but we keep the current UI on screen so the user
  // can continue typing uninterrupted.
  if (loading && !preview) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="text-center text-muted-foreground">
          Loading checkout preview...
        </div>
      </div>
    );
  }

  if (!preview) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="text-center text-muted-foreground">
          Unable to load checkout data.
        </div>
      </div>
    );
  }

  return (
    <div className="mx-auto px-4 py-8">
      <div className="flex items-center justify-between gap-1 mb-8">
        <div className="flex flex-col gap-0">
          <h1 className="text-4xl font-bold">Checkout</h1>
          <p className="text-muted-foreground text-md">Complete your order</p>
        </div>
        <Button
          variant="outline"
          size="default"
          className="w-fit rounded-md cursor-pointer mt-2 p-2 h-fit hover:bg-transparent text-muted-foreground hover:text-foreground"
          onClick={() => navigate("/cart")}
        >
          <ChevronLeft className="h-4 w-4 mr-1" />
          Back to Cart
        </Button>
      </div>

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Left Column: Checkout Details */}
        <div className="flex-1 space-y-6">
          {/* Shipping Address Section */}
          <section className="bg-white rounded-xl border p-6 shadow-sm">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-semibold flex items-center gap-2">
                <MapPin className="h-5 w-5 text-primary" />
                Delivery Address
              </h2>
              {addresses.length > 0 && (
                <Button
                  variant="outline"
                  className="text-primary font-semibold hover:no-underline hover:bg-blue-400/30 hover:text-primary cursor-pointer p-2 rounded-md bg-blue-400/30 border-0 h-auto"
                  onClick={() => setIsAddressListModalOpen(true)}
                >
                  Change
                </Button>
              )}
            </div>

            {selectedAddress ? (
              <div
                className="group relative p-4 rounded-xl border-2 border-primary/20 bg-primary/5 hover:border-primary/40 transition-all cursor-pointer"
                onClick={() => setIsAddressListModalOpen(true)}
              >
                <div className="flex items-start justify-between">
                  <div className="space-y-1">
                    <div className="flex items-center gap-3">
                      <span className="font-bold text-lg text-foreground">
                        {selectedAddress.fullName}
                      </span>
                      <span className="text-muted-foreground">|</span>
                      <span className="text-sm font-medium text-muted-foreground">
                        {selectedAddress.phone}
                      </span>
                      {selectedAddress.isDefault && (
                        <Badge
                          variant="outline"
                          className="bg-primary/10 text-primary border-none text-[10px] px-2 py-0.5"
                        >
                          Default
                        </Badge>
                      )}
                    </div>
                    <p className="text-md text-foreground/80 leading-relaxed">
                      {selectedAddress.detail
                        ? `${selectedAddress.detail}, `
                        : ""}
                      {selectedAddress.street
                        ? `${selectedAddress.street}, `
                        : ""}
                      {selectedAddress.ward ? `${selectedAddress.ward}, ` : ""}
                      {selectedAddress.district
                        ? `${selectedAddress.district}, `
                        : ""}
                      {selectedAddress.city}
                    </p>
                  </div>
                  <ChevronRight className="h-5 w-5 text-muted-foreground group-hover:text-primary transition-colors mt-1" />
                </div>
              </div>
            ) : (
              <div className="text-center py-8 border-2 border-dashed rounded-xl bg-muted/30">
                <p className="text-sm text-muted-foreground mb-4">
                  No address selected for delivery
                </p>
                <Button
                  variant="default"
                  className="bg-[#AAED56] cursor-pointer text-[#324E0F] hover:bg-[#9CD845] border-none font-bold px-6"
                  onClick={handleOpenAddAddress}
                >
                  <Plus className="h-4 w-4 mr-2" />
                  Add New Address
                </Button>
              </div>
            )}
          </section>

          {/* Address Selection Modal */}
          <Dialog
            open={isAddressListModalOpen}
            onOpenChange={setIsAddressListModalOpen}
          >
            <DialogContent className="max-w-2xl max-h-[90vh] overflow-hidden flex flex-col p-0 border-none rounded-2xl shadow-2xl">
              <DialogHeader className="px-6 py-8 border-b bg-white">
                <div className="flex items-center justify-between">
                  <DialogTitle className="text-2xl font-bold">
                    Select Delivery Address
                  </DialogTitle>
                  <Button
                    size="sm"
                    className="bg-[#AAED56] cursor-pointer text-[#324E0F] hover:bg-[#9CD845] border-none font-bold rounded-full px-4 h-9 shadow-sm"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleOpenAddAddress();
                    }}
                  >
                    <Plus className="h-4 w-4 mr-1.5" />
                    New Address
                  </Button>
                </div>
              </DialogHeader>

              <div className="flex-1 overflow-y-auto p-6 scrollbar-thin">
                <RadioGroup
                  value={selectedAddressId}
                  onValueChange={(val) => {
                    setSelectedAddressId(val);
                    setIsAddressListModalOpen(false);
                  }}
                >
                  <div className="grid gap-4">
                    {addresses.map((addr: Address) => (
                      <div
                        key={addr._id}
                        className={cn(
                          "group relative flex flex-col p-5 rounded-2xl border-2 transition-all cursor-pointer",
                          selectedAddressId === addr._id
                            ? "border-primary bg-primary/3 shadow-inner"
                            : "border-border hover:border-primary/30 hover:bg-muted/30",
                        )}
                        onClick={() => {
                          setSelectedAddressId(addr._id);
                          setIsAddressListModalOpen(false);
                        }}
                      >
                        <div className="flex items-start justify-between gap-4">
                          <div className="flex-1 space-y-1.5">
                            <div className="flex items-center gap-2 flex-wrap">
                              <span className="font-bold text-lg text-foreground">
                                {addr.fullName}
                              </span>
                              <span className="text-muted-foreground opacity-50">
                                |
                              </span>
                              <span className="text-sm font-medium text-muted-foreground">
                                {addr.phone}
                              </span>
                              {addr.isDefault && (
                                <Badge
                                  variant="outline"
                                  className="bg-blue-500/10 text-blue-600 border-none text-[10px] font-bold px-2 py-0.5"
                                >
                                  Default
                                </Badge>
                              )}
                            </div>
                            <p className="text-sm text-foreground/70 leading-relaxed font-medium">
                              {addr.detail ? `${addr.detail}, ` : ""}
                              {addr.street ? `${addr.street}, ` : ""}
                              {addr.ward ? `${addr.ward}, ` : ""}
                              {addr.district ? `${addr.district}, ` : ""}
                              {addr.city}
                            </p>
                          </div>

                          <div className="flex items-center gap-1 shrink-0">
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-9 w-9 cursor-pointer rounded-full hover:bg-white hover:shadow-sm text-muted-foreground hover:text-primary transition-all"
                              onClick={(e) => {
                                e.stopPropagation();
                                handleOpenEditAddress(e, addr);
                              }}
                            >
                              <Pencil className="h-4 w-4" />
                            </Button>
                            {!addr.isDefault && (
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-9 w-9 cursor-pointer rounded-full hover:bg-white hover:shadow-sm text-muted-foreground hover:text-destructive transition-all"
                                onClick={(e) => {
                                  e.stopPropagation();
                                  openDeleteConfirm(e, addr._id);
                                }}
                              >
                                <Trash2 className="h-4 w-4" />
                              </Button>
                            )}
                            <div className="ml-2">
                              <RadioGroupItem
                                value={addr._id}
                                className="w-5 h-5 border-2 border-primary/30 text-primary"
                              />
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </RadioGroup>

                {addresses.length === 0 && (
                  <div className="flex flex-col items-center justify-center py-12 text-center space-y-4">
                    <div className="w-16 h-16 bg-muted rounded-full flex items-center justify-center">
                      <MapPin className="h-8 w-8 text-muted-foreground" />
                    </div>
                    <div className="space-y-1">
                      <p className="font-bold text-lg">No addresses found</p>
                      <p className="text-sm text-muted-foreground">
                        Add an address to continue with your checkout
                      </p>
                    </div>
                    <Button
                      className="bg-[#AAED56] text-[#324E0F] hover:bg-[#9CD845] font-bold px-6"
                      onClick={handleOpenAddAddress}
                    >
                      <Plus className="h-4 w-4 mr-2" />
                      Add Address
                    </Button>
                  </div>
                )}
              </div>
            </DialogContent>
          </Dialog>

          {/* Shipping Method Section */}
          <section className="bg-white rounded-xl border p-6 shadow-sm">
            <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
              <Truck className="h-5 w-5 text-primary" />
              Shipping Method
            </h2>
            <RadioGroup
              value={shippingMethod}
              onValueChange={setShippingMethod}
            >
              <div className="grid gap-3">
                <Label
                  className={cn(
                    "flex items-center justify-between p-4 rounded-lg border-2 cursor-pointer transition-all",
                    shippingMethod === "standard"
                      ? "border-primary bg-primary/5"
                      : "border-border hover:border-muted-foreground/30",
                  )}
                >
                  <div className="flex items-center gap-3">
                    <RadioGroupItem value="standard" />
                    <div>
                      <p className="font-semibold text-sm">Standard Shipping</p>
                      <p className="text-xs text-muted-foreground">
                        Estimated delivery 5-7 days
                      </p>
                    </div>
                  </div>
                  <span className="font-semibold text-sm">+$5.00</span>
                </Label>

                <Label
                  className={cn(
                    "flex items-center justify-between p-4 rounded-lg border-2 cursor-pointer transition-all",
                    shippingMethod === "express"
                      ? "border-primary bg-primary/5"
                      : "border-border hover:border-muted-foreground/30",
                  )}
                >
                  <div className="flex items-center gap-3">
                    <RadioGroupItem value="express" />
                    <div>
                      <p className="font-semibold text-sm">Express Shipping</p>
                      <p className="text-xs text-muted-foreground">
                        Estimated delivery 3-4 days
                      </p>
                    </div>
                  </div>
                  <span className="font-semibold text-sm">+$15.00</span>
                </Label>
              </div>
            </RadioGroup>
          </section>

          {/* Payment Method Section */}
          <section className="bg-white rounded-xl border p-6 shadow-sm">
            <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
              <CreditCard className="h-5 w-5 text-primary" />
              Payment Method
            </h2>
            <RadioGroup value={paymentMethod} onValueChange={setPaymentMethod}>
              <div className="grid gap-3 mb-4">
                  <Label
                    className={cn(
                      "flex items-center gap-3 p-4 rounded-lg border-2 cursor-pointer transition-all",
                      paymentMethod === "cod"
                        ? "border-primary bg-primary/5"
                        : "border-border hover:border-muted-foreground/30",
                    )}
                  >
                    <RadioGroupItem value="cod" />
                    <span className="font-semibold text-sm">Cash on Delivery (COD)</span>
                  </Label>
                  <Label
                    className={cn(
                      "flex items-center gap-3 p-4 rounded-lg border-2 cursor-not-allowed transition-all opacity-50",
                      "border-border",
                    )}
                    onClick={(e) => e.preventDefault()}
                  >
                    <RadioGroupItem value="bank" disabled />
                    <span className="font-semibold text-sm">Bank Transfer</span>
                    <span className="ml-auto text-xs font-medium text-muted-foreground bg-muted px-2 py-0.5 rounded-full">Coming Soon</span>
                  </Label>
              </div>
            </RadioGroup>
          </section>

          <section className="bg-white rounded-xl border p-6 shadow-sm space-y-4">
            <h3 className="font-bold text-lg">Global Voucher (Whole Order)</h3>
            <div className="flex gap-2">
              <Input
                placeholder="Enter global voucher code"
                value={globalVoucherInput}
                onChange={(e) =>
                  setGlobalVoucherInput(e.target.value.toUpperCase())
                }
                className="uppercase"
              />
              <Button
                className="cursor-pointer"
                onClick={handleApplyGlobalVoucher}
              >
                Apply
              </Button>
              {globalVoucherCode && (
                <Button
                  variant="outline"
                  className="cursor-pointer"
                  onClick={handleClearGlobalVoucher}
                >
                  Remove
                </Button>
              )}
            </div>
            <select
              value={globalVoucherCode}
              onChange={(e) => {
                const code = e.target.value;
                setGlobalVoucherInput(code);
                setGlobalVoucherCode(code);
              }}
              className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
              disabled={loadingVoucherOptions}
            >
              <option value="">Quick select global voucher</option>
              {globalVoucherOptions.map((voucher) => (
                <option key={voucher._id} value={voucher.code}>
                  {voucher.code} -{" "}
                  {voucher.type === "percentage"
                    ? `${voucher.value}%`
                    : `$${voucher.value}`}
                </option>
              ))}
            </select>
            <div className="space-y-2">
              {globalVoucherOptions.map((voucher) => (
                <VoucherTicket
                  key={voucher._id}
                  voucher={voucher}
                  selected={globalVoucherCode === voucher.code}
                  onSelect={handleSelectGlobalVoucher}
                />
              ))}
              {!globalVoucherOptions.length && (
                <p className="text-xs text-muted-foreground">
                  No global vouchers available.
                </p>
              )}
            </div>
          </section>

          <section className="bg-white rounded-xl border p-6 shadow-sm space-y-5">
            <h3 className="font-bold text-lg">Order Details</h3>
            {preview.groups.map((group: CheckoutGroup) => (
              <div
                key={group.sellerId}
                className="border rounded-xl p-4 space-y-4"
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2 font-semibold">
                    <Store className="h-4 w-4 text-primary" />
                    <span>{group.sellerName || "Seller"}</span>
                  </div>
                  <Badge variant="outline">
                    Subtotal ${group.subtotalAmount.toFixed(2)}
                  </Badge>
                </div>

                <div className="mt-2">
                  <Textarea
                    placeholder="Note for this shop..."
                    value={sellerNotes[group.sellerId] || ""}
                    onChange={(e) =>
                      setSellerNotes((prev) => ({
                        ...prev,
                        [group.sellerId]: e.target.value,
                      }))
                    }
                    className="w-full"
                    rows={2}
                  />
                </div>

                <div className="space-y-2">
                  {group.items.map((item: CheckoutGroupItem) => (
                    <div
                      key={`${group.sellerId}-${item.productId}-${item.cartItemId || ""}`}
                      className="flex flex-col gap-2 p-3 bg-muted/10 rounded-lg border border-muted"
                    >
                      <div className="flex items-center justify-between text-sm">
                        <div>
                          <p className="font-medium">{item.title}</p>
                          {item.selectedVariants &&
                            item.selectedVariants.length > 0 && (
                              <p className="text-xs text-muted-foreground">
                                {item.selectedVariants
                                  .map(
                                    (v: { name: string; value: string }) =>
                                      `${v.name}: ${v.value}`,
                                  )
                                  .join(" • ")}
                              </p>
                            )}
                        </div>
                        <div className="text-right">
                          <p>${item.lineTotal.toFixed(2)}</p>
                          <p className="text-xs text-muted-foreground">
                            x{item.quantity}
                          </p>
                        </div>
                      </div>
                      {/* no per-item note any more */}
                    </div>
                  ))}
                </div>

                <Separator />
                <div className="space-y-3">
                  <Label className="font-semibold">Voucher For This Shop</Label>
                  <div className="flex gap-2">
                    <Input
                      placeholder="Enter shop voucher code"
                      value={sellerVoucherInputs[group.sellerId] || ""}
                      onChange={(e) =>
                        setSellerVoucherInputs((prev) => ({
                          ...prev,
                          [group.sellerId]: e.target.value.toUpperCase(),
                        }))
                      }
                      className="uppercase"
                    />
                    <Button
                      className="cursor-pointer"
                      onClick={() => handleApplySellerVoucher(group.sellerId)}
                    >
                      Apply
                    </Button>
                    {sellerVoucherCodes[group.sellerId] && (
                      <Button
                        variant="outline"
                        className="cursor-pointer"
                        onClick={() => handleClearSellerVoucher(group.sellerId)}
                      >
                        Remove
                      </Button>
                    )}
                  </div>

                  <select
                    value={sellerVoucherCodes[group.sellerId] || ""}
                    onChange={(e) => {
                      const code = e.target.value;
                      setSellerVoucherInputs((prev) => ({
                        ...prev,
                        [group.sellerId]: code,
                      }));
                      setSellerVoucherCodes((prev) => ({
                        ...prev,
                        [group.sellerId]: code,
                      }));
                    }}
                    className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
                    disabled={loadingVoucherOptions}
                  >
                    <option value="">Quick select shop voucher</option>
                    {(sellerVoucherOptions[group.sellerId] || []).map(
                      (voucher) => (
                        <option key={voucher._id} value={voucher.code}>
                          {voucher.code} -{" "}
                          {voucher.type === "percentage"
                            ? `${voucher.value}%`
                            : `$${voucher.value}`}
                        </option>
                      ),
                    )}
                  </select>

                  <div className="space-y-2">
                    {(sellerVoucherOptions[group.sellerId] || []).map(
                      (voucher) => (
                        <VoucherTicket
                          key={voucher._id}
                          voucher={voucher}
                          selected={
                            sellerVoucherCodes[group.sellerId] === voucher.code
                          }
                          onSelect={(v) =>
                            handleSelectSellerVoucher(group.sellerId, v)
                          }
                        />
                      ),
                    )}
                    {!(sellerVoucherOptions[group.sellerId] || []).length && (
                      <p className="text-xs text-muted-foreground">
                        No shop vouchers available for this seller.
                      </p>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </section>
        </div>

        {/* Right Column: Order Summary Sidebar */}
        <div className="w-full lg:w-[400px]">
          <div className="sticky top-8 space-y-6">
            <section className="bg-white rounded-xl border p-6 shadow-sm">
              <h2 className="text-xl font-semibold mb-6">
                Order Summary ({preview.totals.itemCount} items)
              </h2>
              <div className="space-y-6 max-h-[400px] overflow-y-auto pr-2 scrollbar-thin">
                {preview.groups
                  .flatMap((g: CheckoutGroup) => g.items)
                  .map((item: CheckoutGroupItem) => (
                    <div
                      key={`${item.productId}-${item.cartItemId}`}
                      className="flex gap-4"
                    >
                      <div className="w-20 h-20 bg-muted rounded-lg shrink-0 overflow-hidden">
                        <img
                          src={(item as any).image || "/placeholder.png"}
                          alt={item.title}
                          className="w-full h-full object-cover"
                        />
                      </div>
                      <div className="flex-1 flex flex-col justify-between">
                        <div>
                          <div className="flex justify-between items-start">
                            <p className="font-semibold text-sm line-clamp-1">
                              {item.title}
                            </p>
                          </div>
                          {item.selectedVariants &&
                            item.selectedVariants.length > 0 && (
                              <p className="text-[11px] text-muted-foreground uppercase tracking-wider">
                                {item.selectedVariants
                                  .map(
                                    (v: { name: string; value: string }) =>
                                      v.value,
                                  )
                                  .join(" / ")}
                              </p>
                            )}
                        </div>
                        <div className="flex justify-between items-end">
                          <p className="font-bold text-sm">
                            ${item.lineTotal.toFixed(2)}
                          </p>
                        </div>
                      </div>
                    </div>
                  ))}
              </div>

              <div className="mt-6 pt-6 border-t space-y-3">
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Subtotal</span>
                  <span className="font-medium">
                    ${preview.totals.subtotalAmount.toFixed(2)}
                  </span>
                </div>
                <div className="flex justify-between text-sm text-yellow-700">
                  <span>Global Voucher</span>
                  <span>
                    -${(preview.totals.globalDiscountAmount || 0).toFixed(2)}
                  </span>
                </div>
                <div className="flex justify-between text-sm text-blue-700">
                  <span>Shop Vouchers</span>
                  <span>
                    -${(preview.totals.sellerDiscountAmount || 0).toFixed(2)}
                  </span>
                </div>
                <div className="flex justify-between text-sm text-green-600 font-medium">
                  <span>Total Discount</span>
                  <span>
                    -${(preview.totals.discountAmount || 0).toFixed(2)}
                  </span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Shipping Fee</span>
                  <span className="font-medium">
                    ${shippingCosts[shippingMethod].toFixed(2)}
                  </span>
                </div>
                <Separator className="my-4" />
                <div className="flex justify-between items-baseline">
                  <span className="font-bold text-lg">Total</span>
                  <span className="text-2xl font-black text-primary">
                    ${totalAmount.toFixed(2)}
                  </span>
                </div>
              </div>

              {preview.voucherErrors && preview.voucherErrors.length > 0 && (
                <div className="mt-4 rounded-md border border-red-200 bg-red-50 p-3 space-y-1">
                  {preview.voucherErrors.map((error, index) => (
                    <p
                      key={`${error.code}-${index}`}
                      className="text-xs text-red-700"
                    >
                      {error.scope === "seller" && error.sellerName
                        ? `${error.sellerName}: `
                        : ""}
                      {error.code} - {error.message}
                    </p>
                  ))}
                </div>
              )}

              <div className="mt-8 space-y-3">
                <Button
                  size="lg"
                  className="w-full cursor-pointer h-12 text-md font-bold shadow-lg shadow-primary/20"
                  onClick={handleConfirmPayment}
                  disabled={
                    processing || !preview.canProceed || (loading && !!preview)
                  }
                >
                  {processing
                    ? "Processing..."
                    : loading && !!preview
                      ? "Updating…"
                      : "Place Order"}
                </Button>
                <Button
                  variant="outline"
                  size="lg"
                  className="w-full cursor-pointer h-12 text-sm text-muted-foreground"
                  onClick={() => navigate("/cart")}
                >
                  Back to Cart
                </Button>
              </div>
            </section>

            {preview.outOfStockItems.length > 0 && (
              <Card className="border-red-200 bg-red-50/50">
                <CardHeader className="pb-2">
                  <CardTitle className="text-sm text-red-600 flex items-center gap-2">
                    Unavailable Items
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-2">
                  {preview.outOfStockItems.map(
                    (item: CheckoutUnavailableItem, index: number) => (
                      <div key={index} className="text-xs text-red-700">
                        • {item.title}: {item.message}
                      </div>
                    ),
                  )}
                </CardContent>
              </Card>
            )}
          </div>
        </div>
      </div>
      <AddressForm
        open={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        initialData={selectedAddressForEdit}
        onSubmit={handleAddressSubmit}
      />

      <ConfirmDialog
        open={confirmDialogOpen}
        onOpenChange={setConfirmDialogOpen}
        title={
          confirmDialogAction === "delete"
            ? "Delete Address"
            : "Set Default Address"
        }
        description={
          confirmDialogAction === "delete"
            ? "Are you sure you want to delete this address? This action cannot be undone."
            : "Are you sure you want to set this as your default address?"
        }
        confirmText={
          confirmDialogAction === "delete" ? "Delete" : "Set as Default"
        }
        isDangerous={confirmDialogAction === "delete"}
        loading={isActionLoading}
        onConfirm={handleConfirmAction}
      />
    </div>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { createComplaint, getMyComplaints, getMyOrders, type ComplaintPayload } from '@/api/complaint';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Empty,
  EmptyDescription,
  EmptyHeader,
  EmptyTitle,
} from '@/components/ui/empty';
import { Button } from '@/components/ui/button';
import { Link, useNavigate } from 'react-router-dom';
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Textarea } from '@/components/ui/textarea';
import { toast } from 'sonner';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import {
  ArrowRightIcon,
  BadgeDollarSignIcon,
  ChevronRightIcon,
  PackageIcon,
} from 'lucide-react';
import { formatDateTime, formatUsd } from '@/lib/utils';

export default function MyOrdersPage() {
  const [orders, setOrders] = useState<any[]>([]);
  const [complaints, setComplaints] = useState<any[]>([]);
  const [complaintForm, setComplaintForm] = useState<Partial<ComplaintPayload> | null>(null);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    (async () => {
      try {
        const res = await getMyOrders();
        const data = Array.isArray(res?.data) ? (res.data as any[]) : [];
        setOrders(data);
        const complaintsRes = await getMyComplaints();
        const complaintsData = Array.isArray(complaintsRes?.data)
          ? (complaintsRes.data as any[])
          : [];
        setComplaints(complaintsData);
      } catch (err: unknown) {
        console.error(err);
      }
    })();
  }, []);

  const complainedOrderIds = useMemo(() => {
    return new Set((complaints ?? []).map((c: any) => c.orderId));
  }, [complaints]);

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'created':
        return (
          <Badge
            variant='outline'
            className='text-blue-600 border-blue-200 bg-blue-50'
          >
            Created
          </Badge>
        );
      case 'confirmed':
        return (
          <Badge
            variant='outline'
            className='text-indigo-600 border-indigo-200 bg-indigo-50'
          >
            Confirmed
          </Badge>
        );
      case 'shipped':
        return (
          <Badge
            variant='outline'
            className='text-amber-600 border-amber-200 bg-amber-50'
          >
            Shipped
          </Badge>
        );
      case 'delivered':
        return (
          <Badge
            variant='outline'
            className='text-green-600 border-green-200 bg-green-50'
          >
            Delivered
          </Badge>
        );
      case 'cancelled':
        return (
          <Badge
            variant='outline'
            className='text-red-600 border-red-200 bg-red-50'
          >
            Cancelled
          </Badge>
        );
      default:
        return <Badge variant='outline'>{status}</Badge>;
    }
  };

  const openComplaintDialog = (order: any) => {
    setComplaintForm({
      orderId: order._id,
      sellerId: order.seller._id,
      reason: 'question',
      content: '',
    });
    setIsDialogOpen(true);
  };

  const submitComplaint = async () => {
    if (!complaintForm?.content?.trim()) {
      return;
    }
    try {
      await createComplaint(complaintForm as ComplaintPayload);
      setIsDialogOpen(false);
      setComplaintForm(null);
      toast.success('Complaint sent successfully');
      navigate('/my-ebay/complaints');
    } catch (e) {
      toast.error('Failed to send complaint');
      console.error(e);
    }
  };

  if (!orders.length) {
    return (
      <div className='p-4 md:p-6'>
        <Empty className='border'>
          <EmptyHeader>
            <EmptyTitle>No orders yet</EmptyTitle>
            <EmptyDescription>When you place an order, it will appear here.</EmptyDescription>
          </EmptyHeader>
        </Empty>
      </div>
    );
  }

  return (
    <div className='p-4 md:p-6 max-w-7xl mx-auto'>
      <Card>
        <CardHeader className='pb-4'>
          <div className='flex items-center justify-between'>
            <CardTitle className='text-2xl font-bold flex items-center gap-2'>
              <PackageIcon className='w-6 h-6 text-primary' />
              My Orders
              <Badge variant='secondary' className='ml-2'>
                {orders.length}
              </Badge>
            </CardTitle>
            <Link
              to='/complaints'
              className='text-primary hover:text-primary/80 font-medium transition-colors flex items-center gap-1'
            >
              Complaints History
              <ChevronRightIcon className='w-4 h-4' />
            </Link>
          </div>
        </CardHeader>
        <CardContent>
          <div className='rounded-lg border'>
            <Table>
              <TableHeader>
                <TableRow className='bg-gray-50/50'>
                  <TableHead className='font-semibold'>Order</TableHead>
                  <TableHead className='font-semibold'>Seller</TableHead>
                  <TableHead className='font-semibold'>Products</TableHead>
                  <TableHead className='font-semibold text-right'>
                    Total
                  </TableHead>
                  <TableHead className='font-semibold'>Status</TableHead>
                  <TableHead className='font-semibold'>Created</TableHead>
                  <TableHead className='font-semibold'>Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {orders.map((order) => (
                  <TableRow
                    key={order._id}
                    className='hover:bg-gray-50/50 transition-colors'
                  >
                    <TableCell className='font-mono text-sm text-gray-600'>
                      #{order._id.slice(-8)}
                    </TableCell>
                    <TableCell>
                      <div className='flex items-center gap-2'>
                        <div className='w-8 h-8 bg-primary/10 rounded-full flex items-center justify-center'>
                          <span className='text-xs font-medium text-primary'>
                            {order.seller?.username?.charAt(0).toUpperCase() ??
                              'S'}
                          </span>
                        </div>
                        <span className='font-medium'>
                          {order.seller?.username}
                        </span>
                      </div>
                    </TableCell>
                    <TableCell className='max-w-[420px]'>
                      <div
                        className='truncate'
                        title={order.items
                          .map((it: any) => `${it.title} x ${it.quantity}`)
                          .join(', ')}
                      >
                        {order.items
                          .map((it: any) => `${it.title} x ${it.quantity}`)
                          .join(', ')}
                      </div>
                    </TableCell>
                    <TableCell className='text-right'>
                      <div className='inline-flex items-center gap-1'>
                        <BadgeDollarSignIcon className='w-4 h-4 text-emerald-600' />
                        <span className='font-medium'>
                          {formatUsd(order.totalAmount)}
                        </span>
                      </div>
                    </TableCell>
                    <TableCell>{getStatusBadge(order.status)}</TableCell>
                    <TableCell className='text-sm text-gray-600'>
                      {formatDateTime(order.createdAt)}
                    </TableCell>
                    <TableCell>
                      {complainedOrderIds.has(order._id) ? (
                        <Button
                          variant='outline'
                          disabled={complainedOrderIds.has(order._id)}
                          onClick={() => openComplaintDialog(order)}
                        >
                          Complainted
                        </Button>
                      ) : (
                        <Button
                          variant='outline'
                          onClick={() => openComplaintDialog(order)}
                        >
                          Complaint
                        </Button>
                      )}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Create Complaint</DialogTitle>
          </DialogHeader>
          <div className='space-y-3'>
            <div className='space-y-1.5'>
              <div className='text-sm font-medium'>Reason</div>
              <Select
                value={complaintForm?.reason}
                onValueChange={(val) =>
                  setComplaintForm((prev: any) => ({ ...prev, reason: val }))
                }
              >
                <SelectTrigger className='w-full justify-between'>
                  <SelectValue placeholder='Select Reason' />
                </SelectTrigger>
                <SelectContent align='start'>
                  <SelectItem value='question'>Question about order</SelectItem>
                  <SelectItem value='late'>Late Delivery</SelectItem>
                  <SelectItem value='return'>Return / Refund</SelectItem>
                  <SelectItem value='fraud'>Fraud</SelectItem>
                  <SelectItem value='cancel'>Request Cancellation</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className='space-y-1.5'>
              <div className='text-sm font-medium'>Content</div>
              <Textarea
                rows={5}
                placeholder='Describe your problem...'
                value={complaintForm?.content ?? ''}
                onChange={(e) =>
                  setComplaintForm((prev: any) => ({
                    ...prev,
                    content: e.target.value,
                  }))
                }
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant='outline' onClick={() => setIsDialogOpen(false)}>
              Cancel
            </Button>
            <Button
              onClick={submitComplaint}
              disabled={!complaintForm?.content?.trim()}
            >
              Send Complaint
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import { getOrderDetails, cancelOrder, type Order } from "@/api/orders";
import { Separator } from "@/components/ui/separator";
import { toast } from "sonner";
import {
  ChevronLeft,
  ShoppingBag,
  Settings2,
  Truck,
  PackageCheck,
  Star,
  Package,
  CheckCircle2,
  AlertTriangle,
  MessageSquare,
  XCircle,
  Flag,
  ShieldAlert,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import {
  getDisputeByOrder,
  confirmReceived,
  reportNotReceived,
  buyerConfirmAfterDispute,
  buyerReportToAdmin,
  type DeliveryDispute,
} from "@/api/deliveryDispute";
import ShippingTimeline from "@/components/shipping-timeline";

export default function OrderDetailsPage() {
  const { orderId } = useParams<{ orderId: string }>();
  const navigate = useNavigate();
  const [orders, setOrders] = useState<Order[]>([]);
  const [groupTotal, setGroupTotal] = useState<number>(0);
  const [groupSubtotal, setGroupSubtotal] = useState<number>(0);
  const [groupShippingTotal, setGroupShippingTotal] = useState<number>(0);
  const [groupDiscount, setGroupDiscount] = useState<number>(0);
  const [loading, setLoading] = useState(true);
  // Delivery confirmation state (per sub-order)
  const [disputes, setDisputes] = useState<
    Record<string, DeliveryDispute | null>
  >({});
  const [reportNote, setReportNote] = useState<Record<string, string>>({});
  const [showReportForm, setShowReportForm] = useState<Record<string, boolean>>(
    {},
  );
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  // Cancel order dialog state
  const [cancelDialogOpen, setCancelDialogOpen] = useState(false);
  const [subOrderIdToCancel, setSubOrderIdToCancel] = useState<string | null>(
    null,
  );
  const cancelReasons = [
    "changed_mind",
    "ordered_by_mistake",
    "wrong_quantity",
    "found_better_price",
    "payment_issue",
    "delivery_too_long",
    "seller_not_responding",
    "want_change_address",
    "want_change_product",
    "other",
  ];
  const [cancelReason, setCancelReason] = useState<string>("");
  const [cancelOtherText, setCancelOtherText] = useState<string>("");

  const totalAmount = groupSubtotal + groupShippingTotal - groupDiscount;

  useEffect(() => {
    if (!orderId) return;

    const fetchOrderDetails = async () => {
      try {
        setLoading(true);
        const res = await getOrderDetails(orderId, { role: "buyer" });
        setOrders(res.data);

        // Fetch disputes for delivered/completed sub-orders
        const deliveredOrders = res.data.filter(
          (o) => o.status === "delivered" || o.status === "completed",
        );
        const disputeResults = await Promise.allSettled(
          deliveredOrders.map((o) =>
            getDisputeByOrder(o._id).then((r) => ({
              id: o._id,
              dispute: r.data.dispute,
            })),
          ),
        );
        const disputeMap: Record<string, DeliveryDispute | null> = {};
        disputeResults.forEach((r) => {
          if (r.status === "fulfilled") {
            disputeMap[r.value.id] = r.value.dispute;
          }
        });
        setDisputes(disputeMap);

        // Calculate group totals properly
        let subtotal = 0;
        let discountTotal = 0;

        for (const order of res.data) {
          subtotal += order.subtotalAmount || order.totalAmount || 0;
          discountTotal +=
            order.discountAmount || order.voucher?.discountAmount || 0;
        }

        const shippingPrice = res.shippingPrice || 0;
        const totalAmount =
          res.groupTotal || subtotal + shippingPrice - discountTotal;

        setGroupSubtotal(subtotal);
        setGroupShippingTotal(shippingPrice);
        setGroupDiscount(discountTotal);
        setGroupTotal(totalAmount);
      } catch (err) {
        console.error("Failed to fetch order details", err);
        toast.error("Failed to load order details");
      } finally {
        setLoading(false);
      }
    };

    fetchOrderDetails();
  }, [orderId]);

  const handleConfirmReceived = async (subOrderId: string) => {
    setActionLoading(subOrderId + "_confirm");
    try {
      await confirmReceived(subOrderId);
      toast.success("Order confirmed as received! You can now leave a review.");
      setOrders((prev) =>
        prev.map((o) =>
          o._id === subOrderId ? { ...o, status: "completed", paymentStatus: "paid" } : o,
        ),
      );
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to confirm");
    } finally {
      setActionLoading(null);
    }
  };

  const handleReportNotReceived = async (
    subOrderId: string,
    skipToAdmin = false,
  ) => {
    setActionLoading(subOrderId + (skipToAdmin ? "_reportAdmin" : "_report"));
    try {
      const res = await reportNotReceived(
        subOrderId,
        reportNote[subOrderId] || "",
        skipToAdmin,
      );
      toast.info(
        skipToAdmin
          ? "Report sent to admin. We will review and contact you shortly."
          : "Report submitted. The shipper will be notified.",
      );
      setDisputes((prev) => ({ ...prev, [subOrderId]: res.data.dispute }));
      setShowReportForm((prev) => ({ ...prev, [subOrderId]: false }));
    } catch (err: any) {
      const msg = err?.response?.data?.message || "Failed to submit report";
      if (err?.response?.status === 409 && err?.response?.data?.data) {
        setDisputes((prev) => ({
          ...prev,
          [subOrderId]: err.response.data.data,
        }));
      }
      toast.error(msg);
    } finally {
      setActionLoading(null);
    }
  };

  const handleConfirmAfterDispute = async (
    subOrderId: string,
    disputeId: string,
  ) => {
    setActionLoading(subOrderId + "_disputeConfirm");
    try {
      await buyerConfirmAfterDispute(disputeId);
      toast.success("Confirmed! Order is now completed.");
      setOrders((prev) =>
        prev.map((o) =>
          o._id === subOrderId ? { ...o, status: "completed", paymentStatus: "paid" } : o,
        ),
      );
      setDisputes((prev) => ({
        ...prev,
        [subOrderId]: prev[subOrderId]
          ? { ...prev[subOrderId]!, status: "CONFIRMED" }
          : null,
      }));
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to confirm");
    } finally {
      setActionLoading(null);
    }
  };

  const handleReportToAdmin = async (subOrderId: string, disputeId: string) => {
    setActionLoading(subOrderId + "_reportAdmin");
    try {
      await buyerReportToAdmin(disputeId);
      toast.info(
        "Your report has been sent to admin. We will review and contact you shortly.",
      );
      setDisputes((prev) => ({
        ...prev,
        [subOrderId]: prev[subOrderId]
          ? { ...prev[subOrderId]!, status: "REPORTED_TO_ADMIN" }
          : null,
      }));
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to report to admin");
    } finally {
      setActionLoading(null);
    }
  };

  const handleCancelOrder = async () => {
    if (!subOrderIdToCancel) return;
    if (!cancelReason) {
      toast.error("Please select a reason for cancellation");
      return;
    }
    if (cancelReason === "other" && !cancelOtherText.trim()) {
      toast.error("Please provide details for 'Other' reason");
      return;
    }
    setActionLoading(subOrderIdToCancel + "_cancel");
    try {
      const res = await cancelOrder(
        subOrderIdToCancel,
        cancelReason,
        cancelReason === "other" ? cancelOtherText.trim() : undefined,
      );
      toast.success(
        res.data.status === "cancel_requested"
          ? "Cancellation request sent to seller."
          : "Order cancelled successfully.",
      );
      setOrders((prev) =>
        prev.map((o) =>
          o._id === subOrderIdToCancel ? { ...o, status: res.data.status } : o,
        ),
      );
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to cancel order");
    } finally {
      setActionLoading(null);
      setCancelDialogOpen(false);
      setSubOrderIdToCancel(null);
      setCancelReason("");
      setCancelOtherText("");
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <p className="text-muted-foreground">Loading order details...</p>
      </div>
    );
  }

  if (!orders || orders.length === 0) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <p className="text-muted-foreground">Order not found.</p>
      </div>
    );
  }

  // Nếu là group order, lấy thông tin chung từ đơn hàng đầu tiên (vì buyer giống nhau)
  const baseOrder = orders[0];

  const formatDate = (iso: string) =>
    new Date(iso).toLocaleDateString(undefined, {
      year: "numeric",
      month: "long",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      timeZone: "Asia/Ho_Chi_Minh",
    });

  // ─── Status timeline logic ───
  const STATUS_STEPS = [
    { key: "created", label: "Order Placed", Icon: ShoppingBag },
    { key: "packaging", label: "Packaging", Icon: Settings2 },
    { key: "ready_to_ship", label: "Waiting", Icon: Package },
    { key: "shipping", label: "Shipping", Icon: Truck },
    { key: "delivered", label: "Delivered", Icon: PackageCheck },
    { key: "completed", label: "Completed", Icon: Star },
  ] as const;

  type StepKey = (typeof STATUS_STEPS)[number]["key"];

  const STATUS_RANK: Record<string, number> = {
    created: 0,
    cancelled: 0,
    cancel_requested: 1,
    failed: 0,
    packaging: 1,
    ready_to_ship: 2,
    queued: 2,
    pending_acceptance: 2,
    shipping: 3,
    delivered: 4,
    completed: 5,
    waiting_return_shipment: 5,
    return_shipping: 5,
    delivered_to_seller: 5,
    returned: 5,
  };

  const STATUS_DISPLAY_LABELS: Record<string, string> = {
    created: "CREATED",
    packaging: "PACKAGING",
    ready_to_ship: "READY TO SHIP",
    queued: "WAITING",
    pending_acceptance: "FINDING SHIPPER",
    shipping: "SHIPPING",
    delivered: "DELIVERED",
    completed: "COMPLETED",
    cancelled: "CANCELLED",
    returned: "RETURNED",
    failed: "FAILED",
    cancel_requested: "CANCEL REQUESTED",
    waiting_return_shipment: "WAITING RETURN",
    return_shipping: "RETURN SHIPPING",
    delivered_to_seller: "RETURNED TO SELLER",
  };

  const getStepState = (stepKey: StepKey, currentStatus: string): "done" | "active" | "pending" => {
    const currentRank = STATUS_RANK[currentStatus.toLowerCase()] ?? 0;
    const stepRank = STATUS_RANK[stepKey] ?? 0;
    if (stepRank < currentRank) return "done";
    if (stepRank === currentRank) return "active";
    return "pending";
  };

  return (
    <div className="mx-auto px-4 py-8">
      <div className="mb-6 flex items-center justify-between">
        <h1 className="text-3xl font-bold">Order Details</h1>
        <Button
          variant="outline"
          className="flex items-center gap-2 cursor-pointer"
          onClick={() => navigate("/my-ebay/activity/purchases")}
        >
          <ChevronLeft className="h-4 w-4" />
          Back
        </Button>
      </div>

      <div className="bg-white rounded-xl border shadow-sm p-6 space-y-8">

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <p className="text-sm font-semibold text-muted-foreground mb-1">
              ORDER DATE
            </p>
            <p className="font-medium">{formatDate(baseOrder.createdAt)}</p>
          </div>
          <div>
            <p className="text-sm font-semibold text-muted-foreground mb-1">
              TOTAL AMOUNT
            </p>
            <p className="text-2xl font-bold">${totalAmount.toFixed(2)}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div>
            <p className="text-sm font-semibold text-muted-foreground mb-3 tracking-wider">
              SHIPPING ADDRESS
            </p>
            {baseOrder.shippingAddress ? (
              <div className="space-y-1 text-sm bg-muted/20 p-4 rounded-lg border border-border">
                <p className="font-bold text-base">
                  {baseOrder.shippingAddress.fullName}
                </p>
                <p className="text-muted-foreground">
                  {baseOrder.shippingAddress.phone}
                </p>
                <p className="mt-2 text-foreground/80 leading-relaxed">
                  {baseOrder.shippingAddress.detail &&
                    `${baseOrder.shippingAddress.detail}, `}
                  {baseOrder.shippingAddress.street &&
                    `${baseOrder.shippingAddress.street}, `}
                  {baseOrder.shippingAddress.ward &&
                    `${baseOrder.shippingAddress.ward}, `}
                  {baseOrder.shippingAddress.district &&
                    `${baseOrder.shippingAddress.district}, `}
                  {baseOrder.shippingAddress.city}
                </p>
              </div>
            ) : (
              <p className="text-sm text-muted-foreground italic">
                No shipping address provided
              </p>
            )}
          </div>

        </div>

        <Separator />

        <div>
          <p className="text-sm font-semibold text-muted-foreground mb-1">
            BUYER
          </p>
          <div className="flex items-center gap-2">
            <span className="font-medium text-lg">
              {baseOrder.customer?.username}
            </span>
          </div>
          <p className="text-sm text-muted-foreground tracking-tighter mt-1">
            Email: ({baseOrder.customer?.email})
          </p>
        </div>

        <Separator />

        <div className="space-y-6">
          <p className="text-lg font-bold">Sub-orders</p>
          {orders.map((subOrder) => (
            <div key={subOrder._id} className="border rounded-lg p-4 space-y-4">
              <div className="flex items-start justify-between">
                <div>
                  <p className="text-base font-bold text-blue-600 underline cursor-pointer">
                    Seller: {subOrder.seller?.username}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    Shipper:{" "}
                    {subOrder.shipper ? (
                      <span className="font-medium text-foreground">{subOrder.shipper.username}</span>
                    ) : (
                      <span className="italic">Not assigned yet</span>
                    )}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    Order ID: {subOrder._id}
                  </p>
                </div>
                <div className="flex flex-col items-end gap-2">
                  <div className="flex gap-2">
                    <div className="px-3 py-1 rounded-full text-xs font-bold text-blue-700 bg-blue-50 border border-blue-200 uppercase whitespace-nowrap">
                      {subOrder.paymentMethod || "COD"}
                    </div>
                    <div
                      className={`px-3 py-1 rounded-full text-xs font-bold whitespace-nowrap ${
                        subOrder.paymentStatus === "paid"
                          ? "text-emerald-700 bg-emerald-50 border border-emerald-200"
                          : subOrder.paymentStatus === "unpaid"
                            ? "text-amber-700 bg-amber-50 border border-amber-200"
                            : "text-red-700 bg-red-50 border border-red-200"
                      }`}
                    >
                      {subOrder.paymentStatus === "unpaid"
                        ? "UNPAID"
                        : subOrder.paymentStatus === "paid"
                          ? "PAID"
                          : (subOrder.paymentStatus || "UNPAID").toUpperCase()}
                    </div>
                  </div>
                  <div
                    className={`px-4 py-1.5 rounded-full text-sm font-bold border ${
                      subOrder.status.toLowerCase() === "cancelled" ||
                      subOrder.status.toLowerCase() === "failed"
                        ? "text-red-700 bg-red-50 border-red-200"
                        : subOrder.status.toLowerCase() === "cancel_requested"
                          ? "text-amber-700 bg-amber-50 border-amber-200"
                          : subOrder.status.toLowerCase() === "queued"
                            ? "text-orange-700 bg-orange-50 border-orange-200"
                            : [
                                  "waiting_return_shipment",
                                  "return_shipping",
                                  "delivered_to_seller",
                                  "returned",
                                ].includes(subOrder.status.toLowerCase())
                              ? "text-orange-700 bg-orange-50 border-orange-200"
                              : STATUS_RANK[subOrder.status.toLowerCase()] === undefined
                                ? "text-gray-700 bg-gray-50 border-gray-200"
                                : STATUS_RANK[subOrder.status.toLowerCase()] >= 3
                                  ? "text-green-700 bg-green-50 border-green-200"
                                  : STATUS_RANK[subOrder.status.toLowerCase()] >= 2
                                    ? "text-blue-700 bg-blue-50 border-blue-200"
                                    : STATUS_RANK[subOrder.status.toLowerCase()] >= 1
                                      ? "text-cyan-700 bg-cyan-50 border-cyan-200"
                                      : "text-blue-700 bg-blue-50 border-blue-200"
                    }`}
                  >
                    {STATUS_DISPLAY_LABELS[subOrder.status.toLowerCase()] ?? subOrder.status.toUpperCase().replace(/_/g, " ")}
                  </div>
                </div>
              </div>

              {/* ─── Status Timeline per Sub-order ─── */}
              <div className="pt-2 pb-6 border-b">
                {[
                  "waiting_return_shipment",
                  "return_shipping",
                  "delivered_to_seller",
                  "returned",
                ].includes(subOrder.status.toLowerCase()) ? (
                  <div className="flex items-center gap-4 p-4 bg-orange-50 border border-orange-200 rounded-xl">
                    <div className="h-10 w-10 rounded-full bg-orange-100 border-2 border-orange-500 flex items-center justify-center shadow-md shrink-0">
                      <Truck className="h-5 w-5 text-orange-600" />
                    </div>
                    <div>
                      <p className="font-bold text-orange-700 text-sm">
                        {subOrder.status === "returned"
                          ? "Order Returned"
                          : "Return in Progress"}
                      </p>
                      <p className="text-xs text-orange-600 mt-0.5">
                        {subOrder.status === "returned"
                          ? "This order has been returned and refunded."
                          : "This order is currently being returned to the seller."}
                      </p>
                    </div>
                  </div>
                ) : subOrder.status === "cancelled" ||
                  subOrder.status === "failed" ? (
                  <div className="flex items-center gap-4 p-4 bg-red-50 border border-red-200 rounded-xl">
                    <div className="h-10 w-10 rounded-full bg-red-100 border-2 border-red-500 flex items-center justify-center shadow-md shrink-0">
                      <XCircle className="h-5 w-5 text-red-600" />
                    </div>
                    <div>
                      <p className="font-bold text-red-700 text-sm">
                        Order{" "}
                        {subOrder.status === "failed" ? "Failed" : "Cancelled"}
                      </p>
                      <p className="text-xs text-red-500 mt-0.5">
                        {subOrder.status === "failed"
                          ? "This order could not be processed."
                          : "This order was cancelled. Any payment will be refunded."}
                      </p>
                    </div>
                  </div>
                ) : (
                  <div className="relative flex items-start justify-between">
                    <div className="absolute top-[20px] left-6 right-6 h-0.5 bg-border z-0" />
                    {STATUS_STEPS.map((step) => {
                      const state = getStepState(step.key, subOrder.status);
                      const { Icon } = step;
                      return (
                        <div
                          key={step.key}
                          className="relative z-10 flex flex-col items-center gap-2 flex-1"
                        >
                          {state === "done" ? (
                            <div className="h-10 w-10 rounded-full bg-emerald-50 border-2 border-emerald-400 flex items-center justify-center shadow-sm">
                              <Icon className="h-5 w-5 text-emerald-500" />
                            </div>
                          ) : state === "active" ? (
                            <div className="h-10 w-10 rounded-full bg-blue-50 border-2 border-blue-500 flex items-center justify-center shadow-md ring-4 ring-blue-100">
                              <Icon className="h-5 w-5 text-blue-600" />
                            </div>
                          ) : (
                            <div className="h-10 w-10 rounded-full bg-muted border border-border flex items-center justify-center">
                              <Icon className="h-5 w-5 text-muted-foreground/40" />
                            </div>
                          )}
                          <span
                            className={`text-[10px] sm:text-xs font-semibold text-center leading-tight tracking-wide ${
                              state === "done"
                                ? "text-emerald-600"
                                : state === "active"
                                  ? "text-blue-600"
                                  : "text-muted-foreground/50"
                            }`}
                          >
                            {step.label}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>

              {(() => {
                const history = subOrder.statusHistory || [];
                // Find the latest cancel_requested index
                const cancelRequestedIndex = [...history]
                  .reverse()
                  .findIndex((h) => h.status === "cancel_requested");

                let resolutionType: "approve" | "reject" | "direct" | null =
                  null;
                let resolutionNote = "";

                if (cancelRequestedIndex !== -1) {
                  const actualIndex = history.length - 1 - cancelRequestedIndex;
                  const nextEntry = history[actualIndex + 1];
                  if (nextEntry) {
                    if (nextEntry.status === "cancelled") {
                      resolutionType = "approve";
                      resolutionNote = nextEntry.note || "";
                    } else if (nextEntry.status === "packaging") {
                      resolutionType = "reject";
                      resolutionNote = nextEntry.note || "";
                    }
                  }
                }

                // If not a resolution, check for direct cancellation (from 'created')
                if (!resolutionType) {
                  const cancelEntry = history.find(
                    (h) => h.status === "cancelled" && h.note && h.note.trim(),
                  );
                  if (cancelEntry) {
                    resolutionType = "direct";
                    resolutionNote = cancelEntry.note || "";
                  }
                }

                const buyerNote = subOrder.note;

                return (
                  <>
                    {buyerNote && (
                      <div className="mb-4 mt-0 p-3 bg-yellow-50/50 border border-yellow-100 rounded-lg text-sm text-yellow-800 italic">
                        Note: "{buyerNote}"
                      </div>
                    )}
                    {resolutionType && resolutionNote && (
                      <div
                        className={`mb-4 mt-0 p-3 border rounded-lg text-sm italic ${
                          resolutionType === "reject"
                            ? "bg-amber-50/50 border-amber-100 text-amber-800"
                            : resolutionType === "approve"
                              ? "bg-green-50/50 border-green-100 text-green-800"
                              : "bg-red-50/50 border-red-100 text-red-800"
                        }`}
                      >
                        {resolutionType === "approve" ? (
                          <><strong>Approve Note:</strong> "{resolutionNote}"</>
                        ) : resolutionType === "reject" ? (
                          <><strong>Reject Note:</strong> "{resolutionNote}"</>
                        ) : resolutionNote.startsWith("Auto-cancelled:") ? (
                          <><strong>System:</strong> {resolutionNote}</>
                        ) : (
                          <><strong>Buyer cancelled</strong> — Reason: "{resolutionNote}"</>
                        )}
                      </div>
                    )}
                  </>
                );
              })()}

              {/* Lịch sử vận chuyển */}
              {subOrder.statusHistory && subOrder.statusHistory.length > 0 && (
                <ShippingTimeline
                  statusHistory={subOrder.statusHistory}
                  currentStatus={subOrder.status}
                />
              )}

              <div className="space-y-4 mt-4">
                {subOrder.items.map((item, index) => (
                  <div
                    key={`${item.productId?._id}-${index}`}
                    className="flex flex-col gap-2"
                  >
                    <div
                      className="flex flex-col sm:flex-row gap-4 p-4 bg-muted/30 rounded-lg border-2 border-transparent hover:border-border transition-colors cursor-pointer"
                      onClick={() =>
                        navigate(`/products/${item.productId?._id}`)
                      }
                    >
                      <div className="h-24 w-24 bg-muted rounded-md flex items-center justify-center shrink-0 overflow-hidden border">
                        {item.productId?.image ||
                        item.productId?.images?.[0] ? (
                          <img
                            src={
                              item.productId.image || item.productId.images?.[0]
                            }
                            alt={item.title}
                            className="h-full w-full object-cover"
                          />
                        ) : (
                          <span className="text-xs text-muted-foreground">
                            No image
                          </span>
                        )}
                      </div>
                      <div className="flex-1 space-y-1">
                        <p className="font-medium text-lg leading-tight hover:underline">
                          {item.productId?.title || item.title}
                        </p>
                        <p className="text-sm text-muted-foreground">
                          Quantity: {item.quantity}
                        </p>
                        <p className="text-sm font-semibold mt-1">
                          ${item.unitPrice.toFixed(2)} x {item.quantity} = $
                          {(item.unitPrice * item.quantity).toFixed(2)}
                        </p>
                        {item.selectedVariants &&
                          item.selectedVariants.length > 0 && (
                            <div className="flex flex-wrap gap-2 mt-2">
                              {item.selectedVariants.map((v) => (
                                <span
                                  key={`${v.name}-${v.value}`}
                                  className="px-2 py-1 bg-white border rounded text-xs text-muted-foreground"
                                >
                                  <span className="font-medium text-foreground mr-1">
                                    {v.name}:
                                  </span>
                                  {v.value}
                                </span>
                              ))}
                            </div>
                          )}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
              <div className="bg-muted/10 p-4 rounded-lg border mt-4 text-sm space-y-2">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Subtotal</span>
                  <span className="font-medium">
                    $
                    {(subOrder.subtotalAmount ?? subOrder.totalAmount).toFixed(
                      2,
                    )}
                  </span>
                </div>
                {Number(
                  subOrder.discountAmount ?? subOrder.voucher?.discountAmount,
                ) > 0 && (
                  <div className="flex justify-between">
                    <span className="text-muted-foreground">
                      Voucher Discount
                    </span>
                    <span className="text-emerald-600 font-medium">
                      -$
                      {(
                        subOrder.discountAmount ??
                        subOrder.voucher?.discountAmount ??
                        0
                      ).toFixed(2)}
                    </span>
                  </div>
                )}
                {/* Shipping removed from sub-orders as it is now at the group level */}
                <Separator className="my-2" />
                <div className="flex justify-between text-base font-bold">
                  <span>Seller Total</span>
                  <span>${subOrder.totalAmount.toFixed(2)}</span>
                </div>
              </div>

              {/* ─── Delivery Confirmation Actions ─── */}
              <div className="mt-4 flex flex-wrap gap-2">
                {["shipping", "delivered", "completed"].includes(
                  subOrder.status.toLowerCase(),
                ) && (
                  <Button
                    variant="outline"
                    size="sm"
                    className="text-amber-600 border-amber-200 hover:bg-amber-50 hover:text-amber-700 h-9"
                    onClick={() =>
                      navigate(`/purchases/${subOrder._id}/complaint`)
                    }
                  >
                    <ShieldAlert className="h-4 w-4 mr-1.5" />
                    Report an issue / Complaint
                  </Button>
                )}
              </div>

              {subOrder.status === "delivered" &&
                (() => {
                  const dispute = disputes[subOrder._id];

                  // Dispute đã CONFIRMED: hoàn tất
                  if (dispute?.status === "CONFIRMED") {
                    return (
                      <div className="mt-4 p-3 bg-gray-50 border rounded-lg text-sm text-gray-600">
                        You have confirmed receipt of this order.
                      </div>
                    );
                  }

                  // Đã báo cáo admin, admin chưa phản hồi
                  if (
                    dispute?.status === "REPORTED_TO_ADMIN" &&
                    !dispute.adminNotifiedAt
                  ) {
                    return (
                      <div className="mt-4 p-3 bg-purple-50 border border-purple-200 rounded-lg text-sm text-purple-700">
                        <AlertTriangle className="h-4 w-4 inline mr-1" />
                        Your report has been sent to admin. Please wait for
                        their response.
                      </div>
                    );
                  }

                  // Admin đã phản hồi → buyer xác nhận nhận hàng
                  if (
                    dispute?.status === "REPORTED_TO_ADMIN" &&
                    dispute.adminNotifiedAt
                  ) {
                    return (
                      <div className="mt-4 p-4 border border-purple-200 bg-purple-50 rounded-lg space-y-3">
                        <p className="text-sm font-semibold text-purple-800">
                          Admin responded to your report:
                        </p>
                        <p className="text-sm text-purple-700">
                          {dispute.adminNote}
                        </p>
                        <p className="text-xs text-purple-500">
                          {new Date(dispute.adminNotifiedAt).toLocaleString()}
                        </p>
                        <Button
                          size="sm"
                          className="bg-emerald-600 hover:bg-emerald-700 text-white"
                          disabled={!!actionLoading}
                          onClick={() =>
                            handleConfirmAfterDispute(subOrder._id, dispute._id)
                          }
                        >
                          <CheckCircle2 className="h-3.5 w-3.5 mr-1" />
                          {actionLoading === subOrder._id + "_disputeConfirm"
                            ? "..."
                            : "I have received my order"}
                        </Button>
                      </div>
                    );
                  }

                  // Shipper đã phản hồi: buyer xác nhận hoặc report lên admin
                  if (dispute?.status === "SHIPPER_RESPONDED") {
                    return (
                      <div className="mt-4 p-4 border border-blue-200 bg-blue-50 rounded-lg space-y-3">
                        <p className="text-sm font-semibold text-blue-800">
                          Shipper responded to your report:
                        </p>
                        <p className="text-sm text-blue-700">
                          {dispute.shipperNote}
                        </p>
                        {dispute.shipperImages?.length > 0 && (
                          <div className="flex gap-2 flex-wrap">
                            {dispute.shipperImages.map((url, i) => (
                              <img
                                key={i}
                                src={url}
                                alt={`Evidence ${i + 1}`}
                                className="h-20 w-20 object-cover rounded-md border border-blue-200"
                              />
                            ))}
                          </div>
                        )}
                        <p className="text-xs text-blue-600">
                          If you have received your order, confirm below.
                          Otherwise, report to admin for further assistance.
                        </p>
                        <div className="flex gap-2 flex-wrap">
                          <Button
                            size="sm"
                            className="bg-emerald-600 hover:bg-emerald-700 text-white"
                            disabled={!!actionLoading}
                            onClick={() =>
                              handleConfirmAfterDispute(
                                subOrder._id,
                                dispute._id,
                              )
                            }
                          >
                            <CheckCircle2 className="h-3.5 w-3.5 mr-1" />
                            {actionLoading === subOrder._id + "_disputeConfirm"
                              ? "..."
                              : "I received it"}
                          </Button>
                          <Button
                            size="sm"
                            variant="outline"
                            className="border-red-300 text-red-600 hover:bg-red-50"
                            disabled={!!actionLoading}
                            onClick={() =>
                              handleReportToAdmin(subOrder._id, dispute._id)
                            }
                          >
                            <AlertTriangle className="h-3.5 w-3.5 mr-1" />
                            {actionLoading === subOrder._id + "_reportAdmin"
                              ? "..."
                              : "Still not received — Report to Admin"}
                          </Button>
                        </div>
                      </div>
                    );
                  }

                  // Dispute đang chờ shipper phản hồi
                  if (dispute?.status === "PENDING_SHIPPER") {
                    return (
                      <div className="mt-4 p-4 bg-amber-50 border border-amber-200 rounded-lg space-y-3">
                        <p className="text-sm text-amber-700">
                          <MessageSquare className="h-4 w-4 inline mr-1" />
                          Your non-receipt report has been sent to the shipper.
                          Waiting for their response...
                        </p>
                        <Button
                          size="sm"
                          variant="outline"
                          className="border-red-300 text-red-600 hover:bg-red-50"
                          disabled={!!actionLoading}
                          onClick={() =>
                            handleReportToAdmin(subOrder._id, dispute._id)
                          }
                        >
                          <AlertTriangle className="h-3.5 w-3.5 mr-1" />
                          {actionLoading === subOrder._id + "_reportAdmin"
                            ? "..."
                            : "Skip shipper — Report to Admin"}
                        </Button>
                      </div>
                    );
                  }

                  // Chưa có dispute: show Confirm or Report buttons
                  return (
                    <div className="mt-4 space-y-3">
                      <p className="text-sm font-medium text-gray-700">
                        Have you received this order?
                      </p>
                      <div className="flex gap-2 flex-wrap">
                        <Button
                          size="sm"
                          className="bg-emerald-600 hover:bg-emerald-700 text-white"
                          disabled={!!actionLoading}
                          onClick={() => handleConfirmReceived(subOrder._id)}
                        >
                          <CheckCircle2 className="h-3.5 w-3.5 mr-1" />
                          {actionLoading === subOrder._id + "_confirm"
                            ? "..."
                            : "Yes, I received it"}
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          className="border-red-300 text-red-600 hover:bg-red-50"
                          disabled={!!actionLoading}
                          onClick={() =>
                            setShowReportForm((prev) => ({
                              ...prev,
                              [subOrder._id]: !prev[subOrder._id],
                            }))
                          }
                        >
                          <AlertTriangle className="h-3.5 w-3.5 mr-1" />
                          No, I didn't receive it
                        </Button>
                      </div>

                      {showReportForm[subOrder._id] && (
                        <div className="p-4 border border-red-200 bg-red-50 rounded-lg space-y-3">
                          <p className="text-sm font-semibold text-red-700">
                            Describe the issue:
                          </p>
                          <Textarea
                            placeholder="Describe the issue (optional)..."
                            value={reportNote[subOrder._id] || ""}
                            onChange={(e) =>
                              setReportNote((prev) => ({
                                ...prev,
                                [subOrder._id]: e.target.value,
                              }))
                            }
                            rows={2}
                          />
                          <div className="flex gap-2 flex-wrap">
                            <Button
                              size="sm"
                              className="bg-red-600 hover:bg-red-700 text-white"
                              disabled={!!actionLoading}
                              onClick={() =>
                                handleReportNotReceived(subOrder._id, false)
                              }
                            >
                              {actionLoading === subOrder._id + "_report"
                                ? "Submitting..."
                                : "Report to Shipper"}
                            </Button>
                            <Button
                              size="sm"
                              variant="outline"
                              disabled={!!actionLoading}
                              onClick={() =>
                                setShowReportForm((prev) => ({
                                  ...prev,
                                  [subOrder._id]: false,
                                }))
                              }
                            >
                              Cancel
                            </Button>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })()}

              {/* ─── Cancel Order (buyer, early statuses only) ─── */}
              {subOrder.status === "created" && (
                <div className="mt-4">
                  <Button
                    size="sm"
                    variant="outline"
                    className="border-red-300 text-red-600 hover:bg-red-50 hover:text-red-600 cursor-pointer"
                    disabled={!!actionLoading}
                    onClick={() => {
                      setSubOrderIdToCancel(subOrder._id);
                      setCancelReason("");
                      setCancelOtherText("");
                      setCancelDialogOpen(true);
                    }}
                  >
                    <XCircle className="h-3.5 w-3.5 mr-1" />
                    {actionLoading === subOrder._id + "_cancel"
                      ? "Cancelling..."
                      : "Cancel Order"}
                  </Button>
                </div>
              )}

              {subOrder.status === "packaging" && (
                <div className="mt-4">
                  <Button
                    size="sm"
                    variant="outline"
                    className="border-amber-300 text-amber-600 hover:bg-amber-50 hover:text-amber-600 cursor-pointer"
                    disabled={!!actionLoading}
                    onClick={() => {
                      setSubOrderIdToCancel(subOrder._id);
                      setCancelReason("");
                      setCancelOtherText("");
                      setCancelDialogOpen(true);
                    }}
                  >
                    <XCircle className="h-3.5 w-3.5 mr-1" />
                    {actionLoading === subOrder._id + "_cancel"
                      ? "Requesting..."
                      : "Request Cancellation"}
                  </Button>
                </div>
              )}

              {subOrder.status === "cancel_requested" && (
                <div className="mt-4">
                  <Button
                    size="sm"
                    variant="outline"
                    className="border-gray-300 text-gray-500 bg-gray-50"
                    disabled={true}
                  >
                    <XCircle className="h-3.5 w-3.5 mr-1" />
                    Cancellation Pending
                  </Button>
                </div>
              )}

              {/* ─── Post-completion actions ─── */}
              {subOrder.status === "completed" && (
                <div className="mt-4 flex gap-3 flex-wrap">
                  {subOrder.items[0]?.productId?._id && (
                    <Link
                      to={`/purchases/${subOrder._id}/feedback/${subOrder.items[0].productId._id}`}
                      className="inline-flex items-center gap-1.5 text-sm text-blue-600 hover:underline"
                    >
                      <Star className="h-3.5 w-3.5" />
                      Leave a review
                    </Link>
                  )}
                  <Link
                    to={`/purchases/${subOrder._id}/return`}
                    className="inline-flex items-center gap-1.5 text-sm text-orange-600 hover:underline"
                  >
                    Request Return/Refund
                  </Link>
                  {subOrder.seller?._id && (
                    <Link
                      to={`/report?sellerId=${subOrder.seller._id}&orderId=${subOrder._id}`}
                      className="inline-flex items-center gap-1.5 text-sm text-red-500 hover:underline"
                    >
                      <Flag className="h-3.5 w-3.5" />
                      Report Seller
                    </Link>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>

        {/* ─── Global Order Summary ─── */}
        <div className="bg-muted/30 rounded-xl p-6 space-y-3 border-2 border-dashed">
          <p className="text-lg font-bold mb-2">Order Summary</p>
          <div className="flex justify-between text-md">
            <span className="text-muted-foreground">Items Subtotal</span>
            <span>${groupSubtotal.toFixed(2)}</span>
          </div>
          {groupDiscount > 0 && (
            <div className="flex justify-between text-md">
              <span className="text-muted-foreground">Total Discount</span>
              <span className="text-emerald-600 font-medium">
                -${groupDiscount.toFixed(2)}
              </span>
            </div>
          )}
          <div className="flex justify-between text-md">
            <span className="text-muted-foreground">Shipping Fee</span>
            <span>
              {groupShippingTotal > 0
                ? `$${groupShippingTotal.toFixed(2)}`
                : "FREE"}
            </span>
          </div>
          <Separator className="my-2" />
          <div className="flex justify-between text-xl font-bold text-blue-600">
            <span>Order Total</span>
            <span>${groupTotal.toFixed(2)}</span>
          </div>
        </div>
      </div>

      {/* Cancel Order Confirmation Dialog */}
      <AlertDialog open={cancelDialogOpen} onOpenChange={setCancelDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Cancel Order</AlertDialogTitle>
            <AlertDialogDescription>
              Please select a reason for cancelling the order. This action
              cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="mt-2 space-y-2">
            {cancelReasons.map((r) => (
              <label key={r} className="flex items-center gap-2">
                <input
                  type="radio"
                  name="cancelReason"
                  value={r}
                  checked={cancelReason === r}
                  onChange={() => setCancelReason(r)}
                />
                <span className="text-sm capitalize">
                  {r.replace(/_/g, " ")}
                </span>
              </label>
            ))}
            {cancelReason === "other" && (
              <Textarea
                value={cancelOtherText}
                onChange={(e) => setCancelOtherText(e.target.value)}
                placeholder="Please specify the reason"
                rows={3}
              />
            )}
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel
              className="cursor-pointer"
              onClick={() => {
                setCancelDialogOpen(false);
                setSubOrderIdToCancel(null);
                setCancelReason("");
                setCancelOtherText("");
              }}
            >
              Keep Order
            </AlertDialogCancel>
            <AlertDialogAction
              className="bg-red-600 cursor-pointer hover:bg-red-700 text-white"
              onClick={handleCancelOrder}
              disabled={
                actionLoading === subOrderIdToCancel + "_cancel" ||
                !cancelReason
              }
            >
              {actionLoading === subOrderIdToCancel + "_cancel"
                ? "Cancelling..."
                : "Confirm Cancel"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "@/lib/axios";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Separator } from "@/components/ui/separator";
import { Dialog, DialogContent, DialogTitle } from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Messages } from "@/components/chat/messages";
import {
  MessageContext,
  type Conversation,
  type Message,
} from "@/hooks/use-message";
import { useAuth } from "@/hooks/use-auth";
import { toast } from "sonner";
import {} from "lucide-react";
import {
  saveSeller as saveSellerApi,
  unsaveSeller as unsaveSellerApi,
  getSavedSellers,
  hideOrder as hideOrderApi,
  cancelOrder as cancelOrderApi,
} from "@/api/orders";

type OrderItem = {
  productId: {
    _id: string;
    title: string;
    price?: number;
    imageUrl?: string;
  };
  title: string;
  unitPrice: number;
  quantity: number;
  selectedVariants?: { name: string; value: string }[];
};

type Order = {
  _id: string;
  orderGroup?: any; // Replaced with any for flexibility or object { _id, shippingPrice }
  buyer: { _id: string; username: string };
  seller: { _id: string; username: string };
  items: OrderItem[];
  subtotalAmount?: number;
  discountAmount?: number;
  voucher?: {
    code?: string;
    discountAmount?: number;
  } | null;
  totalAmount: number;
  shippingPrice?: number;
  status: string;
  paymentStatus?: string;
  createdAt: string;
};

export default function PurchaseHistoryPage() {
  const [orders, setOrders] = useState<Order[]>([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const [savedSellers, setSavedSellers] = useState<Set<string>>(new Set());
  const [processingActions, setProcessingActions] = useState<Set<string>>(
    new Set(),
  );

  // Cancel order dialog state
  const [cancelDialogOpen, setCancelDialogOpen] = useState(false);
  const [orderIdToCancel, setOrderIdToCancel] = useState<string | null>(null);
  const cancelReasons = [
    "changed_mind",
    "ordered_by_mistake",
    "wrong_quantity",
    "found_better_price",
    "payment_issue",
    "delivery_too_long",
    "seller_not_responding",
    "want_change_address",
    "want_change_product",
    "other",
  ];
  const [cancelReason, setCancelReason] = useState<string>("");
  const [cancelOtherText, setCancelOtherText] = useState<string>("");

  // Pagination states
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [limit] = useState(10);

  // Chat dialog states
  const [chatOpen, setChatOpen] = useState(false);
  const { payload } = useAuth();

  // Message context states
  const [participants, setParticipantsState] = useState<string[]>([]);
  const [conversation, setConversation] = useState<Conversation | undefined>();
  const [messages, setMessages] = useState<Message[] | undefined>();
  const [productRef, setProductRef] = useState<string | undefined>();
  const [productContext, setProductContext] = useState<any>();

  const navigate = useNavigate();

  const fetchOrders = async (p = page, s = search) => {
    try {
      setLoading(true);
      // Fetch orders with pagination and search
      const res = await api.get(
        `/api/orders?role=buyer&page=${p}&limit=${limit}&search=${encodeURIComponent(s)}`,
      );
      const { data: ordersData, pagination } = res.data;

      setOrders(ordersData || []);
      setTotalPages(pagination?.pages || 1);
      setPage(pagination?.page || 1);
    } catch (err) {
      console.error("Failed to load orders", err);
      toast.error("Failed to load orders");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOrders();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page]);

  // Fetch saved sellers
  useEffect(() => {
    const fetchSavedSellers = async () => {
      try {
        const res = await getSavedSellers();
        const sellerIds = new Set(res.data.map((seller) => seller._id));
        setSavedSellers(sellerIds);
      } catch (err) {
        console.error("Failed to load saved sellers", err);
      }
    };

    fetchSavedSellers();
  }, []);

  // Handler: View order details
  const handleViewOrderDetails = (orderId: string) => {
    navigate(`/purchases/${orderId}`);
  };

  // Handler: Save/Unsave seller
  const handleToggleSaveSeller = async (
    sellerId: string,
    sellerName: string,
  ) => {
    const actionKey = `save-${sellerId}`;
    if (processingActions.has(actionKey)) return;

    try {
      setProcessingActions((prev) => new Set(prev).add(actionKey));

      if (savedSellers.has(sellerId)) {
        await unsaveSellerApi(sellerId);
        setSavedSellers((prev) => {
          const newSet = new Set(prev);
          newSet.delete(sellerId);
          return newSet;
        });
        toast.success(`Unsaved seller: ${sellerName}`);
      } else {
        await saveSellerApi(sellerId);
        setSavedSellers((prev) => new Set(prev).add(sellerId));
        toast.success(`Saved seller: ${sellerName}`);
      }
    } catch (err: any) {
      console.error("Failed to save/unsave seller", err);
      toast.error(
        err.response?.data?.message || "Failed to update saved seller",
      );
    } finally {
      setProcessingActions((prev) => {
        const newSet = new Set(prev);
        newSet.delete(actionKey);
        return newSet;
      });
    }
  };

  // Handler: Cancel order
  const handleCancelOrder = async () => {
    if (!orderIdToCancel) return;
    if (!cancelReason) {
      toast.error("Please select a reason for cancellation");
      return;
    }
    if (cancelReason === "other" && !cancelOtherText.trim()) {
      toast.error("Please provide details for 'Other' reason");
      return;
    }
    const actionKey = `cancel-${orderIdToCancel}`;
    if (processingActions.has(actionKey)) return;

    try {
      setProcessingActions((prev) => new Set(prev).add(actionKey));
      await cancelOrderApi(
        orderIdToCancel,
        cancelReason,
        cancelReason === "other" ? cancelOtherText.trim() : undefined,
      );

      // Update local state: mark that order as cancelled
      setOrders((prev) =>
        prev.map((o) =>
          o._id === orderIdToCancel ? { ...o, status: "cancelled" } : o,
        ),
      );

      toast.success("Order cancelled successfully");
    } catch (err: any) {
      console.error("Failed to cancel order", err);
      toast.error(err.response?.data?.message || "Failed to cancel order");
    } finally {
      setProcessingActions((prev) => {
        const newSet = new Set(prev);
        newSet.delete(actionKey);
        return newSet;
      });
      setCancelDialogOpen(false);
      setOrderIdToCancel(null);
      setCancelReason("");
      setCancelOtherText("");
    }
  };

  // Handler: Hide order
  const handleHideOrder = async (orderId: string) => {
    const actionKey = `hide-${orderId}`;
    if (processingActions.has(actionKey)) return;

    try {
      setProcessingActions((prev) => new Set(prev).add(actionKey));
      await hideOrderApi(orderId);

      // Remove order from UI
      setOrders((prev) => prev.filter((order) => order._id !== orderId));

      toast.success("Order hidden from list", {
        action: {
          label: "Undo",
          onClick: () => {
            // Refresh to restore
            window.location.reload();
          },
        },
      });
    } catch (err: any) {
      console.error("Failed to hide order", err);
      toast.error(err.response?.data?.message || "Failed to hide order");
    } finally {
      setProcessingActions((prev) => {
        const newSet = new Set(prev);
        newSet.delete(actionKey);
        return newSet;
      });
    }
  };

  // Handler: Open chat with seller
  const handleContactSeller = (sellerId: string, productId: string) => {
    const sender = payload?.userId;
    if (!sender) {
      toast.error("Please sign in to chat with the seller");
      return;
    }

    // Find product from orders
    const product = orders
      .flatMap((o) => o.items)
      .find((item) => item.productId?._id === productId);

    setParticipantsState([sender, sellerId]);
    setProductRef(productId);
    setProductContext(product?.productId);
    setChatOpen(true);
  };

  const handleSearch = () => {
    setPage(1);
    fetchOrders(1, search);
  };

  const [expandedSessions, setExpandedSessions] = useState<Set<string>>(
    new Set(),
  );

  // Toggle session expansion
  const toggleSessionExpansion = (sessionId: string) => {
    setExpandedSessions((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(sessionId)) {
        newSet.delete(sessionId);
      } else {
        newSet.add(sessionId);
      }
      return newSet;
    });
  };

  // Grouping logic: Group orders by orderGroup
  const sessionGroups = useMemo(() => {
    const groups: Record<string, { orders: Order[]; createdAt: string }> = {};

    orders.forEach((order) => {
      const sessionId =
        typeof order.orderGroup === "object" && order.orderGroup?._id
          ? order.orderGroup._id
          : order.orderGroup || order._id;
      if (!groups[sessionId]) {
        groups[sessionId] = {
          orders: [],
          createdAt: order.createdAt,
        };
      }
      groups[sessionId].orders.push(order);
      // Use the earliest createdAt for the session
      if (new Date(order.createdAt) < new Date(groups[sessionId].createdAt)) {
        groups[sessionId].createdAt = order.createdAt;
      }
    });

    return Object.entries(groups)
      .map(([sessionId, data]) => ({
        sessionId,
        ...data,
      }))
      .sort(
        (a, b) =>
          new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
      );
  }, [orders]);

  const filteredGroups = sessionGroups;

  const formatDate = (iso: string) =>
    new Date(iso).toLocaleDateString(undefined, {
      year: "numeric",
      month: "short",
      day: "numeric",
      timeZone: "Asia/Ho_Chi_Minh",
    });

  const shortOrderNumber = (id: string) =>
    id.length > 10 ? id.slice(0, 2) + "-" + id.slice(-8) : id;

  const getStatusMeta = (status: string) => {
    const normalized = String(status || "").toLowerCase();

    if (normalized === "created") {
      return {
        label: "Placed",
        note: "Order has been placed successfully.",
        dotClass: "bg-blue-500",
        textClass: "text-blue-700",
      };
    }
    if (normalized === "packaging") {
      return {
        label: "Packaging",
        note: "Seller is preparing your order.",
        dotClass: "bg-cyan-500",
        textClass: "text-cyan-700",
      };
    }
    if (normalized === "ready_to_ship" || normalized === "queued" || normalized === "pending_acceptance") {
      return {
        label: "Processing",
        note: "Your order is being arranged for delivery.",
        dotClass: "bg-yellow-500",
        textClass: "text-yellow-700",
      };
    }
    if (normalized === "shipping") {
      return {
        label: "Shipping",
        note: "This order is on the way.",
        dotClass: "bg-amber-500",
        textClass: "text-amber-700",
      };
    }
    if (normalized === "delivered") {
      return {
        label: "Delivered",
        note: "This item has been delivered.",
        dotClass: "bg-emerald-500",
        textClass: "text-emerald-700",
      };
    }
    if (normalized === "completed") {
      return {
        label: "Completed",
        note: "Transaction completed.",
        dotClass: "bg-emerald-600",
        textClass: "text-emerald-800",
      };
    }
    if (normalized === "cancelled") {
      return {
        label: "Cancelled",
        note: "This order was cancelled.",
        dotClass: "bg-red-500",
        textClass: "text-red-700",
      };
    }
    if (normalized === "failed") {
      return {
        label: "Failed",
        note: "Payment or order failed.",
        dotClass: "bg-red-600",
        textClass: "text-red-800",
      };
    }
    if (normalized === "returned") {
      return {
        label: "Returned",
        note: "Items were returned.",
        dotClass: "bg-purple-500",
        textClass: "text-purple-700",
      };
    }

    if (["in_transit", "delivery_queued", "pending_delivery_acceptance", "delivering"].includes(normalized)) {
      return {
        label: "On the Way",
        note: "Your order is on its way to you.",
        dotClass: "bg-amber-500",
        textClass: "text-amber-700",
      };
    }
    return {
      label: "Processing",
      note: "Your order is being processed.",
      dotClass: "bg-gray-500",
      textClass: "text-gray-700",
    };
  };

  return (
    <>
      <div className="mb-4 flex items-center justify-between">
        <h1 className="text-2xl font-semibold">Orders</h1>
        <div className="flex items-center gap-2">
          <Input
            placeholder="Search your orders"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSearch()}
            className="w-64"
          />
          <Button variant="default" onClick={handleSearch}>
            Search
          </Button>
        </div>
      </div>

      <div className="mb-4 flex flex-wrap items-center gap-6 text-xs text-muted-foreground">
        <div>
          See orders from: <button className="underline">Last 60 days</button>
        </div>
        <div>
          Filter by: <button className="underline">All</button>
        </div>
      </div>

      <Separator className="mb-4" />

      {loading ? (
        <p className="text-sm text-muted-foreground">Loading your orders...</p>
      ) : filteredGroups.length === 0 ? (
        <p className="text-sm text-muted-foreground">
          You don&apos;t have any purchases yet.
        </p>
      ) : (
        <div className="space-y-4">
          {filteredGroups.map((group) => {
            const isExpanded = expandedSessions.has(group.sessionId);

            const groupShippingPrice =
              group.orders.find(
                (o) =>
                  typeof o.orderGroup === "object" &&
                  o.orderGroup?.shippingPrice !== undefined,
              )?.orderGroup?.shippingPrice || 0;

            const sessionTotalAmount =
              group.orders.reduce((sum, o) => sum + (o.totalAmount || 0), 0) +
              groupShippingPrice;
            const sessionDiscountAmount = group.orders.reduce(
              (sum, o) =>
                sum + (o.discountAmount || o.voucher?.discountAmount || 0),
              0,
            );
            const uniqueSellers = Array.from(
              new Set(group.orders.map((o) => o.seller?.username)),
            ).filter(Boolean);
            const productNames = Array.from(
              new Set(
                group.orders.flatMap((o) =>
                  o.items.map((item) => item.productId?.title || item.title)
                )
              )
            ).filter(Boolean);

            return (
              <Card key={group.sessionId} className="overflow-hidden">
                <CardContent className="p-0">
                  <div
                    className="grid grid-cols-[1.2fr_1fr_1.2fr_1fr_0.8fr] gap-6 p-4 cursor-pointer transition-colors"
                    onClick={() => toggleSessionExpansion(group.sessionId)}
                  >
                    <div className="space-y-1">
                      <div className="text-[11px] font-semibold uppercase text-muted-foreground">
                        Order date
                      </div>
                      <div className="text-xs">
                        {formatDate(group.createdAt)}
                      </div>
                    </div>
                    <div className="space-y-1">
                      <div className="text-[11px] font-semibold uppercase text-muted-foreground">
                        Product
                      </div>
                      <div className="text-xs truncate max-w-[150px]" title={productNames.join(", ")}>
                        {productNames.join(", ")}
                      </div>
                    </div>
                    <div className="space-y-1">
                      <div className="text-[11px] font-semibold uppercase text-muted-foreground">
                        Sold by
                      </div>
                      <div className="text-xs text-blue-600 truncate max-w-[150px]">
                        {uniqueSellers.join(", ")}
                      </div>
                    </div>
                    <div className="space-y-1">
                      <div className="text-[11px] font-semibold uppercase text-muted-foreground">
                        Total
                      </div>
                      <div className="flex flex-col gap-0.5 font-semibold text-xs">
                        <span>US ${sessionTotalAmount.toFixed(2)}</span>
                        <div className="text-[10px] text-muted-foreground font-normal">
                          incl. US ${groupShippingPrice.toFixed(2)} shipping
                        </div>
                        {sessionDiscountAmount > 0 && (
                          <span className="text-[10px] text-green-700 font-medium">
                            Saved: -US ${sessionDiscountAmount.toFixed(2)}
                          </span>
                        )}
                      </div>
                    </div>
                    <div className="flex items-center justify-end">
                      <Button
                        variant="ghost"
                        size="sm"
                        className="text-xs cursor-pointer hover:text-blue-500 hover:bg-blue-400/20 text-blue-600 "
                      >
                        {isExpanded ? "Hide items" : "Show items"}
                      </Button>
                    </div>
                  </div>

                  {isExpanded && (
                    <div className="p-4 pt-2 space-y-6">
                      {group.orders.map((order, orderIdx) => (
                        <div key={order._id} className="space-y-4">
                          <Separator
                            className={orderIdx === 0 ? "hidden" : "block mt-2"}
                          />

                          {/* Seller Sub-Header */}
                          <div className="flex items-center justify-between text-[11px] font-bold text-muted-foreground uppercase px-2">
                            <span className="flex items-center gap-2">
                              Seller:{" "}
                              <span className="text-blue-600 underline cursor-pointer">
                                {order.seller?.username}
                              </span>
                            </span>
                            <span className="text-emerald-700">
                              Order: {shortOrderNumber(order._id)}
                            </span>
                          </div>

                          {order.items.map((item, itemIdx) => {
                            const statusMeta = getStatusMeta(order.status);
                            return (
                              <div
                                key={itemIdx}
                                className="flex flex-wrap items-start justify-between gap-4 px-2"
                              >
                                {/* LEFT: Image */}
                                <div className="flex gap-3">
                                  <div className="flex h-24 w-24 items-center justify-center rounded border bg-muted overflow-hidden">
                                    {item.productId?.imageUrl ? (
                                      <img
                                        src={item.productId.imageUrl}
                                        alt={item.productId.title || item.title}
                                        className="h-full w-full object-cover"
                                      />
                                    ) : (
                                      <span className="text-xs text-muted-foreground text-center px-2">
                                        No image
                                      </span>
                                    )}
                                  </div>
                                </div>

                                {/* MIDDLE: Info & Status */}
                                <div className="flex-1 space-y-2 text-sm">
                                  <button
                                    type="button"
                                    onClick={() =>
                                      handleViewOrderDetails(order._id)
                                    }
                                    className="font-medium leading-snug text-left hover:text-blue-600 hover:underline cursor-pointer"
                                    title="View order detail"
                                  >
                                    {item.productId?.title || item.title}
                                  </button>
                                  {item.selectedVariants?.length ? (
                                    <div className="text-xs text-muted-foreground">
                                      Variant:{" "}
                                      {item.selectedVariants
                                        .map((v) => `${v.name}: ${v.value}`)
                                        .join(", ")}
                                    </div>
                                  ) : null}
                                  <div className="text-xs font-semibold">
                                    Quantity: {item.quantity} | Item Price: US $
                                    {item.unitPrice?.toFixed(2)}
                                  </div>

                                  {/* Status Display matching eBay style */}
                                  <div className="flex items-start gap-2 text-xs pt-1">
                                    <span
                                      className={`mt-1 inline-block h-3 w-3 rounded-full ${statusMeta.dotClass}`}
                                    />
                                    <div>
                                      <div
                                        className={`font-medium ${statusMeta.textClass}`}
                                      >
                                        {statusMeta.label} on{" "}
                                        {formatDate(order.createdAt)}
                                      </div>
                                      <div className="text-muted-foreground">
                                        Tracking number: -
                                      </div>
                                      <div className="flex items-center gap-2 mt-1">
                                        <span className="text-[10px] text-muted-foreground font-medium uppercase">
                                          Payment:
                                        </span>
                                        <span
                                          className={`px-2 py-0.5 rounded-sm font-bold text-[10px] uppercase ${
                                            order.paymentStatus === "paid"
                                              ? "bg-emerald-100 text-emerald-700"
                                              : order.paymentStatus === "unpaid"
                                                ? "bg-amber-100 text-amber-700"
                                                : "bg-red-100 text-red-700"
                                          }`}
                                        >
                                          {order.paymentStatus === "unpaid"
                                            ? "Unpaid"
                                            : order.paymentStatus === "paid"
                                              ? "Paid"
                                              : order.paymentStatus || "Unpaid"}
                                        </span>
                                      </div>
                                      <div className="text-muted-foreground text-[11px] italic">
                                        {statusMeta.note}
                                      </div>
                                    </div>
                                  </div>
                                </div>

                                {/* RIGHT: Actions preserve all original buttons */}
                                <div className="flex flex-col items-end gap-2 text-sm">
                                  <Button
                                    size="sm"
                                    className="w-40 cursor-pointer rounded-none bg-blue-600 text-white hover:bg-blue-700"
                                    onClick={() =>
                                      handleViewOrderDetails(order._id)
                                    }
                                  >
                                    View detail
                                  </Button>

                                  <Button
                                    size="sm"
                                    variant="outline"
                                    className="w-40 cursor-pointer hover:text-blue-500 rounded-none border-blue-600 text-blue-600 hover:bg-blue-50"
                                    onClick={() =>
                                      navigate(
                                        `/products?search=${encodeURIComponent(item.productId?.title || item.title)}`,
                                      )
                                    }
                                  >
                                    View similar items
                                  </Button>

                                </div>
                              </div>
                            );
                          })}
                        </div>
                      ))}
                    </div>
                  )}
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {/* Pagination Controls */}
      {!loading && totalPages > 1 && (
        <div className="mt-8 flex items-center justify-center gap-2 pb-8">
          <Button
            variant="outline"
            size="sm"
            disabled={page <= 1}
            onClick={() => setPage((p) => p - 1)}
            className="cursor-pointer"
          >
            Previous
          </Button>

          <div className="flex items-center gap-1 mx-2">
            {Array.from({ length: totalPages }, (_, i) => i + 1).map((p) => (
              <Button
                key={p}
                variant={page === p ? "default" : "ghost"}
                size="sm"
                onClick={() => setPage(p)}
                className={`w-8 h-8 p-0 cursor-pointer ${page === p ? "bg-blue-600 hover:bg-blue-700" : ""}`}
              >
                {p}
              </Button>
            ))}
          </div>

          <Button
            variant="outline"
            size="sm"
            disabled={page >= totalPages}
            onClick={() => setPage((p) => p + 1)}
            className="cursor-pointer"
          >
            Next
          </Button>
        </div>
      )}

      {/* Chat Dialog */}
      <Dialog open={chatOpen} onOpenChange={setChatOpen}>
        <DialogContent
          className="h-fit overflow-auto flex flex-col p-0 gap-0 left-[unset] right-0 top-[unset] bottom-0 translate-0 m-4"
          aria-describedby=""
          showCloseButton={false}
        >
          <DialogTitle hidden>Chat box</DialogTitle>
          <MessageContext.Provider
            value={{
              participants,
              setParticipants: setParticipantsState,
              conversation,
              setConversation,
              messages,
              setMessages,
              productRef,
              setProductRef,
              product: productContext,
            }}
          >
            <Messages onCloseDialog={() => setChatOpen(false)} />
          </MessageContext.Provider>
        </DialogContent>
      </Dialog>

      {/* Cancel Order Confirmation Dialog */}
      <AlertDialog open={cancelDialogOpen} onOpenChange={setCancelDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Cancel Order</AlertDialogTitle>
            <AlertDialogDescription>
              Please select a reason for cancelling this order. This action
              cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="mt-2 space-y-2">
            {cancelReasons.map((r) => (
              <label key={r} className="flex items-center gap-2">
                <input
                  type="radio"
                  name="cancelReason"
                  value={r}
                  checked={cancelReason === r}
                  onChange={() => setCancelReason(r)}
                />
                <span className="text-sm capitalize">
                  {r.replace(/_/g, " ")}
                </span>
              </label>
            ))}
            {cancelReason === "other" && (
              <Textarea
                value={cancelOtherText}
                onChange={(e) => setCancelOtherText(e.target.value)}
                placeholder="Please specify the reason"
                rows={3}
              />
            )}
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel
              onClick={() => {
                setCancelDialogOpen(false);
                setOrderIdToCancel(null);
                setCancelReason("");
                setCancelOtherText("");
              }}
            >
              Keep Order
            </AlertDialogCancel>
            <AlertDialogAction
              className="bg-red-600 hover:bg-red-700 text-white"
              onClick={handleCancelOrder}
              disabled={
                processingActions.has(`cancel-${orderIdToCancel}`) ||
                !cancelReason
              }
            >
              {processingActions.has(`cancel-${orderIdToCancel}`)
                ? "Cancelling..."
                : "Confirm Cancel"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import api from "@/lib/axios";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";
import { ArrowLeft, AlertCircle } from "lucide-react";

import { Input } from "@/components/ui/input";
import { X, ImagePlus } from "lucide-react";

// Add below imports:
const RETURN_REASONS = [
    "ITEM_NOT_RECEIVED",
    "ITEM_DAMAGED",
    "WRONG_ITEM",
    "NOT_AS_DESCRIBED",
    "CHANGE_OF_MIND",
    "OTHER",
];

const REASON_LABELS: Record<string, string> = {
    ITEM_NOT_RECEIVED: "Item not received",
    ITEM_DAMAGED: "Arrived damaged or defective",
    WRONG_ITEM: "Wrong item sent",
    NOT_AS_DESCRIBED: "Item not as described",
    CHANGE_OF_MIND: "Changed my mind / Ordered by mistake",
    OTHER: "Other",
};

export default function ReturnItemPage() {
    const navigate = useNavigate();
    const { orderId } = useParams();

    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);

    // Request form state
    const [reason, setReason] = useState("");
    const [description, setDescription] = useState("");
    const [images, setImages] = useState<File[]>([]);
    const [imagePreviews, setImagePreviews] = useState<string[]>([]);
    const [uploadingImages, setUploadingImages] = useState(false);

    // Existing refund request state
    const [existingRefund, setExistingRefund] = useState<any>(null);

    useEffect(() => {
        fetchRefundDetails();
    }, [orderId]);

    const fetchRefundDetails = async () => {
        try {
            setLoading(true);
            const res = await api.get(`/api/refund/order/${orderId}`);
            if (res.data?.data) {
                setExistingRefund(res.data.data);
            }
        } catch (err: any) {
            console.error("Failed to load refund details:", err);
            // It might just not exist, which is fine (404/Empty data).
        } finally {
            setLoading(false);
        }
    };

    const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || []);
        if (images.length + files.length > 5) {
            toast.error("You can only upload up to 5 images.");
            return;
        }

        const newImages = [...images, ...files];
        setImages(newImages);

        const newPreviews = files.map((file) => URL.createObjectURL(file));
        setImagePreviews([...imagePreviews, ...newPreviews]);
    };

    const removeImage = (index: number) => {
        const newImages = [...images];
        newImages.splice(index, 1);
        setImages(newImages);

        const newPreviews = [...imagePreviews];
        URL.revokeObjectURL(newPreviews[index]);
        newPreviews.splice(index, 1);
        setImagePreviews(newPreviews);
    };

    const uploadImages = async (): Promise<string[]> => {
        if (images.length === 0) return [];
        setUploadingImages(true);
        const formData = new FormData();
        images.forEach((img) => formData.append("images", img));

        try {
            const res = await api.post("/api/upload/refund-images", formData, {
                headers: { "Content-Type": "multipart/form-data" },
            });
            return res.data.urls || [];
        } catch (error) {
            console.error("Failed to upload images", error);
            throw new Error("Failed to upload images. Please try again.");
        } finally {
            setUploadingImages(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!reason) {
            toast.error("Please select a reason for return");
            return;
        }

        if (images.length === 0 || images.length > 5) {
             toast.error("Please upload between 1 and 5 images as evidence");
             return;
        }

        try {
            setSubmitting(true);
            const uploadedImageUrls = await uploadImages();

            await api.post("/api/refund/request", {
                orderId,
                reason,
                description,
                images: uploadedImageUrls
            });
            toast.success("Return request submitted successfully!");
            fetchRefundDetails(); // Refresh to show details view
        } catch (err: any) {
            console.error("Failed to submit return:", err);
            toast.error(err.response?.data?.message || err.message || "Failed to submit return request");
        } finally {
            setSubmitting(false);
        }
    };

    const handleDispute = async () => {
        try {
            setSubmitting(true);
            await api.post(`/api/refund/${existingRefund._id}/dispute`);
            toast.success("Dispute submitted to Admin for review.");
            fetchRefundDetails();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to open dispute");
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) {
        return <div className="p-8 text-center text-muted-foreground">Loading details...</div>;
    }

    return (
        <div className="mx-auto max-w-3xl py-8 px-4">
            <Button
                variant="ghost"
                onClick={() => navigate("/my-ebay/activity/purchases")}
                className="mb-4"
            >
                <ArrowLeft className="mr-2 h-4 w-4" />
                Back to purchases
            </Button>

            {!existingRefund ? (
                // --- CREATE REFUND FORM ---
                <Card>
                    <CardHeader>
                        <CardTitle className="text-2xl">Return this order</CardTitle>
                        <p className="text-sm text-muted-foreground">
                            Tell us why you're returning these items
                        </p>
                    </CardHeader>
                    <CardContent>
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="space-y-3">
                                <Label className="text-base font-semibold">
                                    Why are you returning this?
                                </Label>
                                <RadioGroup value={reason} onValueChange={setReason}>
                                    {RETURN_REASONS.map((r) => (
                                        <div key={r} className="flex items-center space-x-2">
                                            <RadioGroupItem value={r} id={r} />
                                            <Label htmlFor={r} className="font-normal cursor-pointer">
                                                {REASON_LABELS[r]}
                                            </Label>
                                        </div>
                                    ))}
                                </RadioGroup>
                            </div>

                            <div className="space-y-4">
                                <Label className="text-base font-semibold">
                                    Evidence Images (Required, 1-5 images)
                                </Label>
                                <div className="flex flex-wrap gap-4 mt-2">
                                    {imagePreviews.map((preview, idx) => (
                                        <div key={idx} className="relative w-24 h-24 border rounded-md overflow-hidden bg-muted">
                                            <img src={preview} alt="Evidence preview" className="object-cover w-full h-full" />
                                            <button
                                                type="button"
                                                onClick={() => removeImage(idx)}
                                                className="absolute top-1 right-1 bg-black/50 hover:bg-black/70 text-white rounded-full p-1 transition-colors"
                                            >
                                                <X className="w-3 h-3" />
                                            </button>
                                        </div>
                                    ))}
                                    {images.length < 5 && (
                                        <label className="w-24 h-24 border-2 border-dashed border-muted-foreground/30 rounded-md flex flex-col items-center justify-center cursor-pointer hover:border-primary/50 transition-colors bg-muted/20">
                                            <ImagePlus className="w-6 h-6 text-muted-foreground mb-1" />
                                            <span className="text-xs text-muted-foreground font-medium">Add Photo</span>
                                            <Input
                                                type="file"
                                                accept="image/*"
                                                multiple
                                                className="hidden"
                                                onChange={handleImageChange}
                                            />
                                        </label>
                                    )}
                                </div>
                                <p className="text-xs text-muted-foreground">Please provide clear photos showing the issue with the item.</p>
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="description" className="text-base font-semibold">
                                    Additional details
                                </Label>
                                <Textarea
                                    id="description"
                                    placeholder="Tell us more about why you're returning this order..."
                                    value={description}
                                    onChange={(e) => setDescription(e.target.value)}
                                    rows={4}
                                    className="resize-none"
                                    required
                                />
                            </div>

                            <div className="rounded-lg bg-blue-50 p-4 text-sm">
                                <h4 className="font-semibold mb-2">What happens next?</h4>
                                <ul className="space-y-1 text-muted-foreground">
                                    <li>• The seller will be notified of your request</li>
                                    <li>• They have 48 hours to approve or reject your return</li>
                                    <li>• If they do not respond within 48h, it is auto-approved</li>
                                    <li>• If rejected, you can open a Dispute and Admin will step in</li>
                                </ul>
                            </div>

                            <div className="flex gap-3">
                                <Button
                                    type="submit"
                                    className="flex-1"
                                    disabled={submitting || uploadingImages || !reason}
                                >
                                    {submitting || uploadingImages ? "Submitting..." : "Submit return request"}
                                </Button>
                                <Button
                                    type="button"
                                    variant="outline"
                                    onClick={() => navigate(-1)}
                                    disabled={submitting || uploadingImages}
                                >
                                    Cancel
                                </Button>
                            </div>
                        </form>
                    </CardContent>
                </Card>
            ) : (
                // --- EXISTING REFUND DETAILS ---
                <Card>
                    <CardHeader>
                        <div className="flex items-center justify-between">
                            <CardTitle className="text-2xl">Return Details</CardTitle>
                            <Badge
                                variant={
                                    existingRefund.status === "APPROVED" || existingRefund.status === "AUTO_APPROVED" || existingRefund.status === "ADMIN_APPROVED" ? "default" :
                                        existingRefund.status === "REJECTED" || existingRefund.status === "ADMIN_REJECTED" ? "destructive" :
                                            "secondary"
                                }
                                className="text-sm px-3 py-1 uppercase"
                            >
                                {existingRefund.status.replace("_", " ")}
                            </Badge>
                        </div>
                    </CardHeader>
                    <CardContent className="space-y-6">
                        <div className="grid gap-4 md:grid-cols-2">
                            <div>
                                <h4 className="font-medium text-sm text-muted-foreground">Reason</h4>
                                <p className="mt-1 font-semibold">{REASON_LABELS[existingRefund.reason] || existingRefund.reason}</p>
                            </div>
                            <div>
                                <h4 className="font-medium text-sm text-muted-foreground">Requested At</h4>
                                <p className="mt-1">{new Date(existingRefund.requestedAt).toLocaleString()}</p>
                            </div>
                        </div>

                        <div>
                            <h4 className="font-medium text-sm text-muted-foreground">Buyer Description</h4>
                            <p className="mt-1 bg-muted p-3 rounded-md text-sm">
                                {existingRefund.description || "No description provided."}
                            </p>
                            {existingRefund.images && existingRefund.images.length > 0 && (
                                <div className="mt-3 flex flex-wrap gap-2">
                                    {existingRefund.images.map((img: string, i: number) => (
                                        <a href={img} target="_blank" rel="noopener noreferrer" key={i}>
                                            <img src={img} alt="Evidence" className="h-24 w-24 object-cover rounded border bg-muted" />
                                        </a>
                                    ))}
                                </div>
                            )}
                        </div>

                        {existingRefund.sellerNote && (
                            <div>
                                <h4 className="font-medium text-sm text-muted-foreground">Seller Response</h4>
                                <p className="mt-1 bg-amber-50 dark:bg-amber-900/20 p-3 rounded-md text-sm border border-amber-200">
                                    {existingRefund.sellerNote}
                                </p>
                            </div>
                        )}

                        {existingRefund.adminNote && (
                            <div>
                                <h4 className="font-medium text-sm text-muted-foreground pb-2 flex items-center gap-2">
                                    <AlertCircle className="w-4 h-4 text-primary" /> Admin Final Verdict
                                </h4>
                                <p className="bg-primary/10 p-3 rounded-md text-sm border border-primary/20">
                                    {existingRefund.adminNote}
                                </p>
                            </div>
                        )}

                    </CardContent>

                    {/* Buyer actions for existing refund */}
                    <CardFooter className="bg-muted/30 pt-4 flex gap-3 flex-wrap">
                        {existingRefund.status === "REJECTED" && (
                            <div className="w-full">
                                <div className="mb-4 text-sm text-destructive font-medium flex items-center gap-2">
                                    <AlertCircle className="w-4 h-4" />
                                    The seller rejected your return request. If you believe this is unfair, you can open a dispute.
                                </div>
                                <Button
                                    onClick={handleDispute}
                                    disabled={submitting}
                                    variant="destructive"
                                >
                                    {submitting ? "Processing..." : "Open Dispute (Involve Admin)"}
                                </Button>
                            </div>
                        )}

                        {(existingRefund.status === "APPROVED" || existingRefund.status === "AUTO_APPROVED" || existingRefund.status === "ADMIN_APPROVED") && (
                            <div className="w-full text-sm text-green-700 font-medium">
                                ✓ This return has been approved. The seller will complete your refund shortly.
                            </div>
                        )}
                    </CardFooter>
                </Card>
            )}
        </div>
    );
}

import { useState, useEffect } from "react";
import { UserProfile } from "@/components/user-profile";
import { useAuth } from "@/hooks/use-auth";
import api from "@/lib/axios";

export default function UserProfilePage() {
  const { user } = useAuth();
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchOrders = async () => {
      try {
        setLoading(true);
        const response = await api.get('/api/orders');
        // Transform backend orders to match UserProfile component format
        const formattedOrders = response.data.data?.map((order: any) => ({
          id: order._id,
          orderNumber: order.orderNumber || `ORD-${order._id.slice(-6)}`,
          date: new Date(order.createdAt).toLocaleDateString('en-GB'),
          total: order.totalAmount,
          status: order.status,
          items: order.items?.length || 0,
        })) || [];
        setOrders(formattedOrders);
      } catch (error) {
        console.error('Failed to fetch orders:', error);
        setOrders([]); // Empty orders on error
      } finally {
        setLoading(false);
      }
    };

    if (user) {
      fetchOrders();
    }
  }, [user]);

  return (
    <div className="container mx-auto py-8 px-4">
      <div className="mb-8">
        <h1 className="text-4xl font-bold text-gray-900">User Profile</h1>
        <p className="text-gray-600 mt-2">
          Manage your personal information and view your order history.
        </p>
      </div>

      {loading ? (
        <div className="text-center py-12">
          <p className="text-gray-600">Loading your profile...</p>
        </div>
      ) : (
        user && <UserProfile user={user} orders={orders} />
      )}
    </div>
  );
}

import { useEffect, useState, useCallback } from "react";
import { Link, useNavigate } from "react-router-dom";
import { Clock, Trash2, X, ShoppingCart } from "lucide-react";
import {
  getRecentlyViewed,
  removeRecentlyViewed,
  clearRecentlyViewed,
  type RecentlyViewedItem,
} from "@/api/recently-viewed";
import { Button } from "@/components/ui/button";
import { useCart } from "@/contexts/cart-context";

export default function RecentlyViewedPage() {
  const [items, setItems] = useState<RecentlyViewedItem[]>([]);
  const [loading, setLoading] = useState(true);
  const { addToCart } = useCart();
  const navigate = useNavigate();

  /**
   * If the product has variants, the user must select them on the detail page.
   * Otherwise add directly to cart.
   */
  const handleAddToCart = (productId: string, hasVariants: boolean) => {
    if (hasVariants) {
      navigate(`/products/${productId}`);
    } else {
      addToCart(productId, 1, []);
    }
  };

  const load = useCallback(async () => {
    try {
      setLoading(true);
      const res = await getRecentlyViewed(20);
      setItems(res.data);
    } catch {
      /* ignore */
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { load(); }, [load]);

  const handleRemove = async (productId: string) => {
    try {
      await removeRecentlyViewed(productId);
      setItems((prev) => prev.filter((i) => i.product._id !== productId));
    } catch { /* ignore */ }
  };

  const handleClearAll = async () => {
    try {
      await clearRecentlyViewed();
      setItems([]);
    } catch { /* ignore */ }
  };

  return (
    <div className="flex flex-col gap-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl bg-indigo-100 flex items-center justify-center">
            <Clock className="h-5 w-5 text-indigo-600" />
          </div>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Recently Viewed</h1>
            {!loading && (
              <p className="text-sm text-gray-500 mt-0.5">
                {items.length === 0
                  ? "No items yet"
                  : `${items.length} product${items.length !== 1 ? "s" : ""} viewed`}
              </p>
            )}
          </div>
        </div>
        {items.length > 0 && (
          <Button
            variant="outline"
            size="sm"
            className="gap-2 text-red-500 border-red-200 hover:bg-red-50 hover:text-red-600"
            onClick={handleClearAll}
          >
            <Trash2 className="h-4 w-4" />
            Clear All
          </Button>
        )}
      </div>

      {/* Skeleton */}
      {loading ? (
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {Array.from({ length: 10 }).map((_, i) => (
            <div key={i} className="animate-pulse rounded-xl border border-gray-100 bg-white overflow-hidden">
              <div className="w-full aspect-square bg-gray-200" />
              <div className="p-3 space-y-2">
                <div className="h-3 bg-gray-200 rounded w-3/4" />
                <div className="h-3 bg-gray-200 rounded w-1/2" />
                <div className="h-3 bg-gray-200 rounded w-1/3" />
              </div>
            </div>
          ))}
        </div>
      ) : items.length === 0 ? (
        /* Empty state */
        <div className="flex flex-col items-center justify-center py-24 text-center">
          <div className="w-20 h-20 rounded-full bg-indigo-50 flex items-center justify-center mb-5">
            <Clock className="h-10 w-10 text-indigo-300" />
          </div>
          <h2 className="text-xl font-semibold text-gray-800 mb-2">
            No recently viewed products
          </h2>
          <p className="text-gray-400 text-sm mb-6 max-w-sm">
            Products you browse will appear here so you can easily find them again.
          </p>
          <Link to="/products">
            <Button className="gap-2">
              <ShoppingCart className="h-4 w-4" />
              Browse Products
            </Button>
          </Link>
        </div>
      ) : (
        /* Product grid */
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
          {items.map((item) => {
            const p = item.product;
            const img = p.images?.[0] || p.image || "";
            const finalPrice =
              p.isOnSale && p.discountPercent
                ? p.price * (1 - p.discountPercent / 100)
                : p.price;

            return (
              <div
                key={item._id}
                className="group relative flex flex-col rounded-xl border border-gray-100 bg-white hover:shadow-lg hover:border-indigo-200 transition-all duration-200 overflow-hidden"
              >
                {/* Remove button */}
                <button
                  onClick={() => handleRemove(p._id)}
                  className="absolute top-2 right-2 z-10 w-7 h-7 rounded-full bg-white/90 hover:bg-red-50 border border-gray-200 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity shadow-sm cursor-pointer"
                  title="Remove"
                >
                  <X className="h-3.5 w-3.5 text-gray-400 hover:text-red-500" />
                </button>

                {/* Sale badge */}
                {p.isOnSale && (
                  <div className="absolute top-2 left-2 z-10 bg-gradient-to-r from-red-500 to-rose-500 text-white text-[10px] font-bold px-2 py-0.5 rounded-full shadow-sm">
                    SALE
                  </div>
                )}

                {/* Image */}
                <Link to={`/products/${p._id}`} className="block">
                  <div className="w-full aspect-square bg-gray-50 overflow-hidden">
                    {img ? (
                      <img
                        src={img}
                        alt={p.title}
                        className="w-full h-full object-contain group-hover:scale-105 transition-transform duration-300"
                        onError={(e) => {
                          (e.currentTarget as HTMLImageElement).style.display = "none";
                        }}
                      />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center bg-gray-100">
                        <svg className="h-12 w-12 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2zm6-8a2 2 0 100-4 2 2 0 000 4z" />
                        </svg>
                      </div>
                    )}
                  </div>
                </Link>

                {/* Info */}
                <div className="flex flex-col gap-1.5 p-3 flex-1">
                  <Link to={`/products/${p._id}`}>
                    <p className="text-sm font-medium text-gray-800 line-clamp-2 leading-tight hover:text-indigo-600 transition-colors">
                      {p.title}
                    </p>
                  </Link>

                  <div className="flex items-center gap-2 flex-wrap">
                    <span className={`text-base font-bold ${p.isOnSale ? "text-red-600" : "text-gray-900"}`}>
                      ${finalPrice.toFixed(2)}
                    </span>
                    {p.isOnSale && p.originalPrice && (
                      <span className="text-xs text-gray-400 line-through">
                        ${p.originalPrice.toFixed(2)}
                      </span>
                    )}
                  </div>

                  <p className="text-[11px] text-gray-400">
                    Viewed{" "}
                    {new Date(item.viewedAt).toLocaleDateString("en-US", {
                      month: "short",
                      day: "numeric",
                      hour: "2-digit",
                      minute: "2-digit",
                    })}
                  </p>

                  {/* Add to cart / select variants */}
                  <button
                    onClick={() => handleAddToCart(p._id, (p.variants?.length ?? 0) > 0)}
                    className="mt-auto w-full py-1.5 rounded-lg border border-gray-200 text-xs font-medium text-gray-700 hover:border-indigo-400 hover:text-indigo-600 hover:bg-indigo-50 transition-all flex items-center justify-center gap-1.5 cursor-pointer"
                  >
                    <ShoppingCart className="h-3.5 w-3.5" />
                    {(p.variants?.length ?? 0) > 0 ? "Select Options" : "Add to Cart"}
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useRef } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import { toast } from "sonner";
import api from "@/lib/axios";
import {
  AlertTriangle,
  Flag,
  CheckCircle,
  Upload,
  ArrowLeft,
  ShieldAlert,
  Clock,
  BarChart3,
  ImageIcon,
  X,
  User,
  Package,
  ShoppingBag,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import {
  submitReport,
  getMyReports,
  getMyReportStats,
  REPORT_REASONS,
  type ReportReason,
  type Report,
  type BuyerReportStats,
} from "@/api/reportApi";

const STATUS_MAP: Record<string, { label: string; variant: "default" | "secondary" | "destructive" }> = {
  PENDING: { label: "Pending Review", variant: "secondary" },
  VALID: { label: "Valid", variant: "default" },
  REJECTED: { label: "Rejected", variant: "destructive" },
};

export default function BuyerReportPage() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Pre-fill from query params
  const prefillSellerId = searchParams.get("sellerId") || "";
  const prefillProductId = searchParams.get("productId") || "";
  const prefillOrderId = searchParams.get("orderId") || "";

  // Resolved names for display
  const [sellerName, setSellerName] = useState<string>("");
  const [productTitle, setProductTitle] = useState<string>("");
  const [productImage, setProductImage] = useState<string>("");

  // Form state
  const [sellerId, setSellerId] = useState(prefillSellerId);
  const [reason, setReason] = useState<ReportReason | "">("");
  const [description, setDescription] = useState("");
  const [evidenceUrl, setEvidenceUrl] = useState("");
  const [evidenceFile, setEvidenceFile] = useState<File | null>(null);
  const [evidencePreview, setEvidencePreview] = useState<string>("");
  const [uploading, setUploading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  // My reports + stats
  const [myReports, setMyReports] = useState<Report[]>([]);
  const [stats, setStats] = useState<BuyerReportStats | null>(null);
  const [loadingHistory, setLoadingHistory] = useState(true);
  const [activeTab, setActiveTab] = useState<"submit" | "history">("submit");

  // Fetch seller & product info on load
  useEffect(() => {
    if (prefillProductId) {
      api.get(`/api/products/${prefillProductId}`).then((res) => {
        const p = res.data?.data ?? res.data;
        if (p) {
          setProductTitle(p.title || "");
          setProductImage(p.images?.[0] || p.image || "");
          // Also fill seller from product if not separately provided
          if (p.seller) {
            const name = p.seller.username || p.seller.shopName || p.seller.name || "";
            if (name) setSellerName(name);
          }
        }
      }).catch(() => { });
    }

    if (prefillSellerId && !prefillProductId) {
      // Try fetching seller profile
      api.get(`/api/users/${prefillSellerId}`).then((res) => {
        const u = res.data?.data ?? res.data;
        const name = u?.username || u?.shopName || u?.name || "";
        if (name) setSellerName(name);
      }).catch(() => { });
    }

    fetchHistory();
  }, []);

  const fetchHistory = async () => {
    try {
      setLoadingHistory(true);
      const [reportsRes, statsRes] = await Promise.all([getMyReports({ limit: 20 }), getMyReportStats()]);
      setMyReports(reportsRes.reports);
      setStats(statsRes.data);
    } catch {
      // silently ignore if not authenticated
    } finally {
      setLoadingHistory(false);
    }
  };

  // ── File selection ──────────────────────────────────────
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) {
      toast.error("Image too large. Max size is 5MB.");
      return;
    }
    if (!file.type.startsWith("image/")) {
      toast.error("Only image files are allowed as evidence.");
      return;
    }
    setEvidenceFile(file);
    setEvidencePreview(URL.createObjectURL(file));
    setEvidenceUrl("");
  };

  const handleRemoveEvidence = () => {
    setEvidenceFile(null);
    setEvidencePreview("");
    setEvidenceUrl("");
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  // ── Upload to Cloudinary ────────────────────────────────
  const uploadEvidence = async (): Promise<string | undefined> => {
    if (!evidenceFile) return undefined;
    const formData = new FormData();
    formData.append("evidence", evidenceFile);
    try {
      setUploading(true);
      const res = await api.post("/api/upload/report-evidence", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      const url: string = res.data.url;
      setEvidenceUrl(url);
      return url;
    } catch (err: any) {
      toast.error(err.response?.data?.message || "Failed to upload evidence image");
      return undefined;
    } finally {
      setUploading(false);
    }
  };

  // ── Submit ──────────────────────────────────────────────
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!sellerId.trim()) return toast.error("Seller ID is required");
    if (!reason) return toast.error("Please select a reason");
    if (!description.trim() || description.length < 20)
      return toast.error("Description must be at least 20 characters");

    try {
      setSubmitting(true);
      let finalEvidenceUrl = evidenceUrl;
      if (evidenceFile && !evidenceUrl) {
        finalEvidenceUrl = (await uploadEvidence()) || "";
        if (!finalEvidenceUrl && evidenceFile) { setSubmitting(false); return; }
      }
      await submitReport({
        sellerId,
        productId: prefillProductId || undefined,
        orderId: prefillOrderId || undefined,
        reason: reason as ReportReason,
        description,
        evidenceUrl: finalEvidenceUrl || undefined,
      });
      toast.success("Report submitted! It will be reviewed by our team.");
      setSubmitted(true);
      fetchHistory();
      setReason("");
      setDescription("");
      handleRemoveEvidence();
    } catch (err: any) {
      toast.error(err.response?.data?.message || err.message || "Failed to submit report");
    } finally {
      setSubmitting(false);
    }
  };

  const isBusy = submitting || uploading;

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-white to-blue-50">
      {/* Header */}
      <div className="border-b bg-white/80 backdrop-blur-sm sticky top-0 z-10">
        <div className="max-w-4xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button onClick={() => navigate(-1)} className="text-gray-500 hover:text-gray-800 transition">
              <ArrowLeft className="h-5 w-5" />
            </button>
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 rounded-lg bg-red-100 flex items-center justify-center">
                <Flag className="h-4 w-4 text-red-600" />
              </div>
              <div>
                <h1 className="text-lg font-bold text-gray-900">Report a Seller</h1>
                <p className="text-xs text-gray-500">Help us maintain a safe marketplace</p>
              </div>
            </div>
          </div>
          <div className="flex gap-1 bg-gray-100 rounded-lg p-1">
            {(["submit", "history"] as const).map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all ${activeTab === tab ? "bg-white text-gray-900 shadow-sm" : "text-gray-600 hover:text-gray-800"
                  }`}
              >
                {tab === "submit" ? "Submit Report" : "My Reports"}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="max-w-4xl mx-auto px-4 py-8">
        {/* Stats Banner */}
        {stats && (
          <div className={`mb-6 p-4 rounded-xl border-2 ${stats.underMonitoring ? "bg-red-50 border-red-200"
            : stats.accuracyScore < 0.5 ? "bg-amber-50 border-amber-200"
              : "bg-emerald-50 border-emerald-200"
            }`}>
            <div className="flex items-center justify-between flex-wrap gap-4">
              <div className="flex items-center gap-3">
                {stats.underMonitoring
                  ? <ShieldAlert className="h-6 w-6 text-red-600 shrink-0" />
                  : <BarChart3 className="h-6 w-6 text-emerald-600 shrink-0" />
                }
                <div>
                  <p className="font-semibold text-sm">
                    {stats.underMonitoring ? " Account in Report Monitoring Mode" : "Your Report Statistics"}
                  </p>
                  {stats.underMonitoring && (
                    <p className="text-xs text-red-700 mt-0.5">
                      Your report accuracy is too low. Reporting is temporarily disabled.
                    </p>
                  )}
                </div>
              </div>
              <div className="flex gap-4 text-sm">
                <div className="text-center"><p className="font-bold text-lg">{stats.totalReports}</p><p className="text-xs text-gray-600">Total</p></div>
                <div className="text-center"><p className="font-bold text-lg text-emerald-600">{stats.validReports}</p><p className="text-xs text-gray-600">Valid</p></div>
                <div className="text-center"><p className="font-bold text-lg text-red-600">{stats.rejectedReports}</p><p className="text-xs text-gray-600">Rejected</p></div>
                <div className="text-center">
                  <p className={`font-bold text-lg ${stats.accuracyScore >= 0.6 ? "text-emerald-600" : stats.accuracyScore >= 0.3 ? "text-amber-600" : "text-red-600"}`}>
                    {(stats.accuracyScore * 100).toFixed(0)}%
                  </p>
                  <p className="text-xs text-gray-600">Accuracy</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === "submit" && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* Left: Info */}

            {/* Right: Form */}
            <div className="lg:col-span-2">
              {submitted ? (
                <Card className="p-8 text-center border-0 shadow-sm">
                  <CheckCircle className="h-14 w-14 text-emerald-500 mx-auto mb-4" />
                  <h2 className="text-xl font-bold text-gray-900 mb-2">Report Submitted!</h2>
                  <p className="text-gray-600 text-sm mb-6">
                    Our team will review your report and take appropriate action. Thank you for helping keep the marketplace safe.
                  </p>
                  <Button onClick={() => setSubmitted(false)} variant="outline">Submit Another Report</Button>
                </Card>
              ) : stats?.underMonitoring ? (
                <Card className="p-8 text-center border-0 shadow-sm border-2 border-red-200">
                  <ShieldAlert className="h-14 w-14 text-red-500 mx-auto mb-4" />
                  <h2 className="text-xl font-bold text-gray-900 mb-2">Reporting Restricted</h2>
                  <p className="text-gray-600 text-sm">
                    Your account is in report monitoring mode due to a low report accuracy score. Please contact support if you believe this is a mistake.
                  </p>
                </Card>
              ) : (
                <Card className="p-6 border-0 shadow-sm">
                  <form onSubmit={handleSubmit} className="space-y-5">

                    {/* ── Reporting target info card ── */}
                    {(prefillSellerId || prefillProductId || prefillOrderId) && (
                      <div className="rounded-xl border border-gray-100 bg-gray-50 p-4 space-y-2">
                        <p className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-3">Reporting About</p>

                        {/* Seller */}
                        <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-red-100 flex items-center justify-center shrink-0">
                            <User className="h-4 w-4 text-red-600" />
                          </div>
                          <div>
                            <p className="text-xs text-gray-500">Seller</p>
                            <p className="text-sm font-semibold text-gray-900">
                              {sellerName || prefillSellerId}
                            </p>
                          </div>
                        </div>

                        {/* Product */}
                        {prefillProductId && (
                          <div className="flex items-center gap-3">
                            {productImage ? (
                              <img src={productImage} alt="" className="w-8 h-8 rounded-md object-cover shrink-0 border" />
                            ) : (
                              <div className="w-8 h-8 rounded-md bg-blue-100 flex items-center justify-center shrink-0">
                                <Package className="h-4 w-4 text-blue-600" />
                              </div>
                            )}
                            <div>
                              <p className="text-xs text-gray-500">Product</p>
                              <p className="text-sm font-semibold text-gray-900 line-clamp-1">
                                {productTitle || prefillProductId}
                              </p>
                            </div>
                          </div>
                        )}

                        {/* Order */}
                        {prefillOrderId && (
                          <div className="flex items-center gap-3">
                            <div className="w-8 h-8 rounded-md bg-purple-100 flex items-center justify-center shrink-0">
                              <ShoppingBag className="h-4 w-4 text-purple-600" />
                            </div>
                            <div>
                              <p className="text-xs text-gray-500">Order</p>
                              <p className="text-sm font-mono text-gray-700">#{prefillOrderId.slice(-8)}</p>
                            </div>
                          </div>
                        )}
                      </div>
                    )}

                    {/* Seller ID (manual if not pre-filled) */}
                    {!prefillSellerId && (
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1.5">
                          Seller ID <span className="text-red-500">*</span>
                        </label>
                        <input
                          type="text"
                          className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 bg-gray-50"
                          placeholder="Paste the seller's ID here"
                          value={sellerId}
                          onChange={(e) => setSellerId(e.target.value)}
                          required
                        />
                      </div>
                    )}

                    {/* Reason */}
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Reason <span className="text-red-500">*</span>
                      </label>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                        {REPORT_REASONS.map((r) => (
                          <button
                            key={r.value}
                            type="button"
                            onClick={() => setReason(r.value)}
                            className={`flex items-center gap-2.5 px-4 py-3 rounded-lg border-2 text-sm text-left transition-all ${reason === r.value
                              ? "border-blue-500 bg-blue-50 text-blue-900 font-medium"
                              : "border-gray-200 hover:border-gray-300 bg-white text-gray-700"
                              }`}
                          >
                            <span className="text-lg">{r.icon}</span>
                            {r.label}
                          </button>
                        ))}
                      </div>
                    </div>

                    {/* Description */}
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1.5">
                        Description <span className="text-red-500">*</span>
                      </label>
                      <Textarea
                        rows={4}
                        placeholder="Describe what happened in detail (minimum 20 characters)..."
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        className="resize-none"
                        maxLength={2000}
                      />
                      <p className="mt-1 text-xs text-gray-400 text-right">{description.length}/2000</p>
                    </div>

                    {/* Evidence Photo */}
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1.5">
                        Evidence Photo <span className="text-gray-400 font-normal">(optional, max 5MB)</span>
                      </label>
                      <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
                      {evidencePreview ? (
                        <div className="relative w-full rounded-xl border-2 border-dashed border-emerald-300 bg-emerald-50 overflow-hidden">
                          <img src={evidencePreview} alt="Evidence preview" className="w-full max-h-56 object-contain" />
                          <div className="absolute top-2 right-2 flex gap-2">
                            <button type="button" onClick={() => fileInputRef.current?.click()} className="bg-white/90 hover:bg-white border border-gray-200 rounded-full p-1.5 shadow-sm transition" title="Change image">
                              <ImageIcon className="h-4 w-4 text-gray-600" />
                            </button>
                            <button type="button" onClick={handleRemoveEvidence} className="bg-white/90 hover:bg-red-50 border border-gray-200 rounded-full p-1.5 shadow-sm transition" title="Remove image">
                              <X className="h-4 w-4 text-red-500" />
                            </button>
                          </div>
                          <p className="text-xs text-emerald-700 text-center pb-2">
                            {evidenceFile?.name}
                            {evidenceUrl && <span className="ml-2 text-emerald-600 font-medium">✓ Uploaded</span>}
                          </p>
                        </div>
                      ) : (
                        <button
                          type="button"
                          onClick={() => fileInputRef.current?.click()}
                          className="w-full rounded-xl border-2 border-dashed border-gray-200 bg-gray-50 hover:border-blue-400 hover:bg-blue-50 transition-all py-8 flex flex-col items-center gap-2 text-gray-500 hover:text-blue-600"
                        >
                          <Upload className="h-7 w-7" />
                          <span className="text-sm font-medium">Click to upload evidence photo</span>
                          <span className="text-xs text-gray-400">JPG, PNG, WEBP — max 5MB</span>
                        </button>
                      )}
                    </div>

                    <Button type="submit" disabled={isBusy} className="w-full h-11 bg-red-600 hover:bg-red-700 text-white font-medium">
                      {uploading ? (
                        <span className="flex items-center gap-2">
                          <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" /></svg>
                          Uploading evidence...
                        </span>
                      ) : submitting ? (
                        <span className="flex items-center gap-2">
                          <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" /></svg>
                          Submitting...
                        </span>
                      ) : (
                        <span className="flex items-center gap-2"><Flag className="h-4 w-4" /> Submit Report</span>
                      )}
                    </Button>
                  </form>
                </Card>
              )}
            </div>
          </div>
        )}

        {activeTab === "history" && (
          <div>
            <h2 className="text-lg font-semibold text-gray-900 mb-4">My Submitted Reports</h2>
            {loadingHistory ? (
              <div className="py-16 text-center text-gray-400">Loading...</div>
            ) : myReports.length === 0 ? (
              <Card className="py-16 text-center text-gray-500 border-0 shadow-sm">
                <Flag className="h-10 w-10 mx-auto mb-3 text-gray-300" />
                <p>You haven't submitted any reports yet.</p>
              </Card>
            ) : (
              <div className="space-y-3">
                {myReports.map((report) => (
                  <Card key={report._id} className="p-4 border-0 shadow-sm hover:shadow-md transition-shadow">
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-3">
                      <div className="space-y-1.5">
                        <div className="flex items-center gap-2 flex-wrap">
                          <Badge variant={STATUS_MAP[report.status].variant}>{STATUS_MAP[report.status].label}</Badge>
                          <span className="text-sm font-medium text-gray-900">
                            {REPORT_REASONS.find((r) => r.value === report.reason)?.icon}{" "}
                            {REPORT_REASONS.find((r) => r.value === report.reason)?.label}
                          </span>
                        </div>
                        <p className="text-sm text-gray-600">
                          Seller: <span className="font-medium">{report.seller?.username || "N/A"}</span>
                          {report.product && <span className="text-gray-400"> · {report.product.title}</span>}
                        </p>
                        <p className="text-xs text-gray-400">
                          Submitted {new Date(report.createdAt).toLocaleDateString()}
                          {report.verifiedAt && <> · Reviewed {new Date(report.verifiedAt).toLocaleDateString()}</>}
                        </p>
                        {report.adminNote && (
                          <p className="text-xs text-gray-500 bg-gray-50 rounded px-2 py-1 mt-1">
                            Admin note: {report.adminNote}
                          </p>
                        )}
                      </div>
                    </div>
                    <p className="mt-2 text-sm text-gray-700 line-clamp-2">{report.description}</p>
                    {report.evidenceUrl && (
                      <a href={report.evidenceUrl} target="_blank" rel="noopener noreferrer" className="mt-2 inline-flex items-center gap-1 text-xs text-blue-600 hover:underline">
                        <ImageIcon className="h-3.5 w-3.5" /> View Evidence
                      </a>
                    )}
                  </Card>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

﻿import { useState, useEffect } from "react";
import { Trash2, Search, ExternalLink, Edit2, Package } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import axios from "@/lib/axios";
import { toast } from "sonner";
import { EditSavedSearchDialog } from "@/components/dialogs/edit-saved-search-dialog";

interface SearchFilter {
    categoryId?: string;
    minPrice?: number;
    maxPrice?: number;
    condition?: string;
    sortBy?: string;
}

interface SavedSearch {
    _id: string;
    searchQuery: string;
    filters: SearchFilter;
    name: string;
    productCount: number;
    lastChecked: string;
    createdAt: string;
}

export default function SavedSearchesPage() {
    const [savedSearches, setSavedSearches] = useState<SavedSearch[]>([]);
    const [loading, setLoading] = useState(true);
    const [editDialogOpen, setEditDialogOpen] = useState(false);
    const [selectedSearch, setSelectedSearch] = useState<SavedSearch | null>(
        null
    );
    const navigate = useNavigate();

    useEffect(() => {
        fetchSavedSearches();
    }, []);

    const fetchSavedSearches = async () => {
        try {
            const response = await axios.get("/api/saved-searches");
            if (response.data.success) {
                const searches = response.data.data;
                setSavedSearches(searches);

                // Update product counts for each search
                searches.forEach((search: SavedSearch) => {
                    updateProductCount(search._id);
                });
            }
        } catch (error) {
            console.error("Error fetching saved searches:", error);
            toast.error("Unable to load saved searches");
        } finally {
            setLoading(false);
        }
    };

    const updateProductCount = async (searchId: string) => {
        try {
            const response = await axios.get(`/api/saved-searches/${searchId}/count`);
            if (response.data.success) {
                setSavedSearches((prev) =>
                    prev.map((s) =>
                        s._id === searchId
                            ? { ...s, productCount: response.data.data.count }
                            : s
                    )
                );
            }
        } catch (error) {
            console.error("Error updating product count:", error);
        }
    };

    const handleDeleteSearch = async (id: string) => {
        try {
            const response = await axios.delete(`/api/saved-searches/${id}`);
            if (response.data.success) {
                setSavedSearches(savedSearches.filter((s) => s._id !== id));
                toast.success("Saved search deleted");
            }
        } catch (error) {
            console.error("Error deleting saved search:", error);
            toast.error("Unable to delete saved search");
        }
    };

    const handleEditSearch = (search: SavedSearch) => {
        setSelectedSearch(search);
        setEditDialogOpen(true);
    };

    const handleSaveEdit = async (id: string, name: string) => {
        try {
            const response = await axios.put(`/api/saved-searches/${id}`, { name });
            if (response.data.success) {
                setSavedSearches((prev) =>
                    prev.map((s) => (s._id === id ? { ...s, name } : s))
                );
                toast.success("Saved search updated");
            }
        } catch (error) {
            console.error("Error updating saved search:", error);
            toast.error("Unable to update saved search");
        }
    };

    const handleRunSearch = (search: SavedSearch) => {
        const params = new URLSearchParams();
        if (search.searchQuery) params.set("q", search.searchQuery);
        if (search.filters.categoryId)
            params.set("category", search.filters.categoryId);
        if (search.filters.minPrice)
            params.set("minPrice", search.filters.minPrice.toString());
        if (search.filters.maxPrice)
            params.set("maxPrice", search.filters.maxPrice.toString());
        if (search.filters.condition)
            params.set("condition", search.filters.condition);
        if (search.filters.sortBy) params.set("sortBy", search.filters.sortBy);

        navigate(`/products?${params.toString()}`);
    };

    if (loading) {
        return (
            <div className="container mx-auto px-4 py-8">
                <div className="animate-pulse space-y-4">
                    <div className="h-8 bg-gray-200 rounded w-1/4"></div>
                    <div className="h-32 bg-gray-200 rounded"></div>
                    <div className="h-32 bg-gray-200 rounded"></div>
                </div>
            </div>
        );
    }

    return (
        <div className="container mx-auto px-4 py-8">
            <div className="max-w-4xl mx-auto">
                <h1 className="text-3xl font-bold mb-6">Saved Searches</h1>

                {savedSearches.length === 0 ? (
                    <Card className="p-12 text-center">
                        <Search className="w-16 h-16 mx-auto mb-4 text-gray-400" />
                        <h3 className="text-xl font-semibold mb-2">
                            No saved searches yet
                        </h3>
                        <p className="text-gray-600 mb-4">
                            Save your searches to quickly find items you're looking for
                        </p>
                        <Button onClick={() => navigate("/products")}>
                            Browse Products
                        </Button>
                    </Card>
                ) : (
                    <div className="space-y-4">
                        {savedSearches.map((search) => (
                            <Card key={search._id} className="p-6">
                                <div className="flex items-start justify-between">
                                    <div className="flex-1">
                                        <div className="flex items-center gap-3 mb-2">
                                            <h3 className="text-lg font-semibold">{search.name}</h3>
                                            <Badge variant="secondary" className="flex items-center gap-1">
                                                <Package className="w-3 h-3" />
                                                {search.productCount} products
                                            </Badge>
                                        </div>
                                        <p className="text-gray-600 mb-3">
                                            Search: "{search.searchQuery}"
                                        </p>

                                        {Object.keys(search.filters).length > 0 && (
                                            <div className="flex flex-wrap gap-2 mb-3">
                                                {search.filters.minPrice && (
                                                    <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-sm">
                                                        Min: ${search.filters.minPrice}
                                                    </span>
                                                )}
                                                {search.filters.maxPrice && (
                                                    <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-sm">
                                                        Max: ${search.filters.maxPrice}
                                                    </span>
                                                )}
                                                {search.filters.condition && (
                                                    <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-sm">
                                                        {search.filters.condition}
                                                    </span>
                                                )}
                                            </div>
                                        )}

                                        <p className="text-sm text-gray-500">
                                            Saved on{" "}
                                            {new Date(search.createdAt).toLocaleDateString()}
                                        </p>
                                    </div>

                                    <div className="flex gap-2 ml-4">
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            onClick={() => handleRunSearch(search)}
                                        >
                                            <ExternalLink className="w-4 h-4 mr-2" />
                                            Run Search
                                        </Button>
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            onClick={() => handleEditSearch(search)}
                                        >
                                            <Edit2 className="w-4 h-4" />
                                        </Button>
                                        <Button
                                            variant="ghost"
                                            size="sm"
                                            onClick={() => handleDeleteSearch(search._id)}
                                        >
                                            <Trash2 className="w-4 h-4 text-red-500" />
                                        </Button>
                                    </div>
                                </div>
                            </Card>
                        ))}
                    </div>
                )}
            </div>

            <EditSavedSearchDialog
                open={editDialogOpen}
                onOpenChange={setEditDialogOpen}
                savedSearch={selectedSearch}
                onSave={handleSaveEdit}
            />
        </div>
    );
}

import { useState, useEffect } from "react";
import { Trash2, Store, ExternalLink } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import axios from "@/lib/axios";
import { toast } from "sonner";

interface SavedSeller {
  _id: string;
  username: string;
  email: string;
  avatarUrl?: string;
  reputationScore: number;
  productCount: number;
}

export default function SavedSellersPage() {
  const [savedSellers, setSavedSellers] = useState<SavedSeller[]>([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchSavedSellers();
  }, []);

  const fetchSavedSellers = async () => {
    try {
      const response = await axios.get("/api/saved-sellers");
      if (response.data.success) {
        setSavedSellers(response.data.data);
      }
    } catch {
      toast.error("Unable to load saved sellers");
    } finally {
      setLoading(false);
    }
  };

  const handleRemoveSeller = async (sellerId: string) => {
    try {
      const response = await axios.delete(`/api/saved-sellers/${sellerId}`);
      if (response.data.success) {
        setSavedSellers((prev) => prev.filter((s) => s._id !== sellerId));
        toast.success("Seller removed from saved list");
      }
    } catch {
      toast.error("Unable to remove saved seller");
    }
  };

  if (loading) {
    return (
      <div className="space-y-3">
        {[1, 2, 3].map((i) => (
          <div key={i} className="bg-white rounded-xl border shadow-sm p-4 animate-pulse">
            <div className="flex items-center gap-4">
              <div className="h-12 w-12 rounded-full bg-muted" />
              <div className="flex-1 space-y-2">
                <div className="h-4 bg-muted rounded w-1/3" />
                <div className="h-3 bg-muted rounded w-1/2" />
              </div>
            </div>
          </div>
        ))}
      </div>
    );
  }

  if (savedSellers.length === 0) {
    return (
      <div className="bg-white rounded-xl border shadow-sm p-16 text-center">
        <div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center mx-auto mb-4">
          <Store className="w-8 h-8 text-muted-foreground" />
        </div>
        <h3 className="text-lg font-semibold mb-1">No saved sellers yet</h3>
        <p className="text-muted-foreground text-sm mb-4">
          Follow your favorite sellers to quickly find their products
        </p>
        <Button onClick={() => navigate("/products")}>Browse Products</Button>
      </div>
    );
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-lg font-semibold">
          Saved Sellers
          <span className="ml-2 text-sm font-normal text-muted-foreground">
            ({savedSellers.length})
          </span>
        </h2>
      </div>

      <div className="space-y-3">
        {savedSellers.map((seller) => (
          <div
            key={seller._id}
            className="bg-white rounded-xl border shadow-sm p-4 flex items-center gap-4 hover:shadow-md hover:border-primary/20 transition-all"
          >
            {/* Avatar */}
            <Avatar className="h-12 w-12 shrink-0">
              <AvatarImage src={seller.avatarUrl} alt={seller.username} />
              <AvatarFallback className="bg-primary/10 text-primary font-semibold">
                {seller.username.substring(0, 2).toUpperCase()}
              </AvatarFallback>
            </Avatar>

            {/* Info */}
            <div className="flex-1 min-w-0">
              <h3 className="font-semibold text-sm truncate">{seller.username}</h3>
              <p className="text-xs text-muted-foreground truncate">{seller.email}</p>
              <div className="flex items-center gap-2 mt-1">
                <span className="text-xs text-muted-foreground">Reputation:</span>
                <span className={`text-xs font-semibold ${
                  seller.reputationScore >= 80 ? "text-emerald-600" :
                  seller.reputationScore >= 50 ? "text-amber-600" : "text-red-500"
                }`}>
                  {seller.reputationScore}
                </span>
              </div>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-2 shrink-0">
              <Button
                size="sm"
                variant="outline"
                onClick={() => navigate(`/seller/${seller._id}`)}
              >
                <ExternalLink className="h-3.5 w-3.5 mr-1.5" />
                View Shop
              </Button>
              <Button
                size="sm"
                variant="ghost"
                className="text-muted-foreground hover:text-destructive hover:bg-destructive/10"
                onClick={() => handleRemoveSeller(seller._id)}
              >
                <Trash2 className="h-3.5 w-3.5" />
              </Button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import {
  type WatchlistItem,
  getUserWatchlist,
  toggleWatchlist,
} from "@/api/watchlist";
import { toast } from "sonner";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { useNavigate } from "react-router-dom";
import { formatProductPrice } from "@/lib/utils";
import { Heart, Trash2 } from "lucide-react";

export default function WatchlistPage() {
  const [watchlist, setWatchlist] = useState<WatchlistItem[]>([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  console.log(watchlist);

  const fetchWatchlist = async () => {
    try {
      setLoading(true);
      const res = await getUserWatchlist();
      setWatchlist(res.data.data);
    } catch (err) {
      console.error("Failed to load watchlist", err);
      toast.error("Failed to load watchlist");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchWatchlist();
  }, []);

  const handleRemoveFromWatchlist = async (
    productId: string,
    event: React.MouseEvent,
  ) => {
    event.stopPropagation(); // Prevent clicking on card
    try {
      await toggleWatchlist(productId);
      toast.success("Removed from watchlist");
      // Remove from local state
      setWatchlist((prev) =>
        prev.filter((item) => item.product._id !== productId),
      );
    } catch (err) {
      console.error("Failed to remove from watchlist", err);
      toast.error("Failed to remove from watchlist");
    }
  };

  const handleNavigateToProduct = (productId: string) => {
    navigate(`/products/${productId}`);
  };

  if (loading) {
    return (
      <div className="p-8 text-center text-muted-foreground">
        Loading watchlist...
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-semibold">Watchlist</h1>
        <div className="text-muted-foreground text-sm">
          {watchlist.length} items
        </div>
      </div>

      {watchlist.length === 0 ? (
        <div className="text-center py-12 border rounded-lg bg-muted/10">
          <Heart className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">
            Your watchlist is empty
          </h3>
          <p className="text-gray-600 mb-6">
            Keep track of items you're interested in by adding them to your
            watchlist.
          </p>
          <Button
            className="cursor-pointer"
            onClick={() => navigate("/products")}
          >
            Browse Products
          </Button>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-4">
          {watchlist.map((item) => {
            const product = item.product;
            if (!product) return null; // Handle case where product might be deleted

            return (
              <Card
                key={item._id}
                className="cursor-pointer hover:shadow-md transition-shadow"
                onClick={() => handleNavigateToProduct(product._id)}
              >
                <CardContent className="p-4 flex gap-6">
                  {/* Image */}
                  <div className="h-32 w-32 shrink-0 border rounded-md overflow-hidden bg-muted">
                    {product.image ||
                    (product.images && product.images.length > 0) ? (
                      <img
                        src={product.image || product.images?.[0]}
                        alt={product.title}
                        className="h-full w-full object-cover"
                      />
                    ) : (
                      <div className="h-full w-full flex items-center justify-center text-xs text-muted-foreground">
                        No Image
                      </div>
                    )}
                  </div>

                  {/* Content */}
                  <div className="flex-1 flex flex-col justify-between">
                    <div>
                      <h3 className="font-medium text-lg leading-tight mb-1 hover:underline text-blue-700">
                        {product.title}
                      </h3>
                      {product.condition && (
                        <div className="text-sm text-muted-foreground mb-2">
                          Condition: {product.condition}
                        </div>
                      )}
                      <div className="text-xs text-muted-foreground">
                        Sold by:{" "}
                        {product.sellerId?.username || "Unknown Seller"}
                      </div>
                      <div className="text-xs text-muted-foreground mt-1">
                        {product.watchCount} watchers
                      </div>
                    </div>
                  </div>

                  {/* Price and Actions */}
                  <div className="flex flex-col items-end justify-between min-w-[150px]">
                    <div className="text-xl font-bold">
                      {formatProductPrice(product as any)}
                    </div>
                    <Button
                      variant="ghost"
                      size="sm"
                      className="text-destructive cursor-pointer hover:text-destructive hover:bg-destructive/10 gap-2"
                      onClick={(e) => handleRemoveFromWatchlist(product._id, e)}
                    >
                      <Trash2 className="h-4 w-4" />
                      Remove
                    </Button>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { claimVoucherCode, getMyVoucherWallet, type Voucher } from "@/api/vouchers";
import { useAuth } from "@/hooks/use-auth";
import VoucherTicket from "@/components/voucher/voucher-ticket";

export default function GiftCardsPage() {
  const { user } = useAuth();
  const [code, setCode] = useState("");
  const [claiming, setClaiming] = useState(false);
  const [loading, setLoading] = useState(false);
  const [wallet, setWallet] = useState<Voucher[]>([]);

  const loadWallet = async () => {
    if (!user) return;
    try {
      setLoading(true);
      const response = await getMyVoucherWallet();
      setWallet(response.data || []);
    } catch (error: any) {
      toast.error(error?.response?.data?.message || "Failed to load vouchers");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadWallet();
  }, [user?.username]);

  const grouped = useMemo(() => {
    return {
      global: wallet.filter((item) => item.scope === "global"),
      seller: wallet.filter((item) => item.scope === "seller"),
    };
  }, [wallet]);

  const handleClaim = async () => {
    const normalized = code.trim().toUpperCase();
    if (!normalized) {
      toast.error("Please enter voucher code");
      return;
    }

    try {
      setClaiming(true);
      const response = await claimVoucherCode(normalized);
      toast.success(response.message || "Voucher claimed");
      setCode("");
      await loadWallet();
    } catch (error: any) {
      toast.error(error?.response?.data?.message || "Failed to claim voucher");
    } finally {
      setClaiming(false);
    }
  };

  if (!user) {
    return (
      <div className="py-10">
        <Card className="max-w-xl mx-auto">
          <CardHeader>
            <CardTitle>Gift Cards & Voucher Wallet</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            <p className="text-sm text-muted-foreground">
              Sign in to claim voucher codes and use them at checkout.
            </p>
            <Button asChild>
              <Link to="/auth/sign-in">Sign In</Link>
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="py-8 space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Gift Cards</h1>
        <p className="text-muted-foreground mt-1">
          Enter gift code to receive voucher into your wallet.
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Redeem Code</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex gap-2">
            <Input
              placeholder="Enter gift/voucher code"
              value={code}
              onChange={(e) => setCode(e.target.value.toUpperCase())}
              className="uppercase"
            />
            <Button onClick={handleClaim} disabled={claiming}>
              {claiming ? "Redeeming..." : "Redeem"}
            </Button>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card>
          <CardHeader>
            <CardTitle>Global Vouchers ({grouped.global.length})</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            {loading ? (
              <p className="text-sm text-muted-foreground">Loading...</p>
            ) : grouped.global.length === 0 ? (
              <p className="text-sm text-muted-foreground">No global vouchers in wallet.</p>
            ) : (
              grouped.global.map((voucher) => (
                <VoucherTicket key={voucher._id} voucher={voucher} />
              ))
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Shop Vouchers ({grouped.seller.length})</CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            {loading ? (
              <p className="text-sm text-muted-foreground">Loading...</p>
            ) : grouped.seller.length === 0 ? (
              <p className="text-sm text-muted-foreground">No shop vouchers in wallet.</p>
            ) : (
              grouped.seller.map((voucher) => (
                <VoucherTicket key={voucher._id} voucher={voucher} />
              ))
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

