  useEffect(() => {
    if (user?.username) setFullName(user.username);
    if (user?.email) setEmail(user.email);
  }, [user?.username, user?.email]);

  const canSubmit = useMemo(() => {
    return (
      fullName.trim().length >= 2 &&
      email.trim().includes("@") &&
      subject.trim().length >= 3 &&
      message.trim().length >= 10
