}

// ─── Main component ───────────────────────────────────────────────────────────
function OrderDetailsPopup({
  order,
  onClose,
}: {
  order: Order | null;
  onClose: () => void;
}) {
  if (!order) return null;

  const subtotal =
    order.orderDetails?.reduce(
      (sum, i) => sum + (i.unitPrice ?? 0) * (i.quantity ?? 1),
      0,
    ) ??
    order.total ??
    0;

  return (
    <>
      {/* Backdrop */}
      <div
        onClick={onClose}
        style={{
          position: "fixed",
          inset: 0,
          background: "rgba(15,23,42,0.45)",
          backdropFilter: "blur(4px)",
          zIndex: 50,
          animation: "fadeIn 0.2s ease",
        }}
      />

      {/* Panel */}
      <div
        style={{
          position: "fixed",
          inset: 0,
          zIndex: 51,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          padding: 16,
        }}
      >
        <div
          style={{
            background: "#FFFFFF",
            borderRadius: 20,
            boxShadow:
              "0 25px 60px rgba(15,23,42,0.18), 0 0 0 1px rgba(148,163,184,0.12)",
            width: "100%",
            maxWidth: 820,
            maxHeight: "92vh",
            display: "flex",
            flexDirection: "column",
            animation: "slideUp 0.25s cubic-bezier(0.16,1,0.3,1)",
            fontFamily: "'DM Sans', 'Geist', system-ui, sans-serif",
          }}
        >
          {/* ── Header ── */}
          <div
            style={{
              padding: "24px 28px 20px",
              borderBottom: "1px solid #F1F5F9",
              display: "flex",
              alignItems: "flex-start",
              justifyContent: "space-between",
            }}
          >
            <div>
              <h2
                style={{
                  fontSize: 22,
                  fontWeight: 700,
                  color: "#0F172A",
                  margin: 0,
                  letterSpacing: "-0.02em",
                }}
              >
                Order Details
              </h2>
              <p style={{ fontSize: 13, color: "#64748B", marginTop: 3 }}>
                {order.orderId || order._id}
              </p>
            </div>
            <button
              onClick={onClose}
              style={{
                width: 34,
                height: 34,
                borderRadius: 10,
                border: "1px solid #E2E8F0",
                background: "#F8FAFC",
                cursor: "pointer",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                color: "#64748B",
                transition: "all 0.15s",
              }}
              onMouseEnter={(e) => {
                (e.currentTarget as HTMLButtonElement).style.background =
                  "#F1F5F9";
              }}
              onMouseLeave={(e) => {
                (e.currentTarget as HTMLButtonElement).style.background =
                  "#F8FAFC";
              }}
            >
              <X size={16} />
            </button>
          </div>

          {/* ── Body ── */}
          <div style={{ overflowY: "auto", padding: "24px 28px", flex: 1 }}>
            {/* Info grid */}
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr",
                gap: "28px 48px",
                marginBottom: 32,
              }}
            >
              {/* Customer */}
              <InfoBlock
                icon={<User size={16} color="#6366F1" />}
                label="Customer"
              >
                <p
                  style={{
                    fontWeight: 700,
                    color: "#0F172A",
                    fontSize: 15,
                    margin: "0 0 2px",
                  }}
                >
                  {order.username}
                </p>
                <p style={{ color: "#64748B", fontSize: 13, margin: 0 }}>
                  {order.email}
                </p>
                {order.phone && (
                  <p
                    style={{
                      color: "#64748B",
                      fontSize: 13,
                      margin: "2px 0 0",
                    }}
                  >
                    {order.phone}
                  </p>
                )}
              </InfoBlock>

              {/* Order Time */}
              <InfoBlock
                icon={<Clock size={16} color="#8B5CF6" />}
                label="Order Time"
              >
                <p
                  style={{
                    fontWeight: 600,
                    color: "#0F172A",
                    fontSize: 14,
                    margin: 0,
                  }}
                >
                  {formatDate(order.createdAt || order.date)}
                </p>
                {order.updatedAt && order.updatedAt !== order.createdAt && (
                  <p
                    style={{
                      color: "#94A3B8",
                      fontSize: 12,
                      margin: "3px 0 0",
                    }}
                  >
                    Updated {formatDate(order.updatedAt)}
                  </p>
                )}
              </InfoBlock>

              {/* Address */}
              {order.address && (
                <InfoBlock
                  icon={<MapPin size={16} color="#F43F5E" />}
                  label="Delivery Address"
                >
                  <p
                    style={{
                      color: "#334155",
                      fontSize: 13,
                      margin: 0,
                      lineHeight: 1.5,
                    }}
                  >
                    {order.address}
                  </p>
                </InfoBlock>
              )}

              <InfoBlock
                icon={<Package size={16} color="#F59E0B" />}
                label="Status"
              >
                <div style={{ marginTop: 2 }}>
                  <StatusPill status={order.status} />
                </div>
              </InfoBlock>

              {/* Shipper */}
              <InfoBlock
                icon={<Truck size={16} color="#8B5CF6" />}
                label="Shipper"
              >
                {order.shipper ? (
                  <>
                    <p style={{ fontWeight: 700, color: "#0F172A", fontSize: 15, margin: "0 0 2px" }}>
                      {order.shipper.username}
                    </p>
                    <p style={{ color: "#64748B", fontSize: 13, margin: 0 }}>
                      {order.shipper.email}
                    </p>
                  </>
                ) : (
                  <p style={{ color: "#94A3B8", fontSize: 13, margin: 0, fontStyle: "italic" }}>
                    Not assigned yet
                  </p>
                )}
              </InfoBlock>

              {/* Payment + Status */}
              <InfoBlock
                icon={<CreditCard size={16} color="#10B981" />}
                label="Payment"
              >
                <p
                  style={{
                    fontWeight: 600,
                    color: "#0F172A",
                    fontSize: 14,
                    margin: 0,
                    textTransform: "uppercase",
                    letterSpacing: "0.04em",
                  }}
                >
                  {order.paymentMethod}
                </p>
              </InfoBlock>
              <InfoBlock
                icon={<Wallet size={16} color="#F59E0B" />}
                label="Payment Status"
              >
                <div style={{ marginTop: 2 }}>
                  <PaymentStatusPill paymentStatus={order.paymentStatus} />
                </div>
              </InfoBlock>

              {/* Note */}
              {order.note && (
                <div style={{ gridColumn: "1 / -1" }}>
                  <InfoBlock
                    icon={
                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          justifyContent: "center",
                          width: 16,
                          height: 16,
                        }}
                      >
                        <svg
                          width="14"
                          height="14"
                          viewBox="0 0 24 24"
                          fill="none"
                          stroke="#F59E0B"
                          strokeWidth="2"
                          strokeLinecap="round"
                          strokeLinejoin="round"
                        >
                          <path d="M14.5 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V7.5L14.5 2z"></path>
                          <polyline points="14 2 14 8 20 8"></polyline>
                          <line x1="16" y1="13" x2="8" y2="13"></line>
                          <line x1="16" y1="17" x2="8" y2="17"></line>
                          <line x1="10" y1="9" x2="8" y2="9"></line>
                        </svg>
                      </div>
                    }
                    label="Note from Buyer"
                  >
                    <p
                      style={{
                        color: "#475569",
                        fontSize: 13,
                        margin: 0,
                        lineHeight: 1.5,
                        fontStyle: "italic",
                        backgroundColor: "#FFFBEB",
                        padding: "8px 12px",
                        borderRadius: "8px",
                        border: "1px solid #FEF3C7",
                        borderLeft: "3px solid #F59E0B",
                      }}
                    >
                      "{order.note}"
                    </p>
                  </InfoBlock>
                </div>
              )}
              {order.status === "cancelled" &&
                order.statusHistory &&
                (() => {
                  const cancelEntry = order.statusHistory.find(
                    (h) => h.status === "cancelled" && h.note && h.note.trim(),
                  );
                  if (!cancelEntry) return null;
                  return (
                    <div style={{ gridColumn: "1 / -1" }}>
                      <InfoBlock
                        icon={<XCircle size={16} color="#EF4444" />}
                        label="Cancellation Reason"
                      >
                        <p
                          style={{
                            color: "#B91C1C",
                            fontSize: 13,
                            margin: 0,
                            lineHeight: 1.5,
                            fontStyle: "italic",
                            backgroundColor: "#FEF2F2",
                            padding: "8px 12px",
                            borderRadius: "8px",
                            border: "1px solid #FECACA",
                          }}
                        >
                          "{cancelEntry.note}"
                        </p>
                      </InfoBlock>
                    </div>
                  );
                })()}
            </div>

            {/* ── Shipping History ── */}
            {order.statusHistory && order.statusHistory.length > 0 && (
              <div style={{ gridColumn: "1 / -1" }}>
                <ShippingTimeline
                  statusHistory={order.statusHistory}
                  currentStatus={order.status}
                />
              </div>
            )}

            {/* ── Products table ── */}
            <div>
              <h3
                style={{
                  fontSize: 13,
                  fontWeight: 700,
                  letterSpacing: "0.06em",
                  textTransform: "uppercase",
                  color: "#94A3B8",
                  margin: "0 0 12px",
                  display: "flex",
                  alignItems: "center",
                  gap: 6,
                }}
              >
                <Package size={13} />
                Products · {order.orderDetails?.length || order.items || 0} item
                {(order.orderDetails?.length ?? 1) !== 1 ? "s" : ""}
              </h3>

              <div
                style={{
                  border: "1px solid #E2E8F0",
                  borderRadius: 14,
                  overflow: "hidden",
                }}
              >
                {/* Table head */}
                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "1fr 120px 80px 110px",
                    background: "#F8FAFC",
                    borderBottom: "1px solid #E2E8F0",
                    padding: "10px 16px",
                  }}
                >
                  {["Product", "Unit Price", "Qty", "Subtotal"].map((h) => (
                    <span
                      key={h}
                      style={{
                        fontSize: 11,
                        fontWeight: 700,
                        color: "#94A3B8",
                        letterSpacing: "0.06em",
                        textTransform: "uppercase",
                      }}
                    >
                      {h}
                    </span>
                  ))}
                </div>

                {/* Rows */}
                {order.orderDetails && order.orderDetails.length > 0 ? (
                  order.orderDetails.map((item, i) => (
                    <div
                      key={i}
                      style={{
                        display: "flex",
                        flexDirection: "column",
                        borderTop: i > 0 ? "1px solid #F1F5F9" : "none",
                      }}
                    >
                      <div
                        style={{
                          display: "grid",
                          gridTemplateColumns: "1fr 120px 80px 110px",
                          padding: "14px 16px",
                          alignItems: "center",
                          transition: "background 0.1s",
                        }}
                        onMouseEnter={(e) => {
                          (e.currentTarget as HTMLDivElement).style.background =
                            "#F8FAFC";
                        }}
                        onMouseLeave={(e) => {
                          (e.currentTarget as HTMLDivElement).style.background =
                            "transparent";
                        }}
                      >
                        {/* Product cell */}
                        <div
                          style={{
                            display: "flex",
                            alignItems: "center",
                            gap: 12,
                          }}
                        >
                          {item.productImage ? (
                            <img
                              src={item.productImage}
                              alt={item.productName}
                              style={{
                                width: 44,
                                height: 44,
                                borderRadius: 10,
                                objectFit: "cover",
                                border: "1px solid #E2E8F0",
                              }}
                            />
                          ) : (
                            <div
                              style={{
                                width: 44,
                                height: 44,
                                borderRadius: 10,
                                background:
                                  "linear-gradient(135deg, #EEF2FF, #E0E7FF)",
                                display: "flex",
                                alignItems: "center",
                                justifyContent: "center",
                                border: "1px solid #E0E7FF",
                              }}
                            >
                              <Package size={18} color="#818CF8" />
                            </div>
                          )}
                          <div>
                            <p
                              style={{
                                fontWeight: 600,
                                color: "#0F172A",
                                fontSize: 14,
                                margin: "0 0 2px",
                              }}
                            >
                              {item.productName}
                            </p>
                            {item.selectedVariants?.length ? (
                              <p
                                style={{
                                  fontSize: 12,
                                  color: "#64748B",
                                  margin: "0 0 2px",
                                }}
                              >
                                {item.selectedVariants
                                  .map((v) => `${v.name}: ${v.value}`)
                                  .join(" · ")}
                              </p>
                            ) : null}
                            <p
                              style={{
                                fontSize: 11,
                                color: "#D1D1D1",
                                margin: 0,
                              }}
                            >
                              ID: {item.productId}
                              {item.variantSku
                                ? ` · SKU: ${item.variantSku}`
                                : ""}
                            </p>
                          </div>
                        </div>

                        <span style={{ color: "#475569", fontSize: 14 }}>
                          ${item.unitPrice?.toFixed(2) ?? "0.00"}
                        </span>
                        <span style={{ color: "#475569", fontSize: 14 }}>
                          {item.quantity}
                        </span>
                        <span
                          style={{
                            fontWeight: 600,
                            color: "#0F172A",
                            fontSize: 14,
                            justifySelf: "end",
                          }}
                        >
                          ${item.subtotal?.toFixed(2) ?? "0.00"}
                        </span>
                      </div>
                      {item.note && (
                        <div
                          style={{
                            margin: "0 16px 12px",
                            padding: "8px 12px",
                            background: "#FEF3C7", // yellow-100
                            border: "1px solid #FDE68A", // yellow-200
                            borderRadius: 8,
                            fontSize: 13,
                            color: "#92400E", // yellow-800
                            fontStyle: "italic",
                          }}
                        >
                          Note: "{item.note}"
                        </div>
                      )}
                    </div>
                  ))
                ) : (
                  <div
                    style={{
                      display: "grid",
                      gridTemplateColumns: "1fr 120px 80px 110px",
                      padding: "14px 16px",
                      alignItems: "center",
                    }}
                  >
                    <span style={{ color: "#475569", fontSize: 14 }}>
                      Ordered Product
                    </span>
                    <span style={{ color: "#475569", fontSize: 14 }}>
                      ${order.total?.toFixed(2) ?? "0.00"}
                    </span>
                    <span style={{ color: "#475569", fontSize: 14 }}>
                      {order.items}
                    </span>
                    <span
                      style={{
                        fontWeight: 700,
                        color: "#0F172A",
                        fontSize: 14,
                      }}
                    >
                      ${order.total?.toFixed(2) ?? "0.00"}
                    </span>
                  </div>
                )}
              </div>
            </div>

            {/* ── Total ── */}
            <div
              style={{
                marginTop: 20,
                display: "flex",
                justifyContent: "flex-end",
              }}
            >
              <div
                style={{
                  background:
                    "linear-gradient(135deg, #EEF2FF 0%, #F5F3FF 100%)",
                  border: "1px solid #E0E7FF",
                  borderRadius: 14,
                  padding: "14px 24px",
                  display: "flex",
                  alignItems: "center",
                  gap: 48,
                  minWidth: 260,
                }}
              >
                <span
                  style={{
                    fontWeight: 600,
                    color: "#64748B",
                    fontSize: 14,
                    letterSpacing: "0.02em",
                  }}
                >
                  Order Total
                </span>
                <span
                  style={{
                    fontWeight: 800,
                    color: "#4F46E5",
                    fontSize: 22,
                    letterSpacing: "-0.03em",
                  }}
                >
                  ${(order.total ?? subtotal).toFixed(2)}
                </span>
              </div>
            </div>
          </div>

          {/* ── Footer ── */}
          <div
            style={{
              borderTop: "1px solid #F1F5F9",
              padding: "16px 28px",
              display: "flex",
              justifyContent: "flex-end",
              gap: 10,
            }}
          >
            <button
              onClick={onClose}
              style={{
                padding: "9px 20px",
                borderRadius: 10,
                border: "1px solid #E2E8F0",
                background: "#F8FAFC",
                color: "#475569",
                fontSize: 14,
                fontWeight: 600,
                cursor: "pointer",
                transition: "all 0.15s",
                fontFamily: "inherit",
              }}
              onMouseEnter={(e) => {
                (e.currentTarget as HTMLButtonElement).style.background =
                  "#F1F5F9";
              }}
              onMouseLeave={(e) => {
                (e.currentTarget as HTMLButtonElement).style.background =
                  "#F8FAFC";
              }}
            >
              Close
            </button>
          </div>
        </div>
      </div>

      {/* Animations */}
      <style>{`
        @keyframes fadeIn { from { opacity: 0 } to { opacity: 1 } }
        @keyframes slideUp { from { opacity: 0; transform: translateY(20px) scale(0.97) } to { opacity: 1; transform: translateY(0) scale(1) } }
      `}</style>
    </>
  );
}

export default function SellerOrders() {
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedStatus, setSelectedStatus] = useState("all");
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState<any>(null);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [showOrderDetails, setShowOrderDetails] = useState(false);
  const [loadingDetails, setLoadingDetails] = useState(false);

  // cancellation UI state
  const [cancelDialogOpen, setCancelDialogOpen] = useState(false);
  const [cancelReason, setCancelReason] = useState("");
  const [orderIdToCancel, setOrderIdToCancel] = useState<string | null>(null);
  const [pendingStatus, setPendingStatus] = useState<Order["status"] | null>(
    null,
  );
  const [cancelProcessing, setCancelProcessing] = useState(false);

  useEffect(() => {
    fetchOrders();
    fetchStats();
  }, [selectedStatus]);

  const fetchOrders = async () => {
    setLoading(true);
    try {
      const params: any = {};
      if (selectedStatus !== "all") params.status = selectedStatus;
      const result = await orderService.getOrders(params);
      setOrders(result.orders);
    } catch (error) {
      console.error("Error fetching orders:", error);
      toast.error("Unable to load orders list");
    } finally {
      setLoading(false);
    }
  };

  const fetchStats = async () => {
    try {
      const statsData = await orderService.getOrderStats();
      setStats(statsData);
    } catch (error) {
      console.error("Error fetching stats:", error);
    }
  };

  const handleViewOrderDetails = async (orderId: string) => {
    setLoadingDetails(true);
    try {
      const orderDetails = await orderService.getOrderById(orderId);
      if (orderDetails) {
        setSelectedOrder(orderDetails);
        setShowOrderDetails(true);
      } else {
        toast.error("Unable to load order details");
      }
    } catch (error) {
      console.error("Error fetching order details:", error);
      toast.error("An error occurred while loading order details");
    } finally {
      setLoadingDetails(false);
    }
  };

  const statuses = [
    { value: "all", label: "All", icon: Package },
    { value: "created", label: "New Order", icon: Clock },
    { value: "cancel_requested", label: "Cancel Request", icon: AlertTriangle },
    { value: "packaging", label: "Packaging", icon: Package },
    { value: "ready_to_ship", label: "Waiting", icon: Package },
    { value: "shipping", label: "Shipping", icon: Truck },
    { value: "delivered", label: "Delivered", icon: CheckCircle },
    { value: "cancelled", label: "Cancelled", icon: XCircle },
    { value: "completed", label: "Completed", icon: CheckCircle },
    { value: "failed", label: "Failed", icon: XCircle },
  ];

  const filteredOrders = orders.filter((order) => {
    const term = searchTerm.toLowerCase();
    return (
      order._id.toLowerCase().includes(term) ||
      order.username.toLowerCase().includes(term) ||
      order.email.toLowerCase().includes(term)
    );
  });

  const getStatusBadge = (status: Order["status"]) => {
    switch (status) {
      case "created":
        return (
          <Badge
            variant="outline"
            className="border-yellow-300 text-yellow-800 bg-yellow-50"
          >
            New Order
          </Badge>
        );

      case "packaging":
        return (
          <Badge
            variant="outline"
            className="border-blue-300 text-blue-800 bg-blue-50"
          >
            Packaging
          </Badge>
        );
      case "ready_to_ship":
        return (
          <Badge
            variant="outline"
            className="border-blue-300 text-blue-800 bg-blue-50"
          >
            Waiting
          </Badge>
        );
      case "pending_acceptance":
        return (
          <Badge
            variant="outline"
            className="border-orange-300 text-orange-800 bg-orange-50"
          >
            Waiting Shipper
          </Badge>
        );
      case "shipping":
        return (
          <Badge
            variant="outline"
            className="border-purple-300 text-purple-800 bg-purple-50"
          >
            Shipping
          </Badge>
        );
      case "delivered":
        return (
          <Badge
            variant="outline"
            className="border-green-300 text-green-800 bg-green-50"
          >
            Delivered
          </Badge>
        );
      case "completed":
        return (
          <Badge
            variant="outline"
            className="border-emerald-400 text-emerald-800 bg-emerald-50"
          >
            Completed
          </Badge>
        );
      case "returned":
        return (
          <Badge
            variant="outline"
            className="border-purple-300 text-purple-800 bg-purple-50"
          >
            Returned
          </Badge>
        );
      case "cancelled":
        return (
          <Badge
            variant="outline"
            className="border-red-300 text-red-800 bg-red-50"
          >
            Cancelled
          </Badge>
        );
      case "failed":
        return (
          <Badge
            variant="outline"
            className="border-red-300 text-red-800 bg-red-50"
          >
            Failed
          </Badge>
        );
      case "cancel_requested":
        return (
          <Badge
            variant="outline"
            className="border-amber-300 text-amber-800 bg-amber-50"
          >
            Cancel Requested
          </Badge>
        );
      case "queued":
        return (
          <Badge
            variant="outline"
            className="border-orange-300 text-orange-800 bg-orange-50"
          >
            Waiting
          </Badge>
        );
      default:
        return <Badge variant="outline">Unknown</Badge>;
    }
  };

  const handleUpdateStatus = async (
    orderId: string,
    newStatus: Order["status"],
  ) => {
    try {
      const success = await orderService.updateOrderStatus(orderId, newStatus);
      if (!success) {
        toast.error("Update failed");
        return;
      }

      toast.success(`Updated order status ${orderId}`);
      fetchOrders();
      fetchStats();

      if (selectedOrder && selectedOrder._id === orderId) {
        const updatedOrder = await orderService.getOrderById(orderId);
        setSelectedOrder(updatedOrder);
      }
    } catch {
      toast.error("An error occurred while updating");
    }
  };

  const openResolutionDialog = (
    orderId: string,
    targetStatus: Order["status"],
  ) => {
    setOrderIdToCancel(orderId);
    setPendingStatus(targetStatus);
    setCancelReason("");
    setCancelDialogOpen(true);
  };

  const handleCancelWithReason = async () => {
    if (!orderIdToCancel) return;
    if (!cancelReason.trim()) {
      toast.error("Please provide a reason for cancellation");
      return;
    }
    const targetStatus = pendingStatus || "cancelled";
    setCancelProcessing(true);
    try {
      const success = await orderService.updateOrderStatus(
        orderIdToCancel,
        targetStatus,
        cancelReason.trim(),
      );
      if (success) {
        toast.success("Order cancelled successfully");
        fetchOrders();
        fetchStats();
        if (selectedOrder && selectedOrder._id === orderIdToCancel) {
          const updated = await orderService.getOrderById(orderIdToCancel);
          setSelectedOrder(updated);
        }
      } else {
        toast.error("Failed to cancel order");
      }
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to cancel order");
    } finally {
      setCancelProcessing(false);
      setCancelDialogOpen(false);
      setOrderIdToCancel(null);
    }
  };

  const totalRevenue = stats?.totalRevenue || 0;

  if (loading) {
    return (
      <div className="p-6">
        <div className="flex items-center justify-center h-64">
          <div className="text-center">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-gray-900 mx-auto"></div>
            <p className="mt-4 text-gray-600">Loading orders...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 relative">
      {showOrderDetails && (
        <OrderDetailsPopup
          order={selectedOrder}
          onClose={() => {
            setShowOrderDetails(false);
            setSelectedOrder(null);
          }}
        />
      )}

      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Order Management</h1>
          <p className="text-gray-600">
            {filteredOrders.length} orders - Total revenue: $
            {totalRevenue.toFixed(2)}
            {stats && ` | Total orders: ${stats.totalOrders || 0}`}
          </p>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-6">
        {statuses.slice(1).map((status) => {
          const Icon = status.icon;
          const count = status.value === "ready_to_ship"
            ? (stats?.counts?.ready_to_ship || 0) + (stats?.counts?.queued || 0) + (stats?.counts?.pending_acceptance || 0)
            : stats?.counts?.[status.value] || 0;
          return (
            <Card key={status.value}>
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-gray-50">
                    <Icon className="h-5 w-5 text-gray-600" />
                  </div>
                  <div>
                    <div className="text-2xl font-bold">{count}</div>
                    <div className="text-sm text-gray-600">{status.label}</div>
                  </div>
                </div>
              </CardContent>
            </Card>
          );
        })}
      </div>

      <Card className="mb-6">
        <CardContent className="p-4">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-3 h-4 w-4 text-gray-400" />
                <Input
                  placeholder="Search by ID, customer name, or email..."
                  className="pl-10"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
            </div>

            <div className="flex w-[80%] gap-2 overflow-x-auto flex-wrap">
              {statuses.map((status) => {
                const Icon = status.icon;
                return (
                  <Button
                    key={status.value}
                    variant={
                      selectedStatus === status.value ? "default" : "outline"
                    }
                    size="sm"
                    onClick={() => setSelectedStatus(status.value)}
                    className="whitespace-nowrap cursor-pointer"
                  >
                    <Icon className="h-4 w-4 mr-2" />
                    {status.label}
                  </Button>
                );
              })}
            </div>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b">
                  <th className="text-left p-4 font-medium text-gray-600">
                    Order ID
                  </th>
                  <th className="text-left p-4 font-medium text-gray-600">
                    Product
                  </th>
                  <th className="text-left p-4 font-medium text-gray-600">
                    Customer
                  </th>
                  <th className="text-left p-4 font-medium text-gray-600">
                    Shipper
                  </th>
                  <th className="text-left p-4 font-medium text-gray-600">
                    Quantity
                  </th>
                  <th className="text-left p-4 font-medium text-gray-600">
                    Total
                  </th>
                  <th className="text-left p-4 font-medium text-gray-600">
                    Payment Status
                  </th>
                  <th className="text-left p-4 font-medium text-gray-600">
                    Status
                  </th>
                  <th className="text-left p-4 font-medium text-gray-600">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody>
                {filteredOrders.map((order) => (
                  <tr key={order._id} className="border-b hover:bg-gray-50">
                    <td className="p-4">
                      <div className="font-medium">
                        {order.orderId || order._id}
                      </div>
                      <div className="text-sm text-gray-500">
                        {order.paymentMethod}
                      </div>
                    </td>
                    <td className="p-4">
                      <div
                        className="font-medium text-sm truncate max-w-[200px]"
                        title={order.orderDetails
                          ?.map((item) => item.productName)
                          .join(", ")}
                      >
                        {order.orderDetails
                          ?.map((item) => item.productName)
                          .join(", ") || "—"}
                      </div>
                    </td>
                    <td className="p-4">
                      <div className="font-medium">{order.username}</div>
                      <div className="text-sm text-gray-500">{order.email}</div>
                    </td>
                    <td className="p-4">
                      {order.shipper ? (
                        <div className="font-medium text-sm">
                          {order.shipper.username}
                        </div>
                      ) : (
                        <span className="text-xs text-gray-400 italic">
                          Not assigned
                        </span>
                      )}
                    </td>
                    <td className="p-4">{order.items} products</td>
                    <td className="p-4 font-medium">
                      ${order.total.toFixed(2)}
                    </td>
                    <td className="p-4">
                      <PaymentStatusPill paymentStatus={order.paymentStatus} />
                    </td>
                    <td className="p-4">{getStatusBadge(order.status)}</td>
                    <td className="p-4">
                      <div className="flex items-center gap-2">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => handleViewOrderDetails(order._id)}
                          disabled={loadingDetails}
                          className="cursor-pointer"
                        >
                          {loadingDetails &&
                          selectedOrder?._id === order._id ? (
                            <div className="h-4 w-4 border-2 border-gray-300 border-t-gray-600 rounded-full animate-spin" />
                          ) : (
                            <Eye className="h-4 w-4" />
                          )}
                        </Button>
                        <DropdownMenu>
                          {[
                            "created",
                            "packaging",
                            "cancel_requested",
                          ].includes(order.status) && (
                            <DropdownMenuTrigger asChild>
                              <Button
                                variant="ghost"
                                className="cursor-pointer"
                                size="sm"
                              >
                                <MoreVertical className="h-4 w-4" />
                              </Button>
                            </DropdownMenuTrigger>
                          )}
                          <DropdownMenuContent align="end">
                            {order.status === "created" && (
                              <DropdownMenuItem
                                className="cursor-pointer"
                                onClick={() =>
                                  handleUpdateStatus(order._id, "packaging")
                                }
                              >
                                <Truck className="h-4 w-4 mr-2" />
                                Mark as Packaging
                              </DropdownMenuItem>
                            )}
                            {order.status === "cancel_requested" && (
                              <>
                                <DropdownMenuItem
                                  className="cursor-pointer text-green-600 hover:text-green-600"
                                  onClick={() =>
                                    openResolutionDialog(order._id, "cancelled")
                                  }
                                >
                                  <CheckCircle className="h-4 w-4 mr-2" />
                                  Approve Cancellation
                                </DropdownMenuItem>
                                <DropdownMenuItem
                                  className="cursor-pointer text-red-600 hover:text-red-600"
                                  onClick={() =>
                                    openResolutionDialog(order._id, "packaging")
                                  }
                                >
                                  <X className="h-4 w-4 mr-2" />
                                  Reject Cancellation
                                </DropdownMenuItem>
                              </>
                            )}
                            {order.status === "packaging" && (
                              <DropdownMenuItem
                                className="cursor-pointer"
                                onClick={() =>
                                  handleUpdateStatus(order._id, "ready_to_ship")
                                }
                              >
                                <Truck className="h-4 w-4 mr-2" />
                                Mark as Ready to Ship
                              </DropdownMenuItem>
                            )}
                            {["created", "packaging", "ready_to_ship"].includes(
                              order.status,
                            ) && (
                              <DropdownMenuItem
                                className="cursor-pointer text-red-600"
                                onClick={() =>
                                  openResolutionDialog(order._id, "cancelled")
                                }
                              >
                                <XCircle className="h-4 w-4 mr-2" />
                                Cancel Order
                              </DropdownMenuItem>
                            )}
                          </DropdownMenuContent>
                        </DropdownMenu>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      {filteredOrders.length === 0 && (
        <div className="text-center py-12">
          <Package className="h-12 w-12 text-gray-400 mx-auto mb-4" />
          <h3 className="text-lg font-medium text-gray-900 mb-2">
            No orders found
          </h3>
          <p className="text-gray-600">
            Try changing filters or search keywords
          </p>
        </div>
      )}

      {/* Cancel order dialog for seller */}
      <AlertDialog open={cancelDialogOpen} onOpenChange={setCancelDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>
              {pendingStatus === "cancelled" || !pendingStatus
                ? "Cancel Order"
                : "Reject Cancellation Request"}
            </AlertDialogTitle>
            <AlertDialogDescription>
              {pendingStatus === "cancelled" || !pendingStatus
                ? "Please provide a reason for cancelling this order. The buyer will see it in their order details."
                : "Please provide a reason for rejecting the cancellation request. The order will remain in 'Packaging' status."}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="mt-2">
            <Textarea
              value={cancelReason}
              onChange={(e) => setCancelReason(e.target.value)}
              placeholder="Reason for cancellation"
              rows={4}
            />
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel
              onClick={() => {
                setCancelDialogOpen(false);
                setOrderIdToCancel(null);
                setPendingStatus(null);
              }}
            >
              Keep Order
            </AlertDialogCancel>
            <AlertDialogAction
              className={
                pendingStatus === "packaging"
                  ? "bg-amber-600 hover:bg-amber-700 text-white"
                  : "bg-red-600 hover:bg-red-700 text-white"
              }
              onClick={handleCancelWithReason}
              disabled={cancelProcessing || !cancelReason.trim()}
            >
              {cancelProcessing
                ? "Processing..."
                : pendingStatus === "packaging"
                  ? "Confirm Reject"
                  : "Confirm"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useEffect, useState } from "react";
import api from "@/lib/axios";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { toast } from "sonner";
import { Eye, CheckCircle2, AlertTriangle } from "lucide-react";

type RefundRequest = {
    _id: string;
    order: { _id: string; totalAmount: number; status: string; items?: any[] };
    buyer: { _id: string; username: string };
    reason: string;
    description: string;
    faultType: string;
    status: string;
    requestedAt: string;
    sellerNote?: string;
    adminNote?: string;
    images?: string[];
};

export default function SellerRefunds() {
    const [refunds, setRefunds] = useState<RefundRequest[]>([]);
    const [loading, setLoading] = useState(true);
    const [page] = useState(1);

    // Dialog state
    const [selectedRefund, setSelectedRefund] = useState<RefundRequest | null>(null);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [sellerNote, setSellerNote] = useState("");
    const [pendingAction, setPendingAction] = useState<"APPROVE" | "REJECT" | "CONFIRM_RECEIPT" | null>(null);
    const [submitting, setSubmitting] = useState(false);
    const [returnCondition, setReturnCondition] = useState<"SELLABLE" | "OPENED" | "DAMAGED">("SELLABLE");

    useEffect(() => {
        fetchRefunds();
    }, [page]);

    const fetchRefunds = async () => {
        try {
            setLoading(true);
            const res = await api.get(`/api/refund/seller?page=${page}&limit=20`);
            setRefunds(res.data.data || []);
        } catch (err: any) {
            toast.error("Failed to load refund requests");
        } finally {
            setLoading(false);
        }
    };

    const handleAction = async (actionType: "APPROVE" | "REJECT") => {
        if (!selectedRefund) return;
        if (actionType === "REJECT" && !sellerNote.trim()) {
            toast.error("Please provide a reason for rejection.");
            return;
        }

        try {
            setSubmitting(true);
            setPendingAction(actionType);
            const endpoint = actionType === "APPROVE" ? "approve" : "reject";
            await api.post(`/api/refund/${selectedRefund._id}/${endpoint}`, {
                sellerNote,
            });

            toast.success(`Refund ${actionType.toLowerCase()}d successfully`);
            setIsDialogOpen(false);
            fetchRefunds();
        } catch (err: any) {
            toast.error(err.response?.data?.message || `Failed to ${actionType.toLowerCase()} refund`);
        } finally {
            setSubmitting(false);
            setPendingAction(null);
        }
    };

    const handleConfirmReceipt = async () => {
        if (!selectedRefund) return;
        try {
            setSubmitting(true);
            setPendingAction("CONFIRM_RECEIPT");
            await api.post(`/api/refund/${selectedRefund._id}/confirm-receipt`, { condition: returnCondition });
            toast.success("Return receipt confirmed successfully. Refund completed.");
            setIsDialogOpen(false);
            fetchRefunds();
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to confirm return receipt");
        } finally {
            setSubmitting(false);
            setPendingAction(null);
        }
    };

    const getStatusTheme = (status: string) => {
        switch (status) {
            case "PENDING":
                return { badge: "secondary", text: "Pending Review" };
            case "APPROVED":
            case "AUTO_APPROVED":
            case "ADMIN_APPROVED":
                return { badge: "default", text: "Approved" };
            case "REJECTED":
            case "ADMIN_REJECTED":
                return { badge: "destructive", text: "Rejected" };
            case "DISPUTED":
                return { badge: "warning", text: "Under Dispute" };
            case "SELLER_RECEIVED_RETURN":
                return { badge: "default", text: "Returned Successfully" };
            default:
                return { badge: "outline", text: status };
        }
    };

    return (
        <div className="p-6">
            <h1 className="text-2xl font-bold mb-6">Refund Requests</h1>

            {loading ? (
                <div className="flex h-40 items-center justify-center">
                    <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent" />
                </div>
            ) : refunds.length === 0 ? (
                <Card className="flex flex-col items-center justify-center py-16 text-muted-foreground">
                    <CheckCircle2 className="mb-4 h-12 w-12 text-muted-foreground/50" />
                    <h3 className="text-xl font-medium">All clear!</h3>
                    <p>No refund requests to review.</p>
                </Card>
            ) : (
                <div className="grid gap-4">
                    {refunds.map((refund) => {
                        const theme = getStatusTheme(refund.status);
                        const firstItem = refund.order?.items?.[0];
                        const productImg = firstItem?.productId?.images?.[0] || firstItem?.image || "";
                        const productTitle = firstItem?.productId?.title || firstItem?.title || "Unknown Product";

                        return (
                            <Card key={refund._id} className="overflow-hidden border border-gray-200 shadow-sm hover:shadow-md transition-shadow">
                                <div className="p-5 flex flex-col md:flex-row justify-between md:items-center gap-4">
                                    <div className="flex-1 space-y-3">
                                        <div className="flex items-center gap-3">
                                            <Badge variant={theme.badge as any} className={theme.badge === 'warning' ? 'bg-amber-500 hover:bg-amber-600' : ''}>
                                                {theme.text}
                                            </Badge>
                                            <span className="text-sm font-semibold">
                                                Order #{refund.order?._id?.slice(-8)?.toUpperCase() || "N/A"}
                                            </span>
                                            <span className="text-sm text-gray-500 whitespace-nowrap hidden sm:inline-block">
                                                {new Date(refund.requestedAt).toLocaleDateString()}
                                            </span>
                                        </div>
                                        
                                        <div className="flex items-start gap-3 mt-2 border p-3 rounded-lg bg-gray-50/50">
                                            {productImg ? (
                                                <img src={productImg} alt="Product" className="w-12 h-12 rounded object-cover flex-shrink-0 border bg-white" />
                                            ) : (
                                                <div className="w-12 h-12 rounded bg-gray-100 flex items-center justify-center flex-shrink-0 border">
                                                    <span className="text-[10px] text-gray-400">No img</span>
                                                </div>
                                            )}
                                            <div className="flex flex-col">
                                                <span className="text-sm font-medium line-clamp-1">{productTitle}</span>
                                                <span className="text-xs text-gray-500 mt-1">
                                                    <span className="font-semibold text-gray-900">{refund.buyer.username}</span> requested a return due to <span className="font-semibold text-gray-900 capitalize">{refund.reason?.replace(/_/g, ' ')?.toLowerCase()}</span>
                                                </span>
                                            </div>
                                        </div>

                                        {refund.status === "PENDING" && (
                                            <div className="flex items-center text-xs text-amber-600 font-medium bg-amber-50 w-fit px-2 py-1 rounded">
                                                <AlertTriangle className="w-3.5 h-3.5 justify-center mr-1" />
                                                Please respond within 48h to avoid auto-approval impacting trust score.
                                            </div>
                                        )}
                                    </div>
                                    <div className="flex flex-col items-end gap-2 min-w-max">
                                        <span className="text-xs text-gray-400 sm:hidden">
                                            {new Date(refund.requestedAt).toLocaleDateString()}
                                        </span>
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            className="hover:bg-blue-50 hover:text-blue-600 transition-colors"
                                            onClick={() => {
                                                setSelectedRefund(refund);
                                                setIsDialogOpen(true);
                                                setSellerNote(refund.sellerNote || "");
                                            }}
                                        >
                                            <Eye className="w-4 h-4 mr-2" />
                                            View Details
                                        </Button>
                                    </div>
                                </div>
                            </Card>
                        )
                    })}
                </div>
            )}

            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent className="max-w-2xl">
                    <DialogHeader>
                        <DialogTitle>Refund Request Details</DialogTitle>
                    </DialogHeader>
                    {selectedRefund && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-2 gap-4 text-sm bg-muted p-4 rounded-lg">
                                <div>
                                    <p className="text-muted-foreground">Order ID</p>
                                    <p className="font-medium flex items-center gap-2">
                                        {selectedRefund.order._id}
                                    </p>
                                </div>
                                <div>
                                    <p className="text-muted-foreground">Reason</p>
                                    <p className="font-medium">{selectedRefund.reason}</p>
                                </div>
                                <div className="col-span-2 mt-2">
                                    <p className="text-muted-foreground">Buyer's Comment</p>
                                    <p className="p-3 bg-background rounded border mt-1 font-medium">{selectedRefund.description}</p>
                                </div>
                            </div>

                            {selectedRefund.images && selectedRefund.images.length > 0 && (
                                <div className="space-y-2 mt-4">
                                    <p className="font-semibold text-sm">Evidence Images</p>
                                    <div className="flex flex-wrap gap-3">
                                        {selectedRefund.images.map((url, idx) => (
                                            <div key={idx} className="w-24 h-24 rounded overflow-hidden border bg-muted group relative">
                                                <img 
                                                    src={url} 
                                                    alt="Evidence" 
                                                    className="w-full h-full object-cover transition-transform hover:scale-105 cursor-pointer"
                                                    onClick={() => window.open(url, "_blank")}
                                                />
                                            </div>
                                        ))}
                                    </div>
                                    <p className="text-xs text-muted-foreground mt-1">Click on an image to view full size</p>
                                </div>
                            )}

                            {selectedRefund.status !== "PENDING" && (
                                <div className="text-sm bg-muted/50 p-4 rounded-lg border">
                                    <p className="text-muted-foreground">Your Response</p>
                                    <p className="font-medium">{selectedRefund.sellerNote || "No message provided."}</p>
                                </div>
                            )}

                            {selectedRefund.adminNote && (
                                <div className="text-sm bg-primary/10 p-4 rounded-lg border border-primary/20">
                                    <p className="font-semibold text-primary pb-1">Admin Verdict</p>
                                    <p>{selectedRefund.adminNote}</p>
                                </div>
                            )}

                            {selectedRefund.status === "PENDING" && (
                                <div className="space-y-4 pt-4 border-t">
                                    <div>
                                        <h4 className="font-medium mb-2">Reply to buyer</h4>
                                        <Textarea
                                            placeholder="Provide instructions for return or a reason for rejection..."
                                            value={sellerNote}
                                            onChange={(e) => setSellerNote(e.target.value)}
                                            rows={3}
                                            className="resize-none"
                                        />
                                    </div>
                                    <div className="flex justify-end gap-3 pt-4">
                                        <Button
                                            variant="destructive"
                                            onClick={() => handleAction("REJECT")}
                                            disabled={submitting}
                                        >
                                            {submitting && pendingAction === "REJECT" ? "Processing..." : "Reject Request"}
                                        </Button>
                                        <Button
                                            className="bg-green-600 hover:bg-green-700"
                                            onClick={() => handleAction("APPROVE")}
                                            disabled={submitting}
                                        >
                                            {submitting && pendingAction === "APPROVE" ? "Processing..." : "Approve Return"}
                                        </Button>
                                    </div>
                                </div>
                            )}

                            {["APPROVED", "AUTO_APPROVED", "ADMIN_APPROVED"].includes(selectedRefund.status) && selectedRefund.order?.status === "delivered_to_seller" && (
                                <div className="space-y-4 pt-4 border-t">
                                    <div className="bg-blue-50 text-blue-800 p-4 rounded-lg flex items-start gap-2">
                                        <CheckCircle2 className="w-5 h-5 mt-0.5 flex-shrink-0" />
                                        <div>
                                            <p className="font-medium">Shipper has returned the package to you.</p>
                                            <p className="text-sm mt-1">Please inspect the item and choose its condition to process the final refund. Inventory will only restock if marked as SELLABLE.</p>
                                        </div>
                                    </div>
                                    <div className="flex flex-col gap-2">
                                        <label className="text-sm font-semibold">Received Item Condition</label>
                                        <select 
                                            className="w-full xl:w-1/2 p-2 border rounded-md text-sm"
                                            value={returnCondition}
                                            onChange={(e) => setReturnCondition(e.target.value as any)}
                                        >
                                            <option value="SELLABLE">🟢 SELLABLE (Brand new, sealed - Restocks inventory)</option>
                                            <option value="OPENED">🟡 OPENED (Used, minor wear - Does NOT restock)</option>
                                            <option value="DAMAGED">🔴 DAMAGED (Broken, missing parts - Does NOT restock)</option>
                                        </select>
                                    </div>
                                    <div className="flex justify-end gap-3 pt-2">
                                        <Button
                                            className="bg-blue-600 hover:bg-blue-700"
                                            onClick={handleConfirmReceipt}
                                            disabled={submitting}
                                        >
                                            {submitting && pendingAction === "CONFIRM_RECEIPT" ? "Processing..." : "Confirm Item Received"}
                                        </Button>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </DialogContent>
            </Dialog>

            {/* Pagination would go here */}
        </div>
    );
}

import { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Upload,
  Tag,
  DollarSign,
  Package,
  Layers,
  X,
  ImagePlus,
  Loader2,
  Star,
  Percent,
} from "lucide-react";
import { toast } from "sonner";
import { createProduct } from "@/api/seller-products";
import type {
  ProductVariant,
  ProductVariantCombination,
} from "@/api/seller-products";
import ProductVariantsManager from "@/components/seller/product-variants-manager";
import api from "@/lib/axios";

interface Category {
  _id: string;
  name: string;
  slug: string;
}

interface ImageFile {
  file: File;
  previewUrl: string;
  uploading: boolean;
  uploadedUrl?: string;
  error?: string;
}

const MAX_IMAGES = 5;
const numericInputClass =
  "h-12 text-lg font-semibold tracking-wide transition-[box-shadow,border-color,background-color] duration-200 focus-visible:shadow-sm focus-visible:ring-2 focus-visible:ring-blue-200";

const getErrorMessage = (error: unknown, fallback: string) => {
  if (
    typeof error === "object" &&
    error !== null &&
    "response" in error &&
    typeof error.response === "object" &&
    error.response !== null &&
    "data" in error.response &&
    typeof error.response.data === "object" &&
    error.response.data !== null &&
    "message" in error.response.data &&
    typeof error.response.data.message === "string"
  ) {
    return error.response.data.message;
  }

  return fallback;
};

export default function AddProduct() {
  const navigate = useNavigate();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageFilesRef = useRef<ImageFile[]>([]);

  const [loading, setLoading] = useState(false);
  const [categories, setCategories] = useState<Category[]>([]);
  const [variants, setVariants] = useState<ProductVariant[]>([]);
  const [variantCombinations, setVariantCombinations] = useState<
    ProductVariantCombination[]
  >([]);
  const [imageFiles, setImageFiles] = useState<ImageFile[]>([]);

  const totalVariantStock = variantCombinations.reduce(
    (sum, combo) => sum + (Number(combo.quantity) || 0),
    0,
  );

  const [formData, setFormData] = useState({
    title: "",
    description: "",
    price: "",
    saleEnabled: false,
    discountPercent: "",
    saleStartDate: "",
    saleEndDate: "",
    quantity: "",
    condition: "new",
    categoryId: "",
  });

  useEffect(() => {
    api
      .get("/api/categories")
      .then((res) => {
        const list = res.data?.data ?? res.data ?? [];
        setCategories(list);
      })
      .catch(() => {});
  }, []);

  useEffect(() => {
    imageFilesRef.current = imageFiles;
  }, [imageFiles]);

  useEffect(() => {
    return () => {
      imageFilesRef.current.forEach((img) => URL.revokeObjectURL(img.previewUrl));
    };
  }, []);

  const handleChange = (
    e: React.ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >,
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  // ── Xử lý chọn file ──────────────────────────────────────────────────────────
  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files ?? []);
    if (!files.length) return;

    const remaining = MAX_IMAGES - imageFiles.length;
    if (remaining <= 0) {
      toast.error(`Maximum ${MAX_IMAGES} images`);
      return;
    }

    const accepted = files.slice(0, remaining);
    const newImages: ImageFile[] = accepted.map((file) => ({
      file,
      previewUrl: URL.createObjectURL(file),
      uploading: false,
    }));

    setImageFiles((prev) => [...prev, ...newImages]);

    // Reset input để có thể chọn lại cùng file
    e.target.value = "";
  };

  // ── Kéo thả ──────────────────────────────────────────────────────────────────
  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    const files = Array.from(e.dataTransfer.files).filter((f) =>
      f.type.startsWith("image/"),
    );
    if (!files.length) return;

    const remaining = MAX_IMAGES - imageFiles.length;
    const accepted = files.slice(0, remaining);
    const newImages: ImageFile[] = accepted.map((file) => ({
      file,
      previewUrl: URL.createObjectURL(file),
      uploading: false,
    }));
    setImageFiles((prev) => [...prev, ...newImages]);
  };

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>) =>
    e.preventDefault();

  // ── Xoá ảnh ──────────────────────────────────────────────────────────────────
  const removeImage = (idx: number) => {
    setImageFiles((prev) => {
      URL.revokeObjectURL(prev[idx].previewUrl);
      return prev.filter((_, i) => i !== idx);
    });
  };

  // ── Set ảnh đại diện (đưa lên đầu) ───────────────────────────────────────────
  const setMainImage = (idx: number) => {
    if (idx === 0) return;
    setImageFiles((prev) => {
      const copy = [...prev];
      const [main] = copy.splice(idx, 1);
      copy.unshift(main);
      return copy;
    });
    toast.success("Set to main image successfully");
  };

  // ── Upload tất cả ảnh lên Cloudinary ─────────────────────────────────────────
  const uploadAllImages = async (): Promise<string[]> => {
    if (imageFiles.length === 0) return [];

    // Mark all as uploading
    setImageFiles((prev) => prev.map((img) => ({ ...img, uploading: true })));

    const formDataUpload = new FormData();
    imageFiles.forEach((img) => formDataUpload.append("images", img.file));

    const res = await api.post("/api/upload/product-images", formDataUpload, {
      headers: { "Content-Type": "multipart/form-data" },
    });

    const urls: string[] = res.data.urls ?? [];

    setImageFiles((prev) =>
      prev.map((img, i) => ({
        ...img,
        uploading: false,
        uploadedUrl: urls[i],
      })),
    );

    return urls;
  };

  // ── Submit form ───────────────────────────────────────────────────────────────
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const hasVariants = variantCombinations.length > 0;
    if (!formData.title || !formData.categoryId) {
      toast.error("Please enter product's name and category");
      return;
    }
    if (!hasVariants && !formData.price) {
      toast.error("Please enter selling price");
      return;
    }

    const variantPrices = variantCombinations
      .map((c) => c.price)
      .filter((p): p is number => p !== undefined && p > 0);
    const effectiveBasePrice = hasVariants
      ? (variantPrices.length > 0 ? Math.min(...variantPrices) : 0)
      : parseFloat(formData.price) || 0;

    let computedSalePrice: number | undefined;
    if (formData.saleEnabled) {
      const pct = parseFloat(formData.discountPercent);
      if (!formData.discountPercent || !Number.isFinite(pct) || pct <= 0 || pct >= 100) {
        toast.error("Discount must be between 1% and 99%");
        return;
      }
      if (!formData.saleStartDate || !formData.saleEndDate) {
        toast.error("Please fill in sale start and end time");
        return;
      }
      if (new Date(formData.saleStartDate) >= new Date(formData.saleEndDate)) {
        toast.error("Start time must be before end time!");
        return;
      }
      if (effectiveBasePrice <= 0) {
        toast.error("Please set variant prices before enabling sale");
        return;
      }
      computedSalePrice = parseFloat((effectiveBasePrice * (1 - pct / 100)).toFixed(2));
    }

    setLoading(true);
    try {
      // Upload ảnh trước nếu có
      let imageUrls: string[] = [];
      if (imageFiles.length > 0) {
        toast.info("Uploading image...");
        imageUrls = await uploadAllImages();
      }

      await createProduct({
        title: formData.title,
        description: formData.description,
        price: hasVariants ? effectiveBasePrice : parseFloat(formData.price),
        saleEnabled: formData.saleEnabled,
        salePrice: formData.saleEnabled ? computedSalePrice : undefined,
        saleStartDate: formData.saleEnabled ? formData.saleStartDate : undefined,
        saleEndDate: formData.saleEnabled ? formData.saleEndDate : undefined,
        quantity: parseInt(formData.quantity) || 0,
        condition: formData.condition,
        categoryId: formData.categoryId,
        image: imageUrls[0] ?? "",
        images: imageUrls,
        variants,
        variantCombinations,
      });

      toast.success("Product add successfully!");
      navigate("/seller/products");
    } catch (error: unknown) {
      const msg = getErrorMessage(error, "Error occur when adding product.");
      toast.error(msg);
      // Nếu lỗi xảy ra sau upload thì reset uploading state
      setImageFiles((prev) =>
        prev.map((img) => ({ ...img, uploading: false })),
      );
    } finally {
      setLoading(false);
    }
  };

  const isUploading = imageFiles.some((img) => img.uploading);

  return (
    <div className="p-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-2xl font-bold text-gray-900">Add Product</h1>
          <p className="text-gray-600">Creating new product for your shop</p>
        </div>

        <form onSubmit={handleSubmit}>
          <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
            {/* Left Column */}
            <div className="lg:col-span-3 space-y-6">
              {/* Product Info */}
              <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                <CardHeader>
                  <CardTitle className="text-lg flex items-center gap-2">
                    <Tag className="h-5 w-5" />
                    Product Information
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="space-y-2">
                    <Label htmlFor="title">Product Name *</Label>
                    <Input
                      id="title"
                      name="title"
                      placeholder="Enter product name here"
                      value={formData.title}
                      onChange={handleChange}
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="description">Product Description</Label>
                    <Textarea
                      id="description"
                      name="description"
                      placeholder="Detail description about the product..."
                      rows={6}
                      value={formData.description}
                      onChange={handleChange}
                    />
                  </div>
                </CardContent>
              </Card>

              {/* ── Image Upload ── */}
              <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                <CardHeader>
                  <CardTitle className="text-lg flex items-center gap-2">
                    <ImagePlus className="h-5 w-5" />
                    Product Images
                    <span className="ml-auto text-sm font-normal text-muted-foreground">
                      {imageFiles.length}/{MAX_IMAGES}
                    </span>
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  {/* Drop zone */}
                  {imageFiles.length < MAX_IMAGES && (
                    <div
                      className="border-2 border-dashed border-border rounded-xl p-8 text-center cursor-pointer hover:border-primary hover:bg-primary/5 transition-colors select-none"
                      onClick={() => fileInputRef.current?.click()}
                      onDrop={handleDrop}
                      onDragOver={handleDragOver}
                    >
                      <Upload className="h-10 w-10 text-muted-foreground mx-auto mb-3" />
                      <p className="text-sm font-medium text-foreground mb-1">
                        Drag image here or click to select image
                      </p>
                      <p className="text-xs text-muted-foreground">
                        JPG, PNG, WEBP · Maximum 5MB/image · Maximum{" "}
                        {MAX_IMAGES} images
                      </p>
                      <input
                        ref={fileInputRef}
                        type="file"
                        accept="image/*"
                        multiple
                        className="hidden"
                        onChange={handleFileSelect}
                      />
                    </div>
                  )}

                  {/* Preview grid */}
                  {imageFiles.length > 0 && (
                    <div className="grid grid-cols-3 sm:grid-cols-5 gap-3">
                      {imageFiles.map((img, idx) => (
                        <div key={idx} className="relative group aspect-square">
                          <img
                            src={img.previewUrl}
                            alt={`product-${idx}`}
                            className={`w-full h-full object-cover rounded-lg border-2 transition-all ${
                              idx === 0
                                ? "border-primary ring-2 ring-primary/30"
                                : "border-border"
                            }`}
                          />

                          {/* Uploading overlay */}
                          {img.uploading && (
                            <div className="absolute inset-0 bg-black/50 rounded-lg flex items-center justify-center">
                              <Loader2 className="h-6 w-6 text-white animate-spin" />
                            </div>
                          )}

                          {/* Main label */}
                          {idx === 0 && !img.uploading && (
                            <div className="absolute bottom-1 left-1 right-1 bg-primary/90 text-white text-[10px] font-medium text-center rounded py-0.5">
                              Main Image
                            </div>
                          )}

                          {/* Action buttons (hover) */}
                          {!img.uploading && (
                            <div className="absolute inset-0 bg-black/40 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                              {/* Set as main */}
                              {idx !== 0 && (
                                <button
                                  type="button"
                                  onClick={() => setMainImage(idx)}
                                  title="Set to Main Image"
                                  className="w-7 h-7 bg-white/90 rounded-full flex items-center justify-center hover:bg-white"
                                >
                                  <Star className="h-3.5 w-3.5 text-amber-500" />
                                </button>
                              )}
                              {/* Remove */}
                              <button
                                type="button"
                                onClick={() => removeImage(idx)}
                                title="Delete Image"
                                className="w-7 h-7 bg-white/90 rounded-full flex items-center justify-center hover:bg-red-50"
                              >
                                <X className="h-3.5 w-3.5 text-red-500" />
                              </button>
                            </div>
                          )}
                        </div>
                      ))}

                      {/* Add more button */}
                      {imageFiles.length < MAX_IMAGES && (
                        <button
                          type="button"
                          onClick={() => fileInputRef.current?.click()}
                          className="aspect-square rounded-lg border-2 border-dashed border-border flex flex-col items-center justify-center text-muted-foreground hover:border-primary hover:text-primary transition-colors"
                        >
                          <ImagePlus className="h-5 w-5 mb-1" />
                          <span className="text-xs">Add</span>
                        </button>
                      )}
                    </div>
                  )}

                  {imageFiles.length > 0 && (
                    <p className="text-xs text-muted-foreground">
                      💡 Hover in image to delete or set the image to main
                      image. The first image will be set to main image.
                    </p>
                  )}
                </CardContent>
              </Card>

              {/* Variants */}
              <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                <CardHeader>
                  <CardTitle className="text-lg flex items-center gap-2">
                    <Layers className="h-5 w-5" />
                    Product Variants
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-sm text-gray-500 mb-4">
                    Add characteristics such as Size, Color... and list the
                    corresponding values.
                  </p>
                  <ProductVariantsManager
                    variants={variants}
                    onChange={setVariants}
                    variantCombinations={variantCombinations}
                    onCombinationsChange={setVariantCombinations}
                    showSkuFields={false}
                  />
                </CardContent>
              </Card>
            </div>

            {/* Right Column */}
            <div className="space-y-6">
              {/* Pricing */}
              <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                <CardHeader>
                  <CardTitle className="text-lg flex items-center gap-2">
                    <DollarSign className="h-5 w-5" />
                    Prices & Stock
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="space-y-2">
                    <Label htmlFor="price">Price *</Label>
                    {variantCombinations.length > 0 ? (() => {
                      const prices = variantCombinations
                        .map((c) => c.price)
                        .filter((p): p is number => p !== undefined && p > 0);
                      const min = prices.length > 0 ? Math.min(...prices) : null;
                      const max = prices.length > 0 ? Math.max(...prices) : null;
                      return (
                        <div className={`flex items-center pl-4 pr-3 rounded-md border border-input bg-muted/50 ${numericInputClass}`}>
                          <span className="text-gray-500 mr-1">$</span>
                          <span className="text-gray-700">
                            {min !== null && max !== null
                              ? min === max
                                ? min.toFixed(2)
                                : `${min.toFixed(2)} - ${max.toFixed(2)}`
                              : "Set per variant below"}
                          </span>
                        </div>
                      );
                    })() : (
                      <div className="relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500">
                          $
                        </span>
                        <Input
                          id="price"
                          name="price"
                          type="number"
                          placeholder="0.00"
                          className={`pl-8 ${numericInputClass}`}
                          value={formData.price}
                          onChange={handleChange}
                          min="0"
                          step="0.01"
                        />
                      </div>
                    )}
                  </div>

                  <div className="rounded-xl border border-dashed border-red-300 p-4 bg-red-50/40 space-y-3">
                    <label className="flex items-center justify-between cursor-pointer">
                      <span className="font-medium text-sm flex items-center gap-2">
                        <Percent className="h-4 w-4 text-red-500" />
                        Sale Discount
                      </span>
                      <input
                        type="checkbox"
                        className="w-4 h-4 accent-red-500"
                        checked={formData.saleEnabled}
                        onChange={(e) =>
                          setFormData((prev) => ({
                            ...prev,
                            saleEnabled: e.target.checked,
                          }))
                        }
                      />
                    </label>
                    {formData.saleEnabled && (
                      <div className="space-y-3 pt-1">
                        <div className="space-y-1">
                          <Label htmlFor="discountPercent" className="text-xs">Discount % *</Label>
                          <div className="relative">
                            <Input
                              id="discountPercent"
                              name="discountPercent"
                              type="number"
                              min="1"
                              max="99"
                              step="1"
                              placeholder="e.g. 20"
                              value={formData.discountPercent}
                              onChange={handleChange}
                              className={`pr-8 ${numericInputClass}`}
                            />
                            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 font-bold">%</span>
                          </div>
                          {(() => {
                            const pct = parseFloat(formData.discountPercent);
                            const hasVariants = variantCombinations.length > 0;
                            if (!Number.isFinite(pct) || pct <= 0) return null;
                            if (hasVariants) {
                              const prices = variantCombinations
                                .map((c) => c.price)
                                .filter((p): p is number => p !== undefined && p > 0);
                              if (prices.length === 0) return null;
                              const min = parseFloat((Math.min(...prices) * (1 - pct / 100)).toFixed(2));
                              const max = parseFloat((Math.max(...prices) * (1 - pct / 100)).toFixed(2));
                              return (
                                <p className="text-xs text-red-600 font-medium">
                                  After discount: <span className="font-bold">
                                    {min === max ? `$${min.toFixed(2)}` : `$${min.toFixed(2)} - $${max.toFixed(2)}`}
                                  </span>
                                </p>
                              );
                            }
                            const base = parseFloat(formData.price);
                            if (!base) return null;
                            return (
                              <p className="text-xs text-red-600 font-medium">
                                After discount: <span className="font-bold">${(base * (1 - pct / 100)).toFixed(2)}</span>
                              </p>
                            );
                          })()}
                        </div>
                        <div className="grid grid-cols-2 gap-2">
                          <div className="space-y-1">
                            <Label htmlFor="saleStartDate" className="text-xs">Start *</Label>
                            <Input
                              id="saleStartDate"
                              name="saleStartDate"
                              type="datetime-local"
                              value={formData.saleStartDate}
                              onChange={handleChange}
                              className="h-10 text-sm"
                            />
                          </div>
                          <div className="space-y-1">
                            <Label htmlFor="saleEndDate" className="text-xs">End *</Label>
                            <Input
                              id="saleEndDate"
                              name="saleEndDate"
                              type="datetime-local"
                              value={formData.saleEndDate}
                              onChange={handleChange}
                              className="h-10 text-sm"
                            />
                          </div>
                        </div>
                      </div>
                    )}
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="quantity">Stock</Label>
                    <div className="relative">
                      <Package className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-500" />
                      <Input
                        id="quantity"
                        name="quantity"
                        type="number"
                        placeholder="Stock"
                        className={`pl-10 ${numericInputClass}`}
                        value={
                          variantCombinations.length > 0
                            ? String(totalVariantStock)
                            : formData.quantity
                        }
                        onChange={handleChange}
                        disabled={variantCombinations.length > 0}
                        min="0"
                      />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="categoryId">Category *</Label>
                    <select
                      id="categoryId"
                      name="categoryId"
                      className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                      value={formData.categoryId}
                      onChange={handleChange}
                      required
                    >
                      <option value="">Select category</option>
                      {categories.map((cat) => (
                        <option key={cat._id} value={cat._id}>
                          {cat.name}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="condition">Condition</Label>
                    <select
                      id="condition"
                      name="condition"
                      className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                      value={formData.condition}
                      onChange={handleChange}
                    >
                      <option value="new">New</option>
                      <option value="like_new">Like New</option>
                      <option value="used">Used</option>
                    </select>
                  </div>
                </CardContent>
              </Card>

              {/* Actions */}
              <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                <CardContent className="pt-6">
                  <div className="space-y-3">
                    <Button
                      type="submit"
                      className="w-full"
                      disabled={loading || isUploading}
                    >
                      {loading || isUploading ? (
                        <>
                          <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                          {isUploading ? "Loading Image..." : "Saving..."}
                        </>
                      ) : (
                        "Create Product"
                      )}
                    </Button>
                    <Button
                      type="button"
                      variant="outline"
                      className="w-full"
                      onClick={() => navigate("/seller/products")}
                      disabled={loading || isUploading}
                    >
                      Cancel
                    </Button>
                  </div>
                </CardContent>
              </Card>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import {
    Upload,
    Tag,
    DollarSign,
    Package,
    Layers,
    X,
    ImagePlus,
    Loader2,
    Star,
    Percent,
    ArrowLeft,
} from 'lucide-react';
import { toast } from 'sonner';
import {
    updateProduct,
    type ProductVariant,
    type ProductVariantCombination,
} from '@/api/seller-products';
import ProductVariantsManager from '@/components/seller/product-variants-manager';
import api from '@/lib/axios';

interface Category {
    _id: string;
    name: string;
}

interface NewImageFile {
    file: File;
    previewUrl: string;
    uploading: boolean;
    uploadedUrl?: string;
}

const MAX_IMAGES = 5;
const numericInputClass =
    "h-12 text-lg font-semibold tracking-wide transition-[box-shadow,border-color,background-color] duration-200 focus-visible:shadow-sm focus-visible:ring-2 focus-visible:ring-blue-200";

const getErrorMessage = (error: unknown, fallback: string) => {
    if (
        typeof error === "object" &&
        error !== null &&
        "response" in error &&
        typeof error.response === "object" &&
        error.response !== null &&
        "data" in error.response &&
        typeof error.response.data === "object" &&
        error.response.data !== null &&
        "message" in error.response.data &&
        typeof error.response.data.message === "string"
    ) {
        return error.response.data.message;
    }

    return fallback;
};

const toInputDateTime = (value?: string | null) => {
    if (!value) return "";
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return "";
    const offset = date.getTimezoneOffset();
    const local = new Date(date.getTime() - offset * 60000);
    return local.toISOString().slice(0, 16);
};

export default function EditProduct() {
    const navigate = useNavigate();
    const { id } = useParams<{ id: string }>();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const newImageFilesRef = useRef<NewImageFile[]>([]);

    const [pageLoading, setPageLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [categories, setCategories] = useState<Category[]>([]);
    const [variants, setVariants] = useState<ProductVariant[]>([]);
    const [variantCombinations, setVariantCombinations] = useState<ProductVariantCombination[]>([]);

    // Existing uploaded images (URLs)
    const [existingImages, setExistingImages] = useState<string[]>([]);
    // New files not yet uploaded
    const [newImageFiles, setNewImageFiles] = useState<NewImageFile[]>([]);

    const totalImages = existingImages.length + newImageFiles.length;

    const totalVariantStock = variantCombinations.reduce(
        (sum, combo) => sum + (Number(combo.quantity) || 0),
        0,
    );

    const [formData, setFormData] = useState({
        title: '',
        description: '',
        price: '',
        saleEnabled: false,
        discountPercent: '',
        saleStartDate: '',
        saleEndDate: '',
        quantity: '',
        condition: 'new',
        categoryId: '',
    });

    useEffect(() => {
        api.get('/api/categories').then((res) => {
            setCategories(res.data?.data ?? res.data ?? []);
        }).catch(() => { });
    }, []);

    useEffect(() => {
        newImageFilesRef.current = newImageFiles;
    }, [newImageFiles]);

    useEffect(() => {
        return () => {
            newImageFilesRef.current.forEach((img) => URL.revokeObjectURL(img.previewUrl));
        };
    }, []);

    useEffect(() => {
        if (!id) return;
        api.get(`/api/products/${id}`)
            .then((res) => {
                const p = res.data?.data ?? res.data;
                setFormData({
                    title: p.title ?? '',
                    description: p.description ?? '',
                    price: String(p.basePrice ?? p.originalPrice ?? p.price ?? ''),
                    saleEnabled: Boolean(p.promotionType === 'daily_deal' || p.discountPercent),
                    discountPercent: p.discountPercent ? String(p.discountPercent) : '',
                    saleStartDate: toInputDateTime(p.saleStartDate ?? p.dealStartDate),
                    saleEndDate: toInputDateTime(p.saleEndDate ?? p.dealEndDate),
                    quantity: String(p.quantity ?? ''),
                    condition: p.condition ?? 'new',
                    categoryId: p.categoryId?._id ?? p.categoryId ?? '',
                });
                // images[] is the authoritative list (includes all images, main is index 0)
                // Fallback: if images[] empty but image exists, use it
                if (p.images?.length > 0) {
                    setExistingImages(p.images);
                } else if (p.image) {
                    setExistingImages([p.image]);
                }
                setVariants(p.variants ?? []);
                setVariantCombinations(p.variantCombinations ?? []);
            })
            .catch(() => {
                toast.error('Unable to load product information');
                navigate('/seller/products');
            })
            .finally(() => setPageLoading(false));
    }, [id, navigate]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
    };

    // ── Image handlers ────────────────────────────────────────────────────────

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files ?? []);
        if (!files.length) return;
        const remaining = MAX_IMAGES - totalImages;
        if (remaining <= 0) {
            toast.error(`Maximum ${MAX_IMAGES} images`);
            return;
        }
        const accepted = files.slice(0, remaining);
        const newImgs: NewImageFile[] = accepted.map((file) => ({
            file,
            previewUrl: URL.createObjectURL(file),
            uploading: false,
        }));
        setNewImageFiles((prev) => [...prev, ...newImgs]);
        e.target.value = "";
    };

    const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        const files = Array.from(e.dataTransfer.files).filter((f) => f.type.startsWith("image/"));
        if (!files.length) return;
        const remaining = MAX_IMAGES - totalImages;
        const accepted = files.slice(0, remaining);
        const newImgs: NewImageFile[] = accepted.map((file) => ({
            file,
            previewUrl: URL.createObjectURL(file),
            uploading: false,
        }));
        setNewImageFiles((prev) => [...prev, ...newImgs]);
    };

    const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => e.preventDefault();

    const removeExistingImage = (index: number) => {
        setExistingImages((prev) => prev.filter((_, i) => i !== index));
    };

    const removeNewImage = (index: number) => {
        setNewImageFiles((prev) => {
            URL.revokeObjectURL(prev[index].previewUrl);
            return prev.filter((_, i) => i !== index);
        });
    };

    // Move an existing image to position 0 (main)
    const setMainExisting = (index: number) => {
        if (index === 0 && existingImages.length > 0) return;
        setExistingImages((prev) => {
            const copy = [...prev];
            const [item] = copy.splice(index, 1);
            copy.unshift(item);
            return copy;
        });
        toast.success("Set to main image successfully");
    };

    // Move a new image to position 0 overall (needs to become first existing after upload,
    // but for now just reorder within newImageFiles and ensure it goes before all new)
    const setMainNew = (newIndex: number) => {
        if (existingImages.length === 0 && newIndex === 0) return;
        setNewImageFiles((prev) => {
            const copy = [...prev];
            const [item] = copy.splice(newIndex, 1);
            copy.unshift(item);
            return copy;
        });
        if (existingImages.length === 0) {
            toast.success("Set to main image successfully");
        }
    };

    const uploadNewImages = async (): Promise<string[]> => {
        if (newImageFiles.length === 0) return [];
        setNewImageFiles((prev) => prev.map((img) => ({ ...img, uploading: true })));
        const fd = new FormData();
        newImageFiles.forEach((img) => fd.append('images', img.file));
        const res = await api.post('/api/upload/product-images', fd, {
            headers: { 'Content-Type': 'multipart/form-data' },
        });
        const urls: string[] = res.data.urls ?? [];
        setNewImageFiles((prev) =>
            prev.map((img, i) => ({ ...img, uploading: false, uploadedUrl: urls[i] })),
        );
        return urls;
    };

    // ── Effective base price ──────────────────────────────────────────────────

    const getEffectiveBasePrice = () => {
        if (variantCombinations.length > 0) {
            const prices = variantCombinations
                .map((c) => c.price)
                .filter((p): p is number => p !== undefined && p > 0);
            return prices.length > 0 ? Math.min(...prices) : 0;
        }
        return parseFloat(formData.price) || 0;
    };

    // ── Submit ────────────────────────────────────────────────────────────────

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const hasVariants = variantCombinations.length > 0;

        if (!formData.title) {
            toast.error('Please enter product name');
            return;
        }
        if (!hasVariants && !formData.price) {
            toast.error('Please enter selling price');
            return;
        }

        const effectiveBasePrice = getEffectiveBasePrice();
        let computedSalePrice: number | undefined;

        if (formData.saleEnabled) {
            const pct = parseFloat(formData.discountPercent);
            if (!formData.discountPercent || !Number.isFinite(pct) || pct <= 0 || pct >= 100) {
                toast.error('Discount must be between 1% and 99%');
                return;
            }
            if (!formData.saleStartDate || !formData.saleEndDate) {
                toast.error('Please fill in sale start and end time');
                return;
            }
            if (new Date(formData.saleStartDate) >= new Date(formData.saleEndDate)) {
                toast.error('Sale start time must be before end time');
                return;
            }
            if (effectiveBasePrice <= 0) {
                toast.error('Please set variant prices before enabling sale');
                return;
            }
            computedSalePrice = parseFloat((effectiveBasePrice * (1 - pct / 100)).toFixed(2));
        }

        setSaving(true);
        try {
            let newUrls: string[] = [];
            if (newImageFiles.length > 0) {
                toast.info("Uploading images...");
                newUrls = await uploadNewImages();
            }
            const allImages = [...existingImages, ...newUrls];

            await updateProduct(id!, {
                title: formData.title,
                description: formData.description,
                price: hasVariants ? effectiveBasePrice : parseFloat(formData.price),
                saleEnabled: formData.saleEnabled,
                salePrice: formData.saleEnabled ? computedSalePrice : undefined,
                saleStartDate: formData.saleEnabled ? formData.saleStartDate : undefined,
                saleEndDate: formData.saleEnabled ? formData.saleEndDate : undefined,
                quantity: parseInt(formData.quantity) || 0,
                condition: formData.condition,
                categoryId: formData.categoryId || undefined,
                image: allImages[0] ?? "",
                images: allImages,
                variants,
                variantCombinations,
            });
            toast.success('Product updated successfully!');
            navigate('/seller/products');
        } catch (error: unknown) {
            toast.error(getErrorMessage(error, 'Failed to update product'));
            setNewImageFiles((prev) => prev.map((img) => ({ ...img, uploading: false })));
        } finally {
            setSaving(false);
        }
    };

    const isUploading = newImageFiles.some((img) => img.uploading);

    // ── Sale price preview ────────────────────────────────────────────────────

    const getSalePricePreview = () => {
        const pct = parseFloat(formData.discountPercent);
        if (!formData.saleEnabled || !Number.isFinite(pct) || pct <= 0) return null;
        if (variantCombinations.length > 0) {
            const prices = variantCombinations
                .map((c) => c.price)
                .filter((p): p is number => p !== undefined && p > 0);
            if (prices.length === 0) return null;
            const min = parseFloat((Math.min(...prices) * (1 - pct / 100)).toFixed(2));
            const max = parseFloat((Math.max(...prices) * (1 - pct / 100)).toFixed(2));
            return min === max ? `$${min.toFixed(2)}` : `$${min.toFixed(2)} - $${max.toFixed(2)}`;
        }
        const base = parseFloat(formData.price);
        if (!base) return null;
        return `$${(base * (1 - pct / 100)).toFixed(2)}`;
    };

    if (pageLoading) {
        return (
            <div className="p-6 flex items-center justify-center h-64">
                <p className="text-gray-500">Loading product information...</p>
            </div>
        );
    }

    const salePricePreview = getSalePricePreview();

    return (
        <div className="p-6">
            <div className="max-w-7xl mx-auto">
                {/* Header */}
                <div className="mb-8 flex items-center gap-4">
                    <Button variant="ghost" onClick={() => navigate('/seller/products')} className="flex items-center gap-2">
                        <ArrowLeft className="h-4 w-4" />
                        Back
                    </Button>
                    <div>
                        <h1 className="text-2xl font-bold text-gray-900">Edit Product</h1>
                        <p className="text-gray-600">Update your product information</p>
                    </div>
                </div>

                <form onSubmit={handleSubmit}>
                    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
                        {/* Left Column */}
                        <div className="lg:col-span-3 space-y-6">
                            {/* Product Info */}
                            <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                                <CardHeader>
                                    <CardTitle className="text-lg flex items-center gap-2">
                                        <Tag className="h-5 w-5" />
                                        Product Information
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="title">Product Name *</Label>
                                        <Input
                                            id="title" name="title"
                                            placeholder="Enter product name here"
                                            value={formData.title}
                                            onChange={handleChange}
                                            required
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor="description">Product Description</Label>
                                        <Textarea
                                            id="description" name="description"
                                            placeholder="Detail description about the product..."
                                            rows={6}
                                            value={formData.description}
                                            onChange={handleChange}
                                        />
                                    </div>
                                </CardContent>
                            </Card>

                            {/* Images */}
                            <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                                <CardHeader>
                                    <CardTitle className="text-lg flex items-center gap-2">
                                        <ImagePlus className="h-5 w-5" />
                                        Product Images
                                        <span className="ml-auto text-sm font-normal text-muted-foreground">
                                            {totalImages}/{MAX_IMAGES}
                                        </span>
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    {/* Drop zone */}
                                    {totalImages < MAX_IMAGES && (
                                        <div
                                            className="border-2 border-dashed border-border rounded-xl p-8 text-center cursor-pointer hover:border-primary hover:bg-primary/5 transition-colors select-none"
                                            onClick={() => fileInputRef.current?.click()}
                                            onDrop={handleDrop}
                                            onDragOver={handleDragOver}
                                        >
                                            <Upload className="h-10 w-10 text-muted-foreground mx-auto mb-3" />
                                            <p className="text-sm font-medium text-foreground mb-1">
                                                Drag image here or click to select image
                                            </p>
                                            <p className="text-xs text-muted-foreground">
                                                JPG, PNG, WEBP · Maximum 5MB/image · Maximum {MAX_IMAGES} images
                                            </p>
                                            <input
                                                ref={fileInputRef}
                                                type="file"
                                                accept="image/*"
                                                multiple
                                                className="hidden"
                                                onChange={handleFileSelect}
                                            />
                                        </div>
                                    )}

                                    {/* Preview grid */}
                                    {totalImages > 0 && (
                                        <div className="grid grid-cols-3 sm:grid-cols-5 gap-3">
                                            {/* Existing images */}
                                            {existingImages.map((url, idx) => (
                                                <div key={`existing-${idx}`} className="relative group aspect-square">
                                                    <img
                                                        src={url}
                                                        alt={`product-${idx}`}
                                                        className={`w-full h-full object-cover rounded-lg border-2 transition-all ${
                                                            idx === 0 && newImageFiles.length === 0
                                                                ? "border-primary ring-2 ring-primary/30"
                                                                : "border-border"
                                                        }`}
                                                    />
                                                    {idx === 0 && newImageFiles.length === 0 && (
                                                        <div className="absolute bottom-1 left-1 right-1 bg-primary/90 text-white text-[10px] font-medium text-center rounded py-0.5">
                                                            Main Image
                                                        </div>
                                                    )}
                                                    <div className="absolute inset-0 bg-black/40 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                                                        {!(idx === 0 && newImageFiles.length === 0) && (
                                                            <button
                                                                type="button"
                                                                onClick={() => setMainExisting(idx)}
                                                                title="Set to Main Image"
                                                                className="w-7 h-7 bg-white/90 rounded-full flex items-center justify-center hover:bg-white"
                                                            >
                                                                <Star className="h-3.5 w-3.5 text-amber-500" />
                                                            </button>
                                                        )}
                                                        <button
                                                            type="button"
                                                            onClick={() => removeExistingImage(idx)}
                                                            title="Delete Image"
                                                            className="w-7 h-7 bg-white/90 rounded-full flex items-center justify-center hover:bg-red-50"
                                                        >
                                                            <X className="h-3.5 w-3.5 text-red-500" />
                                                        </button>
                                                    </div>
                                                </div>
                                            ))}

                                            {/* New files */}
                                            {newImageFiles.map((img, idx) => (
                                                <div key={`new-${idx}`} className="relative group aspect-square">
                                                    <img
                                                        src={img.previewUrl}
                                                        alt={`new-${idx}`}
                                                        className={`w-full h-full object-cover rounded-lg border-2 transition-all ${
                                                            existingImages.length === 0 && idx === 0
                                                                ? "border-primary ring-2 ring-primary/30"
                                                                : "border-border"
                                                        }`}
                                                    />
                                                    {img.uploading && (
                                                        <div className="absolute inset-0 bg-black/50 rounded-lg flex items-center justify-center">
                                                            <Loader2 className="h-6 w-6 text-white animate-spin" />
                                                        </div>
                                                    )}
                                                    {existingImages.length === 0 && idx === 0 && !img.uploading && (
                                                        <div className="absolute bottom-1 left-1 right-1 bg-primary/90 text-white text-[10px] font-medium text-center rounded py-0.5">
                                                            Main Image
                                                        </div>
                                                    )}
                                                    {!img.uploading && (
                                                        <div className="absolute inset-0 bg-black/40 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                                                            {!(existingImages.length === 0 && idx === 0) && (
                                                                <button
                                                                    type="button"
                                                                    onClick={() => setMainNew(idx)}
                                                                    title="Set to Main Image"
                                                                    className="w-7 h-7 bg-white/90 rounded-full flex items-center justify-center hover:bg-white"
                                                                >
                                                                    <Star className="h-3.5 w-3.5 text-amber-500" />
                                                                </button>
                                                            )}
                                                            <button
                                                                type="button"
                                                                onClick={() => removeNewImage(idx)}
                                                                title="Delete Image"
                                                                className="w-7 h-7 bg-white/90 rounded-full flex items-center justify-center hover:bg-red-50"
                                                            >
                                                                <X className="h-3.5 w-3.5 text-red-500" />
                                                            </button>
                                                        </div>
                                                    )}
                                                </div>
                                            ))}

                                            {/* Add more */}
                                            {totalImages < MAX_IMAGES && (
                                                <button
                                                    type="button"
                                                    onClick={() => fileInputRef.current?.click()}
                                                    className="aspect-square rounded-lg border-2 border-dashed border-border flex flex-col items-center justify-center text-muted-foreground hover:border-primary hover:text-primary transition-colors"
                                                >
                                                    <ImagePlus className="h-5 w-5 mb-1" />
                                                    <span className="text-xs">Add</span>
                                                </button>
                                            )}
                                        </div>
                                    )}

                                    {totalImages > 0 && (
                                        <p className="text-xs text-muted-foreground">
                                            💡 Hover on image to delete or set as main image. The first image will be the main image.
                                        </p>
                                    )}
                                </CardContent>
                            </Card>

                            {/* Variants */}
                            <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                                <CardHeader>
                                    <CardTitle className="text-lg flex items-center gap-2">
                                        <Layers className="h-5 w-5" />
                                        Product Variants
                                    </CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <p className="text-sm text-gray-500 mb-4">
                                        Add characteristics such as Size, Color... and list the corresponding values.
                                    </p>
                                    <ProductVariantsManager
                                        variants={variants}
                                        onChange={setVariants}
                                        variantCombinations={variantCombinations}
                                        basePrice={parseFloat(formData.price) || 0}
                                        onCombinationsChange={setVariantCombinations}
                                        showSkuFields={false}
                                    />
                                </CardContent>
                            </Card>
                        </div>

                        {/* Right Column */}
                        <div className="space-y-6">
                            {/* Pricing */}
                            <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                                <CardHeader>
                                    <CardTitle className="text-lg flex items-center gap-2">
                                        <DollarSign className="h-5 w-5" />
                                        Prices & Stock
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-4">
                                    {/* Price */}
                                    <div className="space-y-2">
                                        <Label htmlFor="price">Price *</Label>
                                        {variantCombinations.length > 0 ? (() => {
                                            const prices = variantCombinations
                                                .map((c) => c.price)
                                                .filter((p): p is number => p !== undefined && p > 0);
                                            const min = prices.length > 0 ? Math.min(...prices) : null;
                                            const max = prices.length > 0 ? Math.max(...prices) : null;
                                            return (
                                                <div className={`flex items-center pl-4 pr-3 rounded-md border border-input bg-muted/50 ${numericInputClass}`}>
                                                    <span className="text-gray-500 mr-1">$</span>
                                                    <span className="text-gray-700">
                                                        {min !== null && max !== null
                                                            ? min === max
                                                                ? min.toFixed(2)
                                                                : `${min.toFixed(2)} - ${max.toFixed(2)}`
                                                            : "Set per variant below"}
                                                    </span>
                                                </div>
                                            );
                                        })() : (
                                            <div className="relative">
                                                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500">$</span>
                                                <Input
                                                    id="price" name="price" type="number" placeholder="0.00"
                                                    className={`pl-8 ${numericInputClass}`}
                                                    value={formData.price}
                                                    onChange={handleChange}
                                                    min="0"
                                                    step="0.01"
                                                />
                                            </div>
                                        )}
                                    </div>

                                    {/* Sale Discount */}
                                    <div className="rounded-xl border border-dashed border-red-300 p-4 bg-red-50/40 space-y-3">
                                        <label className="flex items-center justify-between cursor-pointer">
                                            <span className="font-medium text-sm flex items-center gap-2">
                                                <Percent className="h-4 w-4 text-red-500" />
                                                Sale Discount
                                            </span>
                                            <input
                                                type="checkbox"
                                                className="w-4 h-4 accent-red-500"
                                                checked={formData.saleEnabled}
                                                onChange={(e) =>
                                                    setFormData((prev) => ({ ...prev, saleEnabled: e.target.checked }))
                                                }
                                            />
                                        </label>

                                        {formData.saleEnabled && (
                                            <div className="space-y-3 pt-1">
                                                <div className="space-y-1">
                                                    <Label htmlFor="discountPercent" className="text-xs">Discount % *</Label>
                                                    <div className="relative">
                                                        <Input
                                                            id="discountPercent"
                                                            name="discountPercent"
                                                            type="number"
                                                            min="1"
                                                            max="99"
                                                            step="1"
                                                            placeholder="e.g. 20"
                                                            value={formData.discountPercent}
                                                            onChange={handleChange}
                                                            className={`pr-8 ${numericInputClass}`}
                                                        />
                                                        <span className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 font-bold">%</span>
                                                    </div>
                                                    {salePricePreview && (
                                                        <p className="text-xs text-red-600 font-medium">
                                                            After discount: <span className="font-bold">{salePricePreview}</span>
                                                        </p>
                                                    )}
                                                </div>
                                                <div className="grid grid-cols-2 gap-2">
                                                    <div className="space-y-1">
                                                        <Label htmlFor="saleStartDate" className="text-xs">Start *</Label>
                                                        <Input
                                                            id="saleStartDate"
                                                            name="saleStartDate"
                                                            type="datetime-local"
                                                            value={formData.saleStartDate}
                                                            onChange={handleChange}
                                                            className="h-10 text-sm"
                                                        />
                                                    </div>
                                                    <div className="space-y-1">
                                                        <Label htmlFor="saleEndDate" className="text-xs">End *</Label>
                                                        <Input
                                                            id="saleEndDate"
                                                            name="saleEndDate"
                                                            type="datetime-local"
                                                            value={formData.saleEndDate}
                                                            onChange={handleChange}
                                                            className="h-10 text-sm"
                                                        />
                                                    </div>
                                                </div>
                                            </div>
                                        )}
                                    </div>

                                    {/* Stock */}
                                    <div className="space-y-2">
                                        <Label htmlFor="quantity">Stock</Label>
                                        <div className="relative">
                                            <Package className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-500" />
                                            <Input
                                                id="quantity" name="quantity" type="number" placeholder="Stock"
                                                className={`pl-10 ${numericInputClass}`}
                                                value={variantCombinations.length > 0 ? String(totalVariantStock) : formData.quantity}
                                                onChange={handleChange}
                                                disabled={variantCombinations.length > 0}
                                                min="0"
                                            />
                                        </div>
                                    </div>

                                    {/* Category */}
                                    <div className="space-y-2">
                                        <Label htmlFor="categoryId">Category *</Label>
                                        <select
                                            id="categoryId" name="categoryId"
                                            className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                                            value={formData.categoryId}
                                            onChange={handleChange}
                                            required
                                        >
                                            <option value="">Select category</option>
                                            {categories.map((cat) => (
                                                <option key={cat._id} value={cat._id}>{cat.name}</option>
                                            ))}
                                        </select>
                                    </div>

                                    {/* Condition */}
                                    <div className="space-y-2">
                                        <Label htmlFor="condition">Condition</Label>
                                        <select
                                            id="condition" name="condition"
                                            className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                                            value={formData.condition}
                                            onChange={handleChange}
                                        >
                                            <option value="new">New</option>
                                            <option value="like_new">Like New</option>
                                            <option value="used">Used</option>
                                        </select>
                                    </div>
                                </CardContent>
                            </Card>

                            {/* Actions */}
                            <Card className="shadow-sm border-0 ring-1 ring-gray-100">
                                <CardContent className="pt-6">
                                    <div className="space-y-3">
                                        <Button
                                            type="submit"
                                            className="w-full bg-green-600 hover:bg-green-700"
                                            disabled={saving || isUploading}
                                        >
                                            {saving || isUploading ? (
                                                <>
                                                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                                                    {isUploading ? "Uploading Images..." : "Saving..."}
                                                </>
                                            ) : (
                                                "Save Changes"
                                            )}
                                        </Button>
                                        <Button
                                            type="button"
                                            variant="outline"
                                            className="w-full"
                                            onClick={() => navigate('/seller/products')}
                                            disabled={saving || isUploading}
                                        >
                                            Cancel
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>
                        </div>
                    </div>
                </form>
            </div>
        </div>
    );
}

