interface Category {
  _id: string;
  name: string;
}

interface ListingQueryParams {
  status?: string;
  search?: string;
  page?: number;
  limit?: number;
}

const toInputDateTime = (value?: string | null) => {
  if (!value) return '';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '';
  const offset = date.getTimezoneOffset();
  const local = new Date(date.getTime() - offset * 60000);
  return local.toISOString().slice(0, 16);
};

interface EditFormData {
  title: string;
  description: string;
  price: number;
  saleEnabled: boolean;
  discountPercent: string;
  saleStartDate: string;
  saleEndDate: string;
  quantity: number;
  condition: string;
  categoryId: string;
  images: string[];
  variants: ProductVariant[];
  variantCombinations: ProductVariantCombination[];
}

const listingStatusLabel: Record<string, string> = {
  active: 'Active',
  paused: 'Pause',
  ended: 'Ended',
  deleted: 'Deleted',
};

const listingStatusColor: Record<string, string> = {
  active: 'bg-green-100 text-green-800',
  paused: 'bg-yellow-100 text-yellow-800',
  ended: 'bg-gray-100 text-gray-800',
  deleted: 'bg-red-100 text-red-800',
};

type SaleState = 'none' | 'upcoming' | 'active' | 'expired';

interface SaleInfo {
  state: SaleState;
  basePrice: number;
  salePrice: number | null;
  startDate: Date | null;
  endDate: Date | null;
  countdown: string;
}

const toValidDate = (value?: string | null) => {
  if (!value) return null;
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const formatCountdown = (target: Date) => {
  const diffMs = target.getTime() - Date.now();
  if (diffMs <= 0) return 'Ending soon';
  const totalMinutes = Math.floor(diffMs / (1000 * 60));
  const days = Math.floor(totalMinutes / (60 * 24));
  const hours = Math.floor((totalMinutes % (60 * 24)) / 60);
  const mins = totalMinutes % 60;
  if (days > 0) return `${days}d ${hours}h left`;
  if (hours > 0) return `${hours}h ${mins}m left`;
  return `${Math.max(1, mins)}m left`;
};

const numericInputClass =
  'h-12 text-base font-semibold tracking-wide transition-[box-shadow,border-color,background-color] duration-200 focus-visible:shadow-sm focus-visible:ring-2 focus-visible:ring-blue-200';

const getErrorMessage = (error: unknown, fallback: string) => {
  if (
    typeof error === 'object' &&
    error !== null &&
    'response' in error &&
    typeof error.response === 'object' &&
    error.response !== null &&
    'data' in error.response &&
    typeof error.response.data === 'object' &&
    error.response.data !== null &&
    'message' in error.response.data &&
    typeof error.response.data.message === 'string'
  ) {
    return error.response.data.message;
  }

  return fallback;
};

const resolveSaleInfo = (product: Product): SaleInfo => {
  const basePrice = Number(product.basePrice ?? product.originalPrice ?? product.price ?? 0);
  const salePriceRaw = Number(product.salePrice ?? product.price ?? 0);
  const startDate = toValidDate(product.saleStartDate ?? product.dealStartDate ?? null);
  const endDate = toValidDate(product.saleEndDate ?? product.dealEndDate ?? null);
  const hasConfiguredSale = Number.isFinite(salePriceRaw) && salePriceRaw > 0 && salePriceRaw < basePrice;

  if (!hasConfiguredSale) {
    return {
      state: 'none',
      basePrice,
      salePrice: null,
      startDate: null,
      endDate: null,
      countdown: '',
    };
  }

  const now = Date.now();
  if (startDate && now < startDate.getTime()) {
    return {
      state: 'upcoming',
      basePrice,
      salePrice: salePriceRaw,
      startDate,
      endDate,
      countdown: `Starts ${startDate.toLocaleString('vi-VN')}`,
    };
  }

  if (endDate && now > endDate.getTime()) {
    return {
      state: 'expired',
      basePrice,
      salePrice: salePriceRaw,
      startDate,
      endDate,
      countdown: `Ended ${endDate.toLocaleString('vi-VN')}`,
    };
  }

  return {
    state: 'active',
    basePrice,
    salePrice: salePriceRaw,
    startDate,
    endDate,
    countdown: endDate ? formatCountdown(endDate) : 'Sale live',
  };
};

export default function SellerProducts() {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(false);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [total, setTotal] = useState(0);
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [categories, setCategories] = useState<Category[]>([]);

  // Dialog state
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const [isViewDialogOpen, setIsViewDialogOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [uploading, setUploading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [formData, setFormData] = useState<EditFormData>({
    title: '',
    description: '',
    price: 0,
    saleEnabled: false,
    discountPercent: '',
    saleStartDate: '',
    saleEndDate: '',
    quantity: 0,
    condition: 'new',
    categoryId: '',
    images: [],
    variants: [],
    variantCombinations: [],
  });
  const totalVariantStock = formData.variantCombinations.reduce(
    (sum, combo) => sum + (Number(combo.quantity) || 0),
    0,
  );
  const viewingSaleInfo = viewingProduct ? resolveSaleInfo(viewingProduct) : null;

  useEffect(() => {
    api.get('/api/categories').then((res) => {
      setCategories(res.data?.data ?? res.data ?? []);
    }).catch(() => { });
  }, []);

  const fetchProducts = useCallback(async () => {
    setLoading(true);
    try {
      const params: ListingQueryParams = { page, limit: 10 };
      if (search) params.search = search;
      if (statusFilter) params.status = statusFilter;
      const res = await getMyListings(params);
      setProducts(res.data ?? []);
      setTotal(res.total ?? 0);
      setTotalPages(Math.ceil((res.total ?? 0) / 10) || 1);
    } catch {
      toast.error('Failed to load product list');
    } finally {
      setLoading(false);
    }
  }, [page, search, statusFilter]);

  useEffect(() => {
    fetchProducts();
  }, [fetchProducts]);

  const handleSearch = () => {
    setPage(1);
    fetchProducts();
  };

  // Open edit dialog
  const handleEditClick = (product: Product) => {
    setEditingProduct(product);
    setFormData({
      title: product.title,
      description: product.description,
      price: product.basePrice ?? product.originalPrice ?? product.price,
      saleEnabled: Boolean(product.promotionType === 'daily_deal' || product.discountPercent),
      discountPercent: product.discountPercent ? String(product.discountPercent) : '',
      saleStartDate: toInputDateTime(product.saleStartDate ?? product.dealStartDate),
      saleEndDate: toInputDateTime(product.saleEndDate ?? product.dealEndDate),
      quantity: product.quantity ?? 0,
      condition: product.condition || 'new',
      categoryId: typeof product.categoryId === 'object' ? product.categoryId?._id ?? '' : product.categoryId ?? '',
      images: product.images?.length ? product.images : (product.image ? [product.image] : []),
      variants: product.variants ?? [],
      variantCombinations: product.variantCombinations ?? [],
    });
    setIsDialogOpen(true);
  };

  // Image upload
  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    setUploading(true);
    try {
      const fd = new FormData();
      Array.from(files).forEach((file) => fd.append('images', file));
      const res = await api.post('/api/upload/product-images', fd, {
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      const urls: string[] = res.data.urls ?? [];
      setFormData((prev) => ({ ...prev, images: [...prev.images, ...urls] }));
      toast.success(`Uploaded ${urls.length} images`);
    } catch {
      toast.error('Image upload failed');
    } finally {
      setUploading(false);
    }
  };

  const handleRemoveImage = (index: number) => {
    setFormData((prev) => ({ ...prev, images: prev.images.filter((_, i) => i !== index) }));
  };

  // Save edit
  const handleSave = async () => {
    if (!editingProduct) return;
    const hasVariants = formData.variantCombinations.length > 0;

    if (!formData.title) {
      toast.error('Please enter product name');
      return;
    }
    if (!hasVariants && formData.price <= 0) {
      toast.error('Please enter a valid price');
      return;
    }

    const variantPrices = formData.variantCombinations
      .map((c) => c.price)
      .filter((p): p is number => p !== undefined && p > 0);
    const effectiveBasePrice = hasVariants
      ? (variantPrices.length > 0 ? Math.min(...variantPrices) : 0)
      : formData.price;

    let computedSalePrice: number | undefined;
    if (formData.saleEnabled) {
      const pct = parseFloat(formData.discountPercent);
      if (!formData.discountPercent || !Number.isFinite(pct) || pct <= 0 || pct >= 100) {
        toast.error('Discount must be between 1% and 99%');
        return;
      }
      if (!formData.saleStartDate || !formData.saleEndDate) {
        toast.error('Please fill in sale start and end time');
        return;
      }
      if (new Date(formData.saleStartDate) >= new Date(formData.saleEndDate)) {
        toast.error('Sale start date must be before end date');
        return;
      }
      if (effectiveBasePrice <= 0) {
        toast.error('Please set variant prices before enabling sale');
        return;
      }
      computedSalePrice = parseFloat((effectiveBasePrice * (1 - pct / 100)).toFixed(2));
    }

    setSaving(true);
    try {
      await updateProduct(editingProduct._id, {
        title: formData.title,
        description: formData.description,
        price: hasVariants ? effectiveBasePrice : formData.price,
        saleEnabled: formData.saleEnabled,
        salePrice: formData.saleEnabled ? computedSalePrice : undefined,
        saleStartDate: formData.saleEnabled ? formData.saleStartDate : undefined,
        saleEndDate: formData.saleEnabled ? formData.saleEndDate : undefined,
        quantity: formData.quantity,
        condition: formData.condition,
        categoryId: formData.categoryId || undefined,
        image: formData.images[0] ?? "",
        images: formData.images,
        variants: formData.variants,
        variantCombinations: formData.variantCombinations,
      });
      toast.success('Product updated successfully');
      setIsDialogOpen(false);
      fetchProducts();
    } catch (error: unknown) {
      toast.error(getErrorMessage(error, 'Failed to update product'));
    } finally {
      setSaving(false);
    }
  };

  // Toggle listing status
  const handleToggleStatus = async (product: Product) => {
    const newStatus = product.listingStatus === 'active' ? 'paused' : 'active';
    try {
      await updateListingStatus(product._id, newStatus);
      toast.success(`Changed to "${listingStatusLabel[newStatus]}"`);
      fetchProducts();
    } catch {
      toast.error('Failed to update listing status');
    }
  };

  // Soft delete
  const handleDelete = async (product: Product) => {
    if (!confirm(`Are you sure you want to delete product "${product.title}"?`)) return;
    try {
      await deleteProduct(product._id);
      toast.success('Product deleted');
      fetchProducts();
    } catch {
      toast.error('Failed to delete product');
    }
  };

  return (
    <div className="container mx-auto py-8">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-3xl font-bold">Product Management</h1>
          <p className="text-gray-600 mt-1">Total {total} products</p>
        </div>
        <Link to="/seller/products/new">
          <Button className="bg-green-600 hover:bg-green-700">
            <Plus className="h-4 w-4 mr-2" />
            Add New Product
          </Button>
        </Link>
      </div>

      {/* Filters */}
      <div className="flex gap-4 mb-6">
        <div className="flex-1">
          <Input
            placeholder="Search by product name..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
          />
        </div>
        <select
          className="rounded-md border border-input bg-background px-3 py-2 text-sm"
          value={statusFilter}
          onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
        >
          <option value="">All statuses</option>
          <option value="active">Active</option>
          <option value="paused">Pause</option>
          <option value="ended">Ended</option>
        </select>
        <Button onClick={handleSearch}>Search</Button>
      </div>

      {/* Table */}
      <div className="border rounded-lg">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Image</TableHead>
              <TableHead>Product Name</TableHead>
              <TableHead>Category</TableHead>
              <TableHead>Price</TableHead>
              <TableHead>Sale</TableHead>
              <TableHead>Stock</TableHead>
              <TableHead>Rating</TableHead>
              <TableHead>Variants</TableHead>
              <TableHead>Status</TableHead>
              <TableHead>Created Date</TableHead>
              <TableHead className="text-right">Actions</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {loading ? (
              <TableRow>
                <TableCell colSpan={11} className="text-center py-8">Loading...</TableCell>
              </TableRow>
            ) : products.length === 0 ? (
              <TableRow>
                <TableCell colSpan={11} className="text-center py-12">
                  <Package className="h-10 w-10 text-gray-400 mx-auto mb-3" />
                  <p className="text-gray-500">No products found</p>
                  <Link to="/seller/products/new">
                    <Button className="mt-4 bg-green-600 hover:bg-green-700" size="sm">
                      <Plus className="h-4 w-4 mr-1" />
                      Add Your First Product
