                <div>
                  <span className="text-gray-500">Status:</span>
                  <span className={`ml-2 px-2 py-0.5 rounded text-xs ${listingStatusColor[viewingProduct.listingStatus] ?? 'bg-gray-100 text-gray-800'}`}>
                    {listingStatusLabel[viewingProduct.listingStatus]}
                  </span>
                </div>
                <div>
                  <span className="text-gray-500">Created Date:</span>
                  <span className="ml-2">{new Date(viewingProduct.createdAt).toLocaleDateString('vi-VN')}</span>
                </div>
                <div>
                  <span className="text-gray-500">Rating:</span>
                  <span className="ml-2 inline-flex items-center gap-1">
                    <Star className="h-3.5 w-3.5 fill-yellow-400 text-yellow-400" />
                    <span className="font-semibold">{(viewingProduct.averageRating ?? 0).toFixed(1)}</span>
                    <span className="text-gray-400 text-xs">({viewingProduct.ratingCount ?? 0} reviews)</span>
                  </span>
                </div>
              </div>

              {/* Variants */}
              {viewingProduct.variants && viewingProduct.variants.length > 0 && (
                <div>
                  <h4 className="font-semibold mb-3 flex items-center gap-2">
                    <Layers className="h-4 w-4" />
                    Product Variants
                  </h4>
                  <div className="space-y-4">
                    {viewingProduct.variants.map((variant) => (
                      <div key={variant.name}>
                        <p className="text-sm font-medium text-gray-700 mb-2">{variant.name}</p>
                        <div className="flex flex-wrap gap-2">
                          {variant.options.map((opt) => (
                            <div
                              key={opt.value}
                              className="border rounded-md px-3 py-2 text-sm border-solid bg-white"
                            >
                              <div className="font-medium">{opt.value}</div>
                              <div className="text-xs text-gray-500 space-x-2">
                                {opt.sku && <span>SKU: {opt.sku}</span>}
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
              {viewingProduct.variantCombinations && viewingProduct.variantCombinations.length > 0 && (
                <div>
                  <h4 className="font-semibold mb-3">Combination Stock</h4>
                  <div className="space-y-2">
                    {viewingProduct.variantCombinations.map((combo) => (
                      <div key={combo.key} className="flex items-center justify-between border rounded-md px-3 py-2 text-sm">
                        <span>{combo.selections.map((s) => s.value).join(' / ')}</span>
                        <span className="font-semibold">
                          Price: ${Number(combo.price ?? viewingProduct.price ?? 0).toFixed(2)} | Stock: {combo.quantity}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsViewDialogOpen(false)}>Close</Button>
            <Button onClick={() => { setIsViewDialogOpen(false); if (viewingProduct) handleEditClick(viewingProduct); }}>
              Edit Product
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Edit Dialog */}
      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="w-[95vw] max-w-[95vw] sm:max-w-[95vw] max-h-[92vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Edit Product</DialogTitle>
            <DialogDescription>Update product information</DialogDescription>
          </DialogHeader>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 py-4">
            {/* Left — main content */}
            <div className="lg:col-span-2 space-y-4">
              <div className="grid gap-2">
                <Label>Product Name *</Label>
                <Input
                  value={formData.title}
                  onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                />
              </div>

              <div className="grid gap-2">
                <Label>Description</Label>
                <Textarea
                  rows={5}
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                />
              </div>

              {/* Images */}
              <div className="grid gap-2">
                <Label>Product Images</Label>
                <Input
                  type="file"
                  accept="image/*"
                  multiple
                  onChange={handleImageUpload}
                  disabled={uploading}
                />
                {uploading && <p className="text-sm text-gray-500">Uploading...</p>}
                {formData.images.length > 0 && (
                  <div className="grid grid-cols-5 gap-2 mt-1">
                    {formData.images.map((url, index) => (
                      <div key={index} className="relative group aspect-square">
                        <img src={url} alt="" className="w-full h-full object-cover rounded-lg border" />
                        <button
                          type="button"
                          onClick={() => handleRemoveImage(index)}
                          className="absolute top-1 right-1 bg-red-500 text-white rounded-full w-5 h-5 text-xs flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          ×
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Variants */}
              <div className="grid gap-2">
                <Label className="flex items-center gap-2">
                  <Layers className="h-4 w-4" />
                  Product Variants
                </Label>
                <ProductVariantsManager
                  variants={formData.variants}
                  onChange={(variants) => setFormData({ ...formData, variants })}
                  variantCombinations={formData.variantCombinations}
                  basePrice={Number(formData.price) || 0}
                  onCombinationsChange={(variantCombinations) =>
                    setFormData({ ...formData, variantCombinations })
                  }
                  showSkuFields={false}
                />
              </div>
            </div>

            {/* Right — price & stock */}
            <div className="space-y-4">
              {/* Price */}
              <div className="grid gap-2">
                <Label>Price ($) *</Label>
                {formData.variantCombinations.length > 0 ? (() => {
                  const prices = formData.variantCombinations
                    .map((c) => c.price)
                    .filter((p): p is number => p !== undefined && p > 0);
                  const min = prices.length > 0 ? Math.min(...prices) : null;
                  const max = prices.length > 0 ? Math.max(...prices) : null;
                  return (
                    <div className={`flex items-center pl-4 pr-3 rounded-md border border-input bg-muted/50 ${numericInputClass}`}>
                      <span className="text-gray-500 mr-1">$</span>
                      <span className="text-gray-700">
                        {min !== null && max !== null
                          ? min === max ? min.toFixed(2) : `${min.toFixed(2)} - ${max.toFixed(2)}`
                          : 'Set per variant below'}
                      </span>
                    </div>
                  );
                })() : (
                  <Input
                    type="number"
                    min="0"
                    step="0.01"
                    placeholder="0.00"
                    className={numericInputClass}
                    value={formData.price}
                    onChange={(e) => setFormData({ ...formData, price: parseFloat(e.target.value) || 0 })}
                  />
                )}
              </div>

              {/* Quantity */}
              <div className="grid gap-2">
                <Label>Stock</Label>
                <Input
                  type="number"
                  min="0"
                  className={numericInputClass}
                  value={formData.variantCombinations.length > 0 ? totalVariantStock : formData.quantity}
                  onChange={(e) => setFormData({ ...formData, quantity: parseInt(e.target.value) || 0 })}
                  disabled={formData.variantCombinations.length > 0}
                />
              </div>

              {/* Sale Discount */}
              <div className="rounded-xl border border-dashed border-red-300 bg-red-50/40 p-4 space-y-3">
                <label className="flex items-center justify-between cursor-pointer">
                  <span className="font-medium text-sm flex items-center gap-2">
                    <Percent className="h-4 w-4 text-red-500" />
                    Sale Discount
                  </span>
                  <input
                    type="checkbox"
                    className="w-4 h-4 accent-red-500"
                    checked={formData.saleEnabled}
                    onChange={(e) => setFormData({ ...formData, saleEnabled: e.target.checked })}
                  />
                </label>
                {formData.saleEnabled && (
                  <div className="space-y-3 pt-1">
                    <div className="space-y-1">
                      <Label className="text-xs">Discount % *</Label>
                      <div className="relative">
                        <Input
                          type="number"
                          min="1"
                          max="99"
                          step="1"
                          placeholder="e.g. 20"
                          className={`pr-8 ${numericInputClass}`}
                          value={formData.discountPercent}
                          onChange={(e) => setFormData({ ...formData, discountPercent: e.target.value })}
                        />
                        <span className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 font-bold">%</span>
                      </div>
                      {(() => {
                        const pct = parseFloat(formData.discountPercent);
                        if (!Number.isFinite(pct) || pct <= 0) return null;
                        const hasVariants = formData.variantCombinations.length > 0;
                        if (hasVariants) {
                          const prices = formData.variantCombinations
                            .map((c) => c.price)
                            .filter((p): p is number => p !== undefined && p > 0);
                          if (prices.length === 0) return null;
                          const min = parseFloat((Math.min(...prices) * (1 - pct / 100)).toFixed(2));
                          const max = parseFloat((Math.max(...prices) * (1 - pct / 100)).toFixed(2));
                          return (
                            <p className="text-xs text-red-600 font-medium">
                              After discount: <span className="font-bold">
                                {min === max ? `$${min.toFixed(2)}` : `$${min.toFixed(2)} - $${max.toFixed(2)}`}
                              </span>
                            </p>
                          );
                        }
                        if (!formData.price) return null;
                        return (
                          <p className="text-xs text-red-600 font-medium">
                            After discount: <span className="font-bold">${(formData.price * (1 - pct / 100)).toFixed(2)}</span>
                          </p>
                        );
                      })()}
                    </div>
                    <div className="grid grid-cols-2 gap-2">
                      <div className="space-y-1">
                        <Label className="text-xs">Start *</Label>
                        <Input
                          type="datetime-local"
                          className="h-10 text-sm"
                          value={formData.saleStartDate}
                          onChange={(e) => setFormData({ ...formData, saleStartDate: e.target.value })}
                        />
                      </div>
                      <div className="space-y-1">
                        <Label className="text-xs">End *</Label>
                        <Input
                          type="datetime-local"
                          className="h-10 text-sm"
                          value={formData.saleEndDate}
                          onChange={(e) => setFormData({ ...formData, saleEndDate: e.target.value })}
                        />
                      </div>
                    </div>
                  </div>
                )}
              </div>

              {/* Category */}
              <div className="grid gap-2">
                <Label>Category</Label>
                <select
                  className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                  value={formData.categoryId}
                  onChange={(e) => setFormData({ ...formData, categoryId: e.target.value })}
                >
                  <option value="">Select category</option>
                  {categories.map((cat) => (
                    <option key={cat._id} value={cat._id}>{cat.name}</option>
                  ))}
                </select>
              </div>

              {/* Condition */}
              <div className="grid gap-2">
                <Label>Condition</Label>
                <select
                  className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm"
                  value={formData.condition}
                  onChange={(e) => setFormData({ ...formData, condition: e.target.value })}
                >
                  <option value="new">New</option>
                  <option value="like_new">Like New</option>
                  <option value="used">Used</option>
                </select>
              </div>
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setIsDialogOpen(false)}>Cancel</Button>
            <Button onClick={handleSave} disabled={saving}>
              {saving ? 'Saving...' : 'Save Changes'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import {
    PackageIcon,
    AlertTriangleIcon,
    TrendingDownIcon,
    BoxIcon,
    CheckCircleIcon,
} from 'lucide-react';
import { getInventorySummary, getLowStockProducts, type Product } from '@/api/seller-products';

export default function InventoryPage() {
    const [summary, setSummary] = useState({
        totalProducts: 0,
        activeProducts: 0,
        lowStockCount: 0,
        outOfStock: 0,
    });
    const [lowStockProducts, setLowStockProducts] = useState<Product[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchData = async () => {
            try {
                setLoading(true);
                const [summaryRes, lowStockRes] = await Promise.all([
                    getInventorySummary(),
                    getLowStockProducts(),
                ]);

                setSummary(summaryRes.data);
                setLowStockProducts(Array.isArray(lowStockRes?.data) ? lowStockRes.data : []);
            } catch (err) {
                console.error('Failed to load inventory', err);
            } finally {
                setLoading(false);
            }
        };

        fetchData();
    }, []);

    if (loading) {
        return (
            <div className="p-4 md:p-6 max-w-7xl mx-auto">
                <p className="text-center text-muted-foreground">Loading...</p>
            </div>
        );
    }

    return (
        <div className="p-4 md:p-6 max-w-7xl mx-auto space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <h1 className="text-3xl font-bold flex items-center gap-2">
                    <BoxIcon className="w-8 h-8 text-primary" />
                    Inventory Management
                </h1>
                <Link to="/seller/my-listings">
                    <Button variant="outline">View All Listings</Button>
                </Link>
            </div>

            {/* Summary Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-gray-600">Total Products</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="flex items-center justify-between">
                            <div className="text-3xl font-bold">{summary.totalProducts}</div>
                            <PackageIcon className="w-8 h-8 text-blue-500 opacity-50" />
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-gray-600">Active Listings</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="flex items-center justify-between">
                            <div className="text-3xl font-bold text-green-600">{summary.activeProducts}</div>
                            <CheckCircleIcon className="w-8 h-8 text-green-500 opacity-50" />
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-gray-600">Low Stock</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="flex items-center justify-between">
                            <div className="text-3xl font-bold text-yellow-600">{summary.lowStockCount}</div>
                            <AlertTriangleIcon className="w-8 h-8 text-yellow-500 opacity-50" />
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="pb-2">
                        <CardTitle className="text-sm font-medium text-gray-600">Out of Stock</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <div className="flex items-center justify-between">
                            <div className="text-3xl font-bold text-red-600">{summary.outOfStock}</div>
                            <TrendingDownIcon className="w-8 h-8 text-red-500 opacity-50" />
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Low Stock Products */}
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                        <AlertTriangleIcon className="w-5 h-5 text-yellow-600" />
                        Low Stock Products
                        <Badge variant="secondary" className="ml-2">
                            {lowStockProducts.length}
                        </Badge>
                    </CardTitle>
                </CardHeader>
                <CardContent>
                    {lowStockProducts.length === 0 ? (
                        <div className="text-center py-8 text-gray-500">
                            <CheckCircleIcon className="w-12 h-12 mx-auto mb-2 text-green-500" />
                            <p className="font-medium">All products are well-stocked!</p>
                            <p className="text-sm">No low stock alerts at this time.</p>
                        </div>
                    ) : (
                        <div className="rounded-lg border">
                            <Table>
                                <TableHeader>
                                    <TableRow className="bg-gray-50/50">
                                        <TableHead className="font-semibold">Product</TableHead>
                                        <TableHead className="font-semibold text-right">Price</TableHead>
                                        <TableHead className="font-semibold text-right">Current Stock</TableHead>
                                        <TableHead className="font-semibold text-right">Threshold</TableHead>
                                        <TableHead className="font-semibold">Status</TableHead>
                                        <TableHead className="font-semibold">Variants</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {lowStockProducts.map((product) => (
                                        <TableRow key={product._id} className="hover:bg-gray-50/50">
                                            <TableCell>
                                                <div className="flex items-center gap-3">
                                                    <img
                                                        src={product.image || product.images?.[0] || '/placeholder.png'}
                                                        alt={product.title}
                                                        className="w-12 h-12 object-cover rounded border"
                                                    />
                                                    <div>
                                                        <div className="font-medium">{product.title}</div>
                                                        <div className="text-sm text-gray-500">
                                                            {product.categoryId?.name || 'Uncategorized'}
                                                        </div>
                                                    </div>
                                                </div>
                                            </TableCell>
                                            <TableCell className="text-right font-medium">
                                                ${product.price.toFixed(2)}
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <span
                                                    className={
                                                        product.quantity === 0
                                                            ? 'text-red-600 font-bold'
                                                            : 'text-yellow-600 font-medium'
                                                    }
                                                >
                                                    {product.quantity}
                                                </span>
                                            </TableCell>
                                            <TableCell className="text-right text-gray-600">
                                                {product.lowStockThreshold}
                                            </TableCell>
                                            <TableCell>
                                                {product.quantity === 0 ? (
                                                    <Badge variant="outline" className="bg-red-100 text-red-800 border-red-200">
                                                        Out of Stock
                                                    </Badge>
                                                ) : (
                                                    <Badge variant="outline" className="bg-yellow-100 text-yellow-800 border-yellow-200">
                                                        Low Stock
                                                    </Badge>
                                                )}
                                            </TableCell>
                                            <TableCell>
                                                {product.variants && product.variants.length > 0 ? (
                                                    <div className="text-sm">
                                                        {product.variants.map((v, i) => (
                                                            <div key={i} className="text-gray-600">
                                                                {v.name}: {v.options.length} options
                                                            </div>
                                                        ))}
                                                    </div>
                                                ) : (
                                                    <span className="text-gray-400 text-sm">No variants</span>
                                                )}
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import {
    getMyPromotionRequests,
    cancelPromotionRequest,
    type PromotionRequest,
} from '@/api/promotions';
import { toast } from 'sonner';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import {
    Card,
    CardContent,
    CardDescription,
    CardHeader,
    CardTitle,
} from '@/components/ui/card';
import {
    Tabs,
    TabsContent,
    TabsList,
    TabsTrigger,
} from '@/components/ui/tabs';
import { Package, Tag, TrendingUp, AlertCircle } from 'lucide-react';

export default function PromotionRequestsPage() {
    const [requests, setRequests] = useState<PromotionRequest[]>([]);
    const [loading, setLoading] = useState(true);
    const [statusFilter, setStatusFilter] = useState('all');

    const fetchRequests = async () => {
        try {
            setLoading(true);
            const params = statusFilter !== 'all' ? { status: statusFilter } : {};
            const response = await getMyPromotionRequests(params);
            setRequests(response.data);
        } catch (error: any) {
            console.error('Failed to load requests:', error);
            toast.error('Failed to load promotion requests');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchRequests();
    }, [statusFilter]);

    const handleCancel = async (requestId: string) => {
        if (!confirm('Are you sure you want to cancel this request?')) return;

        try {
            await cancelPromotionRequest(requestId);
            toast.success('Promotion request cancelled');
            fetchRequests();
        } catch (error: any) {
            toast.error(error.response?.data?.message || 'Failed to cancel request');
        }
    };

    const getStatusBadge = (status: string) => {
        const variants: Record<string, 'default' | 'secondary' | 'destructive' | 'outline'> = {
            pending: 'secondary',
            approved: 'default',
            rejected: 'destructive',
            expired: 'outline',
            cancelled: 'outline',
        };
        return (
            <Badge variant={variants[status] || 'default'}>
                {status.charAt(0).toUpperCase() + status.slice(1)}
            </Badge>
        );
    };

    const getTypeBadge = (type: string) => {
        return type === 'outlet' ? (
            <Badge className="bg-orange-600">
                <Package className="w-3 h-3 mr-1" />
                Brand Outlet
            </Badge>
        ) : (
            <Badge className="bg-red-600">
                <Tag className="w-3 h-3 mr-1" />
                Sale Time
            </Badge>
        );
    };

    const formatDate = (dateString: string) => {
        return new Date(dateString).toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'short',
            day: 'numeric',
        });
    };

    return (
        <div className="container mx-auto py-8">
            <div className="flex items-center justify-between mb-6">
                <div>
                    <h1 className="text-3xl font-bold">Promotion Requests</h1>
                    <p className="text-gray-600 mt-1">
                        Manage your Brand Outlet and Sale Time requests
                    </p>
                </div>
                <Link to="/seller/my-listings">
                    <Button>
                        <TrendingUp className="w-4 h-4 mr-2" />
                        Request New Promotion
                    </Button>
                </Link>
            </div>

            {/* Instructions Card */}
            <Card className="mb-6 border-blue-200 bg-blue-50">
                <CardHeader>
                    <CardTitle className="text-lg flex items-center gap-2">
                        <AlertCircle className="w-5 h-5 text-blue-600" />
                        How It Works
                    </CardTitle>
                </CardHeader>
                <CardContent className="text-sm space-y-2">
                    <p>
                        <strong>Brand Outlet:</strong> For products that are NEW, listed
                        for 60+ days, with 30%+ discount, and verified seller.
                    </p>
                    <p>
                        <strong>Sale Time:</strong> Time-limited promotions with quantity
                        limits. Requires admin approval.
                    </p>
                    <p className="text-gray-600">
                        All requests are reviewed by our admin team before approval.
                    </p>
                </CardContent>
            </Card>

            {/* Tabs for filtering */}
            <Tabs value={statusFilter} onValueChange={setStatusFilter} className="mb-6">
                <TabsList>
                    <TabsTrigger value="all">All</TabsTrigger>
                    <TabsTrigger value="pending">Pending</TabsTrigger>
                    <TabsTrigger value="approved">Approved</TabsTrigger>
                    <TabsTrigger value="rejected">Rejected</TabsTrigger>
                </TabsList>
            </Tabs>

            {/* Requests Table */}
            <Card>
                <CardContent className="p-0">
                    {loading ? (
                        <div className="text-center py-12">
                            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900 mx-auto"></div>
                            <p className="mt-4 text-gray-600">Loading requests...</p>
                        </div>
                    ) : requests.length === 0 ? (
                        <div className="text-center py-12">
                            <Package className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                            <p className="text-gray-600">No promotion requests found</p>
                            <Link to="/seller/my-listings">
                                <Button className="mt-4" variant="outline">
