                    ) : (
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Product</TableHead>
                                    <TableHead>Type</TableHead>
                                    <TableHead>Pricing</TableHead>
                                    <TableHead>Status</TableHead>
                                    <TableHead>Eligible</TableHead>
                                    <TableHead>Submitted</TableHead>
                                    <TableHead className="text-right">Actions</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {requests.map((request) => (
                                    <TableRow key={request._id}>
                                        <TableCell>
                                            <div className="flex items-center gap-3">
                                                {request.product.image && (
                                                    <img
                                                        src={request.product.image}
                                                        alt={request.product.title}
                                                        className="w-12 h-12 object-cover rounded"
                                                    />
                                                )}
                                                <div>
                                                    <p className="font-medium line-clamp-1">
                                                        {request.product.title}
                                                    </p>
                                                    <p className="text-sm text-gray-500">
                                                        {request.product.condition}
                                                    </p>
                                                </div>
                                            </div>
                                        </TableCell>
                                        <TableCell>{getTypeBadge(request.requestType)}</TableCell>
                                        <TableCell>
                                            <div className="space-y-1">
                                                <p className="line-through text-gray-500 text-sm">
                                                    ${request.originalPrice.toFixed(2)}
                                                </p>
                                                <p className="font-bold text-red-600">
                                                    ${request.discountedPrice.toFixed(2)}
                                                </p>
                                                <Badge variant="outline" className="text-xs">
                                                    {request.discountPercent}% off
                                                </Badge>
                                            </div>
                                        </TableCell>
                                        <TableCell>{getStatusBadge(request.status)}</TableCell>
                                        <TableCell>
                                            {request.eligibilityChecks.allPassed ? (
                                                <Badge variant="default" className="bg-green-600">
                                                    ✓ Eligible
                                                </Badge>
                                            ) : (
                                                <Badge variant="destructive">✗ Not Eligible</Badge>
                                            )}
                                        </TableCell>
                                        <TableCell className="text-sm text-gray-600">
                                            {formatDate(request.createdAt)}
                                        </TableCell>
                                        <TableCell className="text-right">
                                            {request.status === 'pending' && (
                                                <Button
                                                    variant="outline"
                                                    size="sm"
                                                    onClick={() => handleCancel(request._id)}
                                                >
                                                    Cancel
                                                </Button>
                                            )}
                                            {request.status === 'rejected' && request.rejectionReason && (
                                                <Badge variant="destructive" className="text-xs">
                                                    {request.rejectionReason}
                                                </Badge>
                                            )}
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}

