            </CardTitle>
          </CardHeader>
          <CardContent>
            {loading ? (
              <div className="h-8 bg-muted animate-pulse rounded" />
            ) : (
              <>
                <div className="text-2xl font-bold">
                  ${stats.totalGross.toFixed(2)}
                </div>
                <p className="text-xs text-muted-foreground mt-1">
                  Total from {stats.totalOrders} orders
