    } catch (err: any) {
      console.error(err);
      toast.error(err.response?.data?.message || 'Failed to load templates');
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = async () => {
    if (!message.trim()) {
      toast.error('Please enter a message');
      return;
    }

    try {
      await createAutoReplyTemplate({
        trigger,
        message: message.trim(),
        delaySeconds,
      });

      toast.success('Template created. Waiting for admin approval.');
      setDialogOpen(false);
      resetForm();
      fetchTemplates();
    } catch (err: any) {
      console.error(err);
      toast.error(err.response?.data?.message || 'Failed to create template');
    }
  };

  const handleUpdate = async () => {
    if (!editingTemplate || !message.trim()) return;

    try {
      await updateAutoReplyTemplate(editingTemplate._id, {
        message: message.trim(),
        delaySeconds,
      });

      toast.success('Template updated. Admin re-approval is required.');
      setDialogOpen(false);
      resetForm();
      fetchTemplates();
    } catch (err: any) {
      console.error(err);
      toast.error(err.response?.data?.message || 'Failed to update template');
    }
  };

  const handleToggle = async (template: any, enabled: boolean) => {
    if (!template.reviewedByAdmin) {
      toast.error('Template must be approved by admin first');
      return;
    }

    try {
      await updateAutoReplyTemplate(template._id, { enabled });
      toast.success(enabled ? 'Template enabled' : 'Template disabled');
      fetchTemplates();
    } catch (err: any) {
      console.error(err);
      toast.error(err.response?.data?.message || 'Failed to update template');
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this template?')) return;

    try {
      await deleteAutoReplyTemplate(id);
      toast.success('Template deleted');
      fetchTemplates();
    } catch (err: any) {
      console.error(err);
      toast.error(err.response?.data?.message || 'Failed to delete template');
    }
  };

  const openCreateDialog = () => {
    resetForm();
    setEditingTemplate(null);
    setDialogOpen(true);
  };

  const openEditDialog = (template: any) => {
    setEditingTemplate(template);
    setTrigger(template.trigger);
    setMessage(template.message);
    setDelaySeconds(template.delaySeconds || 0);
    setDialogOpen(true);
  };

  const resetForm = () => {
    setTrigger('first_message');
    setMessage('');
    setDelaySeconds(0);
    setEditingTemplate(null);
  };

  const getTriggerLabel = (value: string) => {
    return TRIGGERS.find((t) => t.value === value)?.label || value;
  };

  if (loading) {
    return (
      <div className="p-6 max-w-4xl mx-auto">
        <p className="text-center text-muted-foreground">Loading...</p>
      </div>
    );
  }

  return (
    <div className="p-6 max-w-4xl mx-auto space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Auto-Reply Settings</h1>
        <p className="text-muted-foreground mt-2">Create automatic messages to reply quickly to buyers</p>
      </div>

      <Alert>
        <AlertCircle className="h-4 w-4" />
        <AlertDescription>
          <strong>Note:</strong> All auto-reply templates must be approved by admin before use.
          Messages that violate policy will be rejected.
        </AlertDescription>
      </Alert>

      <Card>
        <CardHeader>
          <div className="flex justify-between items-center">
            <div>
              <CardTitle>Your Auto-Reply Templates</CardTitle>
              <CardDescription>Manage your automatic reply templates</CardDescription>
            </div>
            <Button onClick={openCreateDialog}>
              <Plus className="h-4 w-4 mr-2" />
              Add Template
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {templates.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              <p>No templates yet. Create your first template.</p>
            </div>
          ) : (
            <div className="space-y-4">
              {templates.map((template) => (
                <div key={template._id} className="border rounded-lg p-4 hover:bg-muted/50 transition-colors">
                  <div className="flex justify-between items-start gap-4">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-2">
                        <Badge variant="outline">{getTriggerLabel(template.trigger)}</Badge>
                        {template.reviewedByAdmin ? (
                          <Badge variant="default" className="bg-green-500">
                            Approved
                          </Badge>
                        ) : template.flaggedForReview ? (
                          <Badge variant="destructive">Flagged: {template.flagReason}</Badge>
                        ) : (
                          <Badge variant="secondary">Pending Review</Badge>
                        )}
                        {template.delaySeconds > 0 && <Badge variant="outline">Delay: {template.delaySeconds}s</Badge>}
                      </div>
                      <p className="text-sm mb-2">{template.message}</p>
                      <div className="flex gap-4 text-xs text-muted-foreground">
                        <span>Used {template.usageCount || 0} times</span>
                        {template.lastUsedAt && <span>Last used: {new Date(template.lastUsedAt).toLocaleDateString()}</span>}
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Switch
                        checked={template.enabled}
                        onCheckedChange={(enabled) => handleToggle(template, enabled)}
                        disabled={!template.reviewedByAdmin}
                      />
                      <Button variant="ghost" size="icon-sm" onClick={() => openEditDialog(template)}>
                        <Edit className="h-4 w-4" />
                      </Button>
                      <Button variant="ghost" size="icon-sm" onClick={() => handleDelete(template._id)}>
                        <Trash2 className="h-4 w-4 text-destructive" />
                      </Button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{editingTemplate ? 'Edit Template' : 'Create Auto-Reply Template'}</DialogTitle>
          </DialogHeader>

          <div className="space-y-4">
            <div>
              <Label>Trigger</Label>
              <Select value={trigger} onValueChange={setTrigger} disabled={!!editingTemplate}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {TRIGGERS.map((t) => (
                    <SelectItem key={t.value} value={t.value}>
                      <div>
                        <div className="font-medium">{t.label}</div>
                        <div className="text-xs text-muted-foreground">{t.description}</div>
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Message</Label>
              <Textarea
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                placeholder="Enter your auto-reply message..."
                rows={4}
                maxLength={500}
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">{message.length}/500 characters</p>
            </div>

            <div>
              <Label>Delay (seconds)</Label>
              <Input
                type="number"
                value={delaySeconds}
                onChange={(e) => setDelaySeconds(parseInt(e.target.value) || 0)}
                min={0}
                max={300}
                className="mt-1"
              />
              <p className="text-xs text-muted-foreground mt-1">Delay before sending (0-300 seconds)</p>
            </div>

            <Alert>
              <AlertCircle className="h-4 w-4" />
              <AlertDescription className="text-xs">
                Template will be sent to admin for approval. It must not include phone numbers, emails,
                or external links outside the platform.
              </AlertDescription>
            </Alert>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setDialogOpen(false)}>
              Cancel
            </Button>
            <Button onClick={editingTemplate ? handleUpdate : handleCreate}>
              {editingTemplate ? 'Update' : 'Create'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import {
  type ReactNode,
  useCallback,
  useEffect,
  useMemo,
  useState,
} from "react";
import { Link } from "react-router-dom";
import api from "@/lib/axios";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  AlertTriangle,
  Calculator,
  CheckCircle2,
  Clock3,
  MessageSquareWarning,
  RefreshCw,
  ShieldAlert,
  ShieldCheck,
  Star,
} from "lucide-react";

type TrustTier = "TRUSTED" | "WARNING" | "HIGH_RISK";
type ModerationMode = "AUTO_APPROVED" | "REQUIRE_ADMIN";

interface TrustScoreData {
  finalScore: number;
  tier: TrustTier;
  badge: string;
  riskFlagged: boolean;
  productModerationMode: ModerationMode;
  breakdown: {
    ratingScore: number;
    completionRateScore: number;
    responseRateScore: number;
    disputeScore: number;
    stabilityScore: number;
  };
  metrics: {
    avgRating: number;
    reviewCount: number;
    completionRate: string;
    responseRate: string;
    disputeRate: string;
    accountAgeMonths: number;
  };
  lastCalculatedAt: string | null;
}

type WarningLevel = "high" | "medium" | "low" | "good";

const WEIGHTS = {
  ratingScore: 0.4,
  completionRateScore: 0.2,
  responseRateScore: 0.1,
  disputeScore: 0.15,
  stabilityScore: 0.15,
};

const TIER_STYLE: Record<
  TrustTier,
  {
    label: string;
    badgeClass: string;
    scoreClass: string;
  }
> = {
  TRUSTED: {
    label: "Trusted",
    badgeClass: "bg-emerald-100 text-emerald-700 border-emerald-200",
    scoreClass: "text-emerald-700",
  },
  WARNING: {
    label: "Warning",
    badgeClass: "bg-amber-100 text-amber-700 border-amber-200",
    scoreClass: "text-amber-700",
  },
  HIGH_RISK: {
    label: "High Risk",
    badgeClass: "bg-red-100 text-red-700 border-red-200",
    scoreClass: "text-red-700",
  },
};

const resolveTier = (tier: string): TrustTier => {
  if (tier === "TRUSTED" || tier === "WARNING" || tier === "HIGH_RISK") {
    return tier;
  }
  return "TRUSTED";
};

const toPercentNumber = (value: string) =>
  Number(
    String(value || "")
      .replace("%", "")
      .trim(),
  ) || 0;

const toDateTimeLabel = (value: string | null) => {
  if (!value) return "N/A";
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return "N/A";
  return parsed.toLocaleString();
};

export default function SellerTrustScorePage() {
  const [score, setScore] = useState<TrustScoreData | null>(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const fetchScore = useCallback(async () => {
    setLoading(true);
    try {
      const res = await api.get("/api/trust-score/my-score");
      setScore(res.data?.data || null);
    } catch (error) {
      console.error("Failed to load trust score", error);
      setScore(null);
    } finally {
      setLoading(false);
    }
  }, []);

  const refreshScore = useCallback(async () => {
    setRefreshing(true);
    try {
      // Force live recalculation on the server, return fresh data directly
      const res = await api.post("/api/trust-score/my-score/refresh");
      setScore(res.data?.data || null);
    } catch (error) {
      console.error("Failed to refresh trust score", error);
    } finally {
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    fetchScore();
  }, [fetchScore]);

  const breakdownRows = useMemo(() => {
    if (!score) return [];

    return [
      {
        key: "ratingScore",
        label: "Rating Quality",
        hint: "Bayesian weighted rating to prevent manipulation with too few reviews.",
        score: Number(score.breakdown.ratingScore || 0),
        weight: WEIGHTS.ratingScore,
      },
      {
        key: "completionRateScore",
        label: "Completion",
        hint: "Delivered orders ratio over delivered + cancelled + returned orders.",
        score: Number(score.breakdown.completionRateScore || 0),
        weight: WEIGHTS.completionRateScore,
      },
      {
        key: "responseRateScore",
        label: "Response",
        hint: "How consistently and quickly you respond to buyers.",
        score: Number(score.breakdown.responseRateScore || 0),
        weight: WEIGHTS.responseRateScore,
      },
      {
        key: "disputeScore",
        label: "Dispute Health",
        hint: "Lower dispute ratio gives a higher score.",
        score: Number(score.breakdown.disputeScore || 0),
        weight: WEIGHTS.disputeScore,
      },
      {
        key: "stabilityScore",
        label: "Stability",
        hint: "Account tenure and long-term consistency.",
        score: Number(score.breakdown.stabilityScore || 0),
        weight: WEIGHTS.stabilityScore,
      },
    ];
  }, [score]);

  const warnings = useMemo(() => {
    if (!score) return [];

    const items: { level: WarningLevel; title: string; detail: string }[] = [];
    const disputeRate = toPercentNumber(score.metrics.disputeRate);
    const responseRate = toPercentNumber(score.metrics.responseRate);
    const completionRate = toPercentNumber(score.metrics.completionRate);

    if (score.tier === "HIGH_RISK") {
      items.push({
        level: "high",
        title: "High-risk tier detected",
        detail:
          "New listings can be held for admin review before they go live.",
      });
    } else if (score.tier === "WARNING") {
      items.push({
        level: "medium",
        title: "Warning tier",
        detail:
          "Score is in the warning zone. Further decline may trigger stricter moderation.",
      });
    }

    if (score.riskFlagged) {
      items.push({
        level: "high",
        title: "Under monitoring",
        detail: "Recent refund behavior has triggered dynamic risk monitoring.",
      });
    }

    if (disputeRate > 5) {
      items.push({
        level: "high",
        title: "Dispute rate is high",
        detail: `Current dispute rate is ${score.metrics.disputeRate}. Keep it below 5%.`,
      });
    }

    if (responseRate < 80) {
      items.push({
        level: "medium",
        title: "Response rate can improve",
        detail: `Current response rate is ${score.metrics.responseRate}. Aim for 80%+.`,
      });
    }

    if (completionRate < 90) {
      items.push({
        level: "medium",
        title: "Completion rate can improve",
        detail: `Current completion rate is ${score.metrics.completionRate}. Aim for 90%+.`,
      });
    }

    if (items.length === 0) {
      items.push({
        level: "good",
        title: "Healthy score profile",
        detail: "No major warning is currently detected.",
      });
    }

    return items;
  }, [score]);

  const scoreColorClass = useMemo(() => {
    if (!score) return "text-gray-700";
    return TIER_STYLE[resolveTier(score.tier)]?.scoreClass || "text-gray-700";
  }, [score]);

  const moderationLabel = (mode: ModerationMode) =>
    mode === "AUTO_APPROVED" ? "Auto approved" : "Require admin review";

  if (loading) {
    return (
      <div className="p-6 space-y-4">
        <div className="h-32 rounded-xl bg-muted animate-pulse" />
        <div className="h-64 rounded-xl bg-muted animate-pulse" />
        <div className="h-48 rounded-xl bg-muted animate-pulse" />
      </div>
    );
  }

  if (!score) {
    return (
      <div className="p-6">
        <Card>
          <CardContent className="py-10 text-center">
            <p className="text-sm text-muted-foreground mb-4">
              Unable to load seller score.
            </p>
            <Button onClick={() => fetchScore()}>Retry</Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <Card className="border-blue-200 bg-gradient-to-r from-blue-50 via-cyan-50 to-white">
        <CardContent className="py-6">
          <div className="flex flex-wrap items-start justify-between gap-4">
            <div className="space-y-2">
              <h1 className="text-2xl font-bold text-gray-900">
                Seller Score Center
              </h1>
              <p className="text-sm text-gray-600">
                Monitor trust score, understand calculation logic, and resolve
                warnings early.
              </p>
              <div className="flex flex-wrap items-center gap-2">
                <Badge
                  className={TIER_STYLE[resolveTier(score.tier)].badgeClass}
                >
                  {TIER_STYLE[resolveTier(score.tier)].label}
                </Badge>
                {score.riskFlagged && (
                  <Badge className="bg-red-100 text-red-700 border-red-200">
                    Under Monitoring
                  </Badge>
                )}
                <Badge variant="outline">
                  {moderationLabel(score.productModerationMode)}
                </Badge>
              </div>
            </div>

            <div className="text-right">
              <div
                className={`text-5xl font-extrabold leading-none ${scoreColorClass}`}
              >
                {Number(score.finalScore || 0).toFixed(2)}
              </div>
              <div className="text-xs text-muted-foreground mt-1">
                out of 5.00
              </div>
              <div className="text-xs text-muted-foreground mt-3">
                Last calculated: {toDateTimeLabel(score.lastCalculatedAt)}
              </div>
            </div>
          </div>

          <div className="mt-4 flex flex-wrap items-center gap-2">
            <Button
              variant="outline"
              className="cursor-pointer"
              onClick={refreshScore}
              disabled={refreshing}
            >
              <RefreshCw
                className={`h-4 w-4 mr-2 ${refreshing ? "animate-spin" : ""}`}
              />
              Refresh score
            </Button>
            <Button asChild className="bg-blue-600 hover:bg-blue-700">
              <Link to="/seller/products">Improve listing quality</Link>
            </Button>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
        <StatCard
          icon={<Star className="h-4 w-4 text-yellow-500" />}
          label="Average rating"
          value={Number(score.metrics.avgRating || 0).toFixed(2)}
          sub={`${score.metrics.reviewCount} reviews`}
        />
        <StatCard
          icon={<CheckCircle2 className="h-4 w-4 text-emerald-500" />}
          label="Completion"
          value={score.metrics.completionRate}
          sub="Target 90%+"
        />
        <StatCard
          icon={<MessageSquareWarning className="h-4 w-4 text-blue-500" />}
          label="Response"
          value={score.metrics.responseRate}
          sub="Target 80%+"
        />
        <StatCard
          icon={<ShieldAlert className="h-4 w-4 text-red-500" />}
          label="Dispute"
          value={score.metrics.disputeRate}
          sub="Target under 5%"
        />
        <StatCard
          icon={<Clock3 className="h-4 w-4 text-violet-500" />}
          label="Account age"
          value={`${Math.floor(Number(score.metrics.accountAgeMonths || 0))} mo`}
          sub="Stability factor"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <Card className="lg:col-span-2">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Calculator className="h-5 w-5 text-blue-600" />
              Score Breakdown
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="rounded-lg border border-blue-100 bg-blue-50/50 p-3 text-sm">
              <div className="font-semibold text-blue-800">Formula</div>
              <div className="mt-1 text-blue-700">
                Final = 0.40*Rating + 0.20*Completion + 0.10*Response +
                0.15*Dispute + 0.15*Stability
              </div>
            </div>

            {breakdownRows.map((row) => {
              const contribution = row.score * row.weight;
              const widthPercent = Math.min((row.score / 5) * 100, 100);
              return (
                <div key={row.key} className="rounded-lg border p-3 space-y-2">
                  <div className="flex items-start justify-between gap-3">
                    <div>
                      <div className="text-sm font-semibold text-gray-900">
                        {row.label}
                      </div>
                      <div className="text-xs text-muted-foreground">
                        {row.hint}
                      </div>
                    </div>
                    <div className="text-right text-xs">
                      <div className="font-semibold text-gray-800">
                        {row.score.toFixed(2)} / 5
                      </div>
                      <div className="text-muted-foreground">
                        weight {(row.weight * 100).toFixed(0)}%
                      </div>
                    </div>
                  </div>
                  <div className="h-2 w-full rounded-full bg-gray-100 overflow-hidden">
                    <div
                      className="h-full rounded-full bg-blue-500"
                      style={{ width: `${widthPercent}%` }}
                    />
                  </div>
                  <div className="text-xs text-muted-foreground">
                    Contribution: <strong>{contribution.toFixed(2)}</strong>{" "}
                    points
                  </div>
                </div>
              );
            })}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5 text-amber-500" />
              Warnings
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-3">
            {warnings.map((warning, index) => (
              <div
                key={`${warning.title}-${index}`}
                className={`rounded-lg border p-3 text-sm ${
                  warning.level === "high"
                    ? "border-red-200 bg-red-50 text-red-800"
                    : warning.level === "medium"
                      ? "border-amber-200 bg-amber-50 text-amber-800"
                      : warning.level === "low"
                        ? "border-blue-200 bg-blue-50 text-blue-800"
                        : "border-emerald-200 bg-emerald-50 text-emerald-800"
                }`}
              >
                <div className="font-semibold">{warning.title}</div>
                <div className="mt-1 text-xs">{warning.detail}</div>
              </div>
            ))}

            <div className="rounded-lg border border-gray-200 bg-gray-50 p-3 text-xs text-gray-700">
              Tier thresholds:
              <div className="mt-1">- TRUSTED: 4.00-5.00</div>
              <div>- WARNING: 3.00-3.99</div>
              <div>- HIGH_RISK: below 3.00</div>
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <ShieldCheck className="h-5 w-5 text-emerald-600" />
            How To Improve Your Score
          </CardTitle>
        </CardHeader>
        <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
          <div className="rounded-lg border p-3">
            <div className="font-semibold text-gray-900">
              Improve rating quality
            </div>
            <div className="text-muted-foreground mt-1">
              Deliver exactly as described, proactively communicate, and request
              feedback after successful delivery.
            </div>
          </div>
          <div className="rounded-lg border p-3">
            <div className="font-semibold text-gray-900">
              Keep completion high
            </div>
            <div className="text-muted-foreground mt-1">
              Avoid avoidable cancellations and keep inventory synced to prevent
              failed orders.
            </div>
          </div>
          <div className="rounded-lg border p-3">
            <div className="font-semibold text-gray-900">
              Lower disputes & refunds
            </div>
            <div className="text-muted-foreground mt-1">
              Improve packaging quality, shipping accuracy, and return handling
              speed.
            </div>
          </div>
          <div className="rounded-lg border p-3">
            <div className="font-semibold text-gray-900">Respond quickly</div>
            <div className="text-muted-foreground mt-1">
              Keep response rate above 80% and answer buyer questions within 24
              hours.
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

function StatCard({
  icon,
  label,
  value,
  sub,
}: {
  icon: ReactNode;
  label: string;
  value: string;
  sub: string;
}) {
  return (
    <Card>
      <CardContent>
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          {icon}
          {label}
        </div>
        <div className="text-2xl font-bold mt-2 text-gray-900">{value}</div>
        <div className="text-xs text-muted-foreground mt-1">{sub}</div>
      </CardContent>
    </Card>
  );
}

import { useEffect, useMemo, useState } from "react";
import {
  cancelVoucherRequest,
  getMyVoucherRequests,
  getMyVouchers,
  requestVoucher,
  setMyVoucherStatus,
  type Voucher,
  type VoucherRequest,
  type VoucherType,
} from "@/api/vouchers";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

const defaultForm = {
  code: "",
  type: "percentage" as VoucherType,
  value: "",
  minOrderValue: "0",
  maxDiscountAmount: "",
  usageLimit: "",
  perUserLimit: "1",
  startDate: "",
  endDate: "",
};

const statusBadge = (status: string) => {
  if (status === "approved") return <Badge className="bg-green-600">Approved</Badge>;
  if (status === "rejected") return <Badge variant="destructive">Rejected</Badge>;
  if (status === "cancelled") return <Badge variant="outline">Cancelled</Badge>;
  return <Badge variant="secondary">Pending</Badge>;
};

export default function SellerVouchersPage() {
  const [form, setForm] = useState(defaultForm);
  const [submitting, setSubmitting] = useState(false);
  const [requests, setRequests] = useState<VoucherRequest[]>([]);
  const [vouchers, setVouchers] = useState<Voucher[]>([]);
  const [loadingRequests, setLoadingRequests] = useState(true);
  const [loadingVouchers, setLoadingVouchers] = useState(true);
  const [statusFilter, setStatusFilter] = useState("all");

  const loadRequests = async () => {
    try {
      setLoadingRequests(true);
      const params = statusFilter !== "all" ? { status: statusFilter } : undefined;
      const response = await getMyVoucherRequests(params);
      setRequests(response.data);
    } catch (error) {
      toast.error("Failed to load voucher requests");
    } finally {
      setLoadingRequests(false);
    }
  };

  const loadVouchers = async () => {
    try {
      setLoadingVouchers(true);
      const response = await getMyVouchers();
      setVouchers(response.data);
    } catch (error) {
      toast.error("Failed to load vouchers");
    } finally {
      setLoadingVouchers(false);
    }
  };

  useEffect(() => {
    loadRequests();
  }, [statusFilter]);

  useEffect(() => {
    loadVouchers();
  }, []);

  const onSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();

    if (!form.code.trim() || !form.endDate) {
      toast.error("Code and end date are required");
      return;
    }

    if (form.startDate && form.endDate && new Date(form.startDate) >= new Date(form.endDate)) {
      toast.error("Start date must be before end date");
      return;
    }

    setSubmitting(true);
    try {
      await requestVoucher({
        code: form.code.trim().toUpperCase(),
        type: form.type,
        value: Number(form.value),
        minOrderValue: Number(form.minOrderValue) || 0,
        maxDiscountAmount: form.maxDiscountAmount ? Number(form.maxDiscountAmount) : null,
        usageLimit: form.usageLimit ? Number(form.usageLimit) : null,
        perUserLimit: Number(form.perUserLimit) || 1,
        startDate: form.startDate || undefined,
        endDate: form.endDate,
      });
      toast.success("Voucher request submitted");
      setForm(defaultForm);
      await loadRequests();
    } catch (error: any) {
      toast.error(error?.response?.data?.message || "Failed to submit request");
    } finally {
      setSubmitting(false);
    }
  };

  const handleCancelRequest = async (requestId: string) => {
    if (!window.confirm("Cancel this voucher request?")) return;
    try {
      await cancelVoucherRequest(requestId);
      toast.success("Voucher request cancelled");
      await loadRequests();
    } catch (error: any) {
      toast.error(error?.response?.data?.message || "Failed to cancel request");
    }
  };

  const handleToggleVoucher = async (voucher: Voucher) => {
    try {
      await setMyVoucherStatus(voucher._id, !voucher.isActive);
      toast.success("Voucher status updated");
      await loadVouchers();
    } catch (error: any) {
      toast.error(error?.response?.data?.message || "Failed to update voucher");
    }
  };

  const approvedCount = useMemo(
    () => requests.filter((request) => request.status === "approved").length,
    [requests],
  );

  return (
    <div className="container mx-auto py-8 space-y-6">
      <div>
        <h1 className="text-3xl font-bold">Voucher Management</h1>
        <p className="text-gray-600 mt-1">
          Create voucher requests, wait for admin approval, then manage your active vouchers.
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Create Voucher Request</CardTitle>
          <CardDescription>
            Seller can only activate vouchers after admin approval.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={onSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="code">Code</Label>
              <Input
                id="code"
                value={form.code}
                placeholder="WELCOME10"
                onChange={(e) => setForm((prev) => ({ ...prev, code: e.target.value.toUpperCase() }))}
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="type">Type</Label>
              <select
                id="type"
                className="w-full h-10 rounded-md border border-input bg-background px-3 text-sm"
                value={form.type}
                onChange={(e) =>
                  setForm((prev) => ({ ...prev, type: e.target.value as VoucherType }))
                }
              >
                <option value="percentage">Percentage</option>
                <option value="fixed">Fixed amount</option>
              </select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="value">Value</Label>
              <Input
                id="value"
                type="number"
                min={1}
                value={form.value}
                onChange={(e) => setForm((prev) => ({ ...prev, value: e.target.value }))}
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="minOrderValue">Minimum order value</Label>
              <Input
                id="minOrderValue"
                type="number"
                min={0}
                value={form.minOrderValue}
                onChange={(e) => setForm((prev) => ({ ...prev, minOrderValue: e.target.value }))}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="maxDiscountAmount">Max discount amount (optional)</Label>
              <Input
                id="maxDiscountAmount"
                type="number"
                min={0}
                value={form.maxDiscountAmount}
                onChange={(e) => setForm((prev) => ({ ...prev, maxDiscountAmount: e.target.value }))}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="usageLimit">Total usage limit (optional)</Label>
              <Input
                id="usageLimit"
                type="number"
                min={1}
                value={form.usageLimit}
                onChange={(e) => setForm((prev) => ({ ...prev, usageLimit: e.target.value }))}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="perUserLimit">Per-user limit</Label>
              <Input
                id="perUserLimit"
                type="number"
                min={1}
                value={form.perUserLimit}
                onChange={(e) => setForm((prev) => ({ ...prev, perUserLimit: e.target.value }))}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="startDate">Start date (optional)</Label>
              <Input
                id="startDate"
                type="datetime-local"
                value={form.startDate}
                onChange={(e) => setForm((prev) => ({ ...prev, startDate: e.target.value }))}
              />
            </div>
            <div className="space-y-2 md:col-span-2">
              <Label htmlFor="endDate">End date</Label>
              <Input
                id="endDate"
                type="datetime-local"
                value={form.endDate}
                onChange={(e) => setForm((prev) => ({ ...prev, endDate: e.target.value }))}
                required
              />
            </div>
            <div className="md:col-span-2">
              <Button type="submit" disabled={submitting}>
                {submitting ? "Submitting..." : "Submit Voucher Request"}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>

      <Tabs defaultValue="requests" className="space-y-4">
        <TabsList>
          <TabsTrigger value="requests">Requests ({requests.length})</TabsTrigger>
          <TabsTrigger value="vouchers">My Vouchers ({vouchers.length})</TabsTrigger>
        </TabsList>

        <TabsContent value="requests">
          <Card>
            <CardHeader>
              <CardTitle>Voucher Requests</CardTitle>
              <CardDescription>
                Approved requests: {approvedCount}
              </CardDescription>
              <div className="pt-2">
                <select
                  className="h-10 rounded-md border border-input bg-background px-3 text-sm"
                  value={statusFilter}
                  onChange={(e) => setStatusFilter(e.target.value)}
                >
                  <option value="all">All</option>
                  <option value="pending">Pending</option>
                  <option value="approved">Approved</option>
                  <option value="rejected">Rejected</option>
                  <option value="cancelled">Cancelled</option>
                </select>
              </div>
            </CardHeader>
            <CardContent className="p-0">
              {loadingRequests ? (
                <div className="text-center py-10 text-gray-500">Loading requests...</div>
              ) : requests.length === 0 ? (
                <div className="text-center py-10 text-gray-500">No voucher requests</div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Code</TableHead>
                      <TableHead>Type</TableHead>
                      <TableHead>Value</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead>Admin Notes</TableHead>
                      <TableHead>Created</TableHead>
                      <TableHead className="text-right">Action</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {requests.map((request) => (
                      <TableRow key={request._id}>
                        <TableCell className="font-medium">{request.code}</TableCell>
                        <TableCell>{request.type}</TableCell>
                        <TableCell>
                          {request.type === "percentage" ? `${request.value}%` : `$${request.value}`}
                        </TableCell>
                        <TableCell>{statusBadge(request.status)}</TableCell>
                        <TableCell className="max-w-[280px] truncate">
                          {request.rejectionReason || request.adminNotes || "-"}
                        </TableCell>
                        <TableCell>{new Date(request.createdAt).toLocaleDateString()}</TableCell>
                        <TableCell className="text-right">
                          {request.status === "pending" ? (
                            <Button
                              variant="outline"
                              size="sm"
                              onClick={() => handleCancelRequest(request._id)}
                            >
                              Cancel
                            </Button>
                          ) : (
                            "-"
                          )}
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="vouchers">
          <Card>
            <CardHeader>
              <CardTitle>Approved Vouchers</CardTitle>
              <CardDescription>
                Enable or disable vouchers that are already approved by admin.
              </CardDescription>
            </CardHeader>
            <CardContent className="p-0">
              {loadingVouchers ? (
                <div className="text-center py-10 text-gray-500">Loading vouchers...</div>
              ) : vouchers.length === 0 ? (
                <div className="text-center py-10 text-gray-500">No vouchers yet</div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Code</TableHead>
                      <TableHead>Type</TableHead>
                      <TableHead>Usage</TableHead>
                      <TableHead>Period</TableHead>
                      <TableHead>Status</TableHead>
                      <TableHead className="text-right">Action</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {vouchers.map((voucher) => (
                      <TableRow key={voucher._id}>
                        <TableCell className="font-medium">{voucher.code}</TableCell>
                        <TableCell>
                          {voucher.type === "percentage"
                            ? `${voucher.value}%`
                            : `$${voucher.value}`}
                        </TableCell>
                        <TableCell>
                          {voucher.usedCount}
                          {voucher.usageLimit ? ` / ${voucher.usageLimit}` : " / unlimited"}
                        </TableCell>
                        <TableCell>
                          {new Date(voucher.startDate).toLocaleDateString()} -{" "}
                          {new Date(voucher.endDate).toLocaleDateString()}
                        </TableCell>
                        <TableCell>
                          {voucher.isActive ? (
                            <Badge className="bg-green-600">Active</Badge>
                          ) : (
                            <Badge variant="outline">Inactive</Badge>
                          )}
                        </TableCell>
                        <TableCell className="text-right">
                          <Button
                            size="sm"
                            variant={voucher.isActive ? "outline" : "default"}
                            onClick={() => handleToggleVoucher(voucher)}
                          >
                            {voucher.isActive ? "Disable" : "Enable"}
                          </Button>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useEffect, useState, useCallback, useContext } from "react";
import { toast } from "sonner";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Bell } from "lucide-react";
import { getAvailableOrders, acceptOrder, rejectOrder, type ShipperOrder } from "@/api/shipper";
import { SocketContext } from "@/hooks/use-socket";

export default function ShipperAvailableOrders() {
  const [orders, setOrders] = useState<ShipperOrder[]>([]);
  const [page, setPage] = useState(1);
  const [pages, setPages] = useState(1);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const socketCtx = useContext(SocketContext);

  const fetchOrders = useCallback(async (p: number) => {
    setLoading(true);
    try {
      const res = await getAvailableOrders(p);
      setOrders(res.data.orders);
      setPages(res.data.pages);
      setTotal(res.data.total);
    } catch {
      toast.error("Failed to load available orders");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchOrders(page);
  }, [fetchOrders, page]);

  // Real-time: refresh khi có đơn mới được assign
  useEffect(() => {
    const socket = socketCtx?.socket;
    if (!socket) return;

    const handleNotification = (data: { type: string }) => {
      if (data.type === "order_assigned") {
        fetchOrders(1);
        setPage(1);
      }
    };

    socket.on("notification", handleNotification);
    return () => { socket.off("notification", handleNotification); };
  }, [socketCtx?.socket, fetchOrders]);

  const handleAccept = async (orderId: string) => {
    setActionLoading(orderId);
    try {
      await acceptOrder(orderId);
      toast.success("Order accepted! Check My Deliveries.");
      setOrders((prev) => prev.filter((o) => o._id !== orderId));
      setTotal((t) => t - 1);
    } catch (err: any) {
      const msg = err?.response?.data?.message || "Failed to accept order";
      toast.error(msg);
    } finally {
      setActionLoading(null);
    }
  };

  const handleDecline = async (orderId: string) => {
    setActionLoading(orderId);
    try {
      await rejectOrder(orderId);
      toast.info("Order declined.");
      setOrders((prev) => prev.filter((o) => o._id !== orderId));
      setTotal((t) => t - 1);
    } catch (err: any) {
      const msg = err?.response?.data?.message || "Failed to decline order";
      toast.error(msg);
    } finally {
      setActionLoading(null);
    }
  };

  const pendingOrders = orders.filter((o) =>
    o.status === "pending_acceptance" ||
    o.status === "pending_delivery_acceptance" ||
    o.status === "return_pending_delivery_acceptance"
  );
  const openOrders = orders.filter((o) =>
    o.status !== "pending_acceptance" &&
    o.status !== "pending_delivery_acceptance" &&
    o.status !== "return_pending_delivery_acceptance"
  );

  const renderOrderCard = (order: ShipperOrder, isPending: boolean) => {
    const addr = order.shippingAddress;
    const busy = actionLoading === order._id;
    return (
      <Card key={order._id} className={isPending ? "border-orange-200 bg-orange-50/30" : ""}>
        <CardHeader className="pb-2">
          <div className="flex items-center justify-between">
            <CardTitle className="text-sm font-mono text-gray-600">
              #{order._id.slice(-8).toUpperCase()}
            </CardTitle>
            {order.status === "return_pending_delivery_acceptance" ? (
              <Badge className="bg-rose-100 text-rose-700 border border-rose-300">
                Return Delivery — Awaiting Acceptance
              </Badge>
            ) : order.status === "pending_delivery_acceptance" ? (
              <Badge className="bg-cyan-100 text-cyan-700 border border-cyan-300">
                Delivery — Awaiting Acceptance
              </Badge>
            ) : isPending ? (
              <Badge className="bg-orange-100 text-orange-700 border border-orange-300">
                Pickup — Awaiting Your Acceptance
              </Badge>
            ) : order.status === "delivery_queued" ? (
              <Badge variant="outline" className="text-cyan-700 border-cyan-300 bg-cyan-50">
                Delivery — In Your Area
              </Badge>
            ) : order.status === "return_delivery_queued" ? (
              <Badge variant="outline" className="text-rose-700 border-rose-300 bg-rose-50">
                Return Delivery — To Seller
              </Badge>
            ) : order.status === "waiting_return_shipment" ? (
              <Badge variant="outline" className="text-purple-700 border-purple-300 bg-purple-50">
                Return Pick-up
              </Badge>
            ) : (
              <Badge variant="outline" className="text-blue-700 border-blue-300 bg-blue-50">
                Pickup Available
              </Badge>
            )}
          </div>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4 text-sm">
            <div>
              <p className="text-gray-500">Seller</p>
              <p className="font-medium">
                {order.seller?.sellerInfo?.shopName || order.seller?.username || "—"}
              </p>
              {/* Pickup address for Shipper 1 */}
              {(order.status === "pending_acceptance" || order.status === "ready_to_ship" || order.status === "queued") &&
                order.seller?.sellerInfo?.shopAddress && (
                <p className="text-xs text-orange-600 font-medium mt-0.5">
                  📦 Pickup: {order.seller.sellerInfo.shopAddress}
                </p>
              )}
              {/* Return delivery: deliver to seller */}
              {(order.status === "return_delivery_queued" || order.status === "return_pending_delivery_acceptance") &&
                order.seller?.sellerInfo?.shopAddress && (
                <p className="text-xs text-rose-600 font-medium mt-0.5">
                  📦 Deliver to: {order.seller.sellerInfo.shopAddress}
                </p>
              )}
            </div>
            <div>
              <p className="text-gray-500">Delivery Address</p>
              <p className="font-medium">{addr?.fullName || "—"}</p>
              <p className="text-xs text-gray-400">
                {[addr?.street, addr?.ward, addr?.district, addr?.city].filter(Boolean).join(", ") || "—"}
              </p>
              {addr?.phone && <p className="text-xs text-gray-400">{addr.phone}</p>}
            </div>
            <div>
              <p className="text-gray-500">Total</p>
              <p className="font-medium text-orange-600">${order.totalAmount.toFixed(2)}</p>
            </div>
            <div>
              <p className="text-gray-500">Date</p>
              <p className="font-medium">
                {new Date(order.createdAt).toLocaleDateString()}
              </p>
            </div>
          </div>

          {/* Items */}
          {order.items && order.items.length > 0 && (
            <div className="mb-4 border rounded-lg overflow-hidden">
              <p className="text-xs font-semibold text-gray-500 uppercase tracking-wide px-3 py-2 bg-gray-50 border-b">
                Items ({order.items.length})
              </p>
              <div className="divide-y">
                {order.items.map((item, i) => (
                  <div key={i} className="flex items-center justify-between px-3 py-2 text-sm">
                    <span className="text-gray-800 flex-1 mr-2">{item.title || "—"}</span>
                    <span className="text-gray-500 whitespace-nowrap">
                      x{item.quantity} · <span className="font-medium">${(item.unitPrice * item.quantity).toFixed(2)}</span>
                    </span>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div className="flex gap-2">
            <Button
              size="sm"
              className="bg-orange-600 hover:bg-orange-700 text-white"
              disabled={busy}
              onClick={() => handleAccept(order._id)}
            >
              {busy ? "..." : "Accept"}
            </Button>
            {(order.status === "pending_acceptance" || order.status === "pending_delivery_acceptance" || order.status === "return_pending_delivery_acceptance") && (
              <Button
                size="sm"
                variant="outline"
                disabled={busy}
                onClick={() => handleDecline(order._id)}
              >
                Decline
              </Button>
            )}
          </div>
        </CardContent>
      </Card>
    );
  };

  return (
    <div className="p-6">
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Available Orders</h1>
        <span className="text-sm text-gray-500">{total} orders waiting</span>
      </div>

      {loading ? (
        <div className="text-center py-12 text-gray-500">Loading...</div>
      ) : orders.length === 0 ? (
        <div className="text-center py-12 text-gray-500">No available orders at the moment.</div>
      ) : (
        <div className="space-y-6">
          {/* Pending acceptance - assigned to this shipper */}
          {pendingOrders.length > 0 && (
            <div>
              <div className="flex items-center gap-2 mb-3">
                <Bell className="h-4 w-4 text-orange-600" />
                <h2 className="text-base font-semibold text-orange-700">
                  Assigned to You — Pending Acceptance ({pendingOrders.length})
                </h2>
              </div>
              <div className="space-y-3">
                {pendingOrders.map((order) => renderOrderCard(order, true))}
              </div>
            </div>
          )}

          {/* Open orders - available for any shipper */}
          {openOrders.length > 0 && (
            <div>
              {pendingOrders.length > 0 && (
                <h2 className="text-base font-semibold text-gray-700 mb-3">
                  Open Orders ({openOrders.length})
                </h2>
              )}
              <div className="space-y-3">
                {openOrders.map((order) => renderOrderCard(order, false))}
              </div>
            </div>
          )}
        </div>
      )}

      {pages > 1 && (
        <div className="flex justify-center gap-2 mt-6">
          <Button
            variant="outline"
            size="sm"
            disabled={page <= 1}
            onClick={() => setPage((p) => p - 1)}
          >
            Previous
          </Button>
          <span className="px-3 py-1 text-sm text-gray-600">
            {page} / {pages}
          </span>
          <Button
            variant="outline"
            size="sm"
            disabled={page >= pages}
            onClick={() => setPage((p) => p + 1)}
          >
            Next
          </Button>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState, useCallback } from "react";
import { toast } from "sonner";
import { ImagePlus, X, ShieldAlert, CheckCircle2, Clock, MessageSquare, MapPin, User, PackageX } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import {
  getShipperDisputes,
  shipperRespond,
  uploadDisputeImages,
  type ShipperDisputeItem,
} from "@/api/deliveryDispute";

const STATUS_CONFIG: Record<string, { label: string; badgeClass: string; icon: React.ReactNode }> = {
  PENDING_SHIPPER: {
    label: "Awaiting Response",
    badgeClass: "bg-orange-100 text-orange-700 border-orange-200",
    icon: <Clock className="w-3 h-3" />,
  },
  SHIPPER_RESPONDED: {
    label: "Responded",
    badgeClass: "bg-blue-100 text-blue-700 border-blue-200",
    icon: <MessageSquare className="w-3 h-3" />,
  },
  CONFIRMED: {
    label: "Resolved",
    badgeClass: "bg-green-100 text-green-700 border-green-200",
    icon: <CheckCircle2 className="w-3 h-3" />,
  },
};

type FilterStatus = "all" | "PENDING_SHIPPER" | "SHIPPER_RESPONDED" | "CONFIRMED";

export default function ShipperDisputes() {
  const [disputes, setDisputes] = useState<ShipperDisputeItem[]>([]);
  const [filterStatus, setFilterStatus] = useState<FilterStatus>("all");
  const [loading, setLoading] = useState(true);
  const [respondingId, setRespondingId] = useState<string | null>(null);
  const [note, setNote] = useState("");
  const [imageFiles, setImageFiles] = useState<File[]>([]);
  const [imagePreviews, setImagePreviews] = useState<string[]>([]);
  const [submitting, setSubmitting] = useState(false);

  const fetchDisputes = useCallback(async () => {
    setLoading(true);
    try {
      const res = await getShipperDisputes(filterStatus === "all" ? undefined : filterStatus);
      setDisputes(res.data.disputes);
    } catch {
      toast.error("Failed to load disputes");
    } finally {
      setLoading(false);
    }
  }, [filterStatus]);

  useEffect(() => {
    fetchDisputes();
  }, [fetchDisputes]);

  const openRespond = (id: string) => {
    setRespondingId(id);
    setNote("");
    setImageFiles([]);
    setImagePreviews([]);
  };

  const closeRespond = () => {
    setRespondingId(null);
    setNote("");
    setImageFiles([]);
    setImagePreviews([]);
  };

  const handleImageSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    const combined = [...imageFiles, ...files].slice(0, 5);
    setImageFiles(combined);
    setImagePreviews(combined.map((f) => URL.createObjectURL(f)));
  };

  const removeImage = (idx: number) => {
    const newFiles = imageFiles.filter((_, i) => i !== idx);
    setImageFiles(newFiles);
    setImagePreviews(newFiles.map((f) => URL.createObjectURL(f)));
  };

  const handleSubmitRespond = async (disputeId: string) => {
    if (!note.trim()) {
      toast.error("Please enter your response");
      return;
    }
    setSubmitting(true);
    try {
      let imageUrls: string[] = [];
      if (imageFiles.length > 0) {
        imageUrls = await uploadDisputeImages(imageFiles);
      }
      await shipperRespond(disputeId, { shipperNote: note, shipperImages: imageUrls });
      toast.success("Response submitted. The buyer will be notified.");
      closeRespond();
      fetchDisputes();
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to submit response");
    } finally {
      setSubmitting(false);
    }
  };

  const tabs: { label: string; value: FilterStatus; count?: number }[] = [
    { label: "All", value: "all", count: disputes.length },
    { label: "Awaiting Response", value: "PENDING_SHIPPER", count: disputes.filter(d => d.status === "PENDING_SHIPPER").length },
    { label: "Responded", value: "SHIPPER_RESPONDED", count: disputes.filter(d => d.status === "SHIPPER_RESPONDED").length },
    { label: "Resolved", value: "CONFIRMED", count: disputes.filter(d => d.status === "CONFIRMED").length },
  ];

  const pendingCount = disputes.filter((d) => d.status === "PENDING_SHIPPER").length;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-start justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-orange-100 flex items-center justify-center">
            <ShieldAlert className="w-5 h-5 text-orange-600" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-gray-900">Delivery Disputes</h1>
            <p className="text-sm text-gray-500">Respond to delivery complaints from buyers</p>
          </div>
        </div>
      </div>

      {/* Alert banner */}
      {!loading && pendingCount > 0 && (
        <div className="flex items-center gap-3 bg-orange-50 border border-orange-200 rounded-xl px-5 py-3">
          <Clock className="w-4 h-4 text-orange-600 flex-shrink-0" />
          <p className="text-sm text-orange-700 font-medium">
            You have <span className="font-bold">{pendingCount}</span> dispute{pendingCount > 1 ? "s" : ""} awaiting your response.
          </p>
        </div>
      )}

      {/* Filter tabs */}
      <div className="flex gap-2 flex-wrap">
        {tabs.map((tab) => (
          <button
            key={tab.value}
            onClick={() => setFilterStatus(tab.value)}
            className={`flex items-center gap-1.5 px-4 py-1.5 rounded-full text-xs font-medium transition-all ${
              filterStatus === tab.value
                ? "bg-orange-600 text-white shadow-sm"
                : "bg-white text-gray-600 border border-gray-200 hover:border-orange-300 hover:text-orange-600"
            }`}
          >
            {tab.label}
            {tab.count !== undefined && tab.count > 0 && (
              <span className={`px-1.5 py-0.5 rounded-full text-[10px] font-bold leading-none ${
                filterStatus === tab.value ? "bg-white/30 text-white" : "bg-gray-100 text-gray-500"
              }`}>
                {tab.count}
              </span>
            )}
          </button>
        ))}
      </div>

      {/* Content */}
      {loading ? (
        <div className="space-y-3">
          {[1, 2, 3].map((i) => (
            <div key={i} className="bg-white rounded-2xl border border-gray-100 p-6 animate-pulse">
              <div className="flex justify-between mb-3">
                <div className="h-4 bg-gray-100 rounded w-32" />
                <div className="h-5 bg-gray-100 rounded w-24" />
              </div>
              <div className="h-3 bg-gray-100 rounded w-48 mb-4" />
              <div className="h-16 bg-gray-100 rounded" />
            </div>
          ))}
        </div>
      ) : disputes.length === 0 ? (
        <div className="bg-white rounded-2xl border border-gray-100 py-20 flex flex-col items-center text-center">
          <div className="w-16 h-16 rounded-2xl bg-gray-50 flex items-center justify-center mb-4">
            <PackageX className="w-8 h-8 text-gray-300" />
          </div>
          <p className="text-base font-semibold text-gray-700 mb-1">No disputes found</p>
          <p className="text-sm text-gray-400 max-w-xs">
            {filterStatus === "all"
              ? "You have no delivery disputes at this time."
              : "No disputes with this status."}
          </p>
        </div>
      ) : (
        <div className="space-y-4">
          {disputes.map((dispute) => {
            const cfg = STATUS_CONFIG[dispute.status] || {
              label: dispute.status,
              badgeClass: "bg-gray-100 text-gray-600 border-gray-200",
              icon: null,
            };
            const addr = dispute.order?.shippingAddress;
            const isResponding = respondingId === dispute._id;
            const isPending = dispute.status === "PENDING_SHIPPER";

            return (
              <div
                key={dispute._id}
                className={`bg-white rounded-2xl border overflow-hidden shadow-sm transition-all ${
                  isPending ? "border-orange-200" : "border-gray-100"
                }`}
              >
                {/* Card header */}
                <div className={`flex items-center justify-between px-6 py-4 ${isPending ? "bg-orange-50/60" : "bg-gray-50/40"}`}>
                  <div>
                    <span className="font-mono text-sm font-semibold text-gray-800">
                      Order #{(dispute.order?._id || "").slice(-8).toUpperCase()}
                    </span>
                    <p className="text-xs text-gray-400 mt-0.5">
                      Reported on {new Date(dispute.createdAt).toLocaleString("en-US")}
                    </p>
                  </div>
                  <span className={`inline-flex items-center gap-1.5 text-xs font-medium px-3 py-1 rounded-full border ${cfg.badgeClass}`}>
                    {cfg.icon}
                    {cfg.label}
                  </span>
                </div>

                <div className="px-6 py-5 space-y-4">
                  {/* Info row */}
                  <div className="flex flex-wrap gap-5 text-sm">
                    <div className="flex items-center gap-1.5 text-gray-600">
                      <User className="w-3.5 h-3.5 text-gray-400" />
                      <span className="text-xs text-gray-400">Buyer:</span>
                      <span className="font-medium text-gray-800">{dispute.buyer?.username || "—"}</span>
                    </div>
                    <div className="flex items-center gap-1.5 text-gray-600">
                      <MapPin className="w-3.5 h-3.5 text-gray-400" />
                      <span className="text-xs text-gray-400">Address:</span>
                      <span className="font-medium text-gray-800">
                        {[addr?.district, addr?.city].filter(Boolean).join(", ") || "—"}
                      </span>
                    </div>
                    <div className="flex items-center gap-1.5 text-gray-600">
                      <span className="text-xs text-gray-400">Order value:</span>
                      <span className="font-semibold text-gray-800">${dispute.order?.totalAmount?.toFixed(2)}</span>
                    </div>
                  </div>

                  {/* Buyer's complaint */}
                  {dispute.buyerNote && (
                    <div className="rounded-xl border border-red-100 bg-red-50 p-4">
                      <div className="flex items-center gap-1.5 mb-2">
                        <ShieldAlert className="w-3.5 h-3.5 text-red-500" />
                        <p className="text-xs font-semibold text-red-600 uppercase tracking-wide">Buyer's Complaint</p>
                      </div>
                      <p className="text-sm text-red-800 leading-relaxed">{dispute.buyerNote}</p>
                    </div>
                  )}

                  {/* Shipper's previous response */}
                  {dispute.shipperNote && dispute.status !== "PENDING_SHIPPER" && (
                    <div className="rounded-xl border border-blue-100 bg-blue-50 p-4">
                      <div className="flex items-center gap-1.5 mb-2">
                        <MessageSquare className="w-3.5 h-3.5 text-blue-500" />
                        <p className="text-xs font-semibold text-blue-600 uppercase tracking-wide">Your Response</p>
                      </div>
                      <p className="text-sm text-blue-800 leading-relaxed">{dispute.shipperNote}</p>
                      {dispute.shipperImages?.length > 0 && (
                        <div className="flex gap-2 mt-3 flex-wrap">
                          {dispute.shipperImages.map((url, i) => (
                            <img
                              key={i}
                              src={url}
                              alt={`Evidence ${i + 1}`}
                              className="h-20 w-20 object-cover rounded-lg border border-blue-100 shadow-sm"
                            />
                          ))}
                        </div>
                      )}
                    </div>
                  )}

                  {/* Respond form */}
                  {isPending && (
                    <>
                      {!isResponding ? (
                        <Button
                          size="sm"
                          className="bg-orange-600 hover:bg-orange-700 text-white rounded-lg"
                          onClick={() => openRespond(dispute._id)}
                        >
                          <MessageSquare className="w-3.5 h-3.5 mr-1.5" />
                          Respond to Dispute
                        </Button>
                      ) : (
                        <div className="rounded-xl border border-orange-200 bg-orange-50/40 p-5 space-y-3">
                          <p className="text-sm font-semibold text-gray-700">Your response:</p>
                          <Textarea
                            placeholder="Describe the delivery situation (required)..."
                            value={note}
                            onChange={(e) => setNote(e.target.value)}
                            rows={3}
                            className="bg-white resize-none text-sm"
                          />

                          {/* Image upload */}
                          <div>
                            <p className="text-xs text-gray-500 mb-2">
                              Attach evidence photos (optional, max 5):
                            </p>
                            {imagePreviews.length > 0 && (
                              <div className="flex gap-2 flex-wrap mb-2">
                                {imagePreviews.map((src, i) => (
                                  <div key={i} className="relative group">
                                    <img
                                      src={src}
                                      alt={`Preview ${i}`}
                                      className="h-[72px] w-[72px] object-cover rounded-lg border border-gray-200 shadow-sm"
                                    />
                                    <button
                                      type="button"
                                      onClick={() => removeImage(i)}
                                      className="absolute -top-1.5 -right-1.5 bg-red-500 text-white rounded-full w-5 h-5 flex items-center justify-center shadow-sm opacity-0 group-hover:opacity-100 transition-opacity"
                                    >
                                      <X className="w-3 h-3" />
                                    </button>
                                  </div>
                                ))}
                              </div>
                            )}
                            {imageFiles.length < 5 && (
                              <label className="cursor-pointer inline-flex items-center gap-1.5 text-sm text-orange-600 hover:text-orange-700 font-medium">
                                <ImagePlus className="h-4 w-4" />
                                Add photos
                                <input
                                  type="file"
                                  accept="image/*"
                                  multiple
                                  className="hidden"
                                  onChange={handleImageSelect}
                                />
                              </label>
                            )}
                          </div>

                          <div className="flex gap-2 pt-1">
                            <Button
                              size="sm"
                              className="bg-orange-600 hover:bg-orange-700 text-white rounded-lg"
                              disabled={submitting}
                              onClick={() => handleSubmitRespond(dispute._id)}
                            >
                              {submitting ? "Submitting..." : "Submit Response"}
                            </Button>
                            <Button
                              size="sm"
                              variant="outline"
                              disabled={submitting}
                              onClick={closeRespond}
                              className="rounded-lg"
                            >
                              Cancel
                            </Button>
                          </div>
                        </div>
                      )}
                    </>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState, useCallback } from "react";
import { toast } from "sonner";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { getMyOrders, markDelivered, arrivedAtDestination, arrivedAtReturnDestination, type ShipperOrder } from "@/api/shipper";

const STATUS_CONFIG: Record<string, { label: string; className: string }> = {
  shipping: { label: "Picking Up", className: "text-purple-700 border-purple-300 bg-purple-50" },
  in_transit: { label: "Arrived at Destination", className: "text-cyan-700 border-cyan-300 bg-cyan-50" },
  delivering: { label: "Delivering", className: "text-blue-700 border-blue-300 bg-blue-50" },
  delivered: { label: "Delivered", className: "text-green-700 border-green-300 bg-green-50" },
  completed: { label: "Completed", className: "text-emerald-700 border-emerald-300 bg-emerald-50" },
  return_shipping: { label: "Return: Picking Up", className: "text-orange-700 border-orange-300 bg-orange-50" },
  return_in_transit: { label: "Return: In Transit", className: "text-amber-700 border-amber-300 bg-amber-50" },
  return_delivering: { label: "Return: Delivering to Seller", className: "text-rose-700 border-rose-300 bg-rose-50" },
  delivered_to_seller: { label: "Returned to Seller", className: "text-teal-700 border-teal-300 bg-teal-50" },
};

type StatusFilter = "all" | "shipping" | "delivered" | "completed";

export default function ShipperMyOrders() {
  const [orders, setOrders] = useState<ShipperOrder[]>([]);
  const [statusFilter, setStatusFilter] = useState<StatusFilter>("all");
  const [page, setPage] = useState(1);
  const [pages, setPages] = useState(1);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const fetchOrders = useCallback(async (p: number, status: StatusFilter) => {
    setLoading(true);
    try {
      const params: Record<string, any> = { page: p };
      if (status !== "all") params.status = status;
      const res = await getMyOrders(params);
      setOrders(res.data.orders);
      setPages(res.data.pages);
      setTotal(res.data.total);
    } catch {
      toast.error("Failed to load orders");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchOrders(page, statusFilter);
  }, [fetchOrders, page, statusFilter]);

  const handleStatusChange = (s: StatusFilter) => {
    setStatusFilter(s);
    setPage(1);
  };

  const handleMarkDelivered = async (orderId: string) => {
    setActionLoading(orderId);
    try {
      const order = orders.find((o) => o._id === orderId);
      const res = await markDelivered(orderId);
      if (order?.status === "return_shipping" || order?.status === "return_delivering") {
        toast.success("Marked as returned to seller!");
      } else {
        toast.success("Order delivered successfully!");
      }
      setOrders((prev) =>
        prev.map((o) => (o._id === orderId ? res.data.order : o)),
      );
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to update order");
    } finally {
      setActionLoading(null);
    }
  };

  const handleArrivedAtDestination = async (orderId: string) => {
    setActionLoading(orderId);
    try {
      const res = await arrivedAtDestination(orderId);
      if (res.data.sameCity) {
        toast.success("Picked up! Delivering directly to buyer.");
      } else {
        toast.success("Arrived at destination — handing off to local delivery shipper.");
      }
      setOrders((prev) =>
        prev.map((o) => (o._id === orderId ? res.data.order : o)),
      );
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to update order");
    } finally {
      setActionLoading(null);
    }
  };

  const handleArrivedAtReturnDestination = async (orderId: string) => {
    setActionLoading(orderId);
    try {
      const res = await arrivedAtReturnDestination(orderId);
      if (res.data.sameCity) {
        toast.success("Picked up return! Delivering directly to seller.");
      } else {
        toast.success("Arrived at seller area — handing off to local shipper.");
      }
      setOrders((prev) =>
        prev.map((o) => (o._id === orderId ? res.data.order : o)),
      );
    } catch (err: any) {
      toast.error(err?.response?.data?.message || "Failed to update order");
    } finally {
      setActionLoading(null);
    }
  };

  const tabs: { label: string; value: StatusFilter }[] = [
    { label: "All", value: "all" },
    { label: "In Transit", value: "shipping" },
    { label: "Delivered", value: "delivered" },
    { label: "Completed", value: "completed" },
  ];

  return (
    <div className="p-6">
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold text-gray-900">My Deliveries</h1>
        <span className="text-sm text-gray-500">{total} orders</span>
      </div>

      <div className="flex gap-2 mb-6">
        {tabs.map((tab) => (
          <button
            key={tab.value}
            onClick={() => handleStatusChange(tab.value)}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors ${
              statusFilter === tab.value
                ? "bg-orange-600 text-white"
                : "bg-gray-100 text-gray-600 hover:bg-gray-200"
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="text-center py-12 text-gray-500">Loading...</div>
      ) : orders.length === 0 ? (
        <div className="text-center py-12 text-gray-500">No orders found.</div>
      ) : (
        <div className="space-y-4">
          {orders.map((order) => {
            const addr = order.shippingAddress;
            const cfg = STATUS_CONFIG[order.status] || {
              label: order.status,
              className: "text-gray-600 border-gray-300 bg-gray-50",
            };
            const busy = actionLoading === order._id;
            return (
              <Card key={order._id}>
                <CardHeader className="pb-2">
                  <div className="flex items-center justify-between">
                    <CardTitle className="text-sm font-mono text-gray-600">
                      #{order._id.slice(-8).toUpperCase()}
                    </CardTitle>
                    <Badge variant="outline" className={cfg.className}>
                      {cfg.label}
                    </Badge>
                  </div>
                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4 text-sm">
                    <div>
                      <p className="text-gray-500">Buyer</p>
                      <p className="font-medium">{order.buyer?.username || "—"}</p>
                    </div>
                    {/* Pickup address: seller shop address (for Shipper 1) */}
                    {order.status === "shipping" && order.seller?.sellerInfo?.shopAddress && (
                      <div>
                        <p className="text-gray-500">Pickup From (Seller)</p>
                        <p className="font-medium">{order.seller.username}</p>
                        <p className="text-xs text-gray-400">{order.seller.sellerInfo.shopAddress}</p>
                      </div>
                    )}
                    {/* Return delivery: deliver TO seller */}
                    {(order.status === "return_delivering") && order.seller?.sellerInfo?.shopAddress && (
                      <div>
                        <p className="text-gray-500">Deliver To (Seller)</p>
                        <p className="font-medium">{order.seller.username}</p>
                        <p className="text-xs text-gray-400">{order.seller.sellerInfo.shopAddress}</p>
                      </div>
                    )}
                    <div>
                      <p className="text-gray-500">Delivery Address</p>
                      <p className="font-medium">{addr?.fullName || "—"}</p>
                      <p className="text-xs text-gray-400">
                        {[addr?.street, addr?.ward, addr?.district, addr?.city].filter(Boolean).join(", ") || "—"}
                      </p>
                      {addr?.phone && <p className="text-xs text-gray-400">{addr.phone}</p>}
                    </div>
                    <div>
                      <p className="text-gray-500">Total</p>
                      <p className="font-medium text-orange-600">${order.totalAmount.toFixed(2)}</p>
                    </div>
                    <div>
                      <p className="text-gray-500">Date</p>
                      <p className="font-medium">
                        {new Date(order.updatedAt).toLocaleDateString()}
                      </p>
                    </div>
                  </div>

                  {/* Items */}
                  {order.items && order.items.length > 0 && (
                    <div className="mb-4 border rounded-lg overflow-hidden">
                      <p className="text-xs font-semibold text-gray-500 uppercase tracking-wide px-3 py-2 bg-gray-50 border-b">
                        Items ({order.items.length})
                      </p>
                      <div className="divide-y">
                        {order.items.map((item, i) => (
                          <div key={i} className="flex items-center justify-between px-3 py-2 text-sm">
                            <span className="text-gray-800 flex-1 mr-2">{item.title || "—"}</span>
                            <span className="text-gray-500 whitespace-nowrap">
                              x{item.quantity} · <span className="font-medium">${(item.unitPrice * item.quantity).toFixed(2)}</span>
                            </span>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}

                  <div className="flex gap-2 flex-wrap">
                    {/* Shipper 1: đang lấy hàng từ seller */}
                    {order.status === "shipping" && (() => {
                      const isSameCity =
                        order.sellerCity &&
                        order.shippingAddress?.city &&
                        order.sellerCity === order.shippingAddress.city;
                      return isSameCity ? (
                        <Button
                          size="sm"
                          className="bg-green-600 hover:bg-green-700 text-white"
                          disabled={busy}
                          onClick={() => handleMarkDelivered(order._id)}
                        >
                          {busy ? "..." : "Mark Delivered"}
                        </Button>
                      ) : (
                        <Button
                          size="sm"
                          className="bg-cyan-600 hover:bg-cyan-700 text-white"
                          disabled={busy}
                          onClick={() => handleArrivedAtDestination(order._id)}
                        >
                          {busy ? "..." : "Arrived at Destination"}
                        </Button>
                      );
                    })()}
                    {/* Shipper 2: đang giao đến buyer */}
                    {order.status === "delivering" && (
                      <Button
                        size="sm"
                        className="bg-green-600 hover:bg-green-700 text-white"
                        disabled={busy}
                        onClick={() => handleMarkDelivered(order._id)}
                      >
                        {busy ? "..." : "Mark Delivered"}
                      </Button>
                    )}
                    {/* Return Shipper 1: đang lấy hàng từ buyer */}
                    {order.status === "return_shipping" && (() => {
                      const isSameCity =
                        order.sellerCity &&
                        order.shippingAddress?.city &&
                        order.sellerCity === order.shippingAddress.city;
                      return isSameCity ? (
                        <Button
                          size="sm"
                          className="bg-green-600 hover:bg-green-700 text-white"
                          disabled={busy}
                          onClick={() => handleMarkDelivered(order._id)}
                        >
                          {busy ? "..." : "Mark Returned to Seller"}
                        </Button>
                      ) : (
                        <Button
                          size="sm"
                          className="bg-rose-600 hover:bg-rose-700 text-white"
                          disabled={busy}
                          onClick={() => handleArrivedAtReturnDestination(order._id)}
                        >
                          {busy ? "..." : "Arrived at Seller Area"}
                        </Button>
                      );
                    })()}
                    {/* Return Shipper 2: đang giao đến seller */}
                    {order.status === "return_delivering" && (
                      <Button
                        size="sm"
                        className="bg-green-600 hover:bg-green-700 text-white"
                        disabled={busy}
                        onClick={() => handleMarkDelivered(order._id)}
                      >
                        {busy ? "..." : "Mark Returned to Seller"}
                      </Button>
                    )}
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </div>
      )}

      {pages > 1 && (
        <div className="flex justify-center gap-2 mt-6">
          <Button
            variant="outline"
            size="sm"
            disabled={page <= 1}
            onClick={() => setPage((p) => p - 1)}
          >
            Previous
          </Button>
          <span className="px-3 py-1 text-sm text-gray-600">
            {page} / {pages}
          </span>
          <Button
            variant="outline"
            size="sm"
            disabled={page >= pages}
            onClick={() => setPage((p) => p + 1)}
          >
            Next
          </Button>
        </div>
      )}
    </div>
  );
}

